                    }
                    if (DataBaseAccess.isQERequired() == false)
                    {
                        wsDts.Column(24).Hidden = true;
                    }
                    if (DataBaseAccess.getShopDefaultReportColumnSetting("LiveReport", "DailyAndShift_Target") == false)
                    {
                        wsDts.Column(10).Hidden = true;
                    }
                    if (DataBaseAccess.getShopDefaultReportColumnSetting("LiveReport", "DailyAndShift_Diff") == false)
                    {
                        wsDts.Column(12).Hidden = true;
                    }
                    string modelRange = "A8:Y" + (row - 1).ToString();
                    var modelTable = wsDts.Cells[modelRange];
                    //Added by abhi to hide columns
                    //if (ConfigurationManager.AppSettings["AdvikPages"].ToString().Equals("1"))
                    //{
                    //    wsDts.Column(11).Hidden = true;
                    //    wsDts.Column(14).Hidden = true;
                    //    wsDts.Column(17).Hidden = true;
                    //    wsDts.Column(18).Hidden = true;
                    //}
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Production report-Machinewise Shift-Format- 1 Report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex); ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }


        public static string ProductionDantalReports(string PlantID, string MachineID, string CellID, DateTime StartDate, DateTime EndDate, string Plant)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "ProductionDantalReport.xlsx";

                src = Util.GetReportPath(reportName);

                string tempfileName = "ProductionDantalReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));
                if (MachineID.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    MachineID = "";
                if (PlantID.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    PlantID = "";
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Dantal Production report - \n " + src);
                }
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["PRODUCTION REPORT_PLANT WISE"];
                string timeFormat = DataBaseAccess.getTimeFormatFromCockpit();


                wsDts.Cells["B2"].Value = StartDate.ToString("dd-MMM-yyyy");
                wsDts.Cells["D2"].Value = EndDate.ToString("dd-MMM-yyyy");
                //if (PlantID == "")
                //{
                //    wsDts.Cells["F2"].Value = "All";
                //}
                //else
                //{
                wsDts.Cells["F2"].Value = Plant;
                //}
                wsDts.Cells["H2"].Value = CellID;
                wsDts.Cells[2, 10, 2, 17].Merge = true;
                //wsDts.Cells["J2"].Value = MachineID;
                wsDts.Cells[2, 10, 2, 17].Style.WrapText = true;



                int row = 0;
                DataTable dt = TMPTrakDataBase.DantalProductionReport(PlantID, CellID, MachineID, StartDate, EndDate, out DataTable dt2);
                var rowheader = 3;
                var colheader = 14;
                foreach (DataRow item in dt2.Rows)
                {
                    var downcode = item["downid"];
                    wsDts.Cells[rowheader, colheader].Value = downcode;
                    colheader++;
                }
                //var down1 = dt2.AsEnumerable().Where(x => x["slno"].ToString() == "1").Select(x => x["downid"].ToString()).FirstOrDefault();
                //var down2 = dt2.AsEnumerable().Where(x => x["slno"].ToString() == "2").Select(x => x["downid"].ToString()).FirstOrDefault();
                //var down3 = dt2.AsEnumerable().Where(x => x["slno"].ToString() == "3").Select(x => x["downid"].ToString()).FirstOrDefault();
                //var down4 = dt2.AsEnumerable().Where(x => x["slno"].ToString() == "4").Select(x => x["downid"].ToString()).FirstOrDefault();
                //wsDts.Cells["N3"].Value = down1;
                //wsDts.Cells["O3"].Value = down2;
                //wsDts.Cells["P3"].Value = down3;
                //wsDts.Cells["Q3"].Value = down4;
                if (dt != null && dt.Rows.Count > 0)
                {
                    row = 4;
                    string previousCellName = "";
                    int cellWiseStartRow = 0;
                    int colCount = 1;
                    bool isCellDifined = true;
                    Color backColor = Color.FromArgb(155, 194, 230);
                    var distCell = dt.AsEnumerable().Select(k => k.Field<string>("GroupID")).Distinct().ToList();
                    if (distCell != null)
                    {
                        if (distCell.Count == 1 && string.IsNullOrEmpty(distCell[0]))
                        {
                            isCellDifined = false;
                        }
                    }
                    for (int i = 0; i < dt.Rows.Count; i++)
                    {
                        if (previousCellName != dt.Rows[i]["GroupID"].ToString())
                        {
                            previousCellName = dt.Rows[i]["GroupID"].ToString();
                            cellWiseStartRow = row;
                        }
                        colCount = 1;
                        wsDts.Cells[row, colCount].Value = Convert.ToDateTime(dt.Rows[i]["Day"]).ToString("dd-MM-yyyy");
                        colCount++;
                        wsDts.Cells[row, colCount].Value = dt.Rows[i]["GroupID"];
                        colCount++;
                        wsDts.Cells[row, colCount].Value = dt.Rows[i]["MachineId"];
                        colCount++;
                        wsDts.Cells[row, colCount].Value = dt.Rows[i]["MachineDescription"];
                        colCount++;
                        wsDts.Cells[row, colCount].Value = dt.Rows[i]["shift"];
                        colCount++;
                        wsDts.Cells[row, colCount].Value = getDoubleValue(dt.Rows[i]["Target"].ToString());
                        colCount++;
                        wsDts.Cells[row, colCount].Value = getDoubleValue(dt.Rows[i]["Actual"].ToString());
                        colCount++;
                        wsDts.Cells[row, colCount].Value = Math.Round(getDoubleValue(dt.Rows[i]["Diff"].ToString()), 2);
                        colCount++;
                        if (!Convert.IsDBNull(dt.Rows[i]["AvailabilityEfficiency"]))
                            wsDts.Cells[row, colCount].Value = Convert.ToDouble(dt.Rows[i]["AvailabilityEfficiency"]);
                        colCount++;
                        if (!Convert.IsDBNull(dt.Rows[i]["ProductionEfficiency"]))
                            wsDts.Cells[row, colCount].Value = Convert.ToDouble(dt.Rows[i]["ProductionEfficiency"]);
                        colCount++;
                        //if (!(dt.Rows[i]["QualityEfficiency"] is DBNull))
                        //    wsDts.Cells[row, colCount].Value = Convert.ToDouble(dt.Rows[i]["QualityEfficiency"]);
                        //colCount++;
                        if (!Convert.IsDBNull(dt.Rows[i]["OverallEfficiency"]))
                            wsDts.Cells[row, colCount].Value = Convert.ToDouble(dt.Rows[i]["OverallEfficiency"]);
                        colCount++;
                        setTimeSpanFormat(timeFormat, wsDts, row, colCount, dt.Rows[i]["frmtUtilisedTime"].ToString());
                        colCount++;
                        setTimeSpanFormat(timeFormat, wsDts, row, colCount, dt.Rows[i]["frmtDownTime"].ToString());
                        colCount++;
                        setTimeSpanFormat(timeFormat, wsDts, row, colCount, dt.Rows[i]["A"].ToString());
                        colCount++;
                        setTimeSpanFormat(timeFormat, wsDts, row, colCount, dt.Rows[i]["B"].ToString());
                        colCount++;
                        setTimeSpanFormat(timeFormat, wsDts, row, colCount, dt.Rows[i]["C"].ToString());
                        colCount++;
                        setTimeSpanFormat(timeFormat, wsDts, row, colCount, dt.Rows[i]["D"].ToString());
                        colCount++;
                        row++;
                    }


                    if (isCellDifined == false)
                    {
                        wsDts.Column(1).Hidden = true;
                    }
                    if (DataBaseAccess.isQERequired() == false)
                    {
                        //wsDts.Column(24).Hidden = true;//11
                    }
                    string modelRange = "A3:Q" + (row - 1).ToString();
                    var modelTable = wsDts.Cells[modelRange];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Production Dantal Report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex); ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }





        public static void setTimeSpanFormat(string timeFormat, ExcelWorksheet worksheet, int rowPos, int colPos, string value)
        {
            try
            {

                if (timeFormat.Equals("hh:mm:ss"))
                {
                    if (value.Contains("-"))
                    {
                        worksheet.Cells[rowPos, colPos].Value = value;
                    }
                    else
                    {
                        //TimeSpan timeSpan = TimeSpan.Parse(dt.Rows[i][item].ToString());
                        var valueSplit = value.Split(':');
                        TimeSpan timeSpan = new TimeSpan(int.Parse(valueSplit[0]),    // hours
                                                         int.Parse(valueSplit[1]),    // minutes
                                                         int.Parse(valueSplit[2]));
                        worksheet.Cells[rowPos, colPos].Value = timeSpan;

                        worksheet.Cells[rowPos, colPos].Style.Numberformat.Format = "[h]:mm:ss";
                    }
                }
                else if (timeFormat.Equals("hh:mm", StringComparison.OrdinalIgnoreCase))
                {
                    //TimeSpan timeSpan = TimeSpan.Parse(dt.Rows[i][item].ToString());
                    var valueSplit = value.Split(':');
                    TimeSpan timeSpan = new TimeSpan(int.Parse(valueSplit[0]),    // hours
                                                     int.Parse(valueSplit[1]),    // minutes
                                                     0);
                    worksheet.Cells[rowPos, colPos].Value = timeSpan;
                    worksheet.Cells[rowPos, colPos].Style.Numberformat.Format = "[h]:mm";
                }
                else
                {
                    worksheet.Cells[rowPos, colPos].Value = string.IsNullOrEmpty(value) ? 0 : Convert.ToDouble(value);
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("setTimeSpanFormat = " + ex.Message);
            }
        }
        public static void setCellTimeSpanFormat(string timeFormat, ExcelWorksheet worksheet, int rowPos, int colPos)
        {
            try
            {
                if (timeFormat.Equals("hh:mm:ss"))
                {
                    worksheet.Cells[rowPos, colPos].Style.Numberformat.Format = "[h]:mm:ss";
                }
                else if (timeFormat.Equals("hh:mm", StringComparison.OrdinalIgnoreCase))
                {
                    worksheet.Cells[rowPos, colPos].Style.Numberformat.Format = "[h]:mm";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("setTimeSpanFormat = " + ex.Message);
            }
        }
        #endregion

