                        colCount++;
                        if (mergeCount != 0)
                        {
                            wsDts.Cells[row, colCount].Value = Convert.ToDouble(dt.Rows[i]["OverallEfficiency"]);//decimal.Round(, 2, MidpointRounding.AwayFromZero); 
                        }

                        if (mergeCount > 1)
                        {
                            wsDts.Cells[row, 20, row + mergeCount - 1, 20].Merge = true;
                            wsDts.Cells[row, 21, row + mergeCount - 1, 21].Merge = true;
                            wsDts.Cells[row, 22, row + mergeCount - 1, 22].Merge = true;
                            wsDts.Cells[row, 23, row + mergeCount - 1, 23].Merge = true;
                            wsDts.Cells[row, 24, row + mergeCount - 1, 24].Merge = true;
                            wsDts.Cells[row, 25, row + mergeCount - 1, 25].Merge = true;
                        }

                        if (ConfigurationManager.AppSettings["MultiTechPages"].ToString().Equals("1"))
                        {
                            if (HelperClassGeneric.getCheckboxValue(dt.Rows[i]["PalletEnabled"].ToString()))
                            {

                                if (tempColorMachine != dt.Rows[i]["MachineId"].ToString())
                                {
                                    if (backColor == Color.FromArgb(155, 194, 230))
                                    {
                                        backColor = Color.FromArgb(208, 226, 244);
                                    }
                                    else
                                    {
                                        backColor = Color.FromArgb(155, 194, 230);
                                    }
                                }

                                wsDts.Cells[row, 1, row, colCount].Style.Fill.PatternType = ExcelFillStyle.Solid;
