                                tempColorMachine = dt.Rows[i]["MachineId"].ToString();
                            }
                        }
                        row++;
                    }
                    if (isCellDifined == true)
                    {
                        wsDts.Cells[row, 1].Value = "CELL WISE TOTAL";
