                        //wsDts.Cells[row, 24].Formula = "=ROUNDUP(AVERAGE(X" + cellWiseStartRow.ToString() + ":X" + (row - 1).ToString() + "),2)";

                        var cellTotal = dtCellWiseTotal.AsEnumerable().Where(k => k["Groupid"].ToString().Equals(previousCellName, StringComparison.OrdinalIgnoreCase)).FirstOrDefault();
                        if (cellTotal != null)
                        {
                            setTimeSpanFormat(timeFormat, wsDts, row, 20, cellTotal["UtilisedTime"].ToString());
                            setTimeSpanFormat(timeFormat, wsDts, row, 21, cellTotal["DownTime"].ToString());
                            wsDts.Cells[row, 22].Value = getDoubleValue(cellTotal["AvailabilityEfficiency"].ToString());
                            wsDts.Cells[row, 23].Value = getDoubleValue(cellTotal["ProductionEfficiency"].ToString());
                            wsDts.Cells[row, 24].Value = getDoubleValue(cellTotal["QualityEfficiency"].ToString());
                            wsDts.Cells[row, 25].Value = getDoubleValue(cellTotal["OverAllEfficiency"].ToString());
                        }

                        wsDts.Cells[row, 1, row, colCount].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        wsDts.Cells[row, 1, row, colCount].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(217, 217, 217));
                        //wsDts.Cells[5, 1, row, 21].AutoFitColumns();
                        row++;
                    }
                    wsDts.Cells[8, 1, row, colCount].AutoFitColumns();
                    if (dtTotal.Rows.Count > 0)
                    {
                        for (int i = 0; i < dtTotal.Rows.Count; i++)
                        {
                            wsDts.Cells[row, 1].Value = "Total / Average";
                            wsDts.Cells[row, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[row, 1].Style.Font.Bold = true;
                            wsDts.Cells[row, 1, row, 7].Merge = true;
                            wsDts.Cells[row, 8].Value = targetQtyGrandSum;
                            wsDts.Cells[row, 12].Value = proQtyGrandSum;
                            wsDts.Cells[row, 13].Value = diffGrandSum;
                            wsDts.Cells[row, 20].Value = dtTotal.Rows[i]["UtilisedTime"];
                            wsDts.Cells[row, 21].Value = dtTotal.Rows[i]["TotalDownTime"];
                            //wsDts.Cells[row, 21].Value = Convert.ToDouble(dtTotal.Rows[i]["AvailabilityEfficiency"]);
                            if (!(dtTotal.Rows[i]["AvailabilityEfficiency"] is DBNull))
                                wsDts.Cells[row, 22].Value = Convert.ToDouble(dtTotal.Rows[i]["AvailabilityEfficiency"]);
                            if (!(dtTotal.Rows[i]["ProductionEfficiency"] is DBNull))
                                wsDts.Cells[row, 23].Value = Convert.ToDouble(dtTotal.Rows[i]["ProductionEfficiency"]);
                            if (!(dtTotal.Rows[i]["QualityEfficiency"] is DBNull))
                                wsDts.Cells[row, 24].Value = Convert.ToDouble(dtTotal.Rows[i]["QualityEfficiency"]);
                            if (!(dtTotal.Rows[i]["OverallEfficiency"] is DBNull))
                                wsDts.Cells[row, 25].Value = Convert.ToDouble(dtTotal.Rows[i]["OverallEfficiency"]);
                            wsDts.Cells[row, 1, row, colCount].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            wsDts.Cells[row, 1, row, colCount].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(252, 213, 180));
                            row++;
                        }
                    }
                    string modelRange = "A8:Y" + (row - 1).ToString();
                    var modelTable = wsDts.Cells[modelRange];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;


                    for (int shiftC = 1; shiftC <= 3; shiftC++)
                    {
                        if (shiftC > shiftCount)
                        {
                            wsDts.Column(9 + (shiftC - 1)).Hidden = true;
                        }
                    }
                    if (isCellDifined == false)
                    {
                        wsDts.Column(1).Hidden = true;
                    }
                    if (DataBaseAccess.isQERequired() == false)
                    {
                        wsDts.Column(24).Hidden = true;
                    }
                    if (DataBaseAccess.getShopDefaultReportColumnSetting("LiveReport", "DailyAndShift_Target") == false)
                    {
                        wsDts.Column(8).Hidden = true;
                    }
                    if (DataBaseAccess.getShopDefaultReportColumnSetting("LiveReport", "DailyAndShift_Diff") == false)
                    {
                        wsDts.Column(13).Hidden = true;
                    }
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Production report-Machinewise Daily-Format-1 EXCEL Report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "NodataFound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog($"Production report-Machinewise Daily-Format-1 : {ex.Message}");
            }
            return Generated;
        }


