        public static string Column(int column)
        {
            column--;
            if (column >= 0 && column < 26)
                return ((char)('A' + column)).ToString();
            else if (column > 25)
                return Column(column / 26) + Column(column % 26 + 1);
            else
                throw new Exception("Invalid Column #" + (column + 1).ToString());
        }

        internal static string ToolChangeFrequencyTool(DateTime fromDate, DateTime toDate, string PlantId, string MachineId)
        {

            string generated = "";

            List<ToolChangefrequency> ToolChangeFreqData = new List<ToolChangefrequency>();
            try
            {
                string Source = string.Empty, destination = string.Empty, template = string.Empty;
                string ReportName = "ToolChangeFrequency.xlsx";
                Source = Util.GetReportPath(ReportName);
                template = "ToolChangeFrequency_" + DateTime.Now + ".xlsx";
                destination = Path.Combine(appPath, "Temp", SafeFileName(template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("Tool Change Frequency - \n " + Source);
                }
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var WorkSheet = Excel.Workbook.Worksheets[1];
                WorkSheet.Cells["B7"].Value = fromDate;
                WorkSheet.Cells["B9"].Value = toDate;
                WorkSheet.Cells["B11"].Value = MachineId;
                ToolChangeFreqData = TMPTrakDataBase.ToolChangeFreqData(fromDate, toDate, MachineId);
                if (ToolChangeFreqData != null && ToolChangeFreqData.Count > 0)
                {
                    int i = 16, k = 16, j = 1, l = 1;
                    foreach (ToolChangefrequency toolentity in ToolChangeFreqData)
                    {
                        j = 1;
                        WorkSheet.Cells[i, j].Value = toolentity.Tool;
                        j++;
                        WorkSheet.Cells[i, j].Value = toolentity.NoOfChanges;
                        j++;
                        WorkSheet.Cells[i, j].Value = toolentity.Starttime;
                        j++;
                        WorkSheet.Cells[i, j].Value = toolentity.Endtime;
                        j++;
                        WorkSheet.Cells[i, j].Value = toolentity.Operation;
                        j++;
                        WorkSheet.Cells[i, j].Value = toolentity.cyclecount;
                        i++;
                    }
                    i--;
                    WorkSheet.Cells[k, l, i, j].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    WorkSheet.Cells[k, l, i, j].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    WorkSheet.Cells[k, l, i, j].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    WorkSheet.Cells[k, l, i, j].Style.Border.Bottom.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    WorkSheet.Cells[k, l, i, j].Style.Border.Top.Color.SetColor(System.Drawing.Color.Black);
                    WorkSheet.Cells[k, l, i, j].Style.Border.Left.Color.SetColor(System.Drawing.Color.Black);
                    WorkSheet.Cells[k, l, i, j].Style.Border.Right.Color.SetColor(System.Drawing.Color.Black);
                    WorkSheet.Cells[k, l, i, j].Style.Border.Bottom.Color.SetColor(System.Drawing.Color.Black);

                    WorkSheet.Cells[i + 4, l].Value = DateTime.Now.ToShortDateString();
                    WorkSheet.Cells[i + 4, l + 1, i + 4, l + 4].Merge = true;
                    WorkSheet.Cells[i + 4, l + 3].Value = "TPM-Track::Tool Change Frequency Report";
                    WorkSheet.Cells[i + 4, l + 3].Style.Font.Bold = true;
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog("Tool Change Frequency report saved.");
                    generated = "Generated";
                }
                else
                {
                    generated = "Nodatafound";
                }
            }
            catch (Exception ex)
            {

            }
            return generated;
        }

