        #region "Production report-Componentwise Report"
        public static string ComponentwiseReport(DateTime StartDate, string ComponentID, string OperationNo, DateTime EndDate)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "PR_ComponentwiseReport.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "PR_ComponentwiseReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (OperationNo.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    OperationNo = "";
                if (ComponentID.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    ComponentID = "";
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Production report-Componentwise Report EXCEL - \n " + src);
                }
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];

                //string str1 = VDGDataBaseAccess.GetLogicalDayStart(StartDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strfromdate = DateTime.Now;
                //DateTime.TryParse(str1, out strfromdate);

                //string str2 = VDGDataBaseAccess.GetLogicalDayEnd(EndDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strtodate = DateTime.Now;
                //DateTime.TryParse(str2, out strtodate);

                wsDts.Cells["B2"].Value = StartDate.ToString("dd-MMM-yyyy hh:mm:ss tt");
                wsDts.Cells["B4"].Value = EndDate.ToString("dd-MMM-yyyy hh:mm:ss tt");
                wsDts.Cells["H2"].Value = ComponentID == "" ? "All" : ComponentID;
                wsDts.Cells["H4"].Value = OperationNo == "" ? "All" : OperationNo;
                int row = 9;
                DataTable dt = TMPTrakDataBase.ComponentwiseReport(StartDate, ComponentID, OperationNo, EndDate);
                if (dt != null && dt.Rows.Count > 0)
                {
                    string timeFormat = DataBaseAccess.getTimeFormatFromCockpit();

                    foreach (DataRow item in dt.Rows)
                    {
                        wsDts.Cells[row, 1].Value = item["ComponentID"];
                        wsDts.Cells[row, 2].Value = Convert.ToInt32(item["OperationNo"].ToString());
                        wsDts.Cells[row, 3].Value = item["MachineID"];
                        wsDts.Cells[row, 4].Value = item["Machinedescription"];
                        setTimeSpanFormat(timeFormat, wsDts, row, 5, item["StdCycleTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 6, item["AvgCycleTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 7, item["MaxCycleTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 8, item["MinCycleTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 9, item["StdLoadUnload"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 10, item["AvgLoadUnload"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 11, item["MaxLoadUnload"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 12, item["MinLoadUnload"].ToString());
                        //wsDts.Cells[row, 5].Value = item["StdCycleTime"];
                        //wsDts.Cells[row, 6].Value = item["AvgCycleTime"];
                        //wsDts.Cells[row, 7].Value = item["MaxCycleTime"];
                        //wsDts.Cells[row, 8].Value = item["MinCycleTime"];
                        //wsDts.Cells[row, 9].Value = item["StdLoadUnload"];
                        //wsDts.Cells[row, 10].Value = item["AvgLoadUnload"];
                        //wsDts.Cells[row, 11].Value = item["MaxLoadUnload"];
                        //wsDts.Cells[row, 12].Value = item["MinLoadUnload"];
                        wsDts.Cells[row, 13].Value = item["SpeedRation"];
                        wsDts.Cells[row, 14].Value = item["LoadRation"];
                        wsDts.Cells[row, 15].Value = item["ProdCount"];
                        if (!(item["AvailabilityEfficiency"] is DBNull))
                            wsDts.Cells[row, 16].Value = Math.Round(Convert.ToDouble(item["AvailabilityEfficiency"]), 2);
                        if (!(item["ProductionEfficiency"] is DBNull))
                            wsDts.Cells[row, 17].Value = Math.Round(Convert.ToDouble(item["ProductionEfficiency"]), 2);
                        if (!(item["QualityEfficiency"] is DBNull))
                            wsDts.Cells[row, 18].Value = Math.Round(Convert.ToDouble(item["QualityEfficiency"]), 2);
                        if (!(item["OverAllEfficiency"] is DBNull))
                            wsDts.Cells[row, 19].Value = Math.Round(Convert.ToDouble(item["OverAllEfficiency"]), 2);
                        //wsDts.Cells[row, 18].Value = item["ComponentID"];
                        row++;
                    }

                    string modelRange = "A9:S" + (row - 1).ToString();
                    var modelTable = wsDts.Cells[modelRange];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    wsDts.Cells[modelRange].AutoFitColumns();
                    if (DataBaseAccess.isQERequired() == false)
                    {
                        wsDts.Column(18).Hidden = true;
                    }
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Production report-Componentwise Report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("ComponentwiseReport=" + ex.Message);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }


