                                changeColorRow = row;
                                if (prevMachineID != item["Machineid"].ToString() || prevShift != item["ShiftName"].ToString())
                                {
                                    if (prevColor == "Orange")
                                    {
                                        ws.Cells[changeColorRow, 1, changeColorRow, temp_Col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                        ws.Cells[changeColorRow, 1, changeColorRow, temp_Col].Style.Fill.BackgroundColor.SetColor(Color.White);
                                        prevColor = "White";
                                    }
                                    else
                                    {
                                        ws.Cells[changeColorRow, 1, changeColorRow, temp_Col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                        ws.Cells[changeColorRow, 1, changeColorRow, temp_Col].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(235, 168, 87));
                                        prevColor = "Orange";
                                    }

                                    prevMachineID = item["Machineid"].ToString();
                                    prevShift = item["ShiftName"].ToString();

                                }
                                else
                                {
                                    if (prevColor == "White")
                                    {
                                        ws.Cells[changeColorRow, 1, changeColorRow, 34].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                        ws.Cells[changeColorRow, 1, changeColorRow, 34].Style.Fill.BackgroundColor.SetColor(Color.White);
                                        prevColor = "White";
                                    }
                                    else
                                    {
                                        ws.Cells[changeColorRow, 1, changeColorRow, 34].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                        ws.Cells[changeColorRow, 1, changeColorRow, 34].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(235, 168, 87));
                                        prevColor = "Orange";
                                    }

                                    prevMachineID = item["Machineid"].ToString();
                                    prevShift = item["ShiftName"].ToString();
                                }
                                #endregion
                                row++;
                                col += 2;
                            }
                            else
                            {
                                ws.Cells[row - 1, col].Value = item["Actual"];
                                ws.Cells[row - 1, col + 1].Value = item["RejCount"];
                                if (Convert.ToInt32(item["HourID"]) >= 9)
                                {
                                    ws.Column(col).Width = 5;
                                    ws.Column(col + 1).Width = 5;
                                }
                                col += 2;
                            }
                        }
                        setThinBorder(ws, 3, 1, row - 1,PMLPagesEnabled?36:35);
                    }
                }
                
                DownloadMultipleFile(dst, pck.GetAsByteArray());
                Logger.WriteDebugLog("Daily Prod and Down Log by day-Excel generated sucessfully.");
