        private static void ExcelSheetCopy(ExcelWorkbook workbook, string existingWorksheetName, string newWorksheetName)
        {
            workbook.Worksheets.Copy(existingWorksheetName, newWorksheetName);
        }

        #region "Production and down time report- machinewise"
        public static string ProductionandDownTimeReport_Machinewise(DateTime StartDate, string PlantId, string MachineId, string ShiftId, DateTime EndDate, string ComponentId, string OperationNo)
        {
            bool dataavailable = false;
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "ProductionandDownTimeReport_Machinewise.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "DownTimeReport_Machinewise" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (PlantId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    PlantId = "";
                if (MachineId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                {
                    var allMachineName = VDGDataBaseAccess.GetAllMachines(PlantId);
                }
                if (ShiftId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    ShiftId = "";
                if (ComponentId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    ComponentId = "";
                if (OperationNo.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    OperationNo = "";
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Production and down time report- machinewise - \n " + src);
                }

                //string str1 = VDGDataBaseAccess.GetLogicalDayStart(StartDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strfromdate = DateTime.Now;
                //DateTime.TryParse(str1, out strfromdate);

                //string str2 = VDGDataBaseAccess.GetLogicalDayEnd(EndDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strtodate = DateTime.Now;
                //DateTime.TryParse(str2, out strtodate);
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                ExcelWorksheet wsDts = null;
                string timeFormat = DataBaseAccess.getTimeFormatFromCockpit();
                if (MachineId.Equals("ALL", StringComparison.OrdinalIgnoreCase) || string.IsNullOrEmpty(MachineId))
                {
                    List<string> mid = new List<string>();
                    mid = VDGDataBaseAccess.GetAllMachines(PlantId);
                    string MID = mid[0];
                    var copyworksheet = pck.Workbook.Worksheets["sheet1"];
                    wsDts = pck.Workbook.Worksheets["sheet1"];
                    wsDts.PrinterSettings.PaperSize = ePaperSize.A3;
                    wsDts.PrinterSettings.Orientation = eOrientation.Landscape;
                    wsDts.PrinterSettings.HorizontalCentered = true;
                    wsDts.PrinterSettings.FitToWidth = 1;
                    wsDts.PrinterSettings.FitToHeight = 0;
                    wsDts.PrinterSettings.FitToPage = true;

                    foreach (string id in mid)
                    {
                        if (MID != id)
                        {
                            wsDts = pck.Workbook.Worksheets.Add(id, copyworksheet);
                        }
                        else
                            wsDts.Name = id;
                        wsDts.Cells["B2"].Value = StartDate.ToString("dd-MMM-yyyy hh:mm:ss");
                        //wsDts.Cells["B4"].Value = EndDate.ToString("dd-MMM-yyyy hh:mm:ss");
                        wsDts.Cells["L2"].Value = id == "" ? "ALL" : id;
                        int row = 9;
                        DataTable dt = TMPTrakDataBase.ProductionandDownTimeReport_Machinewise(StartDate, ShiftId, PlantId, id, EndDate, ComponentId, OperationNo, "ProdAndDown");
                        if (dt != null && dt.Rows.Count > 0)
                        {
                            foreach (DataRow item in dt.Rows)
                            {
                                wsDts.Cells[row, 1].Value = item["MachineID"];
                                wsDts.Cells[row, 2].Value = item["MachineDescription"];
                                wsDts.Cells[row, 3].Value = item["shftstarttime"];
                                wsDts.Cells[row, 4].Value = item["Shift"];
                                wsDts.Cells[row, 5].Value = item["Component"];
                                wsDts.Cells[row, 6].Value = item["Operation"];
                                wsDts.Cells[row, 7].Value = item["OperationCount"];
                                wsDts.Cells[row, 8].Value = item["Target"];
                                setTimeSpanFormat(timeFormat, wsDts, row, 9, item["frmtUtilisedTime"].ToString());
                                //wsDts.Cells[row, 10].Value = item["frmtCycleTime"];
                                //wsDts.Cells[row, 11].Value = item["frmtAvgCycleTime"];
                                setTimeSpanFormat(timeFormat, wsDts, row, 10, item["frmtCycleTime"].ToString());
                                setTimeSpanFormat(timeFormat, wsDts, row, 11, item["frmtAvgCycleTime"].ToString());
                                if (!(item["CyclEfficiency"] is DBNull))
                                    wsDts.Cells[row, 12].Value = Math.Round(Convert.ToDecimal(item["CyclEfficiency"]), 2);
                                //wsDts.Cells[row, 13].Value = item["frmtLoadUnload"];
                                //wsDts.Cells[row, 14].Value = item["frmtAvgLoadUnload"];
                                setTimeSpanFormat(timeFormat, wsDts, row, 13, item["frmtLoadUnload"].ToString());
                                setTimeSpanFormat(timeFormat, wsDts, row, 14, item["frmtAvgLoadUnload"].ToString());
                                if (!(item["LoadUnloadEfficiency"] is DBNull))
                                    wsDts.Cells[row, 15].Value = Math.Round(Convert.ToDecimal(item["LoadUnloadEfficiency"]), 2);
                                // wsDts.Cells[row, 16].Value = item["frmtDownTime"];
