        #region "Table Cockpit Generate Tamplate ---------"
        public static void TableCockpitReport(string PlantId, string ShiftId, string StartDate, DataTable dt, List<string> colHeader, List<string> displayCol)
        {
            try
            {
                string src, dst = string.Empty;
                string reportName = "Table_cockpit.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "Table_cockpit" + PlantId + "_" + ShiftId + "_" + StartDate + "_" + Guid.NewGuid() + ".xlsx";
                //dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (PlantId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    PlantId = "";

                if (ShiftId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    ShiftId = "";

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Table Cockpit Generate Tamplate report- machinewise - \n " + src);
                }
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];
                wsDts.Cells["B2"].Value = StartDate;
                wsDts.Cells["F2"].Value = ShiftId;
                wsDts.Cells["J2"].Value = PlantId == "" ? "All" : PlantId;

                int startChar = 65;
                for (int k = 1; k < colHeader.Count; k++)
                {
                    var val = (char)startChar;
                    var range = string.Format(val + "{0}" + ":" + val + "{1}", 5, 6);
                    wsDts.Cells[range].Merge = true;
                    wsDts.Cells[range].Value = colHeader[k].ToString();
                    wsDts.Cells[range].Style.Fill.PatternType = ExcelFillStyle.Solid;
                    wsDts.Cells[range].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#F8CBAD"));
                    wsDts.Cells[range].Style.Font.Color.SetColor(Color.Black);
                    wsDts.Cells[range].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    wsDts.Cells[range].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    wsDts.Cells[range].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    wsDts.Cells[range].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    wsDts.Cells[range].Style.Border.Right.Color.SetColor(Color.Black);
                    wsDts.Cells[range].Style.Font.Bold = true;
                    wsDts.Cells[range].Style.Font.Size = 11;
                    wsDts.Cells[range].Style.Font.Name = "Calibri";
                    wsDts.Cells[range].Style.WrapText = true;
                    startChar++;
                }
                int row = 7, column = 2;
                if (dt != null && dt.Rows.Count > 0)
                {
                    for (int j = 0; j < dt.Rows.Count; j++)
                    {
                        wsDts.Cells[row, 1].Value = dt.Rows[j]["MachineId"];
                        column = 2;
                        for (int i = 0; i < displayCol.Count; i++)
                        {
                            wsDts.Cells[row, column].Value = dt.Rows[j][displayCol[i]];
                            column++;
                        }
                        row++;
                    }

                    char c = Convert.ToChar(65 + column - 2);
                    string modelRange = "A7:" + c + (row - 1).ToString();
                    var modelTable = wsDts.Cells[modelRange];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                }
                wsDts.Cells.AutoFitColumns();
                DownloadMultipleFile(dst, pck.GetAsByteArray());
                Logger.WriteDebugLog("Table Cockpit Generate Tamplate report generated sucessfully.");
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("TableCockpitReport=" + ex.Message);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
        }

