        #region "Down time report to Machine wise down time details"
        public static string MachineWiseDownTimeDetails(DateTime StartDate, string PlantId, string MachineId, DateTime EndDate, string DownID, int Exclude, bool machinewiseSheet, string cellID)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "MachineWiseDowntimeDetails.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "DownTimeReport_Machinewise" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (PlantId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    PlantId = "";
                if (MachineId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    MachineId = "";

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Down time report to Machine wise down time details - \n " + src);
                }

                //string str1 = VDGDataBaseAccess.GetLogicalDayStart(StartDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strfromdate = DateTime.Now;
                //DateTime.TryParse(str1, out strfromdate);

                //string str2 = VDGDataBaseAccess.GetLogicalDayEnd(EndDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strtodate = DateTime.Now;
                //DateTime.TryParse(str2, out strtodate);

                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var firstWsDts = pck.Workbook.Worksheets["Sheet1"];
                firstWsDts.Cells["B2"].Value = StartDate.ToString("dd-MMM-yyyy hh:mm:ss");
                if (ConfigurationManager.AppSettings["IndiaNippon"].Equals("1"))
                {
                    firstWsDts.Cells["I2"].Value = EndDate.ToString("dd-MMM-yyyy hh:mm:ss");
                }
                else
                {
                    firstWsDts.Cells["G2"].Value = EndDate.ToString("dd-MMM-yyyy hh:mm:ss");
                }
                int row = 5;
                int startRow = row;
                TimeSpan downs = new TimeSpan();
                TimeSpan total = new TimeSpan();
                string modelRange = "";
                TimeSpan DownTimeValue = TimeSpan.Zero;
                DataTable dt = TMPTrakDataBase.MachineWiseDownTimeDetails(StartDate, MachineId, EndDate, DownID, PlantId, Exclude, cellID);
                if (dt != null && dt.Rows.Count > 0)
                {
                    string timeFormat = DataBaseAccess.getTimeFormatFromCockpit();
                    //DateTime totaldowntime;
                    if (ConfigurationManager.AppSettings["IndiaNippon"].Equals("1"))
                    {
                        foreach (DataRow item in dt.Rows)
                        {
                            firstWsDts.Cells[row, 1].Value = item["MachineId"];
                            firstWsDts.Cells[row, 2].Value = item["machineDescription"];
                            firstWsDts.Cells[row, 3].Value = item["componentId"];
                            firstWsDts.Cells[row, 4].Value = item["OperationNo"];
                            firstWsDts.Cells[row, 5].Value = item["Shift"];
                            firstWsDts.Cells[row, 6].Value = item["EmployeeName"];
                            firstWsDts.Cells[row, 7].Value = item["OperatorName"];
                            firstWsDts.Cells[row, 8].Value = Convert.ToDateTime(item["StartTime"]).ToString("dd/MMM/yyyy hh:mm:ss tt");
                            firstWsDts.Cells[row, 9].Value = Convert.ToDateTime(item["EndTime"]).ToString("dd/MMM/yyyy hh:mm:ss tt");
                            string Downtime = item["DownTime"].ToString();
                            var split = Downtime.Split(new char[] { ':' });
                            total = new TimeSpan(int.Parse(split[0]), int.Parse(split[1]), int.Parse(split[2]));
                            firstWsDts.Cells[row, 10].Value = total;
                            firstWsDts.Cells[row, 10].Style.Numberformat.Format = "[h]:mm:ss";
                            //TimeSpan.TryParse(Convert.ToDateTime(item["DownTime"]).ToString("HH:mm:ss"), out total);
                            // totaldowntime = Convert.ToDateTime(item["DownTime"]);
                            firstWsDts.Cells[row, 11].Value = item["DownDescription"] + " ( " + item["DownID"] + ")";
                            firstWsDts.Cells[row, 12].Value = item["Remarks"];
                            firstWsDts.Cells[row, 13].Value = item["StdSetup"];
                            firstWsDts.Cells[row, 14].Value = item["SetupEff"];
                            row++;
                            downs = downs.Add(total);
                        }
                        int lastrow = row - 1;
                        firstWsDts.Cells[row, 10].Value = downs;
                        firstWsDts.Cells[row, 10].Style.Numberformat.Format = "[h]:mm:ss";
                        modelRange = "A5:N" + (row - 1).ToString();
                        var modelTable = firstWsDts.Cells[modelRange];
                        // Assign borders
                        modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                        modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                        modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                        modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    }
                    else
                    {

                        if (string.Equals(ConfigurationManager.AppSettings["OperatorInReport"].ToString(), "Name", StringComparison.OrdinalIgnoreCase))
                        {
                            firstWsDts.Cells[4, 5].Value = "Operator Name";
                        }
                        else
                        {
                            firstWsDts.Cells[4, 5].Value = "Operator ID";
                        }

                        List<string> distMachinewise = new List<string>();
