        public static string MachineWiseDownTimeDetailsAgg(DateTime StartDate, string PlantId, string MachineId, DateTime EndDate, string DownID, int Exclude, bool machinewiseSheet, string cellID)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "MachineWiseDowntimeDetailsAgg.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "DownTimeReport_MachinewiseAgg" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (PlantId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    PlantId = "";
                if (MachineId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    MachineId = "";

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Down time report to Machine wise down time details - \n " + src);
                }

                //string str1 = VDGDataBaseAccess.GetLogicalDayStart(StartDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strfromdate = DateTime.Now;
                //DateTime.TryParse(str1, out strfromdate);

                //string str2 = VDGDataBaseAccess.GetLogicalDayEnd(EndDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strtodate = DateTime.Now;
                //DateTime.TryParse(str2, out strtodate);

                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var firstWsDts = pck.Workbook.Worksheets["Sheet1"];
                //firstWsDts.Cells["B2"].Value = "Start Date";

                //firstWsDts.Cells["G2"].Value = "End Date";

                firstWsDts.Cells["C2"].Value = Util.GetDateTime(StartDate.ToString()).ToString("dd-MM-yyyy");
                firstWsDts.Cells["H2"].Value = Util.GetDateTime(EndDate.ToString()).ToString("dd-MM-yyyy");
                int row = 5;
                int startRow = row;
                TimeSpan downs = new TimeSpan();
                TimeSpan total = new TimeSpan();
                string modelRange = "";
                TimeSpan DownTimeValue = TimeSpan.Zero;
                DataTable dt = TMPTrakDataBase.MachineWiseDownTimeDetailsAgg(StartDate, MachineId, EndDate, DownID, PlantId, Exclude, cellID);
                if (dt != null && dt.Rows.Count > 0)
                {
                    string timeFormat = DataBaseAccess.getTimeFormatFromCockpit();
                    if (string.Equals(ConfigurationManager.AppSettings["OperatorInReport"].ToString(), "Name", StringComparison.OrdinalIgnoreCase))
                    {
                        firstWsDts.Cells[4, 5].Value = "Operator Name";
                    }
                    else
                    {
                        firstWsDts.Cells[4, 5].Value = "Operator ID";
                    }

                    List<string> distMachinewise = new List<string>();
                    if (machinewiseSheet == true)
                    {
                        distMachinewise = dt.AsEnumerable().Select(k => k.Field<string>("MachineId")).Distinct().ToList();
                    }
                    else
                    {
                        distMachinewise.Add("Sheet");
                    }
                    foreach (string machine in distMachinewise)
                    {
                        List<DataRow> dataRows = new List<DataRow>();
                        downs = new TimeSpan();
                        DataTable tempDt = new DataTable();
                        if (machinewiseSheet == true)
                        {
                            tempDt = dt.AsEnumerable().Where(k => k.Field<string>("MachineId") == machine).CopyToDataTable();
                        }
                        else
                        {
                            tempDt = dt;
                        }
                        var wsDts = pck.Workbook.Worksheets.Add(machine, firstWsDts);
                        row = startRow;
                        foreach (DataRow item in tempDt.Rows)
                        {
                            wsDts.Cells[row, 1].Value = item["MachineID"];
                            wsDts.Cells[row, 2].Value = item["MachineDescription"];
                            wsDts.Cells[row, 3].Value = item["ComponentID"];
                            wsDts.Cells[row, 4].Value = item["OperationNo"];
                            //wsDts.Cells[row, 5].Value = item["EmployeeName"];
                            if (string.Equals(ConfigurationManager.AppSettings["OperatorInReport"].ToString(), "Name", StringComparison.OrdinalIgnoreCase))
                            {
                                wsDts.Cells[row, 5].Value = item["OperatorName"];
                            }
                            else
                            {
                                wsDts.Cells[row, 5].Value = item["OperatorID"];
                            }
                            wsDts.Cells[row, 6].Value = Convert.ToDateTime(item["StartTime"]).ToString("dd/MMM/yyyy hh:mm:ss tt");
                            wsDts.Cells[row, 7].Value = Convert.ToDateTime(item["EndTime"]).ToString("dd/MMM/yyyy hh:mm:ss tt");
                            string Downtime = item["DownTime"].ToString();
                            setTimeSpanFormat(timeFormat, wsDts, row, 8, item["DownTime"].ToString());
                            //var split = Downtime.Split(new char[] { ':' });
                            //total = new TimeSpan(int.Parse(split[0]), int.Parse(split[1]), int.Parse(split[2]));
                            //wsDts.Cells[row, 8].Value = total;
                            //wsDts.Cells[row, 8].Style.Numberformat.Format = "[h]:mm:ss";
                            setTimeSpanFormat(timeFormat, wsDts, row, 9, item["PDT"].ToString());
                            wsDts.Cells[row, 10].Value = item["DownDescription"] + " ( " + item["DownID"] + ")";
                            //wsDts.Cells[row, 10].Value = item["Remarks"];
                            //wsDts.Cells[row, 11].Value = item["StdSetup"];
                            setTimeSpanFormat(timeFormat, wsDts, row, 11, item["StdSetup"].ToString());
                            wsDts.Cells[row, 12].Value = item["SetupEff"];
                            row++;
                            downs = downs.Add(total);
                        }
                        int lastrow = row - 1;
                        wsDts.Cells[row, 8].Formula = "=Sum(H" + startRow.ToString() + ":H" + lastrow.ToString() + ")";
                        wsDts.Cells[row, 8].Style.Numberformat.Format = "[h]:mm:ss";
                        wsDts.Cells[row, 9].Formula = "=Sum(I" + startRow.ToString() + ":I" + lastrow.ToString() + ")";
                        wsDts.Cells[row, 9].Style.Numberformat.Format = "[h]:mm:ss";
                        modelRange = "A5:L" + (row - 1).ToString();
                        var modelTable = wsDts.Cells[modelRange];
                        // Assign borders
                        modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                        modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                        modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                        modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                        wsDts.Cells[5, 1, row, 12].AutoFitColumns();
                        if (DataBaseAccess.getShopDefaultReportColumnSetting("Report", "StdSetupEffVisible") == false)
                        {
                            wsDts.Column(11).Hidden = true;
                            wsDts.Column(12).Hidden = true;
                        }
                    }
                    pck.Workbook.Worksheets.Delete(1);

                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Down time report to Machine wise down time details report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";
                //wsDts.Cells.AutoFitColumns();

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("MachineWiseDownTimeDetailsAgg=" + ex.Message);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }

