        internal static string OperatorWiseReport_KachMotors(string plantId, DateTime fromDate, DateTime toDate, string Operator)
        {
            string Generated = "";
            string time = string.Empty;
            string Filename = "OperatorEfficiencyReport_KachMotors.xlsx";
            string Source = Util.GetReportPath(Filename);
            string Template = "OperatorEfficiencyReport_KachMotors" + DateTime.Now + ".xlsx";
            string TimeFormat = DataBaseAccess.GetCockitSettings();
            string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("OperatorEffeciency template does not found at - \n " + Source);
            }
            try
            {
                DataTable dtList = TMPTrakDataBase.GetOperatorWiseData(plantId, fromDate, toDate, Operator, "");
                if (dtList != null && dtList.Rows.Count > 0)
                {
                    int row = 8;
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var workBook = Excel.Workbook;
                    var workSheet = workBook.Worksheets[1];
                    var workSheet2 = workBook.Worksheets[2];
                    workSheet.Cells["B4"].Value = fromDate.ToString("dd-MM-yyyy HH:mm:ss");
                    workSheet.Cells["F4"].Value = toDate.ToString("dd-MM-yyyy HH:mm:ss");
                    workSheet.Cells["J4"].Value = string.IsNullOrEmpty(plantId) ? "All" : plantId;
                    workSheet.Cells["N4"].Value = string.IsNullOrEmpty(Operator) ? "All" : Operator;
                    List<string> OperatorList = dtList.AsEnumerable().Select(x => x.Field<string>("operator")).Distinct().ToList();

                    DataTable summarydt = TMPTrakDataBase.GetOperatorWiseData(plantId, fromDate, toDate, Operator, "Summary");
                    TimeSpan IdealMachiningTime = new TimeSpan();
                    TimeSpan AvgCycle = new TimeSpan();
                    if (OperatorList != null)
                    {
                        foreach (string emp in OperatorList)
                        {
                            Color backcolor = ColorTranslator.FromHtml("#FEF8ED");
                            DataTable ValuesbyEmp = dtList.AsEnumerable().Where(x => x.Field<string>("operator") == emp).CopyToDataTable();
                            TimeSpan totaldown = new TimeSpan();
                            double totaldown_int = 0;
                            double TotalOEE = 0.0, OEE = 0.0, CycleEffe = 0.0, TotalcycleEff = 0.0, LoadUnloadeff = 0.0, TotalLoadUnloadEff = 0.0, productionQty = 0.0;
                            foreach (DataRow dtRow in ValuesbyEmp.Rows)
                            {
                                workSheet.Cells[row, 1].Value = dtRow["operator"];
                                workSheet.Cells[row, 2].Value = dtRow["GroupID"];
                                workSheet.Cells[row, 3].Value = dtRow["machine"];
                                workSheet.Cells[row, 4].Value = Util.GetDateTime(dtRow["stdate"].ToString()).ToString("yyyy-MM-dd HH:mm:ss");
                                workSheet.Cells[row, 5].Value = dtRow["component"];
                                workSheet.Cells[row, 6].Value = dtRow["operation"];
                                workSheet.Cells[row, 7].Value = Util.GetDateTime(dtRow["BatchStart"].ToString()).ToString("yyyy-MM-dd HH:mm:ss");
                                workSheet.Cells[row, 8].Value = Util.GetDateTime(dtRow["BatchEnd"].ToString()).ToString("yyyy-MM-dd HH:mm:ss");
                                workSheet.Cells[row, 9].Value = dtRow["Production"];
                                productionQty += Convert.ToDouble(dtRow["Production"].ToString());
                                switch (TimeFormat)
                                {
                                    case "hh:mm:ss":
                                        TimeSpan.TryParse(dtRow["IdealMachiningTime"].ToString(), out IdealMachiningTime);
                                        setTimeSpanFormat(TimeFormat, workSheet, row, 10, string.Format("{0}:{1}:{2}", ((int)IdealMachiningTime.TotalHours).ToString("00"), ((int)IdealMachiningTime.Minutes).ToString("00"), ((int)IdealMachiningTime.Seconds).ToString("00")));
                                        TimeSpan.TryParse(dtRow["AvgCycle"].ToString(), out AvgCycle);

                                        setTimeSpanFormat(TimeFormat, workSheet, row, 11, string.Format("{0}:{1}:{2}", ((int)AvgCycle.TotalHours).ToString("00"), ((int)AvgCycle.Minutes).ToString("00"), ((int)AvgCycle.Seconds).ToString("00")));
                                        CycleEffe = (Convert.ToDouble(IdealMachiningTime.TotalSeconds) / AvgCycle.TotalSeconds) * 100;
                                        CycleEffe = CycleEffe.ToString().Equals("∞") ? 0 : Math.Round(CycleEffe, 2);
                                        TotalcycleEff += (CycleEffe * Convert.ToDouble(dtRow["Production"].ToString()));

                                        TimeSpan.TryParse(dtRow["IdealLoadUnload"].ToString(), out IdealMachiningTime);
                                        TimeSpan.TryParse(dtRow["Avgloadunload"].ToString(), out AvgCycle);
                                        LoadUnloadeff = (IdealMachiningTime.TotalSeconds / AvgCycle.TotalSeconds) * 100;
                                        LoadUnloadeff = LoadUnloadeff.ToString().Equals("∞") ? 0 : Math.Round(LoadUnloadeff, 2);
                                        TotalLoadUnloadEff += (LoadUnloadeff * Convert.ToDouble(dtRow["Production"].ToString()));

                                        double CycleEff = CycleEffe.ToString().Equals("∞") ? 0 : Math.Round(CycleEffe, 2);
                                        workSheet.Cells[row, 12].Value = CycleEff;
                                        if (CycleEff > 120)
                                        {
                                            workSheet.Cells[row, 12].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                            workSheet.Cells[row, 12].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#c6efce"));
                                        }
                                        else if (CycleEff < 80)
                                        {
                                            workSheet.Cells[row, 12].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                            workSheet.Cells[row, 12].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#ffc7ce"));
                                        }

                                        setTimeSpanFormat(TimeFormat, workSheet, row, 13, string.Format("{0}:{1}:{2}", ((int)IdealMachiningTime.TotalHours).ToString("00"), ((int)IdealMachiningTime.Minutes).ToString("00"), ((int)IdealMachiningTime.Seconds).ToString("00")));

                                        setTimeSpanFormat(TimeFormat, workSheet, row, 14, string.Format("{0}:{1}:{2}", ((int)AvgCycle.TotalHours).ToString("00"), ((int)AvgCycle.Minutes).ToString("00"), ((int)AvgCycle.Seconds).ToString("00")));

                                        double LoadUnload = LoadUnloadeff.ToString().Equals("∞") ? 0 : Math.Round(LoadUnloadeff, 2);
                                        workSheet.Cells[row, 15].Value = LoadUnload;
                                        if (LoadUnload > 120)
                                        {
                                            workSheet.Cells[row, 15].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                            workSheet.Cells[row, 15].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#c6efce"));
                                        }
                                        else if (LoadUnload < 80)
                                        {
                                            workSheet.Cells[row, 15].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                            workSheet.Cells[row, 15].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#ffc7ce"));
                                        }

                                        setTimeSpanFormat(TimeFormat, workSheet, row, 16, dtRow["BatchDown"].ToString());
                                        var split = dtRow["BatchDown"].ToString().Split(new char[] { ':' });
                                        totaldown += new TimeSpan(int.Parse(split[0]), int.Parse(split[1]), int.Parse(split[2]));
                                        TimeSpan.TryParse(dtRow["IdealMachiningTime"].ToString(), out IdealMachiningTime);
                                        TimeSpan.TryParse(dtRow["IdealLoadUnload"].ToString(), out AvgCycle);
                                        OEE = GetTotalEffectiency(Convert.ToDouble(dtRow["Production"].ToString()), IdealMachiningTime.TotalSeconds, AvgCycle.TotalSeconds, Convert.ToDouble(dtRow["BatchPeriod"].ToString()), Convert.ToDouble(dtRow["Batch"].ToString()));
                                        workSheet.Cells[row, 17].Value = OEE.ToString().Equals("∞") ? 0 : Math.Round(OEE, 2);
                                        break;
                                    default:
                                        workSheet.Cells[row, 10].Value = Math.Round(Convert.ToDouble(dtRow["IdealMachiningTime"].ToString()), 2);
                                        workSheet.Cells[row, 11].Value = Math.Round(Convert.ToDouble(dtRow["AvgCycle"].ToString()), 2);
                                        CycleEffe = (Convert.ToDouble(dtRow["IdealMachiningTime"].ToString()) / Convert.ToDouble(dtRow["AvgCycle"].ToString())) * 100;
                                        CycleEffe = CycleEffe.ToString().Equals("∞") ? 0 : Math.Round(CycleEffe, 2);
                                        TotalcycleEff += (CycleEffe * Convert.ToDouble(dtRow["Production"].ToString()));
                                        LoadUnloadeff = (Convert.ToDouble(dtRow["IdealLoadUnload"].ToString()) / Convert.ToDouble(dtRow["Avgloadunload"].ToString())) * 100;
                                        LoadUnloadeff = LoadUnloadeff.ToString().Equals("∞") ? 0 : Math.Round(LoadUnloadeff, 2);
                                        TotalLoadUnloadEff += (LoadUnloadeff * Convert.ToDouble(dtRow["Production"].ToString()));

                                        CycleEff = CycleEffe.ToString().Equals("∞") ? 0 : Math.Round(CycleEffe, 2);
                                        workSheet.Cells[row, 12].Value = CycleEff;
                                        if (CycleEff > 120)
                                        {
                                            workSheet.Cells[row, 12].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                            workSheet.Cells[row, 12].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#c6efce"));
                                        }
                                        else if (CycleEff < 80)
                                        {
                                            workSheet.Cells[row, 12].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                            workSheet.Cells[row, 12].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#ffc7ce"));
                                        }

                                        workSheet.Cells[row, 13].Value = Math.Round(Convert.ToDouble(dtRow["IdealLoadUnload"].ToString()), 2);
                                        workSheet.Cells[row, 14].Value = Math.Round(Convert.ToDouble(dtRow["Avgloadunload"].ToString()), 2);

                                        LoadUnload = LoadUnloadeff.ToString().Equals("∞") ? 0 : Math.Round(LoadUnloadeff, 2);
                                        workSheet.Cells[row, 15].Value = LoadUnload;
                                        if (LoadUnload > 120)
                                        {
                                            workSheet.Cells[row, 15].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                            workSheet.Cells[row, 15].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#c6efce"));
                                        }
                                        else if (LoadUnload < 80)
                                        {
                                            workSheet.Cells[row, 15].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                            workSheet.Cells[row, 15].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#ffc7ce"));
                                        }

                                        setTimeSpanFormat(TimeFormat, workSheet, row, 16, dtRow["BatchDown"].ToString());
                                        double.TryParse(dtRow["BatchDown"].ToString(), out double down);
                                        totaldown_int += down;
                                        OEE = GetTotalEffectiency(Convert.ToDouble(dtRow["Production"].ToString()), Convert.ToDouble(dtRow["IdealMachiningTime"].ToString()), Convert.ToDouble(dtRow["IdealLoadUnload"].ToString()), Convert.ToDouble(dtRow["BatchPeriod"].ToString()), Convert.ToDouble(dtRow["Batch"].ToString()));
                                        workSheet.Cells[row, 17].Value = OEE.ToString().Equals("∞") ? 0 : Math.Round(OEE, 2);
                                        break;
                                }
                                workSheet.Cells[row, 17].Value = OEE.ToString().Equals("∞") ? 0 : Math.Round(OEE, 2);
                                TotalOEE += (OEE * Convert.ToDouble(dtRow["Production"].ToString()));
                                row++;
                            }
                            if (productionQty != 0 && TotalcycleEff != double.NaN && TotalOEE != double.NaN && TotalLoadUnloadEff != double.NaN)
                            {
                                workSheet.Cells[(row), 12].Value = Math.Round((TotalcycleEff / productionQty), 2);
                                workSheet.Cells[(row), 15].Value = Math.Round((TotalLoadUnloadEff / productionQty), 2);
                                switch (TimeFormat)
                                {
                                    case "hh:mm:ss":
                                        workSheet.Cells[(row), 16].Style.Numberformat.Format = "HH:mm:ss";
                                        setTimeSpanFormat(TimeFormat, workSheet, row, 16, string.Format("{0}:{1}:{2}", ((int)totaldown.TotalHours).ToString("00"), ((int)totaldown.Minutes).ToString("00"), ((int)totaldown.Seconds).ToString("00")));
                                        break;
                                    default:
                                        workSheet.Cells[(row), 16].Style.Numberformat.Format = "00.00";
                                        workSheet.Cells[(row), 16].Value = totaldown_int;
                                        break;
                                }

                                workSheet.Cells[(row), 17].Value = Math.Round((TotalOEE / productionQty), 2);
                            }
                            workSheet.Cells[row, 8].Value = "Total (OR) Weighted Average";
                            workSheet.Cells[row, 1, row, 17].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            workSheet.Cells[row, 1, row, 17].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#0070C0"));
                            workSheet.Cells[row, 10, row, 17].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            workSheet.Cells[row, 10, row, 17].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                            workSheet.Cells[row, 10, row, 17].Style.Font.Bold = true;
                            workSheet.Cells[row, 1, row, 17].Style.Font.Color.SetColor(Color.White);

                            row--;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Border.Top.Color.SetColor(Color.Black);
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Border.Bottom.Color.SetColor(Color.Black);
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Border.Left.Color.SetColor(Color.Black);
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Border.Right.Color.SetColor(Color.Black);
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            //workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 17].Style.Fill.BackgroundColor.SetColor(backcolor);
                            row = row + 2;
                        }

                        int col1 = 1, row1 = 2;
                        foreach (DataRow item in summarydt.Rows)
                        {
                            col1 = 1;
                            workSheet2.Cells[row1, col1].Value = item["Operator"];
                            col1++;
                            workSheet2.Cells[row1, col1].Value = item["Section"];
                            col1++;
                            setTimeSpanFormat(TimeFormat, workSheet2, row1, col1, item["DownTime"].ToString());
                            col1++;
                            workSheet2.Cells[row1, col1].Value = item["OEE"];
                            col1++;

                            double MachineTimeEfficiency = (item["MachineTimeEfficiency"].ToString().Equals("∞") || string.IsNullOrEmpty(item["MachineTimeEfficiency"].ToString())) ? 0 : Math.Round(Convert.ToDouble(item["MachineTimeEfficiency"].ToString()), 2);
                            workSheet2.Cells[row1, col1].Value = MachineTimeEfficiency;
                            if (MachineTimeEfficiency > 120)
                            {
                                workSheet2.Cells[row1, col1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                workSheet2.Cells[row1, col1].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#c6efce"));
                            }
                            else if (Convert.ToDouble(MachineTimeEfficiency) < 80)
                            {
                                workSheet2.Cells[row1, col1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                workSheet2.Cells[row1, col1].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#ffc7ce"));
                            }
                            col1++;
                            double LoadUnloadEfficiency = (item["LoadUnloadEfficiency"].ToString().Equals("∞") || string.IsNullOrEmpty(item["LoadUnloadEfficiency"].ToString())) ? 0 : Math.Round(Convert.ToDouble(item["LoadUnloadEfficiency"].ToString()), 2);
                            workSheet2.Cells[row1, col1].Value = LoadUnloadEfficiency;
                            if (LoadUnloadEfficiency > 120)
                            {
                                workSheet2.Cells[row1, col1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                workSheet2.Cells[row1, col1].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#c6efce"));
                            }
                            else if (Convert.ToDouble(LoadUnloadEfficiency) < 80)
                            {
                                workSheet2.Cells[row1, col1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                workSheet2.Cells[row1, col1].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#ffc7ce"));
                            }
                            row1++;
                        }
                        setThinBorder(workSheet2, 2, 1, row1 - 1, col1);

                        workSheet.PrinterSettings.PaperSize = ePaperSize.A3;
                        workSheet.PrinterSettings.Orientation = eOrientation.Landscape;
                        workSheet.PrinterSettings.FitToPage = true;
                        workSheet.PrinterSettings.FitToWidth = 1;
                        workSheet.PrinterSettings.FitToHeight = 0;
                    }
                    else
                        Generated = "";
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog($"OperatorEff report At :{DateTime.Now:yyyy-MM-dd HH:mm:ss}");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
            return Generated;
        }

        internal static string MachinewiseScrapReport(DateTime fromDate, DateTime toDate, string machine)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "MachineWiseScrapReport.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "MachineWiseScrapReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("MachineWise Scrap report Log by day-Excel - \n " + src);
                }

                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];
                wsDts.Cells["B3"].Value = "From Date";
                wsDts.Cells["D3"].Value = fromDate.ToString("dd-MMM-yyyy hh:mm:ss");
                wsDts.Cells["E3"].Value = "To Date";
                wsDts.Cells["F3"].Value = toDate.ToString("dd-MMM-yyyy hh:mm:ss");
                int row = 6, Slno = 1;
                string modelRange = "";
                DataTable dt = TMPTrakDataBase.GetMachineWiseScrapDetails(fromDate, toDate, machine);
                if (dt != null && dt.Rows.Count > 0)
                {
                    string previousMachineName = "";
                    int prevRow = 0;
                    //var distMachineID = dt.AsEnumerable().Select(k => k.Field<string>("Machineid")).Distinct().ToList();

                    foreach (DataRow item in dt.Rows)
                    {

                        if (previousMachineName != item["Machineid"].ToString())
                        {
                            wsDts.Cells[row, 1].Value = Slno++;
                            previousMachineName = item["Machineid"].ToString();
                            prevRow = row;
                            wsDts.Cells[row, 2].Value = item["Machineid"].ToString();
                            wsDts.Cells[row, 7].Value = item["WeightInKgs"];
                            wsDts.Cells[row, 8].Value = item["RejectionScrap_Kgs"];
                            wsDts.Cells[row, 9].Value = item["LayOutScrap_Kgs"];
                            wsDts.Cells[row, 10].Value = item["DesignScrap_Kgs"];
                            //wsDts.Cells[row, 11].Value = $"{item["RejectionScrapInPercent"].ToString()}%"; 
                            //wsDts.Cells[row, 12].Value = $"{item["LayOutScrapInPercent"].ToString()}%";
                            //wsDts.Cells[row, 13].Value = $"{item["DesignScrapInPercent"].ToString()}% "; 
                            //wsDts.Cells[row, 14].Value = $"{item["yield"].ToString()}% ";
                            wsDts.Cells[row, 11].Value = item["RejectionScrapInPercent"];
                            wsDts.Cells[row, 12].Value = item["LayOutScrapInPercent"];
                            wsDts.Cells[row, 13].Value = item["DesignScrapInPercent"];
                            wsDts.Cells[row, 14].Value = item["yield"];
                        }
                        else
                        {
                            wsDts.Cells[row, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 1, row, 1].Merge = true;

                            wsDts.Cells[row, 2].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 2, row, 2].Merge = true;

                            wsDts.Cells[row, 7].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 7, row, 7].Merge = true;

                            wsDts.Cells[row, 8].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 8, row, 8].Merge = true;

                            wsDts.Cells[row, 9].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 9, row, 9].Merge = true;

                            wsDts.Cells[row, 10].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 10, row, 10].Merge = true;

                            wsDts.Cells[row, 11].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 11, row, 11].Merge = true;

                            wsDts.Cells[row, 12].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 12, row, 12].Merge = true;

                            wsDts.Cells[row, 13].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 13, row, 13].Merge = true;

                            wsDts.Cells[row, 14].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            wsDts.Cells[prevRow, 14, row, 14].Merge = true;

                        }
                        wsDts.Cells[row, 3].Value = item["ComponentID"];
                        wsDts.Cells[row, 4].Value = item["TotalParts"];
                        wsDts.Cells[row, 5].Value = item["Strokes"];
                        wsDts.Cells[row, 6].Value = item["TotalWeightPerPart_Kgs"];

                        row++;
                    }

                    int lastrow = row - 1;
                    modelRange = "A6:N" + (row - 1).ToString();

                    var modelTable = wsDts.Cells[modelRange];
                    // Assign borders

                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                    //wsDts.Cells[modelRange].AutoFitColumns();

                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("OperatorDrawingNo report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("MachinewiseScrapReport=" + ex.Message);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }



        internal static string MachineReworkReport(DateTime fromDate, DateTime toDate, string machine)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "MachineReworkReport.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "MachineReworkReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Machine Rework report Log by day-Excel - \n " + src);
                }

                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];
                wsDts.Cells["B3"].Value = "From Date";
                wsDts.Cells["D3"].Value = fromDate.ToString("dd-MMM-yyyy hh:mm:ss");
                wsDts.Cells["F3"].Value = "To Date";
                wsDts.Cells["G3"].Value = toDate.ToString("dd-MMM-yyyy hh:mm:ss");
                wsDts.Cells["I3"].Value = "Machines";
                wsDts.Cells["J3"].Value = machine;
                int row = 6;
                int StartRow = row;
                string modelRange = "";
                DataTable dt = TMPTrakDataBase.GetMachineReworkDetails(fromDate, toDate, machine);
                if (dt != null && dt.Rows.Count > 0)
                {

                    foreach (DataRow item in dt.Rows)
                    {
                        wsDts.Cells[row, 1].Value = item["machineid"];
                        wsDts.Cells[row, 2].Value = item["componentid"];
                        wsDts.Cells[row, 3].Value = item["operationno"];
                        wsDts.Cells[row, 4].Value = item["Name"];
                        wsDts.Cells[row, 5].Value = Util.GetDateTime(item["sttime"].ToString()).ToString("yyyy-MM-dd HH:mm:ss");
                        wsDts.Cells[row, 6].Value = Util.GetDateTime(item["ndtime"].ToString()).ToString("yyyy-MM-dd HH:mm:ss");
                        //wsDts.Cells[row, 7].Value = Util.GetDateTime(item["TimeDuration"].ToString()).ToString("HH:mm:ss");
                        setTimeSpanFormat("hh:mm:ss", wsDts, row, 7, item["TimeDuration"].ToString());
                        wsDts.Cells[row, 8].Value = item["PartsCount"];
                        wsDts.Cells[row, 8].Style.Numberformat.Format = "0.00000";
                        wsDts.Cells[row, 9].Value = item["WorkOrderNumber"];
                        wsDts.Cells[row, 10].Value = item["DepartmentID"];
                        wsDts.Cells[row, 11].Value = item["DepartmentName"];
                        wsDts.Cells[row, 12].Value = item["PartialCycleIndicator"];
                        row++;
                    }
                    int lastrow = row - 1;
                    wsDts.Cells[row, 7].Formula = "=Sum(G" + StartRow.ToString() + ":G" + lastrow.ToString() + ")";
                    wsDts.Cells[row, 7].Style.Numberformat.Format = "[h]:mm:ss";
                    wsDts.Cells[row, 1].Value = "Total";
                    wsDts.Cells[row, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                    wsDts.Cells[row, 1].Style.Font.Bold = true;
                    wsDts.Cells[row, 1, row, 6].Merge = true;
                    wsDts.Cells[row, 8, row, 12].Merge = true;

                    modelRange = "A6:L" + (row).ToString();
                    var modelTable = wsDts.Cells[modelRange];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                    //wsDts.Cells[modelRange].AutoFitColumns();

                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("OperatorDrawingNo report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("MachineReworkReport=" + ex.Message);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }

        internal static string GetOperatorDrawingNoDetails(DateTime fromDate, DateTime toDate, string opId)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "Operator_DrawingNoReport.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "Operator_DrawingNoReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Drawing No.report Log by day-Excel - \n " + src);
                }


                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];
                wsDts.Cells["B4"].Value = "From Date";
                wsDts.Cells["C4"].Value = fromDate.ToString("dd-MMM-yyyy hh:mm:ss");
                wsDts.Cells["E4"].Value = "To Date";
                wsDts.Cells["F4"].Value = toDate.ToString("dd-MMM-yyyy hh:mm:ss");
                //wsDts.Cells["F4"].Value = opId;
                int row = 7, i = 1;
                string modelRange = "";
                DataTable dt = TMPTrakDataBase.GetDrawingNoDetails(fromDate, toDate, opId);
                if (dt != null && dt.Rows.Count > 0)
                {

                    foreach (DataRow item in dt.Rows)
                    {
                        wsDts.Cells[row, 1].Value = i++;
                        wsDts.Cells[row, 2].Value = item["Machineid"];
                        wsDts.Cells[row, 3].Value = item["ComponentID"];
                        wsDts.Cells[row, 4].Value = item["OperationNo"];
                        //wsDts.Cells[row, 5].Value = item["InterfaceID"];
                        wsDts.Cells[row, 5].Value = item["OldDrawingNo"];
                        wsDts.Cells[row, 6].Value = item["NewDrawingNo"];
                        wsDts.Cells[row, 7].Value = item["UpdatedBy"];
                        wsDts.Cells[row, 8].Value = Util.GetDateTime(item["UpdatedTS"].ToString()).ToString("yyyy-MM-dd HH:mm:ss");
                        row++;
                    }
                    int lastrow = row - 1;
                    modelRange = "A7:H" + (row - 1).ToString();

                    var modelTable = wsDts.Cells[modelRange];
                    // Assign borders

                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;

                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("OperatorDrawingNo report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";
                //wsDts.Cells.AutoFitColumns();

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("GetOperatorDrawingNoDetails=" + ex.Message);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }

