        #region "SM_Machinewise Prod Report From AutoData"
        public static string SM_MachinewiseProdReportFromAutoData(DateTime StartDate, string MachineId, string PlantId, string CellID, DateTime EndDate)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "SM_MachinewiseProdReportFromAutoData.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "SM_MachinewiseProdReportFromAutoData" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (PlantId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    PlantId = "";
                if (MachineId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    MachineId = "";

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("SM_MachinewiseProdReportFromAutoData details - \n " + src);
                }

                //string str1 = VDGDataBaseAccess.GetLogicalDayStart(StartDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strfromdate = DateTime.Now;
                //DateTime.TryParse(str1, out strfromdate);

                //string str2 = VDGDataBaseAccess.GetLogicalDayEnd(EndDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strtodate = DateTime.Now;
                //DateTime.TryParse(str2, out strtodate);

                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];
                wsDts.Cells["B2"].Value = StartDate.ToString("dd-MMM-yyyy hh:mm:ss");
                wsDts.Cells["H2"].Value = EndDate.ToString("dd-MMM-yyyy hh:mm:ss");
                int row = 6;
                DataTable dt = TMPTrakDataBase.SM_MachinewiseProdReportFromAutoData(StartDate, EndDate, MachineId, PlantId, CellID);
                if (dt != null && dt.Rows.Count > 0)
                {
                    string timeFormat = DataBaseAccess.getTimeFormatFromCockpit();
                    foreach (DataRow item in dt.Rows)
                    {
                        wsDts.Cells[row, 1].Value = item["Remarks2"];
                        wsDts.Cells[row, 2].Value = item["MachineId"];
                        wsDts.Cells[row, 3].Value = item["MachineDescription"];
                        wsDts.Cells[row, 4].Value = item["Components"];
                        setTimeSpanFormat(timeFormat, wsDts, row, 5, item["NetUtilisedTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 6, item["DownTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 7, item["NetManagementLoss"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 8, item["TotalPDT"].ToString());
                        wsDts.Cells[row, 9].Value = item["AvailabilityEfficiency"];
                        wsDts.Cells[row, 10].Value = item["ProductionEfficiency"];
                        wsDts.Cells[row, 11].Value = item["QualityEfficiency"];
                        wsDts.Cells[row, 12].Value = item["OverallEfficiency"];
                        wsDts.Cells[row, 13].Value = item["TurnOver"];
                        wsDts.Cells[row, 14].Value = item["ReturnPerHour"];
                        wsDts.Cells[row, 15].Value = item["ReturnPerHourTOTAL"];
                        row++;
                    }
                    wsDts.Cells[6, 1, row, 15].AutoFitColumns();
                    string modelRange = "A5:O" + (row - 1).ToString();
                    var modelTable = wsDts.Cells[modelRange];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    //wsDts.Cells.AutoFitColumns();
                    wsDts.Column(13).Hidden = true;
                    wsDts.Column(14).Hidden = true;
                    wsDts.Column(15).Hidden = true;

                    if (DataBaseAccess.isQERequired() == false)
                    {
                        wsDts.Column(11).Hidden = true;
                    }
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Down time report to Machine wise down time details report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }


