        #region "Production And Down Pie Chart Report"
        internal static void ProductionDownPieDownTimeChartReport(DateTime StartDate, string PlantId, string MachineId, DateTime EndDate, string DownID, int Exclude, string cellID)
        {
            try
            {
                string source, destination = string.Empty;
                string reportName = "ProductionDownPieDownTimeChartReport.xlsx";
                source = Util.GetReportPath(reportName);

                string tempfileName = "ProductionDownTimeReportCategorywise" + "_" + Guid.NewGuid() + ".xlsx";
                destination = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (PlantId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    PlantId = "";
                if (MachineId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    MachineId = "";

                if (!File.Exists(source))
                {
                    Logger.WriteDebugLog("Down time report to Machine wise down time details - \n " + source);
                }

                FileInfo newFile = new FileInfo(source);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDownCategory = pck.Workbook.Worksheets["Down By Category"];

                #region --- Down By Category -------
                wsDownCategory.Cells["D2"].Value = StartDate.ToString("dd-MMM-yyyy hh:mm:ss");
                wsDownCategory.Cells["J2"].Value = EndDate.ToString("dd-MMM-yyyy hh:mm:ss");

                DataTable dt = TMPTrakDataBase.GetProductionDownPieDownTimeChartData(StartDate, PlantId, MachineId, EndDate, DownID, Exclude, "DTime_By_Catagory_And_PTime", cellID);

                var sortedDT = dt.AsEnumerable()
                                     .GroupBy(r => r.Field<string>("Catagory").ToUpper())
                                     //.OrderBy(g => g.Max(r => r.Field<double>("DownTime")))
                                     .Select(g =>
                                     {
                                         var dTrow = dt.NewRow();
                                         dTrow["Catagory"] = g.Key.ToUpper();
                                         dTrow["DowntimeInSeconds"] = g.Sum(r => r.Field<double>("DowntimeInSeconds"));
                                         return dTrow;
                                     }).CopyToDataTable();


                int row = 30;
                if (sortedDT != null && sortedDT.Rows.Count > 0)
                {
                    wsDownCategory.Column(3).Style.Numberformat.Format = "General";
                    foreach (DataRow item in sortedDT.Rows)
                    {
                        wsDownCategory.Cells[row, 2].Value = item["Catagory"];
                        //var downtime = item["DownInTimeFormat"].ToString().Split(':');
                        //Int64 hour = Convert.ToInt64(downtime[0]) * 3600;
                        //Int64 minutes = Convert.ToInt64(downtime[1]) * 60;
                        //Int64 second = Convert.ToInt64(downtime[2]);
                        //TimeSpan timeSpan = TimeSpan.FromSeconds(Convert.ToDouble(hour + minutes + second));
                        //string answer = string.Format("{0:00}:{1:00}:{2:00}",
                        //         (int)timeSpan.TotalHours,
                        //         timeSpan.Minutes,
                        //         timeSpan.Seconds);
                        wsDownCategory.Cells[row, 3].Value = Convert.ToDecimal(item["DowntimeInSeconds"]) / 86400;
                        wsDownCategory.Cells[row, 3].Style.Numberformat.Format = "[h]:mm:ss";
                        row++;
                    }

                }

                int colCnt = 4;
                if (dt != null && dt.Rows.Count > 0)
                {
                    //List<string> machineIdList = dt.AsEnumerable().Select(x => x.Field<string>("machineDescription")).Distinct().ToList();
                    List<string> machineIdList = dt.AsEnumerable().Select(x => x.Field<string>("MachineID")).Distinct().ToList();
                    List<string> downCategoryList = dt.AsEnumerable().Select(x => x.Field<string>("Catagory")).Distinct(StringComparer.OrdinalIgnoreCase).ToList();
                    foreach (string machineId in machineIdList)
                    {
                        row = 29;
                        //DataTable machineWiseDown = dt.AsEnumerable().Where(x => x.Field<string>("machineDescription") == machineId).CopyToDataTable();
                        DataTable machineWiseDown = dt.AsEnumerable().Where(x => x.Field<string>("MachineID") == machineId).CopyToDataTable();
                        wsDownCategory.Cells[row, colCnt].Value = machineId;
                        row++;
                        int i = 0, count = machineWiseDown.Rows.Count;
                        foreach (string downCategory in downCategoryList)
                        {
                            if (i != count)
                            {
                                if (machineWiseDown.Rows[i]["Catagory"] != null && machineWiseDown.Rows[i]["Catagory"].ToString().Equals(downCategory, StringComparison.OrdinalIgnoreCase))
                                {
                                    //decimal downValue = Convert.ToDecimal(machineWiseDown.AsEnumerable().Where(x => x.Field<string>("Catagory") == downCategory).ToList()[0].ItemArray[4].ToString());
                                    decimal downValue = Convert.ToDecimal(machineWiseDown.AsEnumerable().Where(x => x.Field<string>("Catagory").Equals(downCategory, StringComparison.OrdinalIgnoreCase)).ToList()[0].ItemArray[4].ToString());
                                    wsDownCategory.Cells[row, colCnt].Value = downValue / 86400;
                                    wsDownCategory.Cells[row, colCnt].Style.Numberformat.Format = "[h]:mm:ss";
                                    i++;
                                }
                            }
                            row++;
                        }
                        colCnt++;
                    }
                    setThinBorder(wsDownCategory, 29, 2, row - 1, colCnt - 1);
                    wsDownCategory.Cells[29, 2, row, colCnt].AutoFitColumns();
                    //foreach (DataRow item in dt.Rows)
                    //{
                    //    wsDownCategory.Cells[row, colCnt].Value = item["MachineID"];
                    //    wsDownCategory.Cells[row + 1, colCnt].Value = item["DownTime"];
                    //    colCnt++;
                    //}
                }

                var myChart = wsDownCategory.Drawings.AddChart("chart", eChartType.Pie);
                var series = myChart.Series.Add(string.Format("C30: C{0}", 30 + (sortedDT == null ? 0 : sortedDT.Rows.Count - 1)), string.Format("B30: B{0}", 30 + (sortedDT == null ? 0 : sortedDT.Rows.Count - 1)));
                myChart.Border.Fill.Color = Color.Green;
                myChart.Title.Text = "Down Time - Category Wise";
                myChart.ShowDataLabelsOverMaximum = true;
                myChart.DisplayBlanksAs = eDisplayBlanksAs.Zero;
                var pieSeries = (ExcelPieChartSerie)series;
                pieSeries.DataLabel.ShowCategory = true;
                pieSeries.DataLabel.ShowValue = false;
                pieSeries.DataLabel.ShowPercent = true;
                pieSeries.DataLabel.Position = eLabelPosition.BestFit;
                myChart.SetSize(800, 460);
                myChart.SetPosition(4, 0, 1, 0);

                //pck.Save();
                #endregion

                #region ------ Machinewise Prod --
                wsDownCategory = pck.Workbook.Worksheets["Machinewise Prod"];
                wsDownCategory.Cells["B3"].Value = StartDate.ToString("dd-MMM-yyyy hh:mm:ss");
                wsDownCategory.Cells["D3"].Value = EndDate.ToString("dd-MMM-yyyy hh:mm:ss");
                dt = TMPTrakDataBase.GetMachineWiseProdData(StartDate, EndDate, MachineId, PlantId, cellID);
                row = 7;
                if (dt != null && dt.Rows.Count > 0)
                {
                    foreach (DataRow item in dt.Rows)
                    {
