                        wsDownCategory.Cells[row, 3].Value = item["Components"];
                        wsDownCategory.Cells[row, 4].Value = item["AvailabilityEfficiency"];
                        wsDownCategory.Cells[row, 5].Value = item["ProductionEfficiency"];
                        wsDownCategory.Cells[row, 6].Value = item["QualityEfficiency"];
                        wsDownCategory.Cells[row, 7].Value = item["OverallEfficiency"];
                        row++;
                    }
                }
                wsDownCategory.Cells[5, 1, row, 7].AutoFitColumns();
                if (DataBaseAccess.isQERequired() == false)
                {
                    wsDownCategory.Column(6).Hidden = true;
                }
                #endregion

                #region ------- Down Losses By Down Category ------
                wsDownCategory = pck.Workbook.Worksheets["Down Losses By Down Category"];
                dt = TMPTrakDataBase.GetProductionDownPieDownTimeChartData(StartDate, PlantId, MachineId, EndDate, DownID, Exclude, "DLoss_By_Catagory", cellID);
                row = 3;
                int rowStart = 4;
                List<string> categories = dt.AsEnumerable().Select(x => x.Field<string>("Catagory")).Distinct().ToList();
                foreach (string category in categories)
                {
                    DataTable dtCategory = dt.AsEnumerable().Where(x => x.Field<string>("Catagory").Equals(category)).CopyToDataTable();
                    if (dtCategory != null && dt.Rows.Count > 0)
                    {
                        Color colFromHex = ColorTranslator.FromHtml("#FFCC99");
                        wsDownCategory.Cells[row, 1].Value = dtCategory.Columns[0].ColumnName;
                        wsDownCategory.Cells[row, 2].Value = dtCategory.Columns[1].ColumnName;
                        wsDownCategory.Cells[row, 3].Value = dtCategory.Columns[2].ColumnName + " (hh:mm:ss)";
                        wsDownCategory.Cells[row, 1, row, 3].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        wsDownCategory.Cells[row, 1, row, 3].Style.Fill.BackgroundColor.SetColor(colFromHex);
                        wsDownCategory.Cells[row, 1].Style.Border.BorderAround(ExcelBorderStyle.Thin);
                        wsDownCategory.Cells[row, 2].Style.Border.BorderAround(ExcelBorderStyle.Thin);
                        wsDownCategory.Cells[row, 3].Style.Border.BorderAround(ExcelBorderStyle.Thin);

                        row = row + 1;
                        foreach (DataRow dataRow in dtCategory.Rows)
                        {
                            wsDownCategory.Cells[row, 1].Value = dataRow["Catagory"];
                            wsDownCategory.Cells[row, 2].Value = dataRow["DownID"];
                            wsDownCategory.Cells[row, 3].Value = Convert.ToDecimal(dataRow["DowntimeInSeconds"]) / 86400;
                            //wsDownCategory.Cells[row, 3].Style.Numberformat.Format = "[h]:mm:ss";
                            wsDownCategory.Cells[row, 3].Style.HorizontalAlignment = ExcelHorizontalAlignment.Right;
                            row = row + 1;
                        }
                        var pieChart = wsDownCategory.Drawings.AddChart("chart" + row, eChartType.Pie);
                        string xSerieAddress = "B" + rowStart + ": " + "B" + (row - 1);
                        string serieAddress = "C" + rowStart + ": " + "C" + (row - 1);
                        series = pieChart.Series.Add(serieAddress, xSerieAddress);
                        pieChart.Border.Fill.Color = Color.Green;
                        pieChart.Title.Text = category;
                        pieChart.ShowDataLabelsOverMaximum = true;
                        pieChart.DisplayBlanksAs = eDisplayBlanksAs.Zero;
                        pieSeries = (ExcelPieChartSerie)series;
                        pieSeries.DataLabel.ShowCategory = true;
                        pieSeries.DataLabel.ShowValue = false;
                        pieSeries.DataLabel.ShowPercent = true;
                        pieSeries.DataLabel.Position = eLabelPosition.BestFit;
                        pieChart.SetSize(660, 440);
                        pieChart.SetPosition(row, 0, 0, 0);
                    }
                    row = row + 24;
                    rowStart = row + 1;
                }
                wsDownCategory.Cells[3, 1, row, 3].AutoFitColumns();
                #endregion
                //pck.Save();
                DownloadMultipleFile(destination, pck.GetAsByteArray());
                Logger.WriteDebugLog("Down time report to Category wise down time details report generated sucessfully.");
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex); ErrorSignal.FromCurrentContext().Raise(ex);
            }
        }
        #endregion

