                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.MachineNO;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.MONumber;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.ItemCode;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.EmployeeName;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.ActualCount;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.MOQty;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.MOSettingtime;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.MORunningtime;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.TotalCycletime;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.AllowanceTime;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.Actualtimeconsumedforproduction;
                        j++;
                        if (!string.IsNullOrEmpty(entity.Actualtimeconsumedforproduction) && !string.IsNullOrEmpty(entity.TotalCycletime))
                        {
                            difference = (Convert.ToDouble(entity.Actualtimeconsumedforproduction) - Convert.ToDouble(entity.TotalCycletime));
                            EXCELWORKSHEET.Cells[i, j].Value = difference;
                        }
                        else
                        {
                            EXCELWORKSHEET.Cells[i, j].Value = "";
                        }
                        j++;
                        if (!string.IsNullOrEmpty(entity.TotalCycletime))
                        {
                            EXCELWORKSHEET.Cells[i, j].Value = difference / Convert.ToDouble(entity.TotalCycletime);
                        }
                        else
                        {
                            EXCELWORKSHEET.Cells[i, j].Value = "";
                        }
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.Remarks;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.Remarks1;
                        j++;
                        EXCELWORKSHEET.Cells[i, j].Value = entity.Category;
                        i++;
                    }
                    i--;
                    EXCELWORKSHEET.Cells[k, l, i, j].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    EXCELWORKSHEET.Cells[k, l, i, j].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    EXCELWORKSHEET.Cells[k, l, i, j].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    EXCELWORKSHEET.Cells[k, l, i, j].Style.Border.Bottom.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    EXCELWORKSHEET.Cells[k, l, i, j].Style.Border.Top.Color.SetColor(System.Drawing.Color.Black);
                    EXCELWORKSHEET.Cells[k, l, i, j].Style.Border.Left.Color.SetColor(System.Drawing.Color.Black);
                    EXCELWORKSHEET.Cells[k, l, i, j].Style.Border.Right.Color.SetColor(System.Drawing.Color.Black);
                    EXCELWORKSHEET.Cells[k, l, i, j].Style.Border.Bottom.Color.SetColor(System.Drawing.Color.Black);
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Generated = "Generated";
                    Logger.WriteDebugLog("MO Wise report saved.");
                }
                else
                    Generated = "Nodatafound";
            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog(ex.Message);
                throw;
            }
            return Generated;
        }
