        #region Hourlychart

        internal static void MangalHourlychart(DateTime fromDate, string machineId, string plantId)
        {
            DataTable dt = new DataTable();
            DataTable dtloss = new DataTable();
            string Source = string.Empty, destination = string.Empty, Template = string.Empty;
            string Filename = "ShiftProductionCountHourlyBoschBNGTemplate2.xlsx";
            Source = Util.GetReportPath(Filename);
            Template = "HourlyChart" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            int shift = 1;
            string shiftname = "", HourID = "";
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("Hourly Chart Report - \n " + Source);
            }
            FileInfo newFile = new FileInfo(Source);
            ExcelPackage Excel = new ExcelPackage(newFile, true);
            var worksheet = Excel.Workbook.Worksheets[1];

            try
            {
                worksheet.Cells["AK11"].Value = machineId;
                worksheet.Cells["AP11"].Value = fromDate.ToShortDateString();
                dt = DataBaseAccess.ShiftProductionCountHourlyBNG(fromDate, plantId, machineId);
                int row = 16, col = 2;
                foreach (DataRow item in dt.Rows)
                {
                    col = 2;
                    int.TryParse(item["ShiftID"].ToString(), out shift);
                    switch (shift)
                    {
                        case 1:
                            worksheet.Cells[row, col].Value = item["Target"];
                            col = col + 2;
                            worksheet.Cells[row, col].Value = item["Actual"];
                            row++;
                            break;
                        case 2:
                            row++;
                            worksheet.Cells[row, col].Value = item["Target"];
                            col = col + 2;
                            worksheet.Cells[row, col].Value = item["Actual"];
                            break;
                        case 3:
                            if (shiftname != item["ShiftName"].ToString())
                                row = row + 2;
                            else
                                row++;
                            worksheet.Cells[row, col].Value = item["Target"];
                            col = col + 2;
                            worksheet.Cells[row, col].Value = item["Actual"];
                            break;
                    }
                    shiftname = item["ShiftName"].ToString();
                }
                dtloss = DataBaseAccess.ShiftProductionCountHourlyBNGAeeLoss(fromDate, plantId, machineId);
                if (dtloss != null && dtloss.Rows.Count > 0)
                {
                    row = 15; col = 36;
                    for (int i = 0; i <= 8; i++)
                    {
                        worksheet.Cells[row, col].Value = dtloss.Rows[i]["DownCategory"].ToString();
                        col++;
                    }
                    row = 15; col = 36;
                    foreach (DataRow item in dtloss.Rows)
                    {

                        int.TryParse(item["ShiftID"].ToString(), out shift);
                        switch (shift)
                        {
                            case 1:
                                if (HourID != item["HourID"].ToString())
                                {
                                    row++;
                                    col = 36;
                                    HourID = item["HourID"].ToString();
                                }

                                worksheet.Cells[row, col].Value = item["DownTime"];
                                col++;
                                break;
                            case 2:
                                if (item["HourID"].ToString() == "0")
                                    row = row + 1;
                                else
                                {
                                    if (HourID != item["HourID"].ToString())
                                    {
                                        row++;
                                        col = 36;
                                        HourID = item["HourID"].ToString();
                                    }
                                    worksheet.Cells[row, col].Value = item["DownTime"];
                                    col++;
                                }
                                break;
                            case 3:
                                if (item["HourID"].ToString() == "0")
                                {
                                    row++;
                                }
                                else
                                {
                                    if (HourID != item["HourID"].ToString())
                                    {
                                        row++;
                                        col = 36;
                                        HourID = item["HourID"].ToString();
                                    }
                                    worksheet.Cells[row, col].Value = item["DownTime"];
                                    col++;
                                }
                                break;
                        }
                        shiftname = item["ShiftID"].ToString();
                    }
                    worksheet.Cells[15, 36, 15, col - 1].AutoFitColumns();
                    worksheet.Workbook.FullCalcOnLoad = true;
                    worksheet.Workbook.CalcMode = ExcelCalcMode.Automatic;
                    worksheet.Calculate();
                }

                DownloadMultipleFile(destination, Excel.GetAsByteArray());
                Logger.WriteDebugLog("Mangal Downtime.");
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
                throw;
            }
        }

