        internal static bool ReworkDetailReport(DateTime fromdate, DateTime toDate, string MachineID, DataTable dtReworkDetails)
        {
            try
            {
                bool ok = false;
                string Source = string.Empty, destination = string.Empty, Template = string.Empty;
                string Filename = "ReworkDetails.xlsx";
                Source = Util.GetReportPath(Filename);
                Template = "ReworkDetails_" + DateTime.Now + ".xlsx";
                destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("Rework Details- \n " + Source);
                }
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var worksheet = Excel.Workbook.Worksheets[1];
                int row = 7, col = 1;
                worksheet.Cells["B4"].Value = MachineID;
                worksheet.Cells["D4"].Value = fromdate.ToString("dd-MM-yyyy");
                worksheet.Cells["G4"].Value = toDate.ToString("dd-MM-yyyy");
                foreach (DataRow item in dtReworkDetails.Rows)
                {
                    col = 1;
                    worksheet.Cells[row, col].Value = item["MachineId"];
                    col++;
                    worksheet.Cells[row, col].Value = item["ChildBatchID"];
                    col++;
                    worksheet.Cells[row, col].Value = item["ReworkCount"];
                    col++;
                    worksheet.Cells[row, col].Value = item["OperatorID"];
                    col++;
                    worksheet.Cells[row, col].Value = item["PlanNo"];
                    col++;
                    worksheet.Cells[row, col].Value = item["FGMaterialID"];
                    col++;
                    worksheet.Cells[row, col].Value = item["PVNo"];
                    col++;
                    worksheet.Cells[row, col].Value = item["FGBatchID"];
                    col++;
                    worksheet.Cells[row, col].Value = item["ChildPartID"];
                    row++;
                }
                row--;
                worksheet.Cells[4, 1, row, col + 1].AutoFitColumns();
                worksheet.Cells[7, 1, row, col].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                worksheet.Cells[7, 1, row, col].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                worksheet.Cells[7, 1, row, col].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                worksheet.Cells[7, 1, row, col].Style.Border.Bottom.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                worksheet.Cells[7, 1, row, col].Style.Border.Top.Color.SetColor(System.Drawing.Color.Black);
                worksheet.Cells[7, 1, row, col].Style.Border.Left.Color.SetColor(System.Drawing.Color.Black);
                worksheet.Cells[7, 1, row, col].Style.Border.Right.Color.SetColor(System.Drawing.Color.Black);
                worksheet.Cells[7, 1, row, col].Style.Border.Bottom.Color.SetColor(System.Drawing.Color.Black);
                DownloadMultipleFile(destination, Excel.GetAsByteArray());
                ok = true;
                Logger.WriteDebugLog("Rework Details.");
                return ok;
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
                throw;
            }
        }

        internal static string EnergyReport(DateTime fromDate, DateTime toDate, string PlantID, string MachineID, string Type, string View, string nodeid, string Types)
        {
            try
            {
                string generated = "";
                string proc = Types == "aggregate" ? "S_GetSONA_EnergyCockpitDetails_Report" : "S_GetSONA_EnergyCockpitDetails";
                string Source = string.Empty, destination = string.Empty, Template = string.Empty;
                string Filename = "EngeryReport.xlsx";
                Source = Util.GetReportPath(Filename);
                Template = "EngeryReport_" + DateTime.Now + ".xlsx";
                destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
                DataTable dtEnergyData = new DataTable();
                DataTable dtEnergyHeader = new DataTable();
                string shift = "";
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("Engery Report- \n " + Source);
                }
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var worksheet = Excel.Workbook.Worksheets[1];
                int row = 8, col = 1;
                List<string> colPropertyNames = new List<string>();
                List<string> colHeaderNames = DataBaseAccess.GetEnergyColumnsToBind(out colPropertyNames);
                MachineID = MachineID == "ALL" ? "" : MachineID;
                PlantID = PlantID == "ALL" ? "" : PlantID;
                nodeid = nodeid == "ALL" ? "" : nodeid;
                if (Type.Equals("Time-Consolidated", StringComparison.OrdinalIgnoreCase))
                    Type = "";
                else if (Type.Equals("Daily", StringComparison.OrdinalIgnoreCase))
                    Type = "Day";
                else if (Type.Equals("Shift", StringComparison.OrdinalIgnoreCase))
                    Type = "Shift";
                if (View.Equals("NodeView"))
                {
                    dtEnergyData = DataBaseAccess.GetEnergyData(fromDate, toDate, shift, MachineID, PlantID, nodeid, Type, "node", "", proc);
                }
                else if (View.Equals("MachineView"))
                {
                    dtEnergyData = DataBaseAccess.GetEnergyData(fromDate, toDate, shift, MachineID, PlantID, nodeid, Type, "machine", "", proc);
                }
                row = 7; col = 1; int energycol = 0, k = 1;
                worksheet.Cells["B4"].Value = fromDate.ToString("yyyy-MM-dd");
                worksheet.Cells["D4	"].Value = toDate.ToString("yyyy-MM-dd");
                if (dtEnergyData != null && dtEnergyData.Rows.Count > 0)
                {
                    if (Type.Equals("Shift"))
                    {
                        worksheet.Cells[row, col].Value = "Date";
                        col++; energycol++;
                        worksheet.Cells[row, col].Value = "Shift";
                        col++; energycol++;
                    }
                    if (Type.Equals("Day"))
                    {
                        worksheet.Cells[row, col].Value = "Date";
                        col++; energycol++;
                    }
                    foreach (string item in colHeaderNames)
                    {
                        if (View.Equals("MachineView", StringComparison.OrdinalIgnoreCase))
                        {
                            if (item.Equals("NodeID", StringComparison.OrdinalIgnoreCase))
                            {

                            }
                            else
                            {
                                worksheet.Cells[row, col].Value = item;
                                col++;
                                if (item.Equals("Energy", StringComparison.OrdinalIgnoreCase))
                                    energycol = energycol + k;
                                else
                                    k++;
                            }
                        }
                        if (View.Equals("NodeView", StringComparison.OrdinalIgnoreCase))
                        {
                            worksheet.Cells[row, col].Value = item;
                            col++;
                            if (item.Equals("Energy", StringComparison.OrdinalIgnoreCase))
                                energycol = energycol + k;
                            else
                                k++;
                        }

                    }
                    if (View.Equals("MachineView", StringComparison.OrdinalIgnoreCase))
                    {
                        colPropertyNames.Remove("NodeID");
                    }
                    row = 8;

                    foreach (DataRow item in dtEnergyData.Rows)
                    {
                        col = 1;
                        if (Type.Equals("Shift"))
                        {
                            worksheet.Cells[row, col].Value = item["StartTime"];
                            col++;
                            worksheet.Cells[row, col].Value = item["ShiftName"];
                            col++;
                        }
                        else if (Type.Equals("Day"))
                        {
                            worksheet.Cells[row, col].Value = item["StartTime"];
                            col++;
                        }
                        for (int j = 0; j < colPropertyNames.Count; j++)
                        {
                            worksheet.Cells[row, col].Value = item[colPropertyNames[j]];
                            col++;
                        }
                        row++;
                    }
                    row--;
                    worksheet.Cells[7, 1, 7, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                    worksheet.Cells[7, 1, 7, col].Style.Fill.BackgroundColor.SetColor(Color.DarkKhaki);
                    worksheet.Cells[4, 1, row, col + 1].AutoFitColumns();
                    worksheet.Cells[7, 1, row, col - 1].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[7, 1, row, col - 1].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[7, 1, row, col - 1].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[7, 1, row, col - 1].Style.Border.Bottom.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[7, 1, row, col - 1].Style.Border.Top.Color.SetColor(System.Drawing.Color.Black);
                    worksheet.Cells[7, 1, row, col - 1].Style.Border.Left.Color.SetColor(System.Drawing.Color.Black);
                    worksheet.Cells[7, 1, row, col - 1].Style.Border.Right.Color.SetColor(System.Drawing.Color.Black);
                    worksheet.Cells[7, 1, row, col - 1].Style.Border.Bottom.Color.SetColor(System.Drawing.Color.Black);

                    //ExcelBarChart Barchart = worksheet.Drawings.AddChart("Energy Report ", eChartType.ColumnClustered) as ExcelBarChart;
                    //Barchart.Title.Text = "Energy Graph";
                    //if(Type.Equals("Shift",StringComparison.OrdinalIgnoreCase))
                    //{
                    //	Barchart.Series.Add(ExcelRange.GetAddress(8, energycol, row, energycol), ExcelRange.GetAddress(8, 1, row, 4));
                    //}
                    //if (Type.Equals("Day", StringComparison.OrdinalIgnoreCase))
                    //{
                    //	Barchart.Series.Add(ExcelRange.GetAddress(8, energycol, row, energycol), ExcelRange.GetAddress(8, 1, row, 3));
                    //}
                    //else
                    //{
                    //	Barchart.Series.Add(ExcelRange.GetAddress(8, energycol, row, energycol), ExcelRange.GetAddress(8, 1, row, 2));
                    //}
                    //Barchart.Legend.Position = eLegendPosition.Bottom;
                    //Barchart.DataLabel.ShowCategory = true;
                    //Barchart.SetSize(600, 600);
                    //Barchart.SetPosition(row+10, 0, 2, 0);
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog("Energy Report.");
                    generated = "Generated";
                }
                else
                    generated = "NodataFound";
                return generated;
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
                throw;
            }
        }

        internal static String SONA_MIS_REPORT(DateTime fromDate, DateTime toDate, string MachineID, string PlantID, string Type)
        {

            #region NewCode 
            string Generated = "No Data Found";
            string machineName = string.Empty, partNumber = string.Empty, currentShift = "A";
            int rowStart = 9, colStart = 1, firstRow = 0, count = 0;
            int rowindex = 9;
            string proc = Type == "aggregate" ? "s_GetSONA_Agg_ShiftwiseProdAndDownReport" : "s_GetSONA_ShiftwiseProdAndDownReport";
            string Source = string.Empty, destination = string.Empty, Template = string.Empty;
