            DataTable DownTable = new DataTable();
            DataTable ShiftwiseData = new DataTable();
            Source = Util.GetReportPath(Filename);
            Template = "SONAMISReport_" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            File.Copy(Source, destination, true);
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("SONA MIS Report- \n " + Source);
            }
            MachineID = MachineID == "ALL" ? "" : MachineID;
            PlantID = PlantID == "ALL" ? "" : PlantID;
            ShiftwiseData = TMPTrakDataBase.GetSonaMisReport(fromDate.ToString("yyyy-MM-dd"), toDate.ToString("yyyy-MM-dd"), MachineID, PlantID, proc, out DownTable);
            List<string> allShift = BindCockpitView.GetAllShift();
            //success = TPM_TRAK_AnalyticsWebReports.Reports.MISReport(destination, allShift, PlantID, ShiftwiseData, DownTable, fromDate, toDate);
            //if (success)
            //{
            //    byte[] file = System.IO.File.ReadAllBytes(Source);
            //    DownloadMultipleFile(destination, file);
            //    Generated = "Generated";
            //}
            #endregion

            #region oldcode
            FileInfo newFile = new FileInfo(Source);
            ExcelPackage Excel = new ExcelPackage(newFile, true); bool colorshading = false;
            var worksheet = Excel.Workbook.Worksheets[1];
            if (worksheet != null)
            {

                worksheet.Cells["B5"].Value = fromDate.ToString("yyyy-MM-dd");
