                                    }
                                }
                                firstRow = count;
                            }
                            if (string.IsNullOrEmpty(rows["DieNo"].ToString()) || rows["DieNo"].ToString().Equals("0", StringComparison.OrdinalIgnoreCase))
                            {
                                firstRow = count;
                            }
                            count++;
                            Dieno = rows["DieNo"].ToString();
                            shift = rows["Shift"].ToString();
                        }
                        worksheet.Cells[5, 1, count - 1, 63].AutoFitColumns();
                        worksheet.Cells[5, 1, count, 61].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                        worksheet.Cells[5, 1, count, 61].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                        worksheet.Cells[5, 1, count, 61].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
