                        worksheet.Cells[5, 1, count, 61].Style.Border.Bottom.Color.SetColor(System.Drawing.Color.Black);
                        DownloadMultipleFile(destination, Excel.GetAsByteArray());
                        Generated = "Generated";
                    }

                    catch (Exception ex)
