        internal static string ToolChangeReport(DateTime fromDate, DateTime toDate, string MachineID, string PlantID)
        {
            string generated = "";
            string dst = string.Empty, src = string.Empty;
            SqlConnection sqlConn = null;//new SqlConnection("Data Source=PCT-DEV8\\SQLEXP2012; Initial Catalog=SmartMachine;User ID=sa; password=pctadmin$123");
            try
            {

                string reportName = "ToolChangeReport.xlsx";
                src = Util.GetReportPath(reportName);
                string tempfileName = "toolChangeReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Tool Change Template Not Found at the Path - \n " + src);
                    //  return;
                    //return "mxkdownrpt Template Not Found at the Path - \n " + src;
                }
                if (MachineID.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                {
                    MachineID = "";
                }

                int row = 4, col = 1;
                string str1 = VDGDataBaseAccess.GetLogicalDayStart(fromDate.ToString("yyyy-MM-dd HH:mm:ss"));
                DateTime strfromdate = DateTime.Now;
                DateTime.TryParse(str1, out strfromdate);

                string str2 = VDGDataBaseAccess.GetLogicalDayEnd(toDate.ToString("yyyy-MM-dd HH:mm:ss"));
                DateTime strtodate = DateTime.Now;
                DateTime.TryParse(str2, out strtodate);
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                ExcelWorksheet ws = pck.Workbook.Worksheets[1];
                string PrevToolNo = string.Empty;
                ws.Cells[3, 2].Value = strfromdate.ToString("dd-MMM-yyyy hh:mm:ss tt");
                ws.Cells[3, 5].Value = strtodate.ToString("dd-MMM-yyyy hh:mm:ss tt");
                ws.Cells[3, 7].Value = MachineID;
                row = 6; int rowMerge = 6;

                //sqlConn.Open();

                sqlConn = ConnectionManager.GetConnection();
                //SqlCommand cmd = new SqlCommand(@"[s_getToolLifedetails]", sqlConn);
                SqlCommand cmd = new SqlCommand(@"[dbo].[s_Focas_getToolLifedetails]", sqlConn);
                cmd.CommandType = System.Data.CommandType.StoredProcedure;
                cmd.CommandTimeout = 600;
                cmd.Parameters.AddWithValue("@fromTime", strfromdate.ToString("yyyy-MM-dd HH:mm:ss"));
                cmd.Parameters.AddWithValue("@ToTime", strtodate.ToString("yyyy-MM-dd HH:mm:ss"));
                cmd.Parameters.AddWithValue("@Machineid", MachineID);
                SqlDataReader rdr = cmd.ExecuteReader();
                if (rdr.HasRows)
                {
                    while (rdr.Read())
                    {
                        col = 1;
                        if (!string.IsNullOrEmpty(PrevToolNo) && PrevToolNo != rdr["ToolNo"].ToString())
                        {
                            ws.Cells[rowMerge, 1, row - 1, 1].Merge = true;
                            ws.Cells[rowMerge, 2, row - 1, 2].Merge = true;
                            ws.Cells[rowMerge, 3, row - 1, 3].Merge = true;
                            rowMerge = row;
                        }
                        ws.Cells[row, col].Value = rdr["ToolNo"];
                        col = col + 1;
                        ws.Cells[row, col].Value = rdr["ToolDescription"];
                        col = col + 1;
                        ws.Cells[row, col].Value = rdr["NoOfTimesChanged"];
                        col = col + 1;
                        ws.Cells[row, col].Value = rdr["ChangeTime"];
                        col = col + 1;
                        ws.Cells[row, col].Value = rdr["Type"];
                        col = col + 1;
                        ws.Cells[row, col].Value = rdr["ToolTarget"];
                        col = col + 1;
                        ws.Cells[row, col].Value = rdr["ToolActual"];
                        col = col + 1;
                        ws.Cells[row, col].Value = rdr["PartCount"];
                        col = col + 1;
                        ws.Cells[row, col].Value = rdr["ProgramNo"];
                        col = col + 1;
                        PrevToolNo = rdr["ToolNo"].ToString();
                        row = row + 1;
                    }
                    if (rowMerge < row - 1)
                    {
                        ws.Cells[rowMerge, 1, row - 1, 1].Merge = true;
                        ws.Cells[rowMerge, 2, row - 1, 2].Merge = true;
                        ws.Cells[rowMerge, 3, row - 1, 3].Merge = true;
                    }
                    row--; col--;
                    ws.Cells[3, 1, row, col + 1].AutoFitColumns();
                    ws.Cells[6, 1, row, col].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    ws.Cells[6, 1, row, col].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    ws.Cells[6, 1, row, col].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    ws.Cells[6, 1, row, col].Style.Border.Bottom.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    ws.Cells[6, 1, row, col].Style.Border.Top.Color.SetColor(System.Drawing.Color.Black);
                    ws.Cells[6, 1, row, col].Style.Border.Left.Color.SetColor(System.Drawing.Color.Black);
                    ws.Cells[6, 1, row, col].Style.Border.Right.Color.SetColor(System.Drawing.Color.Black);
                    ws.Cells[6, 1, row, col].Style.Border.Bottom.Color.SetColor(System.Drawing.Color.Black);
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Tool Change Report.");
                    generated = "Generated";
                }
                else
                {
                    generated = "Nodatafound";
                }
                if (rdr != null)
                {
                    rdr.Close();
                }
            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog("Error,.!!\n While Creating Excel File..!!\n " + ex.Message);
                dst = string.Empty;
            }
            finally
            {
                if (sqlConn != null) sqlConn.Close();
            }
            return generated;
        }

        public static string MachineBreakDownTimeMatrix(DateTime StartDate, string PlantId, string MachineId, DateTime EndDate, string DownID, int Exclude, string width, string height, string LimitData, string cellID, string type)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty, strtTime = "", endTime = "";
                string proc = "", reportName = "";
                if (type.Equals("aggregate", StringComparison.OrdinalIgnoreCase))
                {
                    proc = "s_GetSONA_AggBreakDownMatrix";
                    reportName = "MachineBreakDownTimeReport.xlsx";
                    strtTime = StartDate.ToString("dd-MMM-yyyy");
                    endTime = EndDate.ToString("dd-MMM-yyyy");
                }
                else if (type.Equals("standard", StringComparison.OrdinalIgnoreCase))
                {
                    proc = "s_GetSONA_BreakDownMatrix";
                    reportName = "MachineBreakDownTimeReport.xlsx";
                    strtTime = StartDate.ToString("dd-MMM-yyyy hh:mm:ss tt");
                    endTime = EndDate.ToString("dd-MMM-yyyy hh:mm:ss tt");
                }
                src = Util.GetReportPath(reportName);
                string tempfileName = "MachineBreakDownPhenomenonTimeReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));
                if (PlantId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    PlantId = "";
                if (MachineId.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    MachineId = "";
                int screenWidth = Convert.ToInt32(width) - 40;
                int screenHeight = Convert.ToInt32(height) - 200;
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Machine Down Time Report Template Not Found at the Path - \n " + src);
                }
                //string str1 = VDGDataBaseAccess.GetLogicalDayStart(StartDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strfromdate = DateTime.Now;
                //DateTime.TryParse(str1, out strfromdate);

                //string str2 = VDGDataBaseAccess.GetLogicalDayEnd(EndDate.ToString("yyyy-MM-dd HH:mm:ss"));
                //DateTime strtodate = DateTime.Now;
                //DateTime.TryParse(str2, out strtodate);

                FileInfo newFile = new FileInfo(src);
                ExcelPackage excelPackage = new ExcelPackage(newFile, true);
                ExcelWorksheet ws = excelPackage.Workbook.Worksheets[1];
                ExcelWorksheet ws2 = excelPackage.Workbook.Worksheets[2];
                ExcelWorksheet ws3 = excelPackage.Workbook.Worksheets[3];
                ExcelWorksheet ws4 = excelPackage.Workbook.Worksheets[4];
                ExcelWorksheet ws5 = excelPackage.Workbook.Worksheets[5];
                ExcelWorksheet ws6 = excelPackage.Workbook.Worksheets[6];
                ExcelWorksheet ws7 = excelPackage.Workbook.Worksheets[7];

                ws.Cells["C2"].Value = strtTime;
                ws.Cells["E2"].Value = endTime;
                ws.Cells["G2"].Value = PlantId == "" ? "All" : PlantId;
                ws2.Cells["F2"].Value = strtTime; ws2.Cells["J2"].Value = endTime;
                int r = 7, count = 0, c = 2;
                List<string> lstMachineNames = new List<string>();
                List<string> lstMacTotal = new List<string>();
                List<string> lstMacFreqTotal = new List<string>();
                string mxkSectohhmmss = string.Empty;

                string PrevDownFreq = string.Empty;
                string DownIDTotal = string.Empty;
                string downtime = string.Empty;
                string PrevMachine = string.Empty;
                int range = Convert.ToInt32(LimitData) + 6;
                string Prevdown = string.Empty;
                #region Sheet1
                DataTable dt = TMPTrakDataBase.MachineDownTimeMatrix(StartDate, EndDate, MachineId, PlantId, DownID, Exclude, "DTime", cellID, proc, "ByPhenomenon");
                if (dt != null && dt.Rows.Count > 0)
                {
                    #region "Frist Sheet Data Plat"
                    #region "Header Part Machine "
                    foreach (DataRow rdr in dt.Rows)
                    {
                        if (count == 0)
                        {
                            Prevdown = rdr["BreakDownCode"].ToString();
                            PrevDownFreq = rdr["BreakDownCode"].ToString();
                            PrevMachine = rdr["machineDescription"].ToString();
                            lstMachineNames.Add(rdr["MachineID"].ToString());
                            if (ConfigurationManager.AppSettings["sonapages"].Equals("1", StringComparison.OrdinalIgnoreCase))
                            {
                                ws.Cells[5, c].Value = rdr["MachineID"].ToString();
                                ws2.Cells[5, c].Value = rdr["MachineID"].ToString();
                                ws3.Cells[5, c].Value = rdr["MachineID"].ToString();
                            }
                            ws.Cells[6, c].Value = PrevMachine;
                            ws2.Cells[6, c].Value = PrevMachine;
                            ws3.Cells[6, c].Value = PrevMachine;
                            lstMacTotal.Add(rdr["TotalMachine"].ToString());
                            lstMacFreqTotal.Add(rdr["TotalMachineFreq"].ToString());
                        }
                        if (PrevMachine != rdr["machineDescription"].ToString())
                        {
                            c = c + 1;
                            if (ConfigurationManager.AppSettings["sonapages"].Equals("1", StringComparison.OrdinalIgnoreCase))
                            {
                                ws.Cells[5, c].Value = rdr["MachineID"].ToString();
                                ws2.Cells[5, c].Value = rdr["MachineID"].ToString();
                                ws3.Cells[5, c].Value = rdr["MachineID"].ToString();
                            }
                            ws.Cells[6, c].Value = rdr["machineDescription"].ToString();
                            ws2.Cells[6, c].Value = rdr["machineDescription"].ToString();
                            ws3.Cells[6, c].Value = rdr["machineDescription"].ToString();
                            lstMachineNames.Add(rdr["MachineID"].ToString());
                            lstMacTotal.Add(rdr["TotalMachine"].ToString());
                            lstMacFreqTotal.Add(rdr["TotalMachineFreq"].ToString());
                        }
                        else if (PrevMachine == rdr["machineDescription"].ToString() && count != 0)
                        {
                            break;
                        }
                        count++;
                    }
                    #endregion

                    #region "Machine Value Define Frist Sheet"
                    r = 7;
                    c = 2;
                    Prevdown = "";
                    foreach (DataRow rdr in dt.Rows)
                    {
                        if (Prevdown == "" || Prevdown == rdr["BreakDownCode"].ToString())
                        {
                            //ws.Cells[r, 1].Value = rdr["DownCode"].ToString();
                            ws.Cells[r, c].Value = Convert.ToDecimal(rdr["BreakDownTime"].ToString()) / 86400;
                        }
                        else if (Prevdown != rdr["BreakDownCode"].ToString())
                        {
                            r = r + 1;
                            c = 2;
                            ws.Cells[r, c].Value = Convert.ToDecimal(rdr["BreakDownTime"].ToString()) / 86400;
                        }
                        c = c + 1;
                        ws.Cells[r, 1].Value = rdr["BreakDownCode"].ToString();
                        Prevdown = rdr["BreakDownCode"].ToString();
                    }
                    c = 2;
                    ws.Cells[r + 2, 1].Value = "Total";

                    foreach (string value in lstMacTotal)
                    {
                        if (Convert.ToInt32(value) > 0)
                        {
                            ws.Cells[r + 2, c].Value = Convert.ToDecimal(value) / 86400;
                        }
                        c = c + 1;

                    }
                    #endregion
                    #endregion

                    #region "Second Sheet Start"
                    r = 7;
                    c = 2;
                    PrevDownFreq = "";
                    ws2.Cells["C2"].Value = strtTime;
                    ws2.Cells["E2"].Value = endTime;
                    ws2.Cells["G2"].Value = PlantId == "" ? "All" : PlantId;
                    foreach (DataRow rdr in dt.Rows)
                    {
                        if (PrevDownFreq == "" || PrevDownFreq == rdr["BreakDownCode"].ToString())
                        {
                            ws2.Cells[r, c].Value = Convert.ToInt32(rdr["BreakDownFreq"].ToString());
                        }
                        else
                        {
