        internal static void HytechReport(DateTime fromDate, string MachineID, string PlantID)
        {
            MachineID = MachineID == "ALL" ? "" : MachineID;
            PlantID = PlantID == "ALL" ? "" : PlantID;
            DataTable downids = new DataTable();
            DataTable dt = TMPTrakDataBase.GetHytechdata(fromDate, MachineID, PlantID, out downids);
            if (dt != null && dt.Rows.Count > 0 && downids != null && downids.Rows.Count > 0)
            {
                try
                {
                    string Source = string.Empty, destination = string.Empty, Template = string.Empty, time = string.Empty;
                    string Filename = "Hytech.xlsx";
                    Source = Util.GetReportPath(Filename);
                    Template = "Hytech_" + DateTime.Now + ".xlsx";
                    destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
                    if (!File.Exists(Source))
                    {
                        Logger.WriteDebugLog("Hy tech Report- \n " + Source);
                    }
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var worksheet = Excel.Workbook.Worksheets[1];
                    int row = 8, col = 7;
                    string Machineid = dt.Rows[0]["MachineID"].ToString();
