        #region "PMT Report"
        internal static string GeneratePMTReport(DateTime fromDate)
        {
            string Generated = "";
            string Month = fromDate.ToString("MMMM").ToUpper();
            string MonthYear = Month + " " + fromDate.Year;
            DataTable dtProdAndDown = new DataTable();
            DataTable dtDownInformation = new DataTable();
            DataTable dtProdAndDownPerGroup = new DataTable();
            DataTable dtGroupWiseEfficiency = new DataTable();
            DataTable dtOperatorWiseEfficiency = new DataTable();
            DataTable dtMonthWiseEfficiency = new DataTable();
            List<string> groupIdList = new List<string>() { "CNC", "VMC", "HMC" };
            dtProdAndDown = TMPTrakDataBase.GetPMTProdAndDownReportData(fromDate, out dtDownInformation);
            dtGroupWiseEfficiency = TMPTrakDataBase.GetOperatorEfficiencyInfo(fromDate, "OEEGroup");
            if (dtProdAndDown != null && dtProdAndDown.Rows.Count > 0 && dtDownInformation.Rows.Count > 0)
            {
                try
                {
                    int colStart = 0, rowStart = 0;
                    string source = string.Empty, destination = string.Empty, template = string.Empty, time = string.Empty;
                    string Filename = "PMT_ProductionEfficiencyReport.xlsx";
                    source = Util.GetReportPath(Filename);
                    template = "PMT_ProductionEfficiencyReport_" + DateTime.Now + ".xlsx";
                    destination = Path.Combine(appPath, "Temp", SafeFileName(template));
                    if (!File.Exists(source))
                    {
                        Logger.WriteDebugLog(@"Report template does not found at :" + source);
                        return Generated;
                    }
                    FileInfo newFile = new FileInfo(source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    ExcelWorksheet worksheet = null;
                    foreach (string GroupID in groupIdList)
                    {
                        worksheet = Excel.Workbook.Worksheets[GroupID];
                        if (worksheet != null)
                        {
                            colStart = 10; rowStart = GroupID.Equals("CNC") ? 4 : 3;
                            if (dtGroupWiseEfficiency != null && dtGroupWiseEfficiency.Rows.Count > 0)
                            {
                                if (IsGroupIDExists(dtGroupWiseEfficiency, GroupID))
                                {
                                    worksheet.Cells["AD2"].Value = dtGroupWiseEfficiency.AsEnumerable().Where(x => x.Field<string>("Groupid").Equals(GroupID)).First()["OEffy"];
                                    worksheet.Cells["AE2"].Value = dtGroupWiseEfficiency.AsEnumerable().Where(x => x.Field<string>("Groupid").Equals(GroupID)).First()["PEffy"];
                                    worksheet.Cells["AF2"].Value = dtGroupWiseEfficiency.AsEnumerable().Where(x => x.Field<string>("Groupid").Equals(GroupID)).First()["QEffy"];
                                    worksheet.Cells["AG2"].Value = dtGroupWiseEfficiency.AsEnumerable().Where(x => x.Field<string>("Groupid").Equals(GroupID)).First()["AEffy"];
                                }
                            }
                            foreach (DataRow drDownInfo in dtDownInformation.Rows)
                            {
                                worksheet.Cells[rowStart, colStart].Value = drDownInfo["Downid"];
                                colStart++;
                            }

                            if (IsGroupIDExists(dtProdAndDown, GroupID))
                            {
                                dtProdAndDownPerGroup = dtProdAndDown.AsEnumerable().Where(x => x.Field<string>("groupid").Equals(GroupID)).CopyToDataTable();
                                if (dtProdAndDownPerGroup != null && dtProdAndDownPerGroup.Rows.Count > 0)
                                {
                                    colStart = 1; rowStart = GroupID.Equals("CNC") ? 5 : 4;
                                    foreach (DataRow drProdDownInfo in dtProdAndDownPerGroup.Rows)
                                    {
                                        worksheet.Cells[rowStart, 1].Value = Convert.ToDateTime(drProdDownInfo["Pdate"]).Date;
                                        worksheet.Cells[rowStart, 2].Value = drProdDownInfo["MachineID"];
                                        worksheet.Cells[rowStart, 3].Value = drProdDownInfo["Shift"];
                                        worksheet.Cells[rowStart, 4].Value = drProdDownInfo["OperatorID"];
                                        worksheet.Cells[rowStart, 5].Value = drProdDownInfo["ComponentID"];
                                        worksheet.Cells[rowStart, 6].Value = drProdDownInfo["OperationNo"];
                                        worksheet.Cells[rowStart, 7].Value = drProdDownInfo["Cycletime"];
                                        worksheet.Cells[rowStart, 8].Value = drProdDownInfo["LUtime"];
                                        worksheet.Cells[rowStart, 9].Value = drProdDownInfo["NoOfPcs"];
                                        worksheet.Cells[rowStart, 10].Value = Convert.ToDouble(drProdDownInfo["D1"]);
                                        worksheet.Cells[rowStart, 11].Value = Convert.ToDouble(drProdDownInfo["D2"]);
                                        worksheet.Cells[rowStart, 12].Value = Convert.ToDouble(drProdDownInfo["D3"]);
                                        worksheet.Cells[rowStart, 13].Value = Convert.ToDouble(drProdDownInfo["D4"]);
                                        worksheet.Cells[rowStart, 14].Value = Convert.ToDouble(drProdDownInfo["D5"]);
                                        worksheet.Cells[rowStart, 15].Value = Convert.ToDouble(drProdDownInfo["D6"]);
                                        worksheet.Cells[rowStart, 16].Value = Convert.ToDouble(drProdDownInfo["D7"]);
                                        worksheet.Cells[rowStart, 17].Value = Convert.ToDouble(drProdDownInfo["D8"]);
                                        worksheet.Cells[rowStart, 18].Value = Convert.ToDouble(drProdDownInfo["D9"]);
                                        worksheet.Cells[rowStart, 19].Value = Convert.ToDouble(drProdDownInfo["D10"]);
                                        worksheet.Cells[rowStart, 20].Value = Convert.ToDouble(drProdDownInfo["D11"]);
                                        worksheet.Cells[rowStart, 21].Value = Convert.ToDouble(drProdDownInfo["D12"]);
                                        worksheet.Cells[rowStart, 22].Value = Convert.ToDouble(drProdDownInfo["D13"]);
                                        worksheet.Cells[rowStart, 23].Value = Convert.ToDouble(drProdDownInfo["D14"]);
                                        worksheet.Cells[rowStart, 24].Value = Convert.ToDouble(drProdDownInfo["D15"]);
                                        worksheet.Cells[rowStart, 28].Value = drProdDownInfo["ActualParts"];
                                        worksheet.Cells[rowStart, 29].Value = drProdDownInfo["OKParts"];
                                        worksheet.Cells[rowStart, 35].Value = Convert.ToDouble(drProdDownInfo["WorkingHours"]);
                                        rowStart++;
                                    }
                                }
                            }
                        }
                    }
                    worksheet = Excel.Workbook.Worksheets["OPT"];
                    if (worksheet != null)
                    {
                        worksheet.Cells["A1"].Value = "BEST PERFORMANCE MONTH OF " + Month;
                        worksheet.Cells["A3"].Value = Month;
                        dtOperatorWiseEfficiency = TMPTrakDataBase.GetOperatorEfficiencyInfo(fromDate, "");
                        if (dtOperatorWiseEfficiency != null && dtOperatorWiseEfficiency.Rows.Count > 0)
                        {
                            rowStart = 3;
                            foreach (DataRow drOperatorWiseEfficiency in dtOperatorWiseEfficiency.Rows)
                            {
                                worksheet.Cells[rowStart, 2].Value = drOperatorWiseEfficiency["Groupid"];
                                worksheet.Cells[rowStart, 3].Value = drOperatorWiseEfficiency["OperatorID"];
                                worksheet.Cells[rowStart, 4].Value = drOperatorWiseEfficiency["AEffy"];
                                worksheet.Cells[rowStart, 5].Value = drOperatorWiseEfficiency["QEffy"];
                                worksheet.Cells[rowStart, 6].Value = drOperatorWiseEfficiency["PEffy"];
                                worksheet.Cells[rowStart, 7].Value = drOperatorWiseEfficiency["OEffy"];
                                rowStart++;
                            }
                        }
                    }
                    worksheet = Excel.Workbook.Worksheets["GRAPH"];
                    if (worksheet != null)
                    {
                        worksheet.Cells["B1"].Value = "OVER ALL LOSSED " + MonthYear;
                        ExcelDrawings drawingList = worksheet.Drawings;
                        if (drawingList != null)
                        {
                            ExcelBarChart overAllLossChart = drawingList["Chart 3"] as ExcelBarChart;
                            overAllLossChart.Title.Text = "OVER ALL LOSSED HRS " + MonthYear;
                            ExcelBarChart oeePercentLossChart = drawingList["Chart 5"] as ExcelBarChart;
                            oeePercentLossChart.Title.Text = "OEE% MONTH OF " + MonthYear;
                            ExcelBarChart opEffPercentChart = drawingList["Chart 6"] as ExcelBarChart;
                            opEffPercentChart.Title.Text = "OEE EFF% MONTH OF " + MonthYear;
                        }
                    }
                    worksheet = Excel.Workbook.Worksheets["YTD"];
                    if (worksheet != null)
                    {
                        worksheet.Cells["A1"].Value = "YEAR " + fromDate.Year;
                        dtMonthWiseEfficiency = TMPTrakDataBase.GetMonthWiseEfficiencyData(fromDate);
                        if (dtMonthWiseEfficiency != null && dtMonthWiseEfficiency.Rows.Count > 0)
                        {
                            rowStart = 2;
                            foreach (DataRow drMonthWiseEfficiency in dtMonthWiseEfficiency.Rows)
                            {
                                worksheet.Cells[rowStart, 2].Value = drMonthWiseEfficiency["OEffy"];
                                worksheet.Cells[rowStart, 3].Value = drMonthWiseEfficiency["QEffy"];
                                worksheet.Cells[rowStart, 4].Value = drMonthWiseEfficiency["AEffy"];
                                worksheet.Cells[rowStart, 5].Value = drMonthWiseEfficiency["PEffy"];
                                worksheet.Cells[rowStart, 6].Value = drMonthWiseEfficiency["DownTime"];
                                rowStart++;
                            }
                        }
                    }
                    worksheet.Workbook.FullCalcOnLoad = true;
                    worksheet.Workbook.CalcMode = ExcelCalcMode.Automatic;
                    worksheet.Calculate();
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Generated = "Generated";
                }
                catch (Exception ex)
                {
                    Logger.WriteErrorLog(ex.Message);
                }
            }
            else
                Generated = "NodataFound";
            return Generated;
        }

        private static bool IsGroupIDExists(DataTable dataTable, string groupID)
        {
            return dataTable.AsEnumerable().Where(x => x.Field<string>("Groupid").Equals(groupID, StringComparison.OrdinalIgnoreCase)).Count() > 0;
        }
