        internal static string BreakDownSona(DateTime fromDate, DateTime toDate, string PlantID, string MachineID, string SubSystem, string TimeFormat, string TypeFormat)
        {
            string Generated = "";
            PlantID = PlantID == "ALL" ? "" : PlantID;
            MachineID = MachineID == "ALL" ? "" : MachineID;
            SubSystem = SubSystem == "ALL" ? "" : SubSystem;
            string Source = string.Empty, destination = string.Empty, Template = string.Empty, time = string.Empty;
            DataTable dt = new DataTable();
            string Filename = "Breakdown_Report_Sona.xlsx";
            Source = Util.GetReportPath(Filename);
            Template = "Breakdown Report SONA" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("Breakdown Report SONA- \n " + Source);
            }
            try
            {
                TMPTrakDataBase.GetBreakdownSona(fromDate, toDate, PlantID, MachineID, SubSystem, TimeFormat, TypeFormat, out dt);
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var worksheet = Excel.Workbook.Worksheets[1];

                worksheet.Cells["B4"].Value = TypeFormat == "Month" ? fromDate.ToString("MMM-yyyy") : fromDate.ToString("yyyy-MM-dd");
                worksheet.Cells["D4"].Value = TypeFormat == "Month" ? toDate.ToString("MMM-yyyy") : toDate.ToString("yyyy-MM-dd");
                worksheet.Cells["F4"].Value = PlantID == "" ? "All" : PlantID;
                worksheet.Cells["J4"].Value = "* Downtime format: " + TimeFormat.ToString();
                int row = 7, col = 1; int i = 1;
                DateTime dates = DateTime.Now;
                if (dt != null && dt.Rows.Count > 0)
                {
                    foreach (DataRow rows in dt.Rows)
                    {
                        col = 1;
                        worksheet.Cells[row, col].Value = i;
                        col++;
                        worksheet.Cells[row, col].Value = rows["PlantID"];
                        col++;
                        worksheet.Cells[row, col].Value = rows["GroupId"];
                        col++;
                        worksheet.Cells[row, col].Value = rows["MachineID"];
                        col++;
                        worksheet.Cells[row, col].Value = rows["MachineDescription"];
                        col++;
                        if (TypeFormat.Equals("Month", StringComparison.OrdinalIgnoreCase))
                        {
                            DateTime.TryParse(rows["dDate"].ToString(), out dates);
                            worksheet.Cells[row, col].Value = dates.ToString("MMM-yyyy");
                        }

                        else
                            worksheet.Cells[row, col].Value = rows["dDate"];
                        col++;
                        if (TypeFormat.Equals("Shift", StringComparison.OrdinalIgnoreCase))
                            worksheet.Cells[row, col].Value = rows["Shift"];

                        col++;
                        worksheet.Cells[row, col].Value = rows["BreakDownCategory"];
                        col++;
                        worksheet.Cells[row, col].Value = rows["BreakDownCode"];
                        col++;
                        if (TimeFormat.Equals("hh:mm:ss", StringComparison.OrdinalIgnoreCase))
                            worksheet.Cells[row, col].Value = rows["DownTime"];
                        else
                        {
                            worksheet.Cells[row, col].Value = getdoubledata(rows["DownTime"].ToString());
                        }
                        row++; i++;
                    }

                    row--;
                    worksheet.Cells[3, 1, row, col + 1].AutoFitColumns();
                    if (TypeFormat.Equals("Daily", StringComparison.OrdinalIgnoreCase) || TypeFormat.Equals("Month", StringComparison.OrdinalIgnoreCase))
                    {
                        worksheet.Column(7).Hidden = true;
                    }

                    worksheet.Cells[6, 1, row, col].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, row, col].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, row, col].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, row, col].Style.Border.Bottom.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, row, col].Style.Border.Top.Color.SetColor(System.Drawing.Color.Black);
                    worksheet.Cells[6, 1, row, col].Style.Border.Left.Color.SetColor(System.Drawing.Color.Black);
                    worksheet.Cells[6, 1, row, col].Style.Border.Right.Color.SetColor(System.Drawing.Color.Black);
                    worksheet.Cells[6, 1, row, col].Style.Border.Bottom.Color.SetColor(System.Drawing.Color.Black);
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog("SONA Break Down Phenomenon Report.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
                throw;
            }
            return Generated;
        }

