                        var ws = Excel.Workbook.Worksheets.Add(machine, copyworksheet);
                        DataTable Dtnew = dt.AsEnumerable().Where(x => x.Field<string>("machineid").Equals(machine)).CopyToDataTable();
                        BindFlowMeterHeader(PlantID, machine, shift, fromDate.ToString("dd-MM-yyyy"), toDate.ToString("dd-MM-yyyy"), ref ws);
                        int row = 6, col = 1;
                        foreach (DataRow Row in Dtnew.Rows)
                        {
                            col = 1;
                            ws.Cells[row, col].Value = Row["StartTime"];
                            ws.Cells[row, col++].Style.Numberformat.Format = "yyyy-MM-dd HH:mm:ss";
                            ws.Cells[row, col].Value = Row["Endtime"];
                            ws.Cells[row, col++].Style.Numberformat.Format = "yyyy-MM-dd HH:mm:ss";
                            if (PlantID.Equals("All", StringComparison.OrdinalIgnoreCase) || string.IsNullOrEmpty(PlantID))
                            {
                                ws.Cells[row, col++].Value = Row["PlantID"];
                            }
                            ws.Cells[row, col++].Value = Row["Shift"];
                            ws.Cells[row, col++].Value = Row["componentid"];
                            ws.Cells[row, col++].Value = Row["operationno"];
                            double maxvalue = getdouble(Row["MaxFlowValue"].ToString());
                            double minvalue = getdouble(Row["MinFlowValue"].ToString());
                            double value = getdouble(Row["Flowvalue1"].ToString());
                            ws.Cells[row, col].Value = value;
                            var FlowVal1clr = System.Drawing.Color.FromName(Row["FlowValue1_Color"].ToString());
                            ws.Cells[row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            if (Row["FlowValue1_Color"].ToString().Equals("Yellow", StringComparison.OrdinalIgnoreCase))
                            {
                                ws.Cells[row, col].Style.Font.Color.SetColor(Color.Black);
                            }
                            else
                                ws.Cells[row, col].Style.Font.Color.SetColor(Color.White);
                            ws.Cells[row, col].Style.Font.Bold = true;
                            ws.Cells[row, col++].Style.Fill.BackgroundColor.SetColor(FlowVal1clr);
                            //if (((value >= minvalue) && (value <= maxvalue)))
                            //{
                            //    ws.Cells[row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            //    ws.Cells[row, col].Style.Font.Color.SetColor(Color.White);
                            //    ws.Cells[row, col].Style.Font.Bold = true;
                            //    ws.Cells[row, col++].Style.Fill.BackgroundColor.SetColor(Color.Green);

                            //}
                            //else
                            //{
                            //    ws.Cells[row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            //    ws.Cells[row, col].Style.Font.Color.SetColor(Color.White);
                            //    ws.Cells[row, col].Style.Font.Bold = true;
                            //    ws.Cells[row, col++].Style.Fill.BackgroundColor.SetColor(Color.Red);
                            //}
                            value = getdouble(Row["Flowvalue2"].ToString());
                            ws.Cells[row, col].Value = Row["Flowvalue2"];
                            var FlowVal2clr = System.Drawing.Color.FromName(Row["FlowValue2_Color"].ToString());
                            ws.Cells[row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            if (Row["FlowValue2_Color"].ToString().Equals("Yellow", StringComparison.OrdinalIgnoreCase))
                            {
                                ws.Cells[row, col].Style.Font.Color.SetColor(Color.Black);
                            }
                            else
                                ws.Cells[row, col].Style.Font.Color.SetColor(Color.White);
                            ws.Cells[row, col].Style.Font.Bold = true;
                            ws.Cells[row++, col++].Style.Fill.BackgroundColor.SetColor(FlowVal2clr);
                            //if (((value >= minvalue) && (value <= maxvalue)))
                            //{
                            //    ws.Cells[row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            //    ws.Cells[row, col].Style.Font.Color.SetColor(Color.White);
                            //    ws.Cells[row, col].Style.Font.Bold = true;
                            //    ws.Cells[row++, col++].Style.Fill.BackgroundColor.SetColor(Color.Green);
                            //}
                            //else
                            //{
                            //    ws.Cells[row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            //    ws.Cells[row, col].Style.Font.Color.SetColor(Color.White);
                            //    ws.Cells[row, col].Style.Font.Bold = true;
                            //    ws.Cells[row++, col++].Style.Fill.BackgroundColor.SetColor(Color.Red);
                            //}
                        }
                        col--;
                        ws.Cells[6, 1, row, col].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                        ws.Cells[6, 1, row, col].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                        ws.Cells[6, 1, row, col].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                        ws.Cells[6, 1, row, col].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                        ws.Cells[6, 1, row, col].Style.Border.Top.Color.SetColor(Color.Black);
                        ws.Cells[6, 1, row, col].Style.Border.Bottom.Color.SetColor(Color.Black);
                        ws.Cells[6, 1, row, col].Style.Border.Left.Color.SetColor(Color.Black);
                        ws.Cells[6, 1, row, col].Style.Border.Right.Color.SetColor(Color.Black);
                        ws.Cells[3, 1, row, col].AutoFitColumns();
                    }
                    Excel.Workbook.Worksheets.Delete(1);
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog("FlowMeter Report successfully generated.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                    Logger.WriteDebugLog("FlowMeter Report not generated: no data");
                }

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("Error in FlowMeterReport:" + ex.ToString());
            }
            return Generated;
        }

        private static void BindFlowMeterHeader(string plantID, string machine, string Shift, string FromDate, string ToDate, ref ExcelWorksheet ws)
        {
            try
            {
                ws.Cells["A3"].Value = "From Date:";
                ws.Cells["C3"].Value = "To Date:";
                ws.Cells["E3"].Value = "PlantID:";
                ws.Cells["G3"].Value = "Shift:";
                ws.Cells["B3"].Value = FromDate;
                ws.Cells["D3"].Value = ToDate;
                ws.Cells["F3"].Value = string.IsNullOrEmpty(plantID) ? "All" : plantID;
                ws.Cells["H3"].Value = string.IsNullOrEmpty(Shift) ? "All" : Shift;
                int col = 1;
                ws.Cells[5, col++].Value = "Start Time";
                ws.Cells[5, col++].Value = "End Time";
                if (plantID.Equals("All", StringComparison.OrdinalIgnoreCase) || string.IsNullOrEmpty(plantID))
                {
                    ws.Cells[5, col++].Value = "Plant ID";
                }
                ws.Cells[5, col++].Value = "Shift";
                ws.Cells[5, col++].Value = "Component ID";
                ws.Cells[5, col++].Value = "Operation No.";
                ws.Cells[5, col++].Value = "Flow Meter1";
                ws.Cells[5, col].Value = "Flow Meter2";
                ws.Cells[5, 1, 5, col].Style.Font.Bold = true;
                ws.Cells[5, 1, 5, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                ws.Cells[5, 1, 5, col].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#F4B084"));
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
        }

        #region --- Daily Rejection Report-----

        internal static string DailyRejectionReport(DateTime fromDate, DateTime toDate, string PlantID, string MachineID, string ComponentID, string cellID)
        {
            string Generated = "";
            string Source = string.Empty, destination = string.Empty, Template = string.Empty, time = string.Empty;

            DataTable dt = new DataTable();
            string Filename = "DailyRejectionReport.xlsx";
            Source = Util.GetReportPath(Filename);
            Template = "DailyRejectionReport_" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("Daily Rejection Report- \n " + Source);
            }
            try
            {
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var ws = Excel.Workbook.Worksheets[1];
                dt = TMPTrakDataBase.GetDailyRejectionReportData(fromDate, toDate, PlantID, MachineID, ComponentID, cellID);

                if (dt != null && dt.Rows.Count > 0)
                {
                    int ROW = 5, COLUMN = 1;
                    ws.Cells["B3"].Value = fromDate;
                    ws.Cells["E3"].Value = toDate;
                    ws.Cells["G3"].Value = PlantID.Equals("") ? "All" : PlantID;
                    //ws.Cells["I3"].Value = MachineID.Equals("") ? "All" : MachineID;
                    switch (ConfigurationManager.AppSettings["PrecesionPage"].ToString())
                    {
                        case "0":
                            ROW = 6;
                            Logger.WriteDebugLog("Daily Rejection Report generation has started...............");
                            for (int i = 0; i < dt.Rows.Count; i++)
                            {
                                COLUMN = 1;
                                for (int j = 0; j < dt.Columns.Count; j++)
                                {
                                    if (dt.Columns[j].ColumnName == "RejectionType")
                                    {
                                        dt.Columns.Remove("RejectionType");
                                    }
                                    if (dt.Columns[j].ColumnName == "Operationno" || dt.Columns[j].ColumnName == "Rejection Qty" || dt.Columns[j].ColumnName == "Rejection during PDT")
                                    {
                                        if (dt.Rows[i][j].ToString() == "")
                                        {
                                            ws.Cells[ROW, COLUMN].Value = dt.Rows[i][j].ToString();
                                        }
                                        else
                                        {
                                            ws.Cells[ROW, COLUMN].Value = Convert.ToInt32(dt.Rows[i][j].ToString());
                                        }
                                    }
                                    else if (dt.Columns[j].ColumnName == "Rejection_BookedTime" || dt.Columns[j].ColumnName == "Date")
                                    {
                                        ws.Cells[ROW, COLUMN].Value = Util.GetDateTime(dt.Rows[i][j].ToString()).ToString("yyyy-MM-dd HH:mm:ss");
                                    }
                                    else
                                    {
                                        ws.Cells[ROW, COLUMN].Value = dt.Rows[i][j].ToString();
                                    }

                                    COLUMN++;
                                }
                                ROW++;
                            }
                            ws.Cells[3, 1, ROW, COLUMN].AutoFitColumns();
                            break;
                        case "1":

                            List<string> RejType = dt.AsEnumerable().Select(x => x.Field<string>("RejectionType")).Distinct().ToList();
                            ws.DeleteRow(5);
                            foreach (string rej in RejType)
                            {
                                switch (rej)
                                {
                                    case "MachiningRejection":
                                        ws.Cells[ROW, 1].Value = "Rejection After Machining";
                                        break;
                                    case "FinalInspectionRejection":
                                        ws.Cells[ROW, 1].Value = "Final Rejection";
                                        break;
                                    case "MaterialRejection":
                                        ws.Cells[ROW, 1].Value = "Rejection Before Machining";
                                        break;
                                }

                                ws.Cells[ROW, 1, ROW, 10].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                ws.Cells[ROW, 1].Style.Font.Bold = true;
                                ws.Cells[ROW, 1].Style.Font.Size = 16;
                                ws.Cells[ROW, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                ws.Cells[ROW, 1].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                                ws.Cells[ROW, 1, ROW, 10].Merge = true;
                                ws.Cells[ROW, 1, ROW++, 10].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#FCD5B4"));
                                ws = BindRejctionHeader(ws, ROW++);

                                DataTable dtRejtypedata = dt.AsEnumerable().Where(x => x.Field<string>("RejectionType").Equals(rej)).CopyToDataTable();
                                if (dtRejtypedata != null && dtRejtypedata.Rows.Count > 0)
                                {
                                    foreach (DataRow row in dtRejtypedata.Rows)
                                    {
                                        ws.Cells[ROW, 1].Value = row["Date"];
                                        ws.Cells[ROW, 2].Value = row["Shift"];
                                        ws.Cells[ROW, 3].Value = row["Machineid"];
                                        ws.Cells[ROW, 4].Value = row["Componentid"];
                                        ws.Cells[ROW, 5].Value = row["Operationno"];
                                        ws.Cells[ROW, 6].Value = row["Employeeid"];
                                        ws.Cells[ROW, 7].Value = row["Rejection Catagory"];
                                        ws.Cells[ROW, 8].Value = row["Rejection Code"];
                                        ws.Cells[ROW, 9].Value = row["Rejection Qty"];
                                        ws.Cells[ROW, 10].Value = row["Rejection during PDT"];
                                        ws.Cells[ROW++, 11].Value = Util.GetDateTime(row["Rejection_BookedTime"].ToString()).ToString("yyyy-MM-dd HH:mm:ss");
                                    }
                                    ROW = ROW + 2;
                                }
                            }
                            ws.Cells[6, 1, ROW, 10].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                            ws.Cells[6, 1, ROW, 10].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                            ws.Cells[6, 1, ROW, 10].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                            ws.Cells[6, 1, ROW, 10].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                            ws.Cells[6, 1, ROW, 10].Style.Border.Top.Color.SetColor(Color.Black);
                            ws.Cells[6, 1, ROW, 10].Style.Border.Bottom.Color.SetColor(Color.Black);
                            ws.Cells[6, 1, ROW, 10].Style.Border.Right.Color.SetColor(Color.Black);
                            ws.Cells[6, 1, ROW, 10].Style.Border.Left.Color.SetColor(Color.Black);
                            ws.Cells[6, 1, ROW, 10].AutoFitColumns();
                            break;
                    }

                    Generated = "Generated";
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    // ws.Cells[ws.Dimension.Address].AutoFitColumns();
                }
                else
                {
                    Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("Error in FlowMeterReport:" + ex.ToString());
            }
            return Generated;
        }

        private static ExcelWorksheet BindRejctionHeader(ExcelWorksheet ws, int Row)
        {
            try
            {
                ws.Cells[Row, 1].Value = "Date";
                ws.Cells[Row, 2].Value = "Shift";
                ws.Cells[Row, 3].Value = "MachineID";
                ws.Cells[Row, 4].Value = "ComponentID";
                ws.Cells[Row, 5].Value = "OperationNo";
                ws.Cells[Row, 6].Value = "EmployeeID";
                ws.Cells[Row, 7].Value = "Rejection Catagory";
                ws.Cells[Row, 8].Value = "Rejection Code";
                ws.Cells[Row, 9].Value = "Rejection Qty";
                ws.Cells[Row, 10].Value = "Rejection during PDT";
                ws.Cells[Row, 11].Value = "Rejection Booked Time";
                ws.Cells[Row, 1, Row, 11].Style.Fill.PatternType = ExcelFillStyle.Solid;
                ws.Cells[Row, 1, Row, 11].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#FABF8F"));
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
            return ws;
        }
        #endregion

        #region ---- Rejection Analysis Report -----
        internal static string RejectionAnalysis(DateTime fromDate, DateTime toDate, string PlantID, string MachineID, string ComponentID, string OperationID, string Category, string RejectionID, string cellID)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "";
                reportName = "RejectionAnalysisReport.xlsx";
                src = Util.GetReportPath(reportName);
                string tempfileName = "RejectionAnalysisReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Rejection Analisys Report Template Not Found at the Path - \n " + src);
                }
                List<RejectAnalysisEntity> listData = TMPTrakDataBase.GetRejectionAnalysisMachineData(fromDate, toDate, PlantID, MachineID, ComponentID, OperationID, Category, RejectionID, cellID);
                FileInfo newFile = new FileInfo(src);
                ExcelPackage excelPackage = new ExcelPackage(newFile, true);
                ExcelWorksheet wsMachine = excelPackage.Workbook.Worksheets[1];

                wsMachine.Cells["B3"].Value = PlantID == string.Empty ? "ALL" : PlantID;
                wsMachine.Cells["D3"].Value = MachineID == string.Empty ? "ALL" : MachineID;
                wsMachine.Column(4).AutoFit();
                wsMachine.Cells["F3"].Value = ComponentID == string.Empty ? "ALL" : ComponentID;
                //wsMachine.Cells["C4"].Value = "Operation";
                //wsMachine.Cells["C4"].Style.Font.Bold = true;
                wsMachine.Cells["H3"].Value = OperationID == string.Empty ? "ALL" : OperationID;
                wsMachine.Cells["J3"].Value = fromDate.ToString("dd-MMM-yy");
                //  wsMachine.Cells["B5"].Style.Numberformat.Format = "dd-MMM-yyyy";
                wsMachine.Cells["L3"].Value = toDate.ToString("dd-MMM-yy");
                //  wsMachine.Cells["D5"].Style.Numberformat.Format = "dd-MMM-yy";

                if (listData.Count > 0)
                {
                    var listofMachineID = listData.Select(x => x.MachineID).Distinct().ToList();

                    int totalCol = 0;
                    for (int i = 0; i < listofMachineID.Count + 1; i++)
                    {
                        if (i != 0)
                        {
                            wsMachine.Cells[4, i + 1].Value = listofMachineID[i - 1];
                        }
                        if (i == listofMachineID.Count)
                        {
                            wsMachine.Cells[4, i + 3].Value = "Total";
                            totalCol = i + 3;
                        }
                    }
                    wsMachine.Cells[4, 2, 4, listofMachineID.Count + 3].AutoFitColumns();
                    wsMachine.Cells[4, 2, 4, listofMachineID.Count + 3].Style.Fill.PatternType = ExcelFillStyle.Solid;
                    wsMachine.Cells[4, 2, 4, listofMachineID.Count + 3].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(250, 191, 143));
                    int cellRowRejDesc = 5;
                    int TotalRow = 0;
                    var listofDistRejDesc = listData.Select(x => x.RejectionDesc).Distinct().ToList();
                    for (int i = 0; i < listofDistRejDesc.Count; i++)
                    {
                        wsMachine.Cells[cellRowRejDesc, 1].Value = listofDistRejDesc[i];
                        wsMachine.Cells[cellRowRejDesc, 1].Style.Font.Size = 8;
                        wsMachine.Cells[cellRowRejDesc, 1].Style.Font.Bold = true;
                        wsMachine.Cells[cellRowRejDesc, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Left;
                        cellRowRejDesc++;
                        if (i == listofDistRejDesc.Count - 1)
                        {
                            cellRowRejDesc += 1;
                            wsMachine.Cells[cellRowRejDesc, 1].Value = "Total";
                            wsMachine.Cells[cellRowRejDesc, 1].Style.Font.Size = 8;
                            wsMachine.Cells[cellRowRejDesc, 1].Style.Font.Bold = true;
                            TotalRow = cellRowRejDesc;
                        }
                    }
                    foreach (RejectAnalysisEntity data in listData)
                    {
                        string machine = data.MachineID;
                        string rejDesc = data.RejectionDesc;
                        for (int i = 5; i < listofDistRejDesc.Count + 5; i++)
                        {
                            for (int j = 2; j < listofMachineID.Count + 2; j++)
                            {
                                if (wsMachine.Cells[4, j].Value.ToString().Trim() == machine.Trim() && wsMachine.Cells[i, 1].Value.ToString().Trim() == rejDesc.Trim())
                                {
                                    wsMachine.Cells[i, j].Value = data.RejQty;
                                }
                            }
                        }
                    }
                    var listRejDescandQty = listData.Select(m => new { m.RejectionDesc, m.RRejQty }).Distinct().ToList();
                    for (int i = 0; i < listRejDescandQty.Count; i++)
                    {
                        for (int j = 5; j < listofDistRejDesc.Count + 5; j++)
                        {
                            if (listRejDescandQty[i].RejectionDesc.ToString().Trim() == wsMachine.Cells[j, 1].Value.ToString().Trim())
                            {
                                wsMachine.Cells[j, listofMachineID.Count + 3].Value = listRejDescandQty[i].RRejQty;
                            }
                        }

                    }
                    var listMachineandQty = listData.Select(m => new { m.MachineID, m.McRejQty }).Distinct().ToList();
                    for (int i = 0; i < listMachineandQty.Count; i++)
                    {
                        for (int j = 2; j <= listofMachineID.Count + 1; j++)
                        {
                            if (listMachineandQty[i].MachineID.ToString().Trim() == wsMachine.Cells[4, j].Value.ToString().Trim())
                            {
                                wsMachine.Cells[TotalRow, j].Value = listMachineandQty[i].McRejQty;
                            }
                        }

                    }
                    var totalValue = listData.Select(x => x.TotalRej).Distinct().ToList();
                    wsMachine.Cells[TotalRow, totalCol].Value = totalValue;
                    for (int i = 1; i <= totalCol - 2; i++)
                    {
                        wsMachine.Cells[2, i, TotalRow, i].AutoFitColumns();
                    }

                    wsMachine.Cells[1, 1, 1, totalCol].Merge = true;
                    wsMachine.Cells[4, 2, TotalRow, totalCol].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    wsMachine.Cells[4, 2, TotalRow, totalCol].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    wsMachine.Cells[4, 2, TotalRow, totalCol].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    wsMachine.Cells[4, 2, TotalRow, totalCol].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                }
                List<RejectAnalysisEntity> complistData = TMPTrakDataBase.GetRejectionAnalysisComponentData(fromDate, toDate, PlantID, MachineID, ComponentID, OperationID, Category, RejectionID, cellID);
                ExcelWorksheet wsComponent = excelPackage.Workbook.Worksheets[2];



                wsComponent.Cells["B3"].Value = PlantID == string.Empty ? "ALL" : PlantID;
                wsComponent.Cells["D3"].Value = MachineID == string.Empty ? "ALL" : MachineID;
                wsComponent.Cells["F3"].Value = ComponentID == string.Empty ? "ALL" : ComponentID;
                wsComponent.Cells["H3"].Value = OperationID == string.Empty ? "ALL" : OperationID;
                wsComponent.Cells["J3"].Value = fromDate.ToString("dd-MMM-yy");
                wsComponent.Cells["L3"].Value = toDate.ToString("dd-MMM-yy");
                if (complistData.Count > 0)

                {
                    var listofCompandOpID = complistData.Select(k => new { k.ComponentID, k.OperationNo }).Distinct().ToList();
                    int totalColComp = 0;
                    for (int i = 0; i < listofCompandOpID.Count + 1; i++)
                    {
                        if (i != 0)
                        {
                            wsComponent.Cells[4, i + 1].Value = listofCompandOpID[i - 1].ComponentID + "<" + listofCompandOpID[i - 1].OperationNo + ">";
                        }
                        if (i == listofCompandOpID.Count)
                        {
                            wsComponent.Cells[4, i + 3].Value = "Total";
                            totalColComp = i + 3;
                        }
                    }
                    wsComponent.Cells[4, 2, 4, listofCompandOpID.Count + 3].Style.Fill.PatternType = ExcelFillStyle.Solid;
                    wsComponent.Cells[4, 2, 4, listofCompandOpID.Count + 3].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(250, 191, 143));
                    int cellRowRejDescComp = 5;
                    int TotalRowComp = 0;
                    var listofDistRejDescComp = complistData.Select(x => x.RejectionDesc).Distinct().ToList();
                    for (int i = 0; i < listofDistRejDescComp.Count; i++)
                    {
                        wsComponent.Cells[cellRowRejDescComp, 1].Value = listofDistRejDescComp[i];
                        wsComponent.Cells[cellRowRejDescComp, 1].Style.Font.Size = 8;
                        wsComponent.Cells[cellRowRejDescComp, 1].Style.Font.Bold = true;
                        cellRowRejDescComp++;
                        if (i == listofDistRejDescComp.Count - 1)
                        {
                            cellRowRejDescComp += 1;
                            wsComponent.Cells[cellRowRejDescComp, 1].Value = "Total";
                            wsComponent.Cells[cellRowRejDescComp, 1].Style.Font.Size = 8;
                            wsComponent.Cells[cellRowRejDescComp, 1].Style.Font.Bold = true;
                            TotalRowComp = cellRowRejDescComp;
                        }
                    }

                    foreach (RejectAnalysisEntity data in complistData)
                    {
                        string comp = data.ComponentID;
                        string opno = data.OperationNo;
                        string rejDesc = data.RejectionDesc;
                        for (int i = 5; i < listofDistRejDescComp.Count + 5; i++)
                        {
                            for (int j = 2; j < listofCompandOpID.Count + 2; j++)
                            {
                                string compopno = comp + "<" + opno + ">";
                                if (wsComponent.Cells[4, j].Value.ToString().Trim() == compopno && wsComponent.Cells[i, 1].Value.ToString().Trim() == rejDesc.Trim())
                                {
                                    wsComponent.Cells[i, j].Value = data.RejQty;
                                }
                            }
                        }
                    }
                    var listRejDescandQtyComp = complistData.Select(m => new { m.RejectionDesc, m.RRejQty }).Distinct().ToList();
                    for (int i = 0; i < listRejDescandQtyComp.Count; i++)
                    {
                        for (int j = 5; j < listofDistRejDescComp.Count + 5; j++)
                        {
                            if (listRejDescandQtyComp[i].RejectionDesc.ToString().Trim() == wsComponent.Cells[j, 1].Value.ToString().Trim())
                            {
                                wsComponent.Cells[j, listofCompandOpID.Count + 3].Value = listRejDescandQtyComp[i].RRejQty;
                            }
                        }

                    }
                    var listCompOpNoandQty = complistData.Select(m => new { m.ComponentID, m.OperationNo, m.SCoRejQty }).Distinct().ToList();
                    for (int i = 0; i < listCompOpNoandQty.Count; i++)
                    {
                        for (int j = 2; j <= listofCompandOpID.Count + 1; j++)
                        {
                            string compopno = listCompOpNoandQty[i].ComponentID + "<" + listCompOpNoandQty[i].OperationNo + ">";
                            if (compopno == wsComponent.Cells[4, j].Value.ToString().Trim())
                            {
                                wsComponent.Cells[TotalRowComp, j].Value = listCompOpNoandQty[i].SCoRejQty;
                            }
                        }

                    }
                    var totalValueComp = complistData.Select(x => x.TotalRej).Distinct().ToList();
                    wsComponent.Cells[TotalRowComp, totalColComp].Value = totalValueComp;
                    for (int i = 1; i <= totalColComp - 2; i++)
                    {
                        wsComponent.Cells[4, i, TotalRowComp, i].AutoFitColumns();
                    }
                    wsComponent.Cells[1, 1, 1, totalColComp].Merge = true;
                    wsComponent.Cells[4, 2, TotalRowComp, totalColComp].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    wsComponent.Cells[4, 2, TotalRowComp, totalColComp].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    wsComponent.Cells[4, 2, TotalRowComp, totalColComp].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    wsComponent.Cells[4, 2, TotalRowComp, totalColComp].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                }
                if (complistData.Count > 0 && listData.Count > 0)
                {
                    DownloadMultipleFile(dst, excelPackage.GetAsByteArray());
                    Generated = "Generated";
                }
                else
                {
                    Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex); ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }
        #endregion


        internal static string HelpRequestReport(DateTime fromDate, DateTime toDate, string plantId, string machineId, string Shift)
        {
            string Generated = "";
            string Source = string.Empty, destination = string.Empty, Template = string.Empty, time = string.Empty;
            string Filename = "HelpReqDetailsRpt.xlsx";

            Source = Util.GetReportPath(Filename);
            Template = "HelpReqDetailsRpt_" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            plantId = plantId.Equals("All", StringComparison.OrdinalIgnoreCase) ? "" : plantId;
            Shift = Shift.Equals("All", StringComparison.OrdinalIgnoreCase) ? "" : Shift;
            machineId = machineId.Equals("All", StringComparison.OrdinalIgnoreCase) ? "" : machineId;
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("Help Req Details Report- \n " + Source);
            }
            try
            {
                DataTable dtHelpReq = TMPTrakDataBase.GetHelpRequestReportAverageMatrix(fromDate, toDate, Shift, plantId, machineId, "");
                DataTable dtHelpReqTab = TMPTrakDataBase.GetHelpRequestReportData(fromDate, toDate, Shift, plantId, machineId, "");
                if (dtHelpReq != null && dtHelpReq.Rows.Count > 0 && dtHelpReqTab != null && dtHelpReqTab.Rows.Count > 0)
                {
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var wrksht = Excel.Workbook.Worksheets[1];
                    string timeFormat = DataBaseAccess.GetCockitSettings();
                    wrksht.Cells[4, 1].Value = plantId;
                    wrksht.Cells["B2"].Value = fromDate;
                    wrksht.Cells["B3"].Value = toDate;
                    wrksht.Cells["A4"].Value = "Help-Request";
                    wrksht.Cells["A4"].Style.Fill.PatternType = ExcelFillStyle.Solid;
                    wrksht.Cells["A4"].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(0, 0, 255));

                    System.Drawing.Image img = System.Drawing.Image.FromFile(HttpContext.Current.Server.MapPath(Util.getCompanyLogoPath()));
                    ExcelPicture pic = wrksht.Drawings.AddPicture("geaLogo", img);
                    pic.SetPosition(0, 0, 0, 0);
                    pic.SetSize(150, 50);

                    int row = 5, col = 6;
                    foreach (DataRow Dtrow in dtHelpReq.Rows)
                    {
                        row = 5;
                        var color = System.Drawing.ColorTranslator.FromHtml("#F2F2F2");
                        wrksht.Cells[row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        wrksht.Cells[row, col].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(0, 0, 255));
                        wrksht.Cells[row++, col].Value = Dtrow["Help_Description"];
                        //wrksht.Cells[row++, col].Value = Dtrow["AvgAcktime"];
                        //wrksht.Cells[row++, col].Value = Dtrow["AvgFixTime"];
                        //wrksht.Cells[row++, col].Value = Dtrow["MTBF"];
                        //wrksht.Cells[row, col].Value = Dtrow["AvgCMPTime"];
                        setTimeSpanFormat(timeFormat, wrksht, row++, col, Dtrow["AvgAcktime"].ToString());
                        setTimeSpanFormat(timeFormat, wrksht, row++, col, Dtrow["AvgFixTime"].ToString());
                        setTimeSpanFormat(timeFormat, wrksht, row++, col, Dtrow["MTBF"].ToString());
                        setTimeSpanFormat(timeFormat, wrksht, row, col, Dtrow["AvgCMPTime"].ToString());
                        col++;
                    }
                    wrksht.Cells[4, 1, 4, col - 1].Merge = true;
                    setThinBorder(wrksht, 4, 1, 9, col - 1);
                    row = 13;
                    int startRow = row;
                    foreach (DataRow Dtrow in dtHelpReqTab.Rows)
                    {
                        //string Remark = "Raised : " + Dtrow["RaisedRemarks"].ToString() + Environment.NewLine + "Ack :" + Dtrow["AckRemarks"].ToString() + Environment.NewLine + "Reset :" + Dtrow["ResetRemarks"].ToString() + Environment.NewLine + "Close :" + Dtrow["CloseRemarks"].ToString();
                        wrksht.Cells[row, 1].Value = Dtrow["ShiftDate"];
                        wrksht.Cells[row, 2].Value = Dtrow["Machineid"];
                        wrksht.Cells[row, 3].Value = Dtrow["ShiftName"];
                        wrksht.Cells[row, 4].Value = Dtrow["Eventid"];
                        wrksht.Cells[row, 5].Value = Dtrow["RequestedTime"];
                        wrksht.Cells[row, 6].Value = Dtrow["AcknowledgeTime"];
                        wrksht.Cells[row, 7].Value = Dtrow["ResetTime"];
                        wrksht.Cells[row, 8].Value = Dtrow["Completedtime"];
                        wrksht.Cells[row, 9].Value = Dtrow["ACKTime"];
                        wrksht.Cells[row, 10].Value = Dtrow["FIXTime"];
                        wrksht.Cells[row, 11].Value = Dtrow["CMPTime"];
                        // wrksht.Cells[row, 12].Value = Remark;
                        wrksht.Cells[row, 12].Value = Dtrow["RaisedRemarks"];
                        wrksht.Cells[row, 13].Value = Dtrow["AckRemarks"];
                        wrksht.Cells[row, 14].Value = Dtrow["ResetRemarks"];
                        wrksht.Cells[row, 15].Value = Dtrow["CloseRemarks"];
                        wrksht.Row(row).Height = 45;
                        wrksht.Cells[row, 15].Style.WrapText = true;

                        // wrksht.Cells[row, 12].IsRichText = true;
                        if (row % 2 != 0)
                        {
                            var color = System.Drawing.ColorTranslator.FromHtml("#FFCC99");
                            wrksht.Cells[row, 1, row, 15].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            wrksht.Cells[row, 1, row, 15].Style.Fill.BackgroundColor.SetColor(color);
                        }
                        row++;
                    }
                    row--;
                    //wrksht.Column(12).Width = 100;
                    wrksht.Cells[startRow, 1, row, 8].AutoFitColumns();
                    setThinBorder(wrksht, startRow, 1, row, 15);
                    //wrksht.Cells[5, 1, row, 12].AutoFitColumns();
                    if (ConfigurationManager.AppSettings["GEAPages"].ToString() == "1")
                    {
                        wrksht.Cells["A6"].Value = "Mean Time To Acknowledge ( MTTA in hh:mm:ss )";
                        wrksht.Cells["A7"].Value = "Mean Time To Repair ( MTTR in hh:mm:ss )";
                    }
                    else wrksht.Row(8).Hidden = true;
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog("Help Request.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
            }
            return Generated;
        }

