        #region CycleAnalysis-Raksha
        internal static string CycleAnalysis(DateTime selectedDate, string MachineID, string CompID, string OperationID, string selView)
        {
            string Generated = "";
            MachineID = MachineID == "ALL" ? "" : MachineID;
            CompID = CompID == "ALL" ? "" : CompID;
            OperationID = OperationID == "ALL" ? "" : OperationID;

            string Source = string.Empty, destination = string.Empty, Template = string.Empty, time = string.Empty;
            DataTable dt = new DataTable();
            string Filename = "CycleAnalysis.xlsx";
            Source = Util.GetReportPath(Filename);
            Template = "Cycle Analysis PBI" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("Cycle Analysis PBI- \n " + Source);
            }
            try
            {
                TMPTrakDataBase.GetCycAnalysis(selectedDate, MachineID, CompID, OperationID, selView, out dt);
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var worksheet = Excel.Workbook.Worksheets[1];

                Color backcolor = ColorTranslator.FromHtml("#b1d1fc");

                worksheet.Cells["A4"].Value = "Year";
                worksheet.Cells["A4"].Style.Font.Bold = true;
                worksheet.Cells["A4"].Style.Font.Size = 12;
                //worksheet.Cells["A1"].Style.Fill.PatternType = ExcelFillStyle.Solid;
                //worksheet.Cells["A1"].Style.Fill.BackgroundColor.SetColor(backcolor);
                //worksheet.Cells["A1"].Style.Font.Color.SetColor(Color.Black);
                worksheet.Cells["B4"].Value = selectedDate.ToString() == "" ? "" : selectedDate.ToString("yyyy");

                worksheet.Cells["D4"].Value = "MachineID";
                worksheet.Cells["D4"].Style.Font.Bold = true;
                worksheet.Cells["D4"].Style.Font.Size = 12;
                worksheet.Cells["E4"].Value = MachineID == "" ? "All" : MachineID;

                worksheet.Cells["G4"].Value = "ComponentID";
                worksheet.Cells["G4"].Style.Font.Bold = true;
                worksheet.Cells["G4"].Style.Font.Size = 12;
                worksheet.Cells["H4"].Value = CompID == "" ? "All" : CompID;

                worksheet.Cells["J4"].Value = "OperationID";
                worksheet.Cells["J4"].Style.Font.Bold = true;
                worksheet.Cells["J4"].Style.Font.Size = 12;
                worksheet.Cells["K4"].Value = OperationID == "" ? "All" : OperationID;

                worksheet.Cells["M4"].Value = "View";
                worksheet.Cells["M4"].Style.Font.Bold = true;
                worksheet.Cells["M4"].Style.Font.Size = 12;
                worksheet.Cells["N4"].Value = selView;

                worksheet.Cells["P4"].Value = "*Time in Seconds";

                worksheet.Cells[1, 1, 1, 16].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                worksheet.Cells[1, 1, 1, 16].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                worksheet.Cells[1, 1, 1, 16].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                worksheet.Cells[1, 1, 1, 16].Style.Border.Bottom.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                worksheet.Cells[1, 1, 1, 16].Style.Border.Top.Color.SetColor(System.Drawing.Color.Black);
                worksheet.Cells[1, 1, 1, 16].Style.Border.Left.Color.SetColor(System.Drawing.Color.Black);
                worksheet.Cells[1, 1, 1, 16].Style.Border.Right.Color.SetColor(System.Drawing.Color.Black);
                worksheet.Cells[1, 1, 1, 16].Style.Border.Bottom.Color.SetColor(System.Drawing.Color.Black);


                int cellRow = 1;
                int cellCol = 1;
                worksheet.Cells[cellRow, cellCol, cellRow, 16].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                //Color backcolor = Color.FromArgb(224, 76, 76);
                worksheet.Cells[cellRow, cellCol, cellRow, 16].Value = "Standard Cycle Time Report by Month";
                worksheet.Cells[cellRow, cellCol, cellRow, 16].Style.Fill.PatternType = ExcelFillStyle.Solid;
                worksheet.Cells[cellRow, cellCol, cellRow, 16].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#093d81"));
                worksheet.Cells[cellRow, cellCol, cellRow, 16].Merge = true;
                worksheet.Cells[cellRow, cellCol, cellRow, 16].Style.Font.Size = 18;
                worksheet.Cells[cellRow, cellCol, cellRow, 16].Style.Font.Bold = true;
                worksheet.Cells[cellRow, cellCol, cellRow, 16].Style.Font.Color.SetColor(Color.White);
                worksheet.Cells[cellRow, cellCol, cellRow + 1, 16].Merge = true;


                Dictionary<string, Int16> MonthList = new Dictionary<string, Int16>();
                MonthList.Add("January", 5);
                MonthList.Add("February", 6);
                MonthList.Add("March", 7);
                MonthList.Add("April", 8);
                MonthList.Add("May", 9);
                MonthList.Add("June", 10);
                MonthList.Add("July", 11);
                MonthList.Add("August", 12);
                MonthList.Add("September", 13);
                MonthList.Add("October", 14);
                MonthList.Add("November", 15);
                MonthList.Add("December", 16);

                int row = 6, col = 1;
                worksheet.Cells[row, col].Value = "MachineID";
                col++;
                worksheet.Cells[row, col].Value = "ComponentID";
                col++;
                worksheet.Cells[row, col].Value = "OperationID";
                col++;
                for (int k = 0; k < MonthList.Count; k++)
                {
                    col = MonthList[MonthList.Keys.ElementAt(k)];
                    worksheet.Cells[row, col].Value = MonthList.Keys.ElementAt(k);
                    col++;
                }

                for (int k = 1; k <= 16; k++)
                {
                    // Color backcolor = ColorTranslator.FromHtml("#b1d1fc");
                    worksheet.Cells[row, k].Style.Fill.PatternType = ExcelFillStyle.Solid;
                    worksheet.Cells[row, k].Style.Fill.BackgroundColor.SetColor(backcolor);
                    worksheet.Cells[row, k].Style.Font.Color.SetColor(Color.Black);
                    worksheet.Cells[row, k].Style.Font.Bold = true;
                }

                row = 7; col = 1;
                int rowColor = 7, colColor = 16;

                DateTime dates = DateTime.Now;
                if (dt != null && dt.Rows.Count > 0)
                {
                    DataRow[] res = dt.Select("MonthName = '" + dt.Rows[0]["MonthName"] + "'");
                    foreach (DataRow rows in res)
                    {
                        col = 1;

                        var color = System.Drawing.ColorTranslator.FromHtml("#F2F2F2");
                        worksheet.Cells[rowColor, 1, row + 4, colColor].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        worksheet.Cells[rowColor, 1, row + 4, colColor].Style.Fill.BackgroundColor.SetColor(color);
                        //worksheet.Cells[rowColor, 1, row + 4, colColor].Style.Font.Bold = true;
                        rowColor++;
                        //colColor++;

                        worksheet.Cells[row, col].Value = rows["MachineID"];
                        col++;
                        worksheet.Cells[row, col].Value = rows["Comp"];
                        col++;
                        worksheet.Cells[row, col].Value = rows["Opn"];
                        row++;
                        col++;
                        worksheet.Cells[row, col].Value = "MinStdTime";
                        row++;
                        worksheet.Cells[row, col].Value = "StdTimeDiff";
                        row++;
                        worksheet.Cells[row, col].Value = "AvgMachineTime";
                        row++;
                        col++;
                        //row = row + 4;
                        // i++;
                    }

                    for (int k = 0; k < MonthList.Count; k++)
                    {
                        row = 8; col = 1;
                        DataRow[] result = dt.Select("MonthName = '" + MonthList.Keys.ElementAt(k).ToString() + "'");

                        foreach (DataRow dtrow in result)
                        {
                            col = MonthList[MonthList.Keys.ElementAt(k)];
                            if (!string.IsNullOrEmpty(dtrow["MinStdTime"].ToString()))
                                worksheet.Cells[row, col].Value = Math.Round(Convert.ToDouble(dtrow["MinStdTime"].ToString()), 2);
                            row++;
                            if (!string.IsNullOrEmpty(dtrow["StdTimeDiff"].ToString()))
                                worksheet.Cells[row, col].Value = Math.Round(Convert.ToDouble(dtrow["StdTimeDiff"].ToString()), 2);
                            row++;
                            if (!string.IsNullOrEmpty(dtrow["AvgMachineTime"].ToString()))
                                worksheet.Cells[row, col].Value = Math.Round(Convert.ToDouble(dtrow["AvgMachineTime"].ToString()), 2);
                            row = row + 2;

                        }
                    }

                    //worksheet.Cells[3, 1, row, col + 1].AutoFitColumns();
                    worksheet.Cells[1, 1, row, 50].AutoFitColumns();

                    worksheet.Cells[6, 1, row, col].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, row, col].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, row, col].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, row, col].Style.Border.Bottom.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, row, col].Style.Border.Top.Color.SetColor(System.Drawing.Color.Black);
