        internal static string HourlyPartCountReports(string MachineID, DateTime fromDate, string Shift)
        {
            string generate = "";
            Logger.WriteDebugLog("Inside hourly partCount method");
            MachineID = MachineID == "ALL" ? "" : MachineID;
            Shift = Shift == "ALL" ? "" : Shift;
            string Source = string.Empty, destination = string.Empty, Template = string.Empty, time = string.Empty;
            DataTable dtHourlyData = new DataTable();
            DataTable dtDownCode = new DataTable();
            DataTable dtDownData = new DataTable();
            string Filename = "HourlyReportPatelBrass.xlsx";
            Source = Util.GetReportPath(Filename);

            Template = "HourlyReport PatelBrass PBI" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("Cycle Analysis PBI- \n " + Source);
            }
            try
            {
                List<Shiftvalues> Shiftdetails = new List<Shiftvalues>();
                var output = TMPTrakDataBase.GeHourlyPartCount(fromDate, MachineID, Shift, out dtDownCode, out dtDownData);
                if (output != null && output.Rows.Count > 0)
                {
                    DataTable dtCloned = output.Clone();
                    dtCloned.Columns["HourID"].DataType = typeof(Int32);
                    foreach (DataRow row in output.Rows)
                    {
                        dtCloned.ImportRow(row);
                    }
                    dtHourlyData = dtCloned.AsEnumerable().OrderBy(x => x.Field<string>("ShiftName")).ThenBy(x => x.Field<int>("HourID")).CopyToDataTable();
                    //dtHourlyData = output.AsEnumerable().OrderBy(x => x.Field<string>("ShiftName") + x.Field<int>("HourID")).CopyToDataTable();
                }
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var ws = Excel.Workbook.Worksheets[1];
                int col = 0;
                Dictionary<string, int> colvalues = new Dictionary<string, int>();
                string Machineid = string.Empty, ComponentID = string.Empty, Operation = string.Empty, Operator = string.Empty;
                Shift = "";
                if (dtHourlyData != null && dtHourlyData.Rows.Count > 0)
                {
                    int id = 0; ; col = 2;
                    //Logger.WriteDebugLog("inside if");
                    foreach (DataRow dtrow in dtHourlyData.Rows)
                    {
                        //Logger.WriteDebugLog("inside for loop");

                        if (Shift == dtrow["ShiftName"].ToString())
                        {

                            if (Convert.ToInt32(dtrow["HourID"].ToString()) > id)
                            {
                                Shiftvalues shiftname = new Shiftvalues();
                                shiftname.shiftname = dtrow["ShiftName"].ToString();
                                //Logger.WriteDebugLog(dtrow["HourStart"].ToString()+" "+ dtrow["HourEnd"].ToString());
                                shiftname.starttime = Convert.ToDateTime(dtrow["HourStart"].ToString());
                                shiftname.endtime = Convert.ToDateTime(dtrow["HourEnd"].ToString());
                                Shiftdetails.Add(shiftname);
                                id = Convert.ToInt32(dtrow["HourID"].ToString()); col = col + 2;
                                colvalues.Add(dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString(), col);
                            }
                        }
                        else
                        {
                            Shiftvalues shiftname = new Shiftvalues();
                            shiftname.shiftname = dtrow["ShiftName"].ToString();
                            //Logger.WriteDebugLog(dtrow["HourStart"].ToString() + " " + dtrow["HourEnd"].ToString());
                            shiftname.starttime = Convert.ToDateTime(dtrow["HourStart"].ToString());
                            shiftname.endtime = Convert.ToDateTime(dtrow["HourEnd"].ToString());
                            Shiftdetails.Add(shiftname);
                            Shift = dtrow["ShiftName"].ToString();
                            id = 1; col = 6;
                            colvalues.Add(dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString(), col);
                        }


                    }
                    int MaxourID = 0; int machinerow = 6; int lastcolls = 0;
                    List<string> shift = Shiftdetails.Select(x => x.shiftname).Distinct().ToList();
                    int Row = 4;
                    int maxshiftid = MaxourID = Convert.ToInt32(dtHourlyData.AsEnumerable().Max(x => x.Field<int>("HourID")).ToString()); int lastcol = 0;
                    foreach (string abc in shift)
                    {
                        ws = GenerateHeader(ws, Row, fromDate, abc, 6, dtDownCode, dtHourlyData, Shiftdetails, out lastcol);
                        Row = Row + 4;
                        if (lastcolls < lastcol)
                        {
                            lastcolls = lastcol;
                        }
                    }
                    ws.DeleteRow((Row - 1), 10);
                    Shift = dtHourlyData.Rows[0]["ShiftName"].ToString();
                    int row = 5; col = 1; int startrow = 5;
                    foreach (DataRow dtrow in dtHourlyData.Rows)
                    {
                        if (!(Shift.Equals(dtrow["ShiftName"].ToString(), StringComparison.OrdinalIgnoreCase)))
                        {
                            ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                            ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                            ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                            ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                            ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Top.Color.SetColor(Color.Black);
                            ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Right.Color.SetColor(Color.Black);
                            ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Left.Color.SetColor(Color.Black);
                            ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Bottom.Color.SetColor(Color.Black);

                            col = 37 + dtDownCode.Rows.Count + 1;
                            row = row + 4; startrow = row; machinerow = row;

                        }
                        if (!(Machineid.Equals(dtrow["MachineID"].ToString(), StringComparison.OrdinalIgnoreCase) && ComponentID.Equals(dtrow["ComponentID"].ToString(), StringComparison.OrdinalIgnoreCase) && Operation.Equals(dtrow["OperationID"].ToString(), StringComparison.OrdinalIgnoreCase) && Operator.Equals(dtrow["OperatorID"].ToString(), StringComparison.OrdinalIgnoreCase) && Shift.Equals(dtrow["ShiftName"].ToString(), StringComparison.OrdinalIgnoreCase)))
                        {
                            if (!(Machineid.Equals(dtrow["MachineID"].ToString(), StringComparison.OrdinalIgnoreCase)) && !string.IsNullOrEmpty(Machineid))
                            {

                                ws.Cells[machinerow, 36, row, 36].Merge = true;
                                ws.Cells[machinerow, (37 + dtDownCode.Rows.Count + 1), row, (37 + dtDownCode.Rows.Count + 1)].Merge = true;
                                machinerow = row + 1;
                            }
                            row++;
                            ws.InsertRow(row, 1);
                            DataTable changeddatatable = new DataTable();
                            try
                            {
                                changeddatatable = dtDownData.AsEnumerable().Where(x => x.Field<string>("MachineID") == dtrow["MachineID"].ToString())
                                       .Where(x => x.Field<string>("OperationID") == dtrow["OperationID"].ToString())
                                       .Where(x => x.Field<string>("ComponentID") == dtrow["ComponentID"].ToString())
                                       .Where(x => x.Field<string>("OperatorID") == dtrow["OperatorID"].ToString())
                                       .Where(x => x.Field<string>("ShiftName") == dtrow["ShiftName"].ToString())
                                       .CopyToDataTable();
                            }
                            catch (Exception)
                            {
                                Logger.WriteErrorLog(dtrow["MachineID"].ToString() + "\n" + dtrow["OperationID"].ToString() + "\n" + dtrow["ComponentID"].ToString() + "\n" + dtrow["OperatorID"].ToString());
                            }

                            if (changeddatatable != null && changeddatatable.Rows.Count > 0)
                            {
                                ws.Cells[row, 34].Value = changeddatatable.Rows[0]["TotalActual"];
                                ws.Cells[row, 35].Value = changeddatatable.Rows[0]["TotalTarget"];
                                ws.Cells[row, 36].Value = changeddatatable.Rows[0]["ShiftQty"];
                                col = 37;
                                for (int k = 1; k < dtDownCode.Rows.Count; k++)
                                {
                                    if (!string.IsNullOrEmpty(changeddatatable.Rows[0]["D" + (k)].ToString()))
                                    {
                                        ws.Cells[row, col].Value = Math.Round(Convert.ToDouble(changeddatatable.Rows[0]["D" + (k)].ToString()), 2); col++;
                                    }
                                }

                                //ws.Cells[row, 37 + dtDownCode.Rows.Count].Value = changeddatatable.Rows[0]["TotalLoss"];
                                //ws.Cells[row, 37 + dtDownCode.Rows.Count + 1].Value = changeddatatable.Rows[0]["ShiftLoss"];
                                ws.Cells[row, 37 + dtDownCode.Rows.Count].Value = Math.Round(Convert.ToDouble(changeddatatable.Rows[0]["TotalLoss"].ToString()), 2);
                                ws.Cells[row, 37 + dtDownCode.Rows.Count + 1].Value = Math.Round(Convert.ToDouble(changeddatatable.Rows[0]["ShiftLoss"].ToString()), 2);
                                //row++;

                            }
                            ws.Cells[row, 1].Value = Machineid = dtrow["MachineID"].ToString();
                            ws.Cells[row, 4].Value = Operation = dtrow["OperationID"].ToString();
                            ws.Cells[row, 3].Value = ComponentID = dtrow["ComponentID"].ToString();
                            ws.Cells[row, 2].Value = Operator = dtrow["OperatorID"].ToString();
                            ws.Cells[row, 5].Value = dtrow["CycleTime"];
                        }
                        if (colvalues.ContainsKey(dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString()))
                        {
                            ws.Cells[row, colvalues[dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString()]].Value = dtrow["Actual"];
                            ws.Cells[row, colvalues[dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString()] + 1].Value = dtrow["HourlyTarget"];
                            if (Convert.ToDouble(dtrow["PE"]) >= Convert.ToDouble(dtrow["PEGreen"]))
                            {
                                ws.Cells[row, colvalues[dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString()]].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                ws.Cells[row, colvalues[dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString()]].Style.Fill.BackgroundColor.SetColor(Color.Green);
                            }
                            else if (Convert.ToDouble(dtrow["PE"]) <= Convert.ToDouble(dtrow["PERed"]))
                            {
                                ws.Cells[row, colvalues[dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString()]].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                ws.Cells[row, colvalues[dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString()]].Style.Fill.BackgroundColor.SetColor(Color.Red);
                            }
                            else
                            {
                                ws.Cells[row, colvalues[dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString()]].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                ws.Cells[row, colvalues[dtrow["ShiftName"].ToString() + dtrow["HourID"].ToString()]].Style.Fill.BackgroundColor.SetColor(Color.Yellow);
                            }
                        }
                        Shift = dtrow["ShiftName"].ToString();
                    }
                    ws.Cells[2, 1, row, col + 2].AutoFitColumns();
                    ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Top.Color.SetColor(Color.Black);
                    ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Right.Color.SetColor(Color.Black);
                    ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Left.Color.SetColor(Color.Black);
                    ws.Cells[startrow - 2, 1, row, col + 2].Style.Border.Bottom.Color.SetColor(Color.Black);
                    for (int k = 6; k <= ((5 + (MaxourID * 2)) - 1); k++)
                    {
                        ws.Column(k).Width = 5.0;
                    }
                    col = lastcolls;
                    for (int k = lastcolls; k < 34; k++)
                    {
                        ws.DeleteColumn(col);
                    }
                    // ws.DeleteColumn(((5 + (MaxourID * 2)) - 1), till);

                    //Logger.WriteDebugLog((((5 + (MaxourID * 2)) - 1).ToString() + till.ToString()));
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());

                }

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
            return generate;
        }

        private static ExcelWorksheet GenerateHeader(ExcelWorksheet ws, int Row, DateTime fromdate, string shift, int col, DataTable dtDownCode, DataTable dtHourlyData, List<Shiftvalues> shiftdata, out int columncount)
        {
            columncount = 0;
            try
            {
                shiftdata = shiftdata.Where(x => x.shiftname == shift).ToList();
                ws.Cells[Row - 1, 1].Value = fromdate;
                ws.Cells[Row - 1, 3].Value = shift;
                foreach (Shiftvalues values in shiftdata)
                {
                    ws.Cells[Row, col].Value = values.starttime.ToString("HH:mm") + "-" + values.endtime.ToString("HH:mm");
                    ws.Cells[Row + 1, col].Value = "A"; col++;
                    ws.Cells[Row + 1, col].Value = "I"; col++;
                }
                columncount = col;
                ws.Cells[Row + 1, 34].Value = "A";
                ws.Cells[Row + 1, 35].Value = "I";

                //ws.Cells[Row+1,6,Row+1,col]
                col = 37;
                foreach (DataRow dt in dtDownCode.Rows)
                {
                    ws.Cells[Row, col].Value = dt["Downid"];
                    col++;
                }
                ws.Cells[Row, col].Value = "Total Loss";
                ws.Cells[Row, col].Style.Font.Bold = true;
                col++;
                ws.Cells[Row, col].Value = "Shift Loss";
                ws.Cells[Row, col].Style.Font.Bold = true;
                col++;
                ws.Cells[Row + 1, 1, Row + 1, col].Style.TextRotation = 0;
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
            }
            return ws;
        }

        internal static void GetSMSStatus(DateTime fromDate, DateTime toDate, int totalNoMessages, int distinctPhNo, int totalNoofMessagesSent, List<SMSStatusEmtity> list)
        {
            Logger.WriteDebugLog("SMS Status Template");
            string Source = string.Empty, destination = string.Empty, Template = string.Empty, time = string.Empty;
            int row = 9;
            string Filename = "SMSStatusTemplate.xlsx";
            Source = Util.GetReportPath(Filename);

            Template = "SMSStatusTemplate" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("SMS Status - \n " + Source);
            }
            try
            {
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var ws = Excel.Workbook.Worksheets[1];
                ws.Cells["B2"].Value = fromDate.ToString("dd-MM-yyyy HH:mm:ss");
                ws.Cells["D2"].Value = toDate.ToString("dd-MM-yyyy HH:mm:ss");
                ws.Cells["B4"].Value = totalNoMessages;
                ws.Cells["D4"].Value = distinctPhNo;
                ws.Cells["B6"].Value = totalNoofMessagesSent;
                foreach (SMSStatusEmtity data in list)
                {
                    ws.Cells[row, 1].Value = data.SLNO;
                    ws.Cells[row, 2].Value = data.DateTime;
                    ws.Cells[row, 3].Value = data.MobileNumber;
                    ws.Cells[row, 4].Value = data.NoOfMessageSent;
                    ws.Cells[row, 5].Value = data.Message.ToString().Trim(char.MinValue); ;
                    row++;
                }
                ws.Cells[7, 1, row, 4].Style.HorizontalAlignment = OfficeOpenXml.Style.ExcelHorizontalAlignment.Center;
                ws.Cells[7, 1, row, 4].Style.VerticalAlignment = OfficeOpenXml.Style.ExcelVerticalAlignment.Center;

                ws.Protection.IsProtected = false;
                ws.Protection.AllowSelectLockedCells = false;
                DownloadMultipleFile(destination, Excel.GetAsByteArray());
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
        }

