        public static DataTable GetDistinctRecords(DataTable dt, string[] Columns)
        {
            DataTable dtUniqRecords = new DataTable();
            dtUniqRecords = dt.DefaultView.ToTable(true, Columns);
            return dtUniqRecords;
        }

        public static DataTable GetFilteredDataTable(DataTable dt, string columnName)
        {
            string value = string.Empty;
            DataTable dtFiltered = new DataTable();
            try
            {
                if (dt != null && dt.Rows.Count > 0)
                {
                    dtFiltered = dt.Clone();
                    foreach (DataRow dataRow in dt.Rows)
                    {
                        if (value != dataRow[columnName].ToString())
                        {
                            dtFiltered.ImportRow(dataRow);
                        }
                        value = dataRow[columnName].ToString();
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog(ex.Message);
            }
            return dtFiltered;
        }

        internal static string ProductionReportGEA(string PlantID, string CellID, string machineID, DateTime FromDate, DateTime ToDate)
        {
            string Generated = "";
            Logger.WriteDebugLog("GEA Report Prod");
            string time = string.Empty;
            string Filename = "ProductionReportGEA.xlsx";
            string Source = Util.GetReportPath(Filename);
            string Template = "ProductioReportGEA" + DateTime.Now + ".xlsx";
            string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("ProductioReportGEA template does not found at - \n " + Source);
            }
            try
            {
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var WorkSheet = Excel.Workbook.Worksheets[1];
                DataTable ExtraDatatable = new DataTable();
                DataTable dtList = TMPTrakDataBase.GetProductionDateGEA(PlantID, CellID, machineID, FromDate, ToDate, out ExtraDatatable);
                if (dtList != null && ExtraDatatable != null && dtList.Rows.Count > 0 && ExtraDatatable.Rows.Count > 0)
                {
                    WorkSheet.Cells["B7"].Value = Util.GetDateTime(FromDate.ToString());
                    WorkSheet.Cells["F7"].Value = Util.GetDateTime(ToDate.ToString());
                    //WorkSheet.Cells["D6"].Value = string.IsNullOrEmpty(MachineID) ? "All" : MachineID;
                    WorkSheet.Cells["B5"].Value = string.IsNullOrEmpty(PlantID) ? "All" : PlantID;
                    WorkSheet.Cells["F5"].Value = string.IsNullOrEmpty(CellID) ? "All" : CellID;
                    // WorkSheet.Cells["G5"].Value = string.IsNullOrEmpty(machineID) ? "All" : machineID;

                    WorkSheet.Cells["B9"].Value = ExtraDatatable.Rows[0]["TotalQty"];
                    WorkSheet.Cells["G9"].Value = ExtraDatatable.Rows[0]["TotalRejection"];
                    WorkSheet.Cells["I9"].Value = ExtraDatatable.Rows[0]["AvgOEE"];
                    int row = 12, slno = 1;
                    string tempMachine = "";
                    foreach (DataRow dtrow in dtList.Rows)
                    {
                        if (tempMachine != dtrow["Machineid"].ToString())
                        {
                            int count = dtList.AsEnumerable().Where(k => k.Field<string>("Machineid") == dtrow["Machineid"].ToString()).ToList().Count();
                            WorkSheet.Cells[row, 1].Value = dtrow["Machineid"];
                            WorkSheet.Cells[row, 1, row + count - 1, 1].Merge = true;
                        }
                        tempMachine = dtrow["Machineid"].ToString();
                        // WorkSheet.Cells[row, 1].Value = slno++;
                        WorkSheet.Cells[row, 2].Value = dtrow["PoNumber"];
                        WorkSheet.Cells[row, 3].Value = dtrow["PartNumber"];
                        WorkSheet.Cells[row, 4].Value = dtrow["FabricationNo"];
                        WorkSheet.Cells[row, 5].Value = dtrow["ListOfCompletedOpr"];
                        WorkSheet.Cells[row, 6].Value = dtrow["Qty"];
                        WorkSheet.Cells[row, 7].Value = dtrow["Rejection"];
                        WorkSheet.Cells[row, 8].Value = dtrow["OEE"];
                        //WorkSheet.Cells[row, 9].Value = dtrow["UtilisedTime"];
                        setTimeSpanFormat("hh:mm:ss", WorkSheet, row, 9, dtrow["UtilisedTime"].ToString());
                        WorkSheet.Cells[row, 10].Value = dtrow["TenthOpnCycleStart"].ToString();
                        WorkSheet.Cells[row, 11].Value = dtrow["FinishOprCycleEnd"].ToString();
                        row++;
                    }
                    WorkSheet.Row(row).Style.Font.Bold = true;
                    WorkSheet.Cells[row, 1].Value = "Total Count";
                    WorkSheet.Cells[row, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                    WorkSheet.Cells[row, 1, row, 5].Merge = true;
                    WorkSheet.Cells[row, 6].Value = ExtraDatatable.Rows[0]["TotalQty"];
                    WorkSheet.Cells[12, 1, row, 11].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    WorkSheet.Cells[12, 1, row, 11].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    WorkSheet.Cells[12, 1, row, 11].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    WorkSheet.Cells[12, 1, row, 11].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    WorkSheet.Cells[12, 1, row, 11].Style.Border.Top.Color.SetColor(Color.Black);
                    WorkSheet.Cells[12, 1, row, 11].Style.Border.Right.Color.SetColor(Color.Black);
                    WorkSheet.Cells[12, 1, row, 11].Style.Border.Left.Color.SetColor(Color.Black);
                    WorkSheet.Cells[12, 1, row, 11].Style.Border.Bottom.Color.SetColor(Color.Black);
                    //WorkSheet.Cells[11, 1, row--, 11].AutoFitColumns();
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog("GEA Production Report Generated.");
                    Generated = "Generated";
                }
                else Generated = "NoDataFound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
            return Generated;
        }


        internal static string OperatorWiseReport(string plantId, DateTime fromDate, DateTime toDate, string Operator)
        {
            string Generated = "";
            Logger.WriteDebugLog("OEE Report Kiswok");
            string time = string.Empty;
            string Filename = "OperatorEffeciency.xlsx";
            string Source = Util.GetReportPath(Filename);
            string Template = "OperatorEffeciency" + DateTime.Now + ".xlsx";
            string TimeFormat = DataBaseAccess.GetCockitSettings();
            string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("OperatorEffeciency template does not found at - \n " + Source);
            }
            try
            {
                DataTable dtList = TMPTrakDataBase.GetOperatorWiseData(plantId, fromDate, toDate, Operator, "");
                if (dtList != null && dtList.Rows.Count > 0)
                {
                    int row = 8;
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var workBook = Excel.Workbook;
                    var workSheet = workBook.Worksheets[1];
                    workSheet.Cells["B4"].Value = fromDate.ToString("dd-MM-yyyy HH:mm:ss");
                    workSheet.Cells["F4"].Value = toDate.ToString("dd-MM-yyyy HH:mm:ss");
                    workSheet.Cells["J4"].Value = string.IsNullOrEmpty(plantId) ? "All" : plantId;
                    workSheet.Cells["N4"].Value = string.IsNullOrEmpty(Operator) ? "All" : Operator;
                    List<string> OperatorList = dtList.AsEnumerable().Select(x => x.Field<string>("operator")).Distinct().ToList();
                    TimeSpan IdealMachiningTime = new TimeSpan();
                    TimeSpan AvgCycle = new TimeSpan();
                    if (OperatorList != null)
                    {
                        foreach (string emp in OperatorList)
                        {
                            Color backcolor = ColorTranslator.FromHtml("#FEF8ED");
                            DataTable ValuesbyEmp = dtList.AsEnumerable().Where(x => x.Field<string>("operator") == emp).CopyToDataTable();
                            workSheet.Cells[row, 1].Value = ValuesbyEmp.Rows[0]["operator"].ToString();
                            workSheet.Cells[row, 1, row, 2].Merge = true;
                            workSheet.Cells[row, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            workSheet.Cells[row, 1].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                            workSheet.Cells[row, 1].Style.Font.Bold = true;
                            workSheet.Cells[row, 3].Value = ValuesbyEmp.Rows[0]["Operatorname"].ToString();
                            workSheet.Cells[row, 3].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            workSheet.Cells[row, 3].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                            workSheet.Cells[row, 3].Style.Font.Bold = true;
                            workSheet.Cells[row, 3, row, 4].Merge = true;
                            workSheet.Cells[row, 1, row, 15].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            workSheet.Cells[row, 1, row, 15].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#8497B0"));
                            workSheet.Cells[row, 1, row, 15].Style.Font.Color.SetColor(Color.White);
                            row++;
                            TimeSpan totaldown = new TimeSpan();
                            double totaldown_int = 0;
                            double TotalOEE = 0.0, OEE = 0.0, CycleEffe = 0.0, TotalcycleEff = 0.0, LoadUnloadeff = 0.0, TotalLoadUnloadEff = 0.0, productionQty = 0.0;
                            foreach (DataRow dtRow in ValuesbyEmp.Rows)
                            {
                                workSheet.Cells[row, 1].Value = dtRow["machine"];
                                workSheet.Cells[row, 2].Value = dtRow["stdate"];
                                workSheet.Cells[row, 3].Value = dtRow["component"];
                                workSheet.Cells[row, 4].Value = dtRow["operation"];
                                workSheet.Cells[row, 5].Value = dtRow["BatchStart"];
                                workSheet.Cells[row, 6].Value = dtRow["BatchEnd"];
                                workSheet.Cells[row, 7].Value = dtRow["Production"];
                                productionQty += Convert.ToDouble(dtRow["Production"].ToString());
                                switch (TimeFormat)
                                {
                                    case "hh:mm:ss":
                                        TimeSpan.TryParse(dtRow["IdealMachiningTime"].ToString(), out IdealMachiningTime);
                                        //workSheet.Cells[row, 8].Value = string.Format("{0}:{1}:{2}", ((int)IdealMachiningTime.TotalHours).ToString("00"), ((int)IdealMachiningTime.Minutes).ToString("00"), ((int)IdealMachiningTime.Seconds).ToString("00"));
                                        setTimeSpanFormat(TimeFormat, workSheet, row, 8, string.Format("{0}:{1}:{2}", ((int)IdealMachiningTime.TotalHours).ToString("00"), ((int)IdealMachiningTime.Minutes).ToString("00"), ((int)IdealMachiningTime.Seconds).ToString("00")));
                                        TimeSpan.TryParse(dtRow["AvgCycle"].ToString(), out AvgCycle);
                                        //workSheet.Cells[row, 9].Value = string.Format("{0}:{1}:{2}", ((int)AvgCycle.TotalHours).ToString("00"), ((int)AvgCycle.Minutes).ToString("00"), ((int)AvgCycle.Seconds).ToString("00"));
                                        setTimeSpanFormat(TimeFormat, workSheet, row, 9, string.Format("{0}:{1}:{2}", ((int)AvgCycle.TotalHours).ToString("00"), ((int)AvgCycle.Minutes).ToString("00"), ((int)AvgCycle.Seconds).ToString("00")));
                                        CycleEffe = (Convert.ToDouble(IdealMachiningTime.TotalSeconds) / AvgCycle.TotalSeconds) * 100;
                                        CycleEffe = CycleEffe.ToString().Equals("∞") ? 0 : Math.Round(CycleEffe, 2);
                                        TotalcycleEff += (CycleEffe * Convert.ToDouble(dtRow["Production"].ToString()));

                                        TimeSpan.TryParse(dtRow["IdealLoadUnload"].ToString(), out IdealMachiningTime);
                                        TimeSpan.TryParse(dtRow["Avgloadunload"].ToString(), out AvgCycle);
                                        LoadUnloadeff = (IdealMachiningTime.TotalSeconds / AvgCycle.TotalSeconds) * 100;
                                        LoadUnloadeff = LoadUnloadeff.ToString().Equals("∞") ? 0 : Math.Round(LoadUnloadeff, 2);
                                        TotalLoadUnloadEff += (LoadUnloadeff * Convert.ToDouble(dtRow["Production"].ToString()));

                                        workSheet.Cells[row, 10].Value = CycleEffe.ToString().Equals("∞") ? 0 : Math.Round(CycleEffe, 2);
                                        //workSheet.Cells[row, 11].Value = string.Format("{0}:{1}:{2}", ((int)IdealMachiningTime.TotalHours).ToString("00"), ((int)IdealMachiningTime.Minutes).ToString("00"), ((int)IdealMachiningTime.Seconds).ToString("00"));
                                        setTimeSpanFormat(TimeFormat, workSheet, row, 11, string.Format("{0}:{1}:{2}", ((int)IdealMachiningTime.TotalHours).ToString("00"), ((int)IdealMachiningTime.Minutes).ToString("00"), ((int)IdealMachiningTime.Seconds).ToString("00")));
                                        //workSheet.Cells[row, 12].Value = string.Format("{0}:{1}:{2}", ((int)AvgCycle.TotalHours).ToString("00"), ((int)AvgCycle.Minutes).ToString("00"), ((int)AvgCycle.Seconds).ToString("00"));
                                        setTimeSpanFormat(TimeFormat, workSheet, row, 12, string.Format("{0}:{1}:{2}", ((int)AvgCycle.TotalHours).ToString("00"), ((int)AvgCycle.Minutes).ToString("00"), ((int)AvgCycle.Seconds).ToString("00")));
                                        workSheet.Cells[row, 13].Value = LoadUnloadeff.ToString().Equals("∞") ? 0 : Math.Round(LoadUnloadeff, 2);
                                        // workSheet.Cells[row, 14].Value = dtRow["BatchDown"];
                                        setTimeSpanFormat(TimeFormat, workSheet, row, 14, dtRow["BatchDown"].ToString());
                                        var split = dtRow["BatchDown"].ToString().Split(new char[] { ':' });
                                        totaldown += new TimeSpan(int.Parse(split[0]), int.Parse(split[1]), int.Parse(split[2]));
                                        TimeSpan.TryParse(dtRow["IdealMachiningTime"].ToString(), out IdealMachiningTime);
                                        TimeSpan.TryParse(dtRow["IdealLoadUnload"].ToString(), out AvgCycle);
                                        OEE = GetTotalEffectiency(Convert.ToDouble(dtRow["Production"].ToString()), IdealMachiningTime.TotalSeconds, AvgCycle.TotalSeconds, Convert.ToDouble(dtRow["BatchPeriod"].ToString()), Convert.ToDouble(dtRow["Batch"].ToString()));
                                        workSheet.Cells[row, 15].Value = OEE.ToString().Equals("∞") ? 0 : Math.Round(OEE, 2);
                                        break;
                                    default:
                                        workSheet.Cells[row, 8].Value = Math.Round(Convert.ToDouble(dtRow["IdealMachiningTime"].ToString()), 2);
                                        workSheet.Cells[row, 9].Value = Math.Round(Convert.ToDouble(dtRow["AvgCycle"].ToString()), 2);
                                        CycleEffe = (Convert.ToDouble(dtRow["IdealMachiningTime"].ToString()) / Convert.ToDouble(dtRow["AvgCycle"].ToString())) * 100;
                                        CycleEffe = CycleEffe.ToString().Equals("∞") ? 0 : Math.Round(CycleEffe, 2);
                                        TotalcycleEff += (CycleEffe * Convert.ToDouble(dtRow["Production"].ToString()));
                                        LoadUnloadeff = (Convert.ToDouble(dtRow["IdealLoadUnload"].ToString()) / Convert.ToDouble(dtRow["Avgloadunload"].ToString())) * 100;
                                        LoadUnloadeff = LoadUnloadeff.ToString().Equals("∞") ? 0 : Math.Round(LoadUnloadeff, 2);
                                        TotalLoadUnloadEff += (LoadUnloadeff * Convert.ToDouble(dtRow["Production"].ToString()));
                                        workSheet.Cells[row, 10].Value = CycleEffe.ToString().Equals("∞") ? 0 : Math.Round(CycleEffe, 2);
                                        workSheet.Cells[row, 11].Value = Math.Round(Convert.ToDouble(dtRow["IdealLoadUnload"].ToString()), 2);
                                        workSheet.Cells[row, 12].Value = Math.Round(Convert.ToDouble(dtRow["Avgloadunload"].ToString()), 2);
                                        workSheet.Cells[row, 13].Value = LoadUnloadeff.ToString().Equals("∞") ? 0 : Math.Round(LoadUnloadeff, 2);
                                        //workSheet.Cells[row, 14].Value = dtRow["BatchDown"];
                                        setTimeSpanFormat(TimeFormat, workSheet, row, 14, dtRow["BatchDown"].ToString());
                                        double.TryParse(dtRow["BatchDown"].ToString(), out double down);
                                        totaldown_int += down;
                                        OEE = GetTotalEffectiency(Convert.ToDouble(dtRow["Production"].ToString()), Convert.ToDouble(dtRow["IdealMachiningTime"].ToString()), Convert.ToDouble(dtRow["IdealLoadUnload"].ToString()), Convert.ToDouble(dtRow["BatchPeriod"].ToString()), Convert.ToDouble(dtRow["Batch"].ToString()));
                                        workSheet.Cells[row, 15].Value = OEE.ToString().Equals("∞") ? 0 : Math.Round(OEE, 2);
                                        break;
                                }
                                //
                                //var split = dtRow["BatchDown"].ToString().Split(new char[] { ':' });
                                //totaldown += new TimeSpan(int.Parse(split[0]), int.Parse(split[1]), int.Parse(split[2]));
                                //OEE = GetTotalEffectiency(Convert.ToDouble(dtRow["Production"].ToString()), Convert.ToDouble(dtRow["IdealMachiningTime"].ToString()), Convert.ToDouble(dtRow["IdealLoadUnload"].ToString()), Convert.ToDouble(dtRow["BatchPeriod"].ToString()), Convert.ToDouble(dtRow["Batch"].ToString()));
                                workSheet.Cells[row, 15].Value = OEE.ToString().Equals("∞") ? 0 : Math.Round(OEE, 2);
                                TotalOEE += (OEE * Convert.ToDouble(dtRow["Production"].ToString()));
                                row++;
                            }
                            if (productionQty != 0 && TotalcycleEff != double.NaN && TotalOEE != double.NaN && TotalLoadUnloadEff != double.NaN)
                            {
                                workSheet.Cells[(row), 10].Value = Math.Round((TotalcycleEff / productionQty), 2);
                                workSheet.Cells[(row), 13].Value = Math.Round((TotalLoadUnloadEff / productionQty), 2);
                                switch (TimeFormat)
                                {
                                    case "hh:mm:ss":
                                        workSheet.Cells[(row), 14].Style.Numberformat.Format = "HH:mm:ss";
                                        //workSheet.Cells[(row), 14].Value = string.Format("{0}:{1}:{2}", ((int)totaldown.TotalHours).ToString("00"), ((int)totaldown.Minutes).ToString("00"), ((int)totaldown.Seconds).ToString("00"));
                                        setTimeSpanFormat(TimeFormat, workSheet, row, 14, string.Format("{0}:{1}:{2}", ((int)totaldown.TotalHours).ToString("00"), ((int)totaldown.Minutes).ToString("00"), ((int)totaldown.Seconds).ToString("00")));
                                        break;
                                    default:
                                        workSheet.Cells[(row), 14].Style.Numberformat.Format = "00.00";
                                        workSheet.Cells[(row), 14].Value = totaldown_int;
                                        break;
                                }

                                workSheet.Cells[(row), 15].Value = Math.Round((TotalOEE / productionQty), 2);
                            }
                            workSheet.Cells[row, 6].Value = "Total (OR) Weighted Average";
                            workSheet.Cells[row, 1, row, 15].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            workSheet.Cells[row, 1, row, 15].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#0070C0"));
                            workSheet.Cells[row, 10, row, 15].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            workSheet.Cells[row, 10, row, 15].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                            workSheet.Cells[row, 10, row, 15].Style.Font.Bold = true;
                            workSheet.Cells[row, 1, row, 15].Style.Font.Color.SetColor(Color.White);
                            //workSheet.Cells[row, 13].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            //workSheet.Cells[row, 13].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                            //workSheet.Cells[row, 13].Style.Font.Bold = true;
                            //workSheet.Cells[row, 14].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            //workSheet.Cells[row, 14].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                            //workSheet.Cells[row, 14].Style.Font.Bold = true;
                            //workSheet.Cells[row, 15].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            //workSheet.Cells[row, 15].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                            //workSheet.Cells[row, 15].Style.Font.Bold = true;
                            row--;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Border.Top.Color.SetColor(Color.Black);
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Border.Bottom.Color.SetColor(Color.Black);
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Border.Left.Color.SetColor(Color.Black);
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Border.Right.Color.SetColor(Color.Black);
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            workSheet.Cells[(row - ValuesbyEmp.Rows.Count + 1), 1, row, 15].Style.Fill.BackgroundColor.SetColor(backcolor);
                            row = row + 2;
                        }
                        workSheet.PrinterSettings.PaperSize = ePaperSize.A3;
                        workSheet.PrinterSettings.Orientation = eOrientation.Landscape;
                        workSheet.PrinterSettings.FitToPage = true;
                        workSheet.PrinterSettings.FitToWidth = 1;
                        workSheet.PrinterSettings.FitToHeight = 0;
                    }
                    else
                        Generated = "";
                    //workSheet.Cells[4, 1, row, 15].AutoFitColumns();
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog($"OperatorEff report At :{DateTime.Now:yyyy-MM-dd HH:mm:ss}");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
            return Generated;
        }

        internal static string MonthlyOeeReportShantiFormat(string PlantID, string Cell, string machineId, DateTime fromDate)
        {
            string Generated = "";
            Logger.WriteDebugLog("OEE Report Kiswok");
            string time = string.Empty;
            string Filename = "MonthwiseOEEReport_Shanthi.xlsx";
            string Source = Util.GetReportPath(Filename);
            string Template = "MonthwiseOEEReport_Shanthi" + DateTime.Now + ".xlsx";
            string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("MonthwiseOEEReport_Shanthi template does not found at - \n " + Source);
            }
            try
            {
                DataTable dtList = TMPTrakDataBase.GetMonthWiseOEEData(Cell, fromDate, machineId, PlantID);
                if (dtList != null && dtList.Rows.Count > 0)
                {
                    int row = 5;
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var workBook = Excel.Workbook;
                    var workSheet = workBook.Worksheets[1];
                    string thisMonth = CultureInfo.CurrentCulture.DateTimeFormat.GetAbbreviatedMonthName(fromDate.Month) + ":" + fromDate.Year;
                    DateTime previousMonth = fromDate.AddMonths(-1);
                    string lastMonth = CultureInfo.CurrentCulture.DateTimeFormat.GetAbbreviatedMonthName(previousMonth.Month) + ":" + previousMonth.Year;
                    workSheet.Cells["A2"].Value = "Selected Month - " + thisMonth;
                    workSheet.Cells["L2"].Value = "Last Month - " + lastMonth;
                    string timeFormat = "hh:mm:ss";
                    foreach (DataRow dtrow in dtList.Rows)
                    {
                        workSheet.Cells[row, 1].Value = dtrow["MachineID"].ToString();
                        workSheet.Cells[row, 2].Value = dtrow["Components"];
                        workSheet.Cells[row, 3].Value = dtrow["RejCount"];
                        workSheet.Cells[row, 4].Value = getdouble(dtrow["AvailabilityEfficiency"].ToString());
                        workSheet.Cells[row, 5].Value = getdouble(dtrow["ProductionEfficiency"].ToString());
                        workSheet.Cells[row, 6].Value = getdouble(dtrow["QualityEfficiency"].ToString());
                        workSheet.Cells[row, 7].Value = getdouble(dtrow["OverAllEfficiency"].ToString());
                        //workSheet.Cells[row, 8].Value = dgetdouble(trow["AvgOverallEfficiency"].ToString());
                        setTimeSpanFormat(timeFormat, workSheet, row, 9, dtrow["Totaltime"].ToString());
                        setTimeSpanFormat(timeFormat, workSheet, row, 10, dtrow["downtime"].ToString());
                        setTimeSpanFormat(timeFormat, workSheet, row, 11, dtrow["UtilisedTime"].ToString());
                        workSheet.Cells[row, 12].Value = dtrow["MachineID1"].ToString();
                        workSheet.Cells[row, 13].Value = dtrow["Components1"];
                        workSheet.Cells[row, 14].Value = dtrow["RejCount1"];
                        workSheet.Cells[row, 15].Value = getdouble(dtrow["AE"].ToString());
                        workSheet.Cells[row, 16].Value = getdouble(dtrow["PE"].ToString());
                        workSheet.Cells[row, 17].Value = getdouble(dtrow["QE"].ToString());
                        workSheet.Cells[row, 18].Value = getdouble(dtrow["OE"].ToString());
                        //workSheet.Cells[row, 19].Value = getdouble(dtrow["AvgOE"].ToString();
                        setTimeSpanFormat(timeFormat, workSheet, row, 20, dtrow["Totaltime1"].ToString());
                        setTimeSpanFormat(timeFormat, workSheet, row, 21, dtrow["downtime1"].ToString());
                        setTimeSpanFormat(timeFormat, workSheet, row++, 22, dtrow["UtilisedTime1"].ToString());
                    }
                    workSheet.Cells[row, 8].Value = getdouble(dtList.Rows[0]["AvgOverallEfficiency"].ToString());
                    workSheet.Cells[row, 19].Value = getdouble(dtList.Rows[0]["AvgOE"].ToString());

                    workSheet.Cells["AC4"].Value = getdouble(dtList.Rows[0]["AvgOverallEfficiency"].ToString());
                    workSheet.Cells["AC5"].Value = getdouble(dtList.Rows[0]["AvgOE"].ToString());
                    workSheet.Cells["AD4"].Value = thisMonth;
                    workSheet.Cells["AD5"].Value = lastMonth;
                    workSheet.Cells[row, 19].Value = getdouble(dtList.Rows[0]["AvgOE"].ToString());

                    workSheet.Cells[4, 28, 5, 30].Style.Font.Color.SetColor(Color.White);
                    ExcelBarChart BarChart = workSheet.Drawings.AddChart("MonthWise OEE Chart", eChartType.BarClustered) as ExcelBarChart;
                    //BarChart.Title.Text = "MonthWise OEE Chart";
                    //BarChart.Series.Add("DATA!$AC$4:$AC$5", "DATA!$AD$4:$AD$5");
                    var barChartSeries = BarChart.Series.Add(ExcelRange.GetAddress(4, 29, 5, 29), ExcelRange.GetAddress(4, 30, 5, 30));
                    barChartSeries.Header = "Avg. % OEE";
                    BarChart.Legend.Position = eLegendPosition.Bottom;
                    BarChart.DataLabel.ShowValue = true;
                    BarChart.SetSize(600, 600);
                    BarChart.SetPosition(row + 5, 0, 2, 0);

                    workSheet.Cells[5, 1, row, 22].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[5, 1, row, 22].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[5, 1, row, 22].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[5, 1, row, 22].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[5, 1, row, 22].Style.Border.Top.Color.SetColor(Color.Black);
                    workSheet.Cells[5, 1, row, 22].Style.Border.Left.Color.SetColor(Color.Black);
                    workSheet.Cells[5, 1, row, 22].Style.Border.Right.Color.SetColor(Color.Black);
                    workSheet.Cells[5, 1, row, 22].Style.Border.Bottom.Color.SetColor(Color.Black);
                    workSheet.Cells[5, 1, row, 22].AutoFitColumns();
                    if (DataBaseAccess.isQERequired() == false)
                    {
                        workSheet.Column(6).Hidden = true;
                        workSheet.Column(17).Hidden = true;
                    }
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog($"MonthWiseOEE report At :{DateTime.Now:yyyy-MM-dd HH:mm:ss}");
                    Generated = "Generated";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
            return Generated;
        }


