                                            workSheet.Cells[row, 1].Value = "Shiftwise Summary";
                                            workSheet.Cells[row, 2].Value = "Shift-A Total Quantity";
                                            workSheet.Cells[row, 3].Value = dtShiftWise.AsEnumerable().Select(x => x.Field<decimal>("ShiftQuantity")).Distinct().Sum();
                                            workSheet.Cells[row, 4].Value = "ShiftWise Accept";
                                            workSheet.Cells[row, 5].Value = dtShiftWise.AsEnumerable().Select(x => x.Field<int>("ShiftAccept")).Distinct().Sum();
                                            workSheet.Cells[row, 6].Value = "ShiftWise Rejection";
                                            workSheet.Cells[row, 7].Value = dtShiftWise.AsEnumerable().Select(x => x.Field<int>("ShiftRejection")).Distinct().Sum();
