                    Generated = "Generated";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
            return Generated;
        }

        internal static string TimeConsolidatedShanthiProductionReport(DateTime fromDate, string machineId, string plantId, string cellID, DateTime toDate)
        {
            string Generated = "";
            string Filename = "ShanthiTimeConsolidatedFormat.xlsx";
            int row = 8;
            string Source = Util.GetReportPath(Filename);
            string Template = "ShanthiTimeConsolidatedFormat_" + DateTime.Now + ".xlsx";
            string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("ShanthiTimeConsolidatedFormat template does not found at - \n " + Source);
            }
            try
            {
                DataTable dtList = TMPTrakDataBase.TimeConsolidatedShanthiFormat(fromDate, machineId, plantId, toDate, cellID, "MachinewiseShanti");
                DataTable dtaverage = TMPTrakDataBase.TimeConsolidatedShanthiFormat(fromDate, machineId, plantId, toDate, cellID, "Groupwise");
                if (dtList != null && dtList.Rows.Count > 0 && dtaverage != null && dtaverage.Rows.Count > 0)
                {
                    string TimeFormat = DataBaseAccess.GetCockitSettings();
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var workBook = Excel.Workbook;
                    var workSheet = Excel.Workbook.Worksheets[1];
                    if (dtList != null && dtaverage != null && dtaverage.Rows.Count > 0 && dtList.Rows.Count > 0)
                    {
                        List<string> CellIDList = dtList.AsEnumerable().Select(x => x.Field<string>("GroupID")).Distinct().ToList();
                        foreach (string Cell in CellIDList)
                        {

                            DataTable dtcellwise = dtList.AsEnumerable().Where(x => x.Field<string>("GroupID").Equals(Cell)).CopyToDataTable();
                            if (dtcellwise != null && dtcellwise.Rows.Count > 0)
                            {
                                List<string> SubGroupList = dtcellwise.AsEnumerable().Select(x => x.Field<string>("SubGroups")).Distinct().ToList();
                                foreach (string SubGrp in SubGroupList)
                                {
                                    workSheet.Cells[row, 1].Value = Cell + " - " + SubGrp;
                                    workSheet.Cells[row++, 1].Style.Font.Bold = true;
                                    DataTable dtMachineWise = dtcellwise.AsEnumerable().Where(x => x.Field<string>("SubGroups").Equals(SubGrp)).CopyToDataTable();
                                    DataTable dtMacavg = dtaverage.AsEnumerable().Where(x => x.Field<string>("GroupID").Equals(Cell)).Where(x => x.Field<string>("SubGroup").Equals(SubGrp)).CopyToDataTable();
                                    if (dtMachineWise != null && dtMachineWise.Rows.Count > 0)
                                    {
                                        foreach (DataRow Row in dtMachineWise.Rows)
                                        {
                                            workSheet.Cells[row, 1].Value = Row["MachineID"];
                                            workSheet.Cells[row, 2].Value = Row["AvailabilityEfficiency"];
                                            workSheet.Cells[row, 3].Value = Row["ProductionEfficiency"];
                                            workSheet.Cells[row, 4].Value = Row["QualityEfficiency"];
                                            workSheet.Cells[row, 5].Value = Row["OverAllEfficiency"];
                                            workSheet.Cells[row, 6].Value = Row["Components"];
                                            workSheet.Cells[row, 7].Value = Row["RejCount"];
                                            //workSheet.Cells[row, 8].Value = Row["NetUtilisedTime"];
                                            //workSheet.Cells[row, 9].Value = Row["DownTime"];
                                            //workSheet.Cells[row, 10].Value = Row["NetManagementLoss"];
                                            setTimeSpanFormat(TimeFormat, workSheet, row, 8, Row["NetUtilisedTime"].ToString());
                                            setTimeSpanFormat(TimeFormat, workSheet, row, 9, Row["DownTime"].ToString());
                                            setTimeSpanFormat(TimeFormat, workSheet, row, 10, Row["NetManagementLoss"].ToString());
                                            workSheet.Cells[row, 11].Value = Row["TurnOver"];
                                            workSheet.Cells[row, 12].Value = Row["ReturnPerHour"];
                                            workSheet.Cells[row++, 13].Value = Row["ReturnPerHourTOTAL"];
                                        }
                                    }
                                    workSheet.Cells[row, 1].Value = "Average"; workSheet.Cells[row, 1].Style.Font.Bold = true;
                                    if (dtMacavg != null && dtMacavg.Rows.Count > 0)
                                    {
                                        foreach (DataRow Row in dtMacavg.Rows)
                                        {
                                            workSheet.Cells[row, 2].Value = Math.Round(dtMachineWise.AsEnumerable().Average(x => x.Field<double>("AvailabilityEfficiency")), 2); workSheet.Cells[row, 3].Style.Font.Bold = true;
                                            workSheet.Cells[row, 3].Value = Math.Round(dtMachineWise.AsEnumerable().Average(x => x.Field<double>("ProductionEfficiency")), 2); workSheet.Cells[row, 2].Style.Font.Bold = true;
                                            workSheet.Cells[row, 4].Value = Math.Round(dtMachineWise.AsEnumerable().Average(x => x.Field<double>("QualityEfficiency")), 2); workSheet.Cells[row, 4].Style.Font.Bold = true;
                                            workSheet.Cells[row, 5].Value = Math.Round(dtMachineWise.AsEnumerable().Average(x => x.Field<double>("OverAllEfficiency")), 2); workSheet.Cells[row++, 5].Style.Font.Bold = true;
                                        }
                                    }
                                }
                            }
                        }
                        workSheet.Cells[row, 1].Value = "Total Average:"; workSheet.Cells[row, 1].Style.Font.Bold = true;
                        workSheet.Cells[row, 2].Value = Math.Round(dtaverage.AsEnumerable().Average(x => x.Field<double>("AEffy")), 2); workSheet.Cells[row, 3].Style.Font.Bold = true;
                        workSheet.Cells[row, 3].Value = Math.Round(dtaverage.AsEnumerable().Average(x => x.Field<double>("PEffy")), 2); workSheet.Cells[row, 2].Style.Font.Bold = true;
                        workSheet.Cells[row, 4].Value = Math.Round(dtaverage.AsEnumerable().Average(x => x.Field<double>("QEffy")), 2); workSheet.Cells[row, 4].Style.Font.Bold = true;
                        workSheet.Cells[row, 5].Value = Math.Round(dtaverage.AsEnumerable().Average(x => x.Field<double>("OEffy")), 2); workSheet.Cells[row, 5].Style.Font.Bold = true;
                    }
                    workSheet.Cells["B4"].Value = fromDate.ToString("dd-MM-yyyy");
                    workSheet.Cells["G4"].Value = toDate.ToString("dd-MM-yyyy");
                    int cellCount = 13;
                    workSheet.Cells[8, 1, row, cellCount].AutoFitColumns();
                    workSheet.Cells[8, 1, row, cellCount].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[8, 1, row, cellCount].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[8, 1, row, cellCount].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[8, 1, row, cellCount].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[8, 1, row, cellCount].Style.Border.Top.Color.SetColor(Color.Black);
                    workSheet.Cells[8, 1, row, cellCount].Style.Border.Right.Color.SetColor(Color.Black);
                    workSheet.Cells[8, 1, row, cellCount].Style.Border.Left.Color.SetColor(Color.Black);
                    workSheet.Cells[8, 1, row, cellCount].Style.Border.Bottom.Color.SetColor(Color.Black);
                    if (DataBaseAccess.isQERequired() == false)
                    {
                        workSheet.Column(4).Hidden = true;
                    }
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog($"ShanthiTimeConsolidatedFormat report At :{DateTime.Now:yyyy-MM-dd HH:mm:ss}");
                    Generated = "Generated";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
            return Generated;
        }


        private static double GetTotalEffectiency(double production, double IdealMachiningtime, double IdealLoadUnloadtime, double BatchPeriod, double Batch)
        {
            double oee = 0.0;
            // return oee = ((production * (IdealMachiningtime + IdealLoadUnloadtime)) / (BatchPeriod - Batch)) * 100;
            //add operator loss to batch period based on the configuration
            return oee = ((production * (IdealMachiningtime + IdealLoadUnloadtime)) / (BatchPeriod)) * 100;
        }

        #region "Jagdev Report"
        internal static string JagdevRejectionAnalysis(DateTime fromDate, DateTime toDate, string PlantID, string MachineID, string ComponentID, string OperationID)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "";
                reportName = "JagdevRejectionAnalysisReport.xlsx";
                src = Util.GetReportPath(reportName);
                string tempfileName = "JagdevRejectionAnalysisReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Jagdev Rejection Analisys Report Template Not Found at the Path - \n " + src);
                }
                List<JagdevRejectionData> listData = TMPTrakDataBase.GetJagdevRejectionAnalysisMachineData(fromDate, toDate, PlantID, MachineID, ComponentID, OperationID);
                FileInfo newFile = new FileInfo(src);
                ExcelPackage excelPackage = new ExcelPackage(newFile, true);
                ExcelWorksheet worksheet = excelPackage.Workbook.Worksheets[1];
                worksheet.Cells["B3"].Value = fromDate.ToString("dd-MMM-yy");
                worksheet.Cells["F3"].Value = toDate.ToString("dd-MMM-yy");

                if (listData.Count > 0)
                {
                    int colStart = 1, rowStart = 6;
                    for (int i = 0; i < listData.Count; i++)
                    {
                        colStart = 1;
                        worksheet.Cells[rowStart, colStart].Value = listData[i].Date;
                        colStart++;
                        worksheet.Cells[rowStart, colStart].Value = listData[i].Shift;
                        colStart++;
                        worksheet.Cells[rowStart, colStart].Value = listData[i].MachineID;
                        colStart++;
                        worksheet.Cells[rowStart, colStart].Value = listData[i].ComponentID;
                        colStart++;
                        worksheet.Cells[rowStart, colStart].Value = listData[i].OperationNo;
                        colStart++;
                        worksheet.Cells[rowStart, colStart].Value = listData[i].Operator;
                        colStart++;
                        worksheet.Cells[rowStart, colStart].Value = listData[i].Accepted;
                        colStart++;
                        worksheet.Cells[rowStart, colStart].Value = listData[i].RejQty;
                        colStart++;
                        worksheet.Cells[rowStart, colStart].Value = listData[i].RejPercentage;
                        rowStart++;
                    }
                    worksheet.Cells[6, 1, rowStart - 1, 9].AutoFitColumns();
                    worksheet.Cells[6, 1, rowStart - 1, 9].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, rowStart - 1, 9].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, rowStart - 1, 9].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    worksheet.Cells[6, 1, rowStart - 1, 9].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                }
                if (listData.Count > 0)
                {
                    DownloadMultipleFile(dst, excelPackage.GetAsByteArray());
                    Generated = "Generated";
                }
                else
                {
                    Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex); ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }
