        #region MivinReport
        internal static string MivinOEEReport(DateTime fromDate, string Plant)
        {
            string Generated = string.Empty;
            try
            {
                string src, dst = string.Empty;
                string reportName = "";
                reportName = "MivinOEEGraph.xlsx";
                src = Util.GetReportPath(reportName);
                string tempfileName = "MivinOEEGraph" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Mivin OEE Graph Template Not Found at the Path - \n " + src);
                }
                DataTable MonthOeeData = new DataTable();
                DataTable DayOEEData = new DataTable();
                DataTable YearOEEData = TMPTrakDataBase.GetMivinOEEData(fromDate, Plant, out MonthOeeData, out DayOEEData);
                FileInfo newFile = new FileInfo(src);
                ExcelPackage excelPackage = new ExcelPackage(newFile, true);
                int Col = 3;
                if (DayOEEData != null && MonthOeeData != null && YearOEEData != null && DayOEEData.Rows.Count > 0 && MonthOeeData.Rows.Count > 0 && YearOEEData.Rows.Count > 0)
                {
                    if (YearOEEData != null && YearOEEData.Rows.Count > 0)
                    {

                        ExcelWorksheet worksheet = excelPackage.Workbook.Worksheets[1];
                        worksheet.Cells["R4"].Value = fromDate.ToString("yyyy");
                        worksheet.Cells["B4"].Value = Plant;
                        worksheet.Cells[9, 1].Value = "Actual";
                        worksheet.Cells[10, 1].Value = "Target";
                        worksheet.Cells[8, 2].Value = "AVG";
                        worksheet.Cells[9, 2].Value = YearOEEData.AsEnumerable().Average(x => x.Field<double>("FirstPassYield"));
                        worksheet.Cells[10, 2].Value = 100;
                        foreach (DataRow dtRow in YearOEEData.Rows)
                        {
                            worksheet.Cells[8, Col].Value = dtRow["MonthName"];
                            worksheet.Cells[9, Col].Value = dtRow["FirstPassYield"];
                            worksheet.Cells[10, Col++].Value = 100;
                        }
                        Col--;
                        worksheet.Cells[8, 1, 10, Col].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                        worksheet.Cells[8, 1, 10, Col].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                        worksheet.Cells[8, 1, 10, Col].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                        worksheet.Cells[8, 1, 10, Col].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                        worksheet.Cells[8, 1, 10, Col].Style.Border.Top.Color.SetColor(Color.Black);
                        worksheet.Cells[8, 1, 10, Col].Style.Border.Bottom.Color.SetColor(Color.Black);
                        worksheet.Cells[8, 1, 10, Col].Style.Border.Left.Color.SetColor(Color.Black);
                        worksheet.Cells[8, 1, 10, Col].Style.Border.Right.Color.SetColor(Color.Black);
                        var chart = (ExcelBarChart)worksheet.Drawings.AddChart("", eChartType.ColumnClustered);
                        //ExcelBarChart chart = (ExcelBarChart)wsDt.Drawings.AddChart("Status", eChartType.BarClustered);
                        chart.SetSize(1200, 600);
                        chart.SetPosition(300, 10);
                        //chart.Title.Text = result;
