                        ExcelChart chart2 = chart.PlotArea.ChartTypes.Add(eChartType.Line);
                        ExcelChartSerie ch2 = chart2.Series.Add(worksheet.Cells[10, 2, 10, (Col)], worksheet.Cells[8, 2, 8, (Col)]);
                        ch1.Header = "Actual";
                        ch2.Header = "Target";
                        chart.DataLabel.ShowValue = true;
                        chart.YAxis.Title.Text = "FPY(%)";
                        chart.XAxis.Title.Text = "Month";
                        chart.Title.Text = "First Pass Yield - " + Plant;

                        chart.VaryColors = true;

                    }
                    if (MonthOeeData != null && MonthOeeData.Rows.Count > 0)
                    {
                        Col = 3;
