                        worksheet.Cells[8, 1, 10, Col].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                        worksheet.Cells[8, 1, 10, Col].Style.Border.Right.Style = ExcelBorderStyle.Thin;
