            }
            return Generated;
        }

        internal static string GetMivinInspectionReport(DateTime fromDate, DateTime toDate, string MachineId, string ShiftID, string Type, string TypeName)
        {
            string Generated = string.Empty;
            string ch = string.Empty;
            try
            {
                string src, dst = string.Empty;
                string reportName = "";
                reportName = "MivinInspectionData.xlsx";
                src = Util.GetReportPath(reportName);
                string tempfileName = "MivinInspectionData" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Jagdev Rejection Analisys Report Template Not Found at the Path - \n " + src);
                }
                DataTable MivinData = TMPTrakDataBase.GetMivinInspectionData(fromDate, toDate, MachineId, ShiftID, Type);
                FileInfo newFile = new FileInfo(src);
                ExcelPackage excelPackage = new ExcelPackage(newFile, true);
                ExcelWorksheet worksheet = excelPackage.Workbook.Worksheets[1];
                int Row = 6;
                if (MivinData != null && MivinData.Rows.Count > 0)
                {
                    var DistinctMacOpnComp = MivinData.AsEnumerable().Select(x => new { ComponentID = x.Field<string>("ComponentID") }).Distinct().ToList();
                    if (DistinctMacOpnComp != null && DistinctMacOpnComp.Count > 0)
                    {
                        foreach (var MacOpnComp in DistinctMacOpnComp)
                        {
                            excelPackage.Workbook.Worksheets.Add(MacOpnComp.ComponentID, worksheet);
                            var copyworksheet = excelPackage.Workbook.Worksheets[MacOpnComp.ComponentID];
                            DataTable dtdist = MivinData.AsEnumerable().Where(x => x.Field<string>("ComponentID").Equals(MacOpnComp.ComponentID)).CopyToDataTable();
                            int Col = 1; Row = 6;

                            Dictionary<string, int> DimensionData = new Dictionary<string, int>();
                            CreateHeader(ref copyworksheet, Row, dtdist, ref Col, out DimensionData);
                            Row = Row + 1;
                            try
                            {
                                if (dtdist != null && dtdist.Rows.Count > 0)
                                {
                                    copyworksheet.Cells["L2"].Value = "Rev Date: " + DateTime.Now.ToString("dd-MMM-yyyy");
                                    copyworksheet.Cells["L3"].Value = "Machine No: " + MachineId;
                                    copyworksheet.Cells["L4"].Value = "Set up/Opn: " + dtdist.Rows[0]["Operation"];

                                    copyworksheet.Cells["A3"].Value = "Part Desc: " + dtdist.Rows[0]["PartDescription"];
                                    List<DateTime> TimeStamp = dtdist.AsEnumerable().Select(x => x.Field<DateTime>("TimeStamp")).Distinct().ToList();
                                    //worksheet.Cells[Row,]
                                    int i = 1;
                                    foreach (DateTime date in TimeStamp)
                                    {
                                        string Remarks = string.Empty, Operator = string.Empty;
                                        DataTable DtData = dtdist.AsEnumerable().Where(x => x.Field<DateTime>("TimeStamp").Equals(date)).CopyToDataTable();
                                        copyworksheet.Cells[Row, 1].Value = date.ToString("dd-MM-yyyy") + "/" + date.ToString("HH:mm:ss tt") + "/" + DtData.Rows[0]["Shiftname"];
                                        copyworksheet.Cells[Row, 4].Value = MacOpnComp.ComponentID;
                                        copyworksheet.Cells[Row, 3].Value = i++;
                                        copyworksheet.Cells["B1"].Value = TypeName;
                                        foreach (DataRow dtRow in DtData.Rows)
                                        {
                                            ch = dtRow["CharacteristicId"].ToString();
                                            int dimcol = DimensionData[dtRow["CharacteristicId"].ToString()];
                                            copyworksheet.Cells[Row, dimcol].Value = dtRow["Value"];

                                            Remarks = dtRow["Remarks"].ToString();
                                            if (!string.IsNullOrEmpty(dtRow["Operator"].ToString()))
                                            {
                                                if (!(Operator.Contains(dtRow["Operator"].ToString())))
                                                    Operator += dtRow["Operator"] + ",";
                                            }
                                        }
                                        // Remarks = Remarks.TrimEnd(',');
                                        Operator = Operator.TrimEnd(',');
                                        copyworksheet.Cells[Row, DimensionData.Count + 5].Value = Remarks;
                                        copyworksheet.Cells[Row, DimensionData.Count + 6].Value = Operator;
                                        copyworksheet.Cells["A4"].Value = "Operator: " + Operator;
                                        Row++;
                                    }
                                }
                            }
                            catch (Exception ex)
                            {
                                Logger.WriteErrorLog(ex.ToString());
                            }
                            Row--;
                            copyworksheet.Cells[7, 2, Row, 2].Merge = true;
                            copyworksheet.Cells[7, 2].Value = "Values";
                            copyworksheet.Cells[7, 2].Style.TextRotation = 90;
                            copyworksheet.Cells[7, 2].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                            copyworksheet.Cells[7, 2].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            copyworksheet.Cells[6, 1, Row, DimensionData.Count + 6].AutoFitColumns();
                            copyworksheet.Cells[7, 1, Row, DimensionData.Count + 6].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                            copyworksheet.Cells[7, 1, Row, DimensionData.Count + 6].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                            copyworksheet.Cells[7, 1, Row, DimensionData.Count + 6].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                            copyworksheet.Cells[7, 1, Row, DimensionData.Count + 6].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                            copyworksheet.Cells[7, 1, Row, DimensionData.Count + 6].Style.Border.Top.Color.SetColor(Color.Black);
                            copyworksheet.Cells[7, 1, Row, DimensionData.Count + 6].Style.Border.Bottom.Color.SetColor(Color.Black);
                            copyworksheet.Cells[7, 1, Row, DimensionData.Count + 6].Style.Border.Left.Color.SetColor(Color.Black);
                            copyworksheet.Cells[7, 1, Row, DimensionData.Count + 6].Style.Border.Right.Color.SetColor(Color.Black);

                        }
                    }
                    excelPackage.Workbook.Worksheets.Delete(1);
                    DownloadMultipleFile(dst, excelPackage.GetAsByteArray());
                    Generated = "Generated";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
            return Generated;
        }
        private static void CreateHeader(ref ExcelWorksheet worksheet, int row, DataTable Values, ref int col, out Dictionary<string, int> DimensionDatas)
        {
            //int firstcol = col;
            DimensionDatas = new Dictionary<string, int>();
            try
            {
                worksheet.Cells[row, col++].Value = "Date/Time/Shift"; col++;
                worksheet.Cells[row, col++].Value = "SLNo";
                worksheet.Cells[row, col++].Value = "Part Number";
                List<string> DimensionData = Values.AsEnumerable().Select(x => x.Field<string>("CharacteristicId")).Distinct().ToList();
                foreach (string dim in DimensionData)
                {
                    worksheet.Cells[row, col].Value = dim;
                    DimensionDatas.Add(dim, col++);
                }
                worksheet.Cells[row, col++].Value = "Remarks";
                worksheet.Cells[row, col].Value = "Operator";
                worksheet.Cells[row, 1, row, col].AutoFitColumns();
                worksheet.Cells[row, 1, row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                worksheet.Cells[row, 1, row, col].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(198, 224, 180));
                worksheet.Cells[row, 1, row, col].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                worksheet.Cells[row, 1, row, col].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                worksheet.Cells[row, 1, row, col].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                worksheet.Cells[row, 1, row, col].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                worksheet.Cells[row, 1, row, col].Style.Border.Top.Color.SetColor(Color.Black);
                worksheet.Cells[row, 1, row, col].Style.Border.Bottom.Color.SetColor(Color.Black);
                worksheet.Cells[row, 1, row, col].Style.Border.Left.Color.SetColor(Color.Black);
                worksheet.Cells[row, 1, row, col].Style.Border.Right.Color.SetColor(Color.Black);
                worksheet.Cells[row, 1, row, col].Style.Font.Bold = true;
                worksheet.Row(6).Height = 40;
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.ToString());
            }
        }

