        public static void SetChartPointsColor(this ExcelBarChart chart, int serieNumber, Color color)
        {
            try
            {

                var chartXml = chart.ChartXml;

                var nsa = chart.WorkSheet.Drawings.NameSpaceManager.LookupNamespace("a");
                var nsuri = chartXml.DocumentElement.NamespaceURI;

                var nsm = new XmlNamespaceManager(chartXml.NameTable);
                nsm.AddNamespace("a", nsa);
                nsm.AddNamespace("c", nsuri);

                var serieNode = chart.ChartXml.SelectSingleNode(@"c:chartSpace/c:chart/c:plotArea/c:bar3DChart/c:ser[c:idx[@val='" + serieNumber + "']]", nsm);
                var serie = chart.Series[serieNumber];
                var points = serie.Series.Length;

                //Add reference to the color for the legend and data points
                var srgbClr = chartXml.CreateNode(XmlNodeType.Element, "srgbClr", nsa);
                var att = chartXml.CreateAttribute("val");
                att.Value = $"{color.R:X2}{color.G:X2}{color.B:X2}";
                srgbClr.Attributes.Append(att);

                var solidFill = chartXml.CreateNode(XmlNodeType.Element, "solidFill", nsa);
                solidFill.AppendChild(srgbClr);

                var spPr = chartXml.CreateNode(XmlNodeType.Element, "spPr", nsuri);
                spPr.AppendChild(solidFill);

                serieNode.AppendChild(spPr);

            }
            catch (Exception ex)
            {

            }
        }
        private static void addDataTableForBarchart(this ExcelChart barChart)
        {
            try
            {
                //Get reference to the worksheet xml for proper namespace
                var chartXml = barChart.ChartXml;
                var nsuri = chartXml.DocumentElement.NamespaceURI;
                var nsm = new XmlNamespaceManager(chartXml.NameTable);
                nsm.AddNamespace("default", nsuri);

                //Add the table node
                var plotAreaNode = chartXml.SelectSingleNode("/default:chartSpace/default:chart/default:plotArea", nsm);
                var dTableNode = chartXml.CreateNode(XmlNodeType.Element, "dTable", nsuri);
                plotAreaNode.AppendChild(dTableNode);

                //With Legend Flag
                var att = chartXml.CreateAttribute("val");
                att.Value = "1";

                var showKeysNode = chartXml.CreateNode(XmlNodeType.Element, "showKeys", nsuri);
                showKeysNode.Attributes.Append(att);
                dTableNode.AppendChild(showKeysNode);
            }
            catch (Exception ex)
            {

            }

        }
        private static void setColorForPiechart(ExcelPieChart pieChart)
        {
            try
            {
                //Get the nodes
                const string PIE_PATH = "c:chartSpace/c:chart/c:plotArea/c:pie3DChart/c:ser";
                var ws = pieChart.WorkSheet;
                var nsm = ws.Drawings.NameSpaceManager;
                var nschart = nsm.LookupNamespace("c");
                var nsa = nsm.LookupNamespace("a");
                var node = pieChart.ChartXml.SelectSingleNode(PIE_PATH, nsm);
                var doc = pieChart.ChartXml;

                //Add the node
                var rand = new Random();
                for (var i = 0; i < 3; i++)
                {
                    //Create the data point node
                    var dPt = doc.CreateElement("dPt", nschart);

                    var idx = dPt.AppendChild(doc.CreateElement("idx", nschart));
                    var valattrib = idx.Attributes.Append(doc.CreateAttribute("val"));
                    valattrib.Value = i.ToString(CultureInfo.InvariantCulture);
                    node.AppendChild(dPt);

                    //Add the solid fill node
                    var spPr = doc.CreateElement("spPr", nschart);
                    var solidFill = spPr.AppendChild(doc.CreateElement("solidFill", nsa));
                    var srgbClr = solidFill.AppendChild(doc.CreateElement("srgbClr", nsa));
                    valattrib = srgbClr.Attributes.Append(doc.CreateAttribute("val"));

                    //Set the color
                    var color = Color.FromArgb(4, 199, 4);
                    if (i == 0)
                    {
                        color = Color.FromArgb(2, 153, 14);
                    }
                    else if (i == 1)
                    {

                        color = Color.FromArgb(255, 255, 3);
                    }
                    else
                    {

                        color = Color.FromArgb(255, 0, 0);
                    }
                    //var color = Color.FromArgb(rand.Next(256), rand.Next(256), rand.Next(256));
                    valattrib.Value = ColorTranslator.ToHtml(color).Replace("#", String.Empty);
                    dPt.AppendChild(spPr);
                }
                // excelPackage.Save();
            }
            catch (Exception ex)
            {

            }

        }

