        public static string OperatorIncentiveReportData(DateTime StartDate, DateTime EndDate, string operatorID, string machineID, string cycleTimeType)
        {
            string Generated = "";
            try
            {
                DataTable dt = new DataTable();
                string Source = string.Empty, destination = string.Empty, template = string.Empty;
                string ReportName = "OperatorIncentiveReport_Anjali.xlsx";
                Source = Util.GetReportPath(ReportName);
                template = "OperatorIncentiveReport_Anjali_" + DateTime.Now + ".xlsx";
                destination = Path.Combine(appPath, "Temp", SafeFileName(template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("OperatorIncentiveReport_Anjali - \n " + Source);
                }
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var worksheet = Excel.Workbook.Worksheets[1];
                worksheet.Cells["B3"].Value = StartDate.ToString("dd-MM-yyyy");
                worksheet.Cells["E3"].Value = EndDate.ToString("dd-MM-yyyy");
                worksheet.Cells["H3"].Value = machineID;
                worksheet.Cells["K3"].Value = operatorID;

                Double difference = 0;
                DataTable summaryDt = new DataTable();
                dt = TMPTrakDataBase.GetOperatorIncentiveReportData(StartDate.ToString("yyyy-MM-dd HH:mm:ss"), EndDate.ToString("yyyy-MM-dd HH:mm:ss"), string.Equals(machineID, "All", StringComparison.OrdinalIgnoreCase) ? "" : machineID, string.Equals(operatorID, "All", StringComparison.OrdinalIgnoreCase) ? "" : operatorID, cycleTimeType, out summaryDt);
                int cellCount = 1;
                if (cycleTimeType.Equals("AvgCycleTime", StringComparison.OrdinalIgnoreCase))
                {
                    cycleTimeType = "Average";
                }
                else
                {
                    cycleTimeType = "Standard";
                }
                worksheet.Cells["M3"].Value = cycleTimeType;
                if (dt != null && dt.Rows.Count > 0)
                {
                    int rowCount = 6;
                    List<string> distinctOperatorID = dt.AsEnumerable().Select(k => k.Field<string>("OperatorID")).Distinct().ToList();
                    for (int oprCount = 0; oprCount < distinctOperatorID.Count; oprCount++)
                    {
                        var dataRows = dt.AsEnumerable().Where(k => k.Field<string>("OperatorID") == distinctOperatorID[oprCount]).ToList();
                        foreach (var row in dataRows)
                        {
                            cellCount = 1;
                            worksheet.Cells[rowCount, cellCount].Value = row["OperatorName"].ToString();
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = string.IsNullOrEmpty(row["Pdate"].ToString()) ? "" : Util.GetDateTime(row["Pdate"].ToString()).ToString("dd-MM-yyyy");
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = row["Shift"].ToString();
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = row["MachineID"].ToString();
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = row["OperationNo"].ToString();
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = row["ComponentID"].ToString();
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = string.IsNullOrEmpty(row["Stdcycletime"].ToString()) ? 0 : Convert.ToDouble(row["Stdcycletime"].ToString());
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = string.IsNullOrEmpty(row["LoadUnload"].ToString()) ? 0 : Convert.ToDouble(row["LoadUnload"].ToString());
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = string.IsNullOrEmpty(row["TotalCycleTime"].ToString()) ? 0 : Convert.ToDouble(row["TotalCycleTime"].ToString());
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = string.IsNullOrEmpty(row["MachineHrRate"].ToString()) ? 0 : Convert.ToDouble(row["MachineHrRate"].ToString());
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = string.IsNullOrEmpty(row["OperationRate"].ToString()) ? 0 : Convert.ToDouble(row["OperationRate"].ToString());
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = string.IsNullOrEmpty(row["ProdCount"].ToString()) ? 0 : Convert.ToDouble(row["ProdCount"].ToString());
                            cellCount++;
                            worksheet.Cells[rowCount, cellCount].Value = string.IsNullOrEmpty(row["ShiftIncentiveTotalInRS"].ToString()) ? 0 : Convert.ToDouble(row["ShiftIncentiveTotalInRS"].ToString());
                            rowCount++;
                        }
                        var summaryDataRows = summaryDt.AsEnumerable().Where(k => k.Field<string>("OperatorID") == distinctOperatorID[oprCount]).ToList();
                        if (summaryDataRows != null)
                        {
                            if (summaryDataRows.Count > 0)
                            {
                                foreach (var row in summaryDataRows)
                                {
                                    worksheet.Row(rowCount).Style.Font.Bold = true;
                                    worksheet.Cells[rowCount, 1, rowCount, 13].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                    worksheet.Cells[rowCount, 1, rowCount, 13].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(255, 255, 0));
                                    worksheet.Cells[rowCount, 1].Value = "Total";
                                    worksheet.Cells[rowCount, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                    worksheet.Cells[rowCount, 1, rowCount, 10].Merge = true;
                                    worksheet.Cells[rowCount, 11].Value = string.IsNullOrEmpty(row["OperationRate"].ToString()) ? 0 : Convert.ToDouble(row["OperationRate"].ToString());
                                    worksheet.Cells[rowCount, 12].Value = string.IsNullOrEmpty(row["ProdCount"].ToString()) ? 0 : Convert.ToDouble(row["ProdCount"].ToString());
                                    worksheet.Cells[rowCount, 13].Value = string.IsNullOrEmpty(row["ShiftIncentiveTotalInRS"].ToString()) ? 0 : Convert.ToDouble(row["ShiftIncentiveTotalInRS"].ToString());
                                    rowCount++;
                                    break;
                                }
                            }
                        }
                    }
                    for (int i = 1; i <= cellCount; i++)
                    {
                        worksheet.Column(i).AutoFit();
                    }
                    setThinBorder(worksheet, 6, 1, rowCount - 1, cellCount);
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Generated = "Generated";
                    Logger.WriteDebugLog("Operator Incentive Report_Anjali saved.");
                }
                else
                    Generated = "Nodatafound";
            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog(ex.Message);
            }
            return Generated;
        }
        #endregion

        #region "Production report-Machinewise Shift-Format- 4 for kiswok"
        public static string AnalysisMachinewiseShiftFormat4Report(DateTime StartDate, string ShiftIn, string MachineID, string ComponentID, string OperationNo, string PlantID, string CellID, DateTime EndDate)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "SM_ShiftProductionReport_Format4.xlsx";

                src = Util.GetReportPath(reportName);

                string tempfileName = "SM_ShiftProductionReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));
                if (ShiftIn.Equals("All", StringComparison.OrdinalIgnoreCase))
                    ShiftIn = "";
                if (MachineID.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    MachineID = "";
                if (PlantID.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    PlantID = "";
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Production report-Machinewise Shift-Format- 1 - \n " + src);
                }
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];

                wsDts.Cells["B3"].Value = StartDate.ToString("dd-MMM-yyyy");
                //wsDts.Cells["E3"].Value = EndDate.ToString("dd-MMM-yyyy");
                int row = 0;
                DataTable dt = TMPTrakDataBase.AnalysisMachinewiseShiftFormat4Report(StartDate, ShiftIn, CellID, MachineID, ComponentID, OperationNo, PlantID, EndDate, "Shift");
                DataTable dtTotal = TMPTrakDataBase.AnalysisMachinewiseShiftFormat4Report(StartDate, ShiftIn, CellID, MachineID, ComponentID, OperationNo, PlantID, EndDate, "Summary");
                DataTable dtShiftTotal = TMPTrakDataBase.AnalysisMachinewiseShiftFormat4Report(StartDate, ShiftIn, CellID, MachineID, ComponentID, OperationNo, PlantID, EndDate, "FinalSummary");
                int startRow = 8;
                if (dt != null && dt.Rows.Count > 0)
                {
                    row = 8;
                    string timeFormat = DataBaseAccess.getTimeFormatFromCockpit();
                    var distShift = dt.AsEnumerable().Select(k => k.Field<string>("shift")).Distinct().ToList();
                    for (int shiftCount = 0; shiftCount < distShift.Count; shiftCount++)
                    {
                        startRow = row;
                        if (shiftCount > 0)
                        {
                            wsDts.Cells[7, 1, 7, 20].Copy(wsDts.Cells[row, 1, row, 20]);
                            row++;
                        }
                        string shiftName = distShift[shiftCount];
                        var shiftDayGpOpnDistinct = dt.AsEnumerable().Where(k => k.Field<string>("shift") == shiftName).Select(k => new { Day = k.Field<DateTime>("Day"), GroupID = k.Field<string>("GroupID"), Operation = k.Field<string>("Operation") }).Distinct().ToList();
                        for (int sDGOCount = 0; sDGOCount < shiftDayGpOpnDistinct.Count; sDGOCount++)
                        {
                            string tempDateMachineShift = "";
                            var shiftDayGpOpnRows = dt.AsEnumerable().Where(k => k.Field<string>("shift") == shiftName && k.Field<DateTime>("Day") == shiftDayGpOpnDistinct[sDGOCount].Day && k.Field<string>("GroupID") == shiftDayGpOpnDistinct[sDGOCount].GroupID && k.Field<string>("Operation") == shiftDayGpOpnDistinct[sDGOCount].Operation).ToList();
                            if (shiftDayGpOpnRows != null)
                            {
                                DataTable shiftDayGpOpnDt = shiftDayGpOpnRows.CopyToDataTable();
                                foreach (var dataRow in shiftDayGpOpnRows)
                                {
                                    string currentDateMachineShift = dataRow["Day"].ToString() + dataRow["MachineId"].ToString() + dataRow["shift"].ToString();
                                    int mergeCount = 0;
                                    if (tempDateMachineShift != currentDateMachineShift)
                                    {
                                        mergeCount = shiftDayGpOpnDt.AsEnumerable().Where(k => k["Day"].ToString() == dataRow["Day"].ToString() && k["MachineId"].ToString() == dataRow["MachineId"].ToString() && k["shift"].ToString() == dataRow["shift"].ToString()).ToList().Count();
                                    }
                                    tempDateMachineShift = currentDateMachineShift;

                                    wsDts.Cells[row, 1].Value = dataRow["shift"];
                                    wsDts.Cells[row, 2].Value = Convert.ToDateTime(dataRow["Day"]).ToString("dd/MM/yyyy");
                                    if (string.Equals(ConfigurationManager.AppSettings["OperatorInReport"].ToString(), "Name", StringComparison.OrdinalIgnoreCase))
                                    {
                                        wsDts.Cells[row, 3].Value = dataRow["OperatorName"];
                                    }
                                    else
                                    {
                                        wsDts.Cells[row, 3].Value = dataRow["OperatorId"];
                                    }
                                    wsDts.Cells[row, 4].Value = dataRow["MachineId"];
                                    wsDts.Cells[row, 5].Value = dataRow["MachineDescription"];
                                    wsDts.Cells[row, 6].Value = dataRow["Component"];
                                    if (!string.IsNullOrEmpty(dataRow["Operation"].ToString()))
                                        wsDts.Cells[row, 7].Value = Convert.ToDecimal(dataRow["Operation"]);
                                    wsDts.Cells[row, 8].Value = dataRow["OperationCount"];
                                    //wsDts.Cells[row, 9].Value = dataRow["frmtCycleTime"];
                                    //wsDts.Cells[row, 10].Value = dataRow["frmtAvgCycleTime"];
                                    setTimeSpanFormat(timeFormat, wsDts, row, 9, dataRow["frmtCycleTime"].ToString());
                                    setTimeSpanFormat(timeFormat, wsDts, row, 10, dataRow["frmtAvgCycleTime"].ToString());
                                    if (!(dataRow["cyclefficiency"] is DBNull))
                                        wsDts.Cells[row, 11].Value = Convert.ToDouble(dataRow["cyclefficiency"]);
                                    //wsDts.Cells[row, 12].Value = dataRow["frmtLoadUnload"];
                                    //wsDts.Cells[row, 13].Value = dataRow["frmtAvgLoadUnload"];
                                    setTimeSpanFormat(timeFormat, wsDts, row, 12, dataRow["frmtLoadUnload"].ToString());
                                    setTimeSpanFormat(timeFormat, wsDts, row, 13, dataRow["frmtAvgLoadUnload"].ToString());
                                    if (!(dataRow["LoadUnloadefficiency"] is DBNull))
                                        wsDts.Cells[row, 14].Value = Convert.ToDouble(dataRow["LoadUnloadefficiency"]);
                                    //wsDts.Cells[row, 15].Value = dataRow["frmtUtilisedTime"];
                                    //wsDts.Cells[row, 16].Value = dataRow["frmtDownTime"];
                                    //if (mergeCount != 0)
                                    //{
                                    setTimeSpanFormat(timeFormat, wsDts, row, 15, dataRow["frmtUtilisedTime"].ToString());
                                    //}
                                    //if (mergeCount != 0)
                                    //{
                                    setTimeSpanFormat(timeFormat, wsDts, row, 16, dataRow["frmtDownTime"].ToString());
                                    //}
                                    //if (mergeCount != 0)
                                    //{
                                    if (!(dataRow["AvailabilityEfficiency"] is DBNull))
                                        wsDts.Cells[row, 17].Value = Convert.ToDouble(dataRow["AvailabilityEfficiency"]);
                                    //}
                                    //if (mergeCount != 0)
                                    //{
                                    if (!(dataRow["ProductionEfficiency"] is DBNull))
                                        wsDts.Cells[row, 18].Value = Convert.ToDouble(dataRow["ProductionEfficiency"]);
                                    //}
                                    //if (mergeCount != 0)
                                    //{
                                    if (!(dataRow["QualityEfficiency"] is DBNull))
                                        wsDts.Cells[row, 19].Value = Convert.ToDouble(dataRow["QualityEfficiency"]);
                                    //}
                                    //if (mergeCount != 0)
                                    //{
                                    if (!(dataRow["OverallEfficiency"] is DBNull))
                                        wsDts.Cells[row, 20].Value = Convert.ToDouble(dataRow["OverallEfficiency"]);
                                    //}
                                    if (mergeCount > 1)
                                    {
                                        wsDts.Cells[row, 15, row + mergeCount - 1, 15].Merge = true;
                                        wsDts.Cells[row, 16, row + mergeCount - 1, 16].Merge = true;
                                        wsDts.Cells[row, 17, row + mergeCount - 1, 17].Merge = true;
                                        wsDts.Cells[row, 18, row + mergeCount - 1, 18].Merge = true;
                                        wsDts.Cells[row, 19, row + mergeCount - 1, 19].Merge = true;
                                        wsDts.Cells[row, 20, row + mergeCount - 1, 20].Merge = true;
                                    }
                                    row++;
                                }

                                //display Shift, Date, Group, Operation summary
                                var summaryRows = dtTotal.AsEnumerable().Where(k => k.Field<string>("SHIFT") == shiftName && k.Field<DateTime>("Day") == shiftDayGpOpnDistinct[sDGOCount].Day && k.Field<string>("GROUPID") == shiftDayGpOpnDistinct[sDGOCount].GroupID && k.Field<string>("Operation") == shiftDayGpOpnDistinct[sDGOCount].Operation).ToList();
                                if (summaryRows != null)
                                {
                                    foreach (var dataRow in summaryRows)
                                    {
                                        wsDts.Row(row).Style.Font.Bold = true;
                                        wsDts.Cells[row, 1, row, 20].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                        wsDts.Cells[row, 1, row, 20].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(255, 255, 0));
                                        wsDts.Cells[row, 1].Value = "Total " + shiftDayGpOpnDistinct[sDGOCount].GroupID + " OP." + shiftDayGpOpnDistinct[sDGOCount].Operation;
                                        wsDts.Cells[row, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                        wsDts.Cells[row, 1, row, 7].Merge = true;

                                        //wsDts.Cells[row, 8].Value = dataRow["ActualProduction"].ToString();
                                        //wsDts.Cells[row, 17].Value = dataRow["AvgAE"].ToString();
                                        //wsDts.Cells[row, 18].Value = dataRow["AvgPE"].ToString();
                                        //wsDts.Cells[row, 19].Value = dataRow["AvgQE"].ToString();
                                        //wsDts.Cells[row, 20].Value = dataRow["AvgOEE"].ToString();
                                        wsDts.Cells[row, 8].Value = Convert.ToDouble(dataRow["ActualProduction"].ToString());
                                        wsDts.Cells[row, 17].Value = Convert.ToDouble(dataRow["AvgAE"].ToString());
                                        wsDts.Cells[row, 18].Value = Convert.ToDouble(dataRow["AvgPE"].ToString());
                                        wsDts.Cells[row, 19].Value = Convert.ToDouble(dataRow["AvgQE"].ToString());
                                        wsDts.Cells[row, 20].Value = Convert.ToDouble(dataRow["AvgOEE"].ToString());
                                        row++;
                                        break;
                                    }
                                }
                            }
                        }
                        setThinBorder(wsDts, startRow, 1, row, 20);
                        //Display Shift Details or Summary
                        var shiftSummaryRows = dtShiftTotal.AsEnumerable().Where(k => k.Field<string>("SHIFT") == shiftName).ToList();
                        if (shiftSummaryRows != null)
                        {
                            if (shiftSummaryRows.Count > 0)
                            {
                                startRow = row;
                                wsDts.Cells[row, 1].Value = shiftName + "\n SHIFT AVERAGE";
                                wsDts.Cells[row, 1].Style.Font.Size = 17;
                                wsDts.Cells[row, 1].Style.WrapText = true;
                                wsDts.Cells[row, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                wsDts.Cells[row, 1].Style.VerticalAlignment = ExcelVerticalAlignment.Center;

                                wsDts.Cells[row, 3].Value = "Production Summary " + PlantID;
                                wsDts.Cells[row, 4].Value = "Plan";
                                wsDts.Cells[row, 5].Value = "Actual";
                                wsDts.Cells[row, 6].Value = "%";
                                wsDts.Cells[row, 7].Value = "OEE %";
                                wsDts.Cells[row, 1, row + shiftSummaryRows.Count + 1, 2].Merge = true;
                                row++;
                                decimal plan = 0, actual = 0, percent = 0;
                                foreach (var dataRow in shiftSummaryRows)
                                {
                                    wsDts.Cells[row, 3].Value = "Total " + dataRow["GroupID"].ToString() + " OP." + dataRow["Operation"].ToString();
                                    wsDts.Cells[row, 4].Value = dataRow["Plan"].ToString();
                                    wsDts.Cells[row, 5].Value = dataRow["Actual"].ToString();
                                    wsDts.Cells[row, 6].Value = dataRow["Percent"].ToString();
                                    wsDts.Cells[row, 7].Value = dataRow["OverallEfficiency"].ToString();
                                    if (!string.IsNullOrEmpty(dataRow["Plan"].ToString()))
                                    {
                                        plan += Convert.ToDecimal(dataRow["Plan"].ToString());
                                    }
                                    if (!string.IsNullOrEmpty(dataRow["Actual"].ToString()))
                                    {
                                        actual += Convert.ToDecimal(dataRow["Actual"].ToString());
                                    }
                                    //if (!string.IsNullOrEmpty(dataRow["Percent"].ToString()))
                                    //{
                                    //    percent += Convert.ToDouble(dataRow["Percent"].ToString());
                                    //}
                                    row++;
                                }
                                wsDts.Cells[row, 3].Value = "Total Production";
                                wsDts.Cells[row, 4].Value = plan;
                                wsDts.Cells[row, 5].Value = actual;
                                wsDts.Cells[row, 6].Value = Math.Round(((actual / plan) * 100), 2);
                                //wsDts.Cells[row, 6].Value = Math.Round((percent / shiftSummaryRows.Count), 0);
                                wsDts.Cells[startRow, 2, row, 7].Style.Font.Size = 14;
                                wsDts.Cells[startRow, 1, row, 7].Style.Font.Bold = true;
                                wsDts.Cells[startRow, 3, row, 3].Style.HorizontalAlignment = ExcelHorizontalAlignment.Left;
                                setThinBorder(wsDts, startRow, 1, row, 7);
                                row += 2;
                            }
                        }

                        if (DataBaseAccess.isQERequired() == false)
                        {
                            wsDts.Column(19).Hidden = true;
                        }

                    }
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Production report-Machinewise Shift-Format- 4 Report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "Nodatafound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex); ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }

