                            if (!string.IsNullOrEmpty(dataRow["Actual"].ToString()))
                            {
                                actual += Convert.ToDecimal(dataRow["Actual"].ToString());
                            }
                            //if (!string.IsNullOrEmpty(dataRow["Percent"].ToString()))
                            //{
                            //    percent += Convert.ToDecimal(dataRow["Percent"].ToString());
                            //}
                            row++;
                        }
                        wsDts.Cells[row, 2].Value = "Total Production";
                        wsDts.Cells[row, 2, row, 3].Merge = true;
                        wsDts.Cells[row, 4].Value = plan;
                        wsDts.Cells[row, 5].Value = actual;
                        wsDts.Cells[row, 6].Value = Math.Round(((actual / plan) * 100), 2);
                        //wsDts.Cells[row, 6].Value = Math.Round((percent/ dtFinalSummary.Rows.Count), 0);
                        wsDts.Cells[startRow, 2, row, 7].Style.Font.Size = 14;
                        wsDts.Cells[startRow, 2, row, 7].Style.Font.Bold = true;
                        wsDts.Cells[startRow, 2, row, 2].Style.HorizontalAlignment = ExcelHorizontalAlignment.Left;
                        setThinBorder(wsDts, startRow, 2, row, 7);
                    }


                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Production report-Machinewise Daily-Format-4 Report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                    Generated = "NodataFound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex); ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }
