        public static Double getDoubleValue(string value)
        {
            Double val = 0;
            try
            {
                if (!string.IsNullOrEmpty(value))
                {
                    val = Convert.ToDouble(value);
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("getDoubleValue" + ex.Message);
            }
            return val;
        }
