                    var distList = dt.AsEnumerable().Select(x => new { shiftDate = x.Field<DateTime>("ShiftDate"), shiftID = x.Field<int>("ShiftID"), machineID = x.Field<string>("MachineID"), operatorID = x.Field<string>("OperatorID") }).Distinct().ToList();
                    workSheet.Cells["B3"].Value = fromDate.ToString("dd-MM-yyyy");
