                    double hourTotalIncentiveTotal = 0, shiftIncentiveTotal = 0;
                    for (int distC = 0; distC < distList.Count; distC++)
                    {
                        colCount = 1;
                        //var dataRows = dt.AsEnumerable().Where(x => x.Field<DateTime>("ShiftDate") == distList[distC].shiftDate && x.Field<int>("ShiftID") == distList[distC].shiftID && x.Field<string>("MachineID") == distList[distC].machineID && x.Field<string>("ComponentID") == distList[distC].compID && x.Field<string>("OperationNo") == distList[distC].operation && x.Field<string>("OperatorID") == distList[distC].operatorID).ToList();
                        var dataRows = dt.AsEnumerable().Where(x => x.Field<DateTime>("ShiftDate") == distList[distC].shiftDate && x.Field<int>("ShiftID") == distList[distC].shiftID && x.Field<string>("MachineID") == distList[distC].machineID && x.Field<string>("OperatorID") == distList[distC].operatorID).ToList();

