                        workSheet.Cells[rowCount, colCount].Value = getDoubleValue(firstRow["ShiftProducedQty"].ToString());
                        colCount++;
                        shiftIncentiveTotalCol = colCount;
                        shiftIncentiveTotal += getDoubleValue(firstRow["ShiftIncentiveTotal"].ToString());
                        workSheet.Cells[rowCount, colCount].Value = getDoubleValue(firstRow["ShiftIncentiveTotal"].ToString());
                        rowCount++;
                    }
                    workSheet.Row(rowCount).Style.Font.Bold = true;
                    workSheet.Cells[rowCount, hourTotalIncentiveCol - 1].Value = "Total";
                    workSheet.Cells[rowCount, hourTotalIncentiveCol].Value = "Rs. " + hourTotalIncentiveTotal;
                    workSheet.Cells[rowCount, shiftIncentiveTotalCol].Value = "Rs. " + shiftIncentiveTotal;
