        #region ------- Daily Rejection Report_Agg -------------
        internal static string DailyRejectionReport_Agg(DateTime fromDate, DateTime toDate, string PlantID, string OperatorId, string MachineId, string ComponentID, string cellID)
        {
            string Generated = "";
            string Source = string.Empty, destination = string.Empty, Template = string.Empty, time = string.Empty;

            DataTable dt = new DataTable();
            string Filename = "DailyRejectionReport_Agg.xlsx";
            Source = Util.GetReportPath(Filename);
            Template = "DailyRejectionReport_" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("Daily Rejection Report- \n " + Source);
            }
            try
            {
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var ws = Excel.Workbook.Worksheets[1];
                dt = TMPTrakDataBase.GetDailyRejectionReportData_Agg(fromDate, toDate, OperatorId, PlantID, MachineId, ComponentID, cellID);

                if (dt != null && dt.Rows.Count > 0)
                {

                    ws.Cells["B3"].Value = fromDate.ToString("dd-MM-yyyy");
                    ws.Cells["D3"].Value = toDate.ToString("dd-MM-yyyy");
                    ws.Cells["F3"].Value = PlantID.Equals("") ? "All" : PlantID;
                    ws.Cells["H3"].Value = ComponentID.Equals("") ? "All" : ComponentID;
                    ws.Cells["J3"].Value = OperatorId.Equals("") ? "All" : OperatorId;
                    int row = 6, col = 1;
                    foreach (DataRow item in dt.Rows)
                    {
                        col = 1;
                        ws.Cells[row, col].Value = Convert.ToDateTime(item["Date"]).ToString("yyyy-MM-dd HH:mm:ss");
                        col++;
                        ws.Cells[row, col].Value = item["Shift"];
                        col++;
                        ws.Cells[row, col].Value = item["Machineid"];
                        col++;
                        ws.Cells[row, col].Value = item["Componentid"];
                        col++;
                        ws.Cells[row, col].Value = item["Operationno"];
                        col++;
                        ws.Cells[row, col].Value = item["EmployeeName"];
                        col++;
                        ws.Cells[row, col].Value = item["RejectionCatagory"];
                        col++;
                        ws.Cells[row, col].Value = item["RejectionCode"];
                        col++;
                        ws.Cells[row, col].Value = item["Rejection Qty"];
                        row++;
                    }
                    row--;

                    ws.Cells[3, 1, row, col + 1].AutoFitColumns();
                    ws.Cells[6, 1, row, col].Style.Border.Top.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    ws.Cells[6, 1, row, col].Style.Border.Left.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    ws.Cells[6, 1, row, col].Style.Border.Right.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    ws.Cells[6, 1, row, col].Style.Border.Bottom.Style = OfficeOpenXml.Style.ExcelBorderStyle.Thin;
                    ws.Cells[6, 1, row, col].Style.Border.Top.Color.SetColor(System.Drawing.Color.Black);
                    ws.Cells[6, 1, row, col].Style.Border.Left.Color.SetColor(System.Drawing.Color.Black);
                    ws.Cells[6, 1, row, col].Style.Border.Right.Color.SetColor(System.Drawing.Color.Black);
                    ws.Cells[6, 1, row, col].Style.Border.Bottom.Color.SetColor(System.Drawing.Color.Black);

                    var table = ws.Tables.Add(ws.Cells[6, 1, row, col], "myTable");
                    table.ShowHeader = false;
                    table.TableStyle = OfficeOpenXml.Table.TableStyles.Light8;
                    var ws1 = Excel.Workbook.Worksheets[2];
                    ExcelPivotTable pivotTable = ws1.PivotTables.Add(ws1.Cells["A2"], ws.Cells[5, 1, row, col], "pivotTable");

                    pivotTable.RowFields.Add(pivotTable.Fields["Date"]);
                    pivotTable.RowFields.Add(pivotTable.Fields["Shift"]);
                    pivotTable.RowFields.Add(pivotTable.Fields["MachineID"]);
                    pivotTable.RowFields.Add(pivotTable.Fields["ComponentID"]);
                    pivotTable.RowFields.Add(pivotTable.Fields["OperationNo"]);
                    pivotTable.RowFields.Add(pivotTable.Fields["Employee Name"]);
                    pivotTable.RowFields.Add(pivotTable.Fields["Rejection Category"]);
                    pivotTable.RowFields.Add(pivotTable.Fields["Rejection Code"]);
                    pivotTable.DataFields.Add(pivotTable.Fields["Rejection Qty"]);

                    pivotTable.ShowHeaders = true;
                    pivotTable.DataOnRows = false;
                    pivotTable.Compact = false;
                    pivotTable.CompactData = false;
                    pivotTable.Indent = 0;
                    pivotTable.RowGrandTotals = false;
                    pivotTable.UseAutoFormatting = true;
                    pivotTable.ShowMemberPropertyTips = false;

                    (from pf in pivotTable.Fields
                     select pf).ToList().ForEach(f =>
                     {
                         f.Compact = false;
                         f.Outline = false;
                         f.SubTotalFunctions = eSubTotalFunctions.None;
                         f.SubtotalTop = false;

                     });

                    ws1.Column(1).Width = 20;
                    ws1.Column(2).Width = 20;
                    ws1.Column(3).Width = 29;
                    ws1.Column(4).Width = 55;
                    ws1.Column(5).Width = 15;
                    ws1.Column(6).Width = 20;
                    ws1.Column(7).Width = 20;
                    ws1.Column(8).Width = 25;
                    ws1.Column(9).Width = 15;
                    ws1.Row(2).Hidden = true;
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Logger.WriteDebugLog("Daily Rejection Report Generated Successfully.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("Error in FlowMeterReport:" + ex.ToString());
            }
            return Generated;
        }

        #endregion

        #region Data Traceability Report Advik Panth
        internal static string DataTraceabilityReportAdvikPanth(DateTime fromDate, DateTime toDate, string model, string qrCodeSearch)
        {
            string Generated = "";
            string time = string.Empty;
            string Filename = "TraceabilityReport_AdvikPanth.xlsx";
            string Source = Util.GetReportPath(Filename);
            string TimeFormat = DataBaseAccess.GetCockitSettings();
            string Template = "TraceabilityReport" + DateTime.Now + ".xlsx";
            string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("TraceabilityReport_AdvikPanth template does not found at - \n " + Source);
            }
            try
            {
                DataTable dt = TMPTrakDataBase.GetTraceabilityReportAdvikPanthData(fromDate, toDate, model, qrCodeSearch);
                if (dt != null && dt.Rows.Count > 0)
                {
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var workBook = Excel.Workbook;
                    var workSheet = workBook.Worksheets[1];

                    int rowCount = 5;
                    int rowStart = rowCount;
                    workSheet.Cells["F2"].Value = fromDate.ToString("dd-MM-yyyy");
                    workSheet.Cells["G2"].Value = toDate.ToString("dd-MM-yyyy");
                    workSheet.Cells["H2"].Value = qrCodeSearch;
                    workSheet.Cells["I2"].Value = model;

                    var distBarCode = dt.AsEnumerable().Select(k => new { BarCode = k.Field<string>("Barcode"), Model = k.Field<string>("Model") });
                    foreach (var item in distBarCode)
                    {
                        DataTable tempDt = dt.AsEnumerable().Where(k => k.Field<string>("Barcode") == item.BarCode && k.Field<string>("Model") == item.Model).CopyToDataTable();
                        workSheet.Cells[rowCount, 1].Value = item.Model;
                        workSheet.Cells[rowCount, 2].Value = item.BarCode;
                        var row = tempDt.AsEnumerable().Where(k => k.Field<int>("OpnNo") == 50).FirstOrDefault();
                        if (row != null)
                        {
                            workSheet.Cells[rowCount, 3].Value = string.IsNullOrEmpty(row["Date"].ToString()) ? "" : Util.GetDateTime(row["Date"].ToString()).ToString("dd-MM-yyyy") + " - " + row["ShiftName"].ToString();
                        }
                        row = tempDt.AsEnumerable().Where(k => k.Field<int>("OpnNo") == 90).FirstOrDefault();
                        if (row != null)
                        {
                            if (!string.IsNullOrEmpty(row["Result"].ToString()))
                            {
                                workSheet.Cells[rowCount, 4].Value = row["RPMValue"];
                                workSheet.Cells[rowCount, 5].Value = row["Result"];
                                workSheet.Cells[rowCount, 6].Value = string.IsNullOrEmpty(row["Date"].ToString()) ? "" : Util.GetDateTime(row["Date"].ToString()).ToString("dd-MM-yyyy") + " - " + row["ShiftName"].ToString();
                            }
                        }
                        var dataRows = tempDt.AsEnumerable().Where(k => k.Field<int>("OpnNo") == 100).ToList();
                        int paramCount = 0;
                        if (dataRows != null)
                        {
                            foreach (DataRow dataRow in dataRows)
                            {
                                if (!string.IsNullOrEmpty(dataRow["Result"].ToString()))
                                {
                                    workSheet.Cells[rowCount + paramCount, 7].Value = dataRow["ParameterID"];
                                    workSheet.Cells[rowCount + paramCount, 8].Value = dataRow["Result"];
                                    workSheet.Cells[rowCount + paramCount, 9].Value = string.IsNullOrEmpty(row["Date"].ToString()) ? "" : Util.GetDateTime(row["Date"].ToString()).ToString("dd-MM-yyyy") + " - " + row["ShiftName"].ToString();
                                    paramCount++;
                                }
                            }
                        }
                        if (paramCount > 1)
                        {
                            for (int i = 1; i <= 6; i++)
                            {
                                workSheet.Cells[rowCount, i, rowCount + paramCount - 1, i].Merge = true;
                            }
                            workSheet.Cells[rowCount, 9, rowCount + paramCount - 1, 9].Merge = true;
                            rowCount = rowCount + paramCount;
                        }
                        else
                        {
                            rowCount++;
                        }
                    }
                    //workSheet.Cells[rowStart, 1, rowCount, 9].AutoFitColumns();
                    setThinBorder(workSheet, rowStart, 1, rowCount - 1, 9);
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    Generated = "Generated";
                }
                else
                {
                    Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Generated = "";
                Logger.WriteErrorLog(ex.Message);
            }
            return Generated;
        }
        #endregion

        #region ---- CUMI Report ----
        internal static string GenerateCumiProductionRejectionReport(string screenType, string selectedMenu, string plant, string fromDate, string toDate, string year, string month)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "CumiProductionRejectionReport.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = ((screenType == "AcceptedScreen") ? "Production" : "Quality") + "_" + selectedMenu.Replace("Menu", "") + "_" + DateTime.Now.ToString("dd-MMM-yyyy") + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("CumiProductionRejectionReport not found - " + src);
                }

                List<MachineTypeDetails> list = new List<MachineTypeDetails>();
                list = (List<MachineTypeDetails>)HttpContext.Current.Session["CumiProductionRejectionDetails"];

                if (list.Count > 0)
                {
                    FileInfo newFile = new FileInfo(src);
                    ExcelPackage pck = new ExcelPackage(newFile, true);
                    var ws = pck.Workbook.Worksheets["Sheet1"];

                    int rowStart = 3, colStart = 1, tempRow = 0, skipRow = 0;

                    ws.Cells[rowStart, colStart].Value = "Plant: ";
                    ws.Cells[rowStart, colStart].Style.Font.Bold = true;
                    colStart++;
                    ws.Cells[rowStart, colStart].Value = plant;
                    colStart++;

                    if (selectedMenu.Equals("ShiftDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("HourlyDataMenu", StringComparison.OrdinalIgnoreCase))
                    {
                        ws.Cells[rowStart, colStart].Value = "From Date: ";
                        ws.Cells[rowStart, colStart].Style.Font.Bold = true;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = fromDate;
                        colStart++;

                        ws.Cells[rowStart, colStart].Value = "To Date: ";
                        ws.Cells[rowStart, colStart].Style.Font.Bold = true;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = toDate;
                        colStart++;
                    }
                    else if (selectedMenu.Equals("DayDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("WeekDataMenu", StringComparison.OrdinalIgnoreCase))
                    {
                        ws.Cells[rowStart, colStart].Value = "Year:";
                        ws.Cells[rowStart, colStart].Style.Font.Bold = true;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = year;
                        colStart++;

                        ws.Cells[rowStart, colStart].Value = "Month: ";
                        ws.Cells[rowStart, colStart].Style.Font.Bold = true;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = month;
                        colStart++;
                    }
                    else if (selectedMenu.Equals("MonthDataMenu", StringComparison.OrdinalIgnoreCase))
                    {
                        ws.Cells[rowStart, colStart].Value = "Year:";
                        ws.Cells[rowStart, colStart].Style.Font.Bold = true;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = year;
                        colStart++;
                    }

                    rowStart = rowStart + 2;
                    int rowStartCopy = rowStart;
                    colStart = 1;

                    bool previousDateVisibility = false;
                    bool previousShiftVisibility = false;

                    var chart = (dynamic)null;
                    if (selectedMenu.Equals("DayDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("WeekDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("MonthDataMenu", StringComparison.OrdinalIgnoreCase))
                    {
                        chart = ws.Drawings.AddChart("chart", eChartType.Line);
                    }



                    int chartXaxisFromRow = 0, chartXaxisFromColumn = 0, chartXaxisToRow = 0, chartXaxisToColumn = 0;

                    for (int i = 0; i < list.Count; i++)
                    {
                        skipRow = 0;
                        colStart = 1;

                        if (i == 0)
                        {
                            if (list[i].DateHeaderVisibility != "none")
                            {
                                CUMIHeaderSet(ws, rowStart, colStart, "Date");
                                colStart++;
                            }
                            if (list[i].ShiftHeaderVisibility != "none")
                            {
                                CUMIHeaderSet(ws, rowStart, colStart, "Shift");
                                colStart++;
                            }
                            if (list[i].HeaderVisibility != "none")
                            {

                                CUMIHeaderSet(ws, rowStart, colStart, "Machine ID");
                                colStart++;
                            }
                            if (list[i].PlanActualHeaderVisibility != "none")
                            {

                                CUMIHeaderSet(ws, rowStart, colStart, "");
                                //ws.Cells[rowStart, colStart].Value = list[i].PlanName;
                                //rowStart++;
                                //ws.Cells[rowStart, colStart].Value = list[i].ActualName;
                                //rowStart++;
                                //if (screenType.Equals("AcceptedScreen", StringComparison.OrdinalIgnoreCase))
                                //{
                                //    ws.Cells[rowStart, colStart].Value = list[i].RowCompletionName;
                                //    rowStart++;
                                //}
                                colStart++;
                            }

                            chartXaxisFromRow = rowStart;
                            chartXaxisFromColumn = colStart;
                            chartXaxisToRow = rowStart;
                            for (int j = 0; j < list[i].DynamicColumnDetails.Count - 1; j++)// -1 for chart remove
                            {
                                CUMIHeaderSet(ws, rowStart, colStart, list[i].DynamicColumnDetails[j].HeaderName);
                                colStart++;

                                if (j == list[i].DynamicColumnCountForExport - 1)
                                {
                                    chartXaxisToColumn = colStart - 1;
                                }
                            }
                            rowStart++;
                        }
                        else
                        {
                            bool isTotalRow = false;

                            if (list[i].DateConentVisibility != "none" || previousDateVisibility)
                            {
                                if (list[i].DateConentVisibility != "none")
                                {
                                    ws.Cells[rowStart, colStart].Value = list[i].Date;
                                    ws.Cells[rowStart, colStart, rowStart + list[i].DateRowSpanForExport - 1, colStart].Merge = true;
                                    ws.Cells[rowStart, colStart, rowStart + list[i].DateRowSpanForExport - 1, colStart].Style.VerticalAlignment = ExcelVerticalAlignment.Top;
                                    previousDateVisibility = true;
                                }
                                else if (previousDateVisibility)
                                {

                                }
                                colStart++;
                            }
                            if (list[i].ShiftConentVisibility != "none" || previousShiftVisibility)
                            {
                                if (list[i].ShiftConentVisibility != "none")
                                {
                                    ws.Cells[rowStart, colStart].Value = list[i].Shift;

                                    //if (list[i].ShiftRowSpan > 0)
                                    //{
                                    //    ws.Cells[rowStart, colStart, rowStart + list[i].ShiftRowSpan, colStart].Merge = true;
                                    previousShiftVisibility = true;
                                    //}
                                }
                                else if (previousShiftVisibility)
                                {

                                }
                                colStart++;
                            }
                            if (list[i].ContentVisibility != "none")
                            {
                                ws.Cells[rowStart, colStart].Value = list[i].MachineID;
                                ws.Cells[rowStart, colStart, (rowStart + list[i].MachineIDRowSpanForExport), colStart].Merge = true;
                                ws.Cells[rowStart, colStart, (rowStart + list[i].MachineIDRowSpanForExport), colStart].Style.VerticalAlignment = ExcelVerticalAlignment.Top;
                                if (list[i].RowBackColor != "")
                                {
                                    isTotalRow = true;
                                    ws.Cells[rowStart, colStart, (rowStart + list[i].MachineIDRowSpanForExport), colStart + list[i].DynamicColumnDetails.Count].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                    ws.Cells[rowStart, colStart, (rowStart + list[i].MachineIDRowSpanForExport), colStart + list[i].DynamicColumnDetails.Count].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#FAEBD7"));
                                }
                                colStart++;
                            }
                            if (list[i].PlanActualConentVisibility != "none")
                            {
                                tempRow = rowStart;
                                ws.Cells[tempRow, colStart].Value = list[i].PlanName;
                                tempRow++;
                                ws.Cells[tempRow, colStart].Value = list[i].ActualName;
                                tempRow++;
                                if (list[i].RowCompletionNameVisibility != "none")
                                {
                                    ws.Cells[tempRow, colStart].Value = list[i].RowCompletionName;
                                    tempRow++;
                                }
                                colStart++;
                            }
                            int mergedRow = 0;
                            int chartYaxisFromRow = 0, chartYaxisFromColumn = 0, chartYaxisToRow = 0, chartYaxisToColumn = 0;
                            for (int j = 0; j < list[i].DynamicColumnDetails.Count; j++)
                            {
                                if (list[i].DynamicColumnDetails[j].DynamicOneRowVisibility != "none")
                                {
                                    ws.Cells[rowStart, colStart].Value = GetDoubleValue(list[i].DynamicColumnDetails[j].Value);
                                    colStart++;
                                }
                                else if (list[i].DynamicColumnDetails[j].DynamicTwoRowsVisibility != "none")
                                {
                                    if (selectedMenu.Equals("DayDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("WeekDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("MonthDataMenu", StringComparison.OrdinalIgnoreCase))
                                    {
                                        if (j == 0)
                                        {
                                            //chartYaxisFromRow = rowStart;
                                            chartYaxisFromColumn = colStart;
                                            //chartYaxisToRow = rowStart;
                                        }
                                    }


                                    tempRow = rowStart;
                                    ws.Cells[tempRow, colStart].Value = GetDoubleValue(list[i].DynamicColumnDetails[j].Plan);

                                    if (selectedMenu.Equals("DayDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("WeekDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("MonthDataMenu", StringComparison.OrdinalIgnoreCase))
                                    {
                                        if (j == list[i].DynamicColumnCountForExport - 1)
                                        {
                                            chartYaxisToColumn = colStart;

                                            ExcelChartSerie ch1 = chart.Series.Add(ExcelRange.GetAddress(tempRow, chartYaxisFromColumn, tempRow, chartYaxisToColumn), ExcelRange.GetAddress(chartXaxisFromRow, chartXaxisFromColumn, chartXaxisToRow, chartXaxisToColumn));
                                            ch1.Header = list[i].MachineID + " " + (screenType == "AcceptedScreen" ? "Plan" : "Production");
                                        }
                                    }

                                    tempRow++;

                                    ws.Cells[tempRow, colStart].Value = GetDoubleValue(list[i].DynamicColumnDetails[j].Actual);

                                    if (selectedMenu.Equals("DayDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("WeekDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("MonthDataMenu", StringComparison.OrdinalIgnoreCase))
                                    {
                                        if (j == list[i].DynamicColumnCountForExport - 1)
                                        {
                                            chartYaxisToColumn = colStart;

                                            ExcelChartSerie ch1 = chart.Series.Add(ExcelRange.GetAddress(tempRow, chartYaxisFromColumn, tempRow, chartYaxisToColumn), ExcelRange.GetAddress(chartXaxisFromRow, chartXaxisFromColumn, chartXaxisToRow, chartXaxisToColumn));
                                            ch1.Header = list[i].MachineID + " Actual";
                                        }
                                    }

                                    tempRow++;
                                    if (list[i].DynamicColumnDetails[j].RowCompletionVisibility != "none")
                                    {
                                        ws.Cells[tempRow, colStart].Value = GetDoubleValue(list[i].DynamicColumnDetails[j].RowCompletion);
                                        tempRow++;
                                    }
                                    colStart++;
                                    skipRow = tempRow - rowStart;
                                    mergedRow = skipRow;



                                }
                                else if (list[i].DynamicColumnDetails[j].DynamicMergedRowVisibility != "none")
                                {
                                    if (isTotalRow)
                                    {
                                        ws.Cells[rowStart, colStart].Value = "";
                                    }
                                    else
                                    {
                                        ws.Cells[rowStart, colStart].Value = GetDoubleValue(list[i].DynamicColumnDetails[j].Completion);
                                    }

                                    ws.Cells[rowStart, colStart, rowStart + mergedRow + (mergedRow == 0 ? 0 : -1), colStart].Merge = true;
                                    ws.Cells[rowStart, colStart, rowStart + mergedRow + (mergedRow == 0 ? 0 : -1), colStart].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                                    colStart++;
                                }
                            }
                            if (skipRow > 0)
                            {
                                rowStart += skipRow;
                            }
                            else
                            {
                                rowStart++;
                            }


                        }
                    }

                    rowStart--;
                    colStart--;


                    ws.Cells[1, 1].Value = selectedMenu.Equals("ShiftDataMenu", StringComparison.OrdinalIgnoreCase) ? "Shift Data" : selectedMenu.Equals("HourlyDataMenu", StringComparison.OrdinalIgnoreCase) ? "Hourly Data" : selectedMenu.Equals("DayDataMenu", StringComparison.OrdinalIgnoreCase) ? "Day Data" : selectedMenu.Equals("WeekDataMenu", StringComparison.OrdinalIgnoreCase) ? "Week Data" : selectedMenu.Equals("MonthDataMenu", StringComparison.OrdinalIgnoreCase) ? "Monthly Data" : "";
                    ws.Cells[1, 1].Style.Font.Bold = true;
                    ws.Cells[1, 1].Style.Font.Color.SetColor(Color.White);
                    ws.Cells[1, 1].Style.Font.Size = 17;
                    ws.Cells[1, 1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                    ws.Cells[1, 1].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#0070c0"));
                    ws.Cells[1, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                    ws.Cells[1, 1, 1, colStart].Merge = true;

                    ws.Cells[rowStartCopy, 1, rowStart, colStart].AutoFitColumns();
                    // Assign borders
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Top.Color.SetColor(Color.Black);
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Right.Color.SetColor(Color.Black);
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Left.Color.SetColor(Color.Black);
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Bottom.Color.SetColor(Color.Black);


                    if (selectedMenu.Equals("DayDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("WeekDataMenu", StringComparison.OrdinalIgnoreCase) || selectedMenu.Equals("MonthDataMenu", StringComparison.OrdinalIgnoreCase))
                    {
                        chart.SetSize(1500, 350);
                        chart.Title.Text = selectedMenu.Equals("DayDataMenu", StringComparison.OrdinalIgnoreCase) ? "Day Wise Chart" : selectedMenu.Equals("WeekDataMenu", StringComparison.OrdinalIgnoreCase) ? "Week Wise Chart" : selectedMenu.Equals("MonthDataMenu", StringComparison.OrdinalIgnoreCase) ? "Month Wise Chart" : "";
                        chart.Title.Font.Bold = true;
                        chart.Title.Font.Size = 18;
                        chart.Legend.Position = eLegendPosition.Bottom;
                        chart.SetPosition(rowStart + 2, 10, 1, 10);
                    }



                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("OperatorDrawingNo report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog("GenerateCumiProductionRejectionReport :  " + ex.Message);
            }
            return Generated;
        }

