        internal static string GenerateCumiPlanEntryDetails(string fromDate, string toDate, List<PlanDetails> list)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "CumiPlanEntryReport.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "CumiPlanEntryReport_" + DateTime.Now.ToString("dd_MM_yyyy HH_mm_ss") + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("CumiPlanEntryReport not found - " + src);
                }

                if (true)
                {
                    FileInfo newFile = new FileInfo(src);
                    ExcelPackage pck = new ExcelPackage(newFile, true);
                    var ws = pck.Workbook.Worksheets["Sheet1"];

