        private static Double GetDoubleValue(string value)
        {
            Double output = (default);
            try
            {

                if (value == "." || string.IsNullOrEmpty(value))
                {
                    output = (default);
                }
                else
                {
                    output = Convert.ToDouble(value);
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("GetDoubleValue: " + ex.Message);
            }
            return output;
        }

