        private static void HeaderSet(ExcelWorksheet ws, int row, int col, string value, bool merge)
        {
            try
            {
                int newrow = 1;
                ws.Cells[row, col].Value = value;
                ws.Cells[row, col].Style.Font.Color.SetColor(Color.White);
                ws.Cells[row, col].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                ws.Cells[row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                ws.Cells[row, col].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#0070c0"));

                newrow = row;
                if (merge)
                {
                    ws.Cells[row, col, row + 1, col].Merge = true;
                    newrow = row + 1;
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("CUMIHeaderSet: " + ex.Message);
            }
        }

