            }
        }
        internal static string GenerateCumiCoolingTowerReport(DataTable dt, DateTime Fromdate, DateTime Todate, string shift)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "CoolingTowerReport.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "CoolingTowerReport" + DateTime.Now.ToString("dd_MM_yyyy HH_mm_ss") + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("CoolingTowerReport not found - " + src);
                }
                if (true)
                {
                    FileInfo newFile = new FileInfo(src);
                    ExcelPackage pck = new ExcelPackage(newFile, true);
                    var ws = pck.Workbook.Worksheets["Sheet1"];

                    ws.Cells["B3"].Value = Fromdate;
                    ws.Cells["F3"].Value = Todate;
                    ws.Cells["J3"].Value = shift.Replace("'", "");

                    int rowStart = 5, colStart = 1, Actualheader = 1, copyheader = 1;
                    string mainHeader = string.Empty;
                    int rowStartCopy = rowStart + 2;

                    if (dt.Rows.Count > 0)
                    {
                        List<string> cols = dt.Columns.Cast<DataColumn>().Select(x => x.ColumnName).ToList();
                        HeaderSet(ws, rowStart, colStart, "Date", true);
                        colStart++;
                        HeaderSet(ws, rowStart, colStart, "Shift", true);
                        colStart++;
                        for (int j = 5; j < cols.Count; j++)
                        {
                            string[] headers = cols[j].Split('[', ']');
                            if (!mainHeader.Equals(headers[0]))
                            {

                                HeaderSetMainHeader(ws, rowStart, colStart, headers[0], false);
                                Actualheader = colStart;
                            }
                            else
                            {
                                ws.Cells[rowStart, Actualheader, rowStart, colStart].Merge = true;

                            }
                            HeaderSet(ws, rowStart + 1, colStart, headers[1], false);
                            mainHeader = headers[0];
                            colStart++;
                        }

                        ws.Cells[5, copyheader, rowStart + 1, colStart].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                        ws.Cells[5, copyheader, rowStart + 1, colStart].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                        ws.Cells[5, copyheader, rowStart + 1, colStart].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                        ws.Cells[5, copyheader, rowStart + 1, colStart].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                        ws.Cells[5, copyheader, rowStart + 1, colStart].Style.Border.Top.Color.SetColor(Color.White);
                        ws.Cells[5, copyheader, rowStart + 1, colStart].Style.Border.Right.Color.SetColor(Color.White);
                        ws.Cells[5, copyheader, rowStart + 1, colStart].Style.Border.Left.Color.SetColor(Color.White);
                        ws.Cells[5, copyheader, rowStart + 1, colStart].Style.Border.Bottom.Color.SetColor(Color.White);
                        rowStart = rowStart + 2;

                        for (int j = 0; j < dt.Rows.Count; j++)
                        {
                            colStart = 1;
                            ws.Cells[rowStart, colStart].Value = Util.GetDateTime(dt.Rows[j]["Date"].ToString()).ToString("yyyy-MM-dd");
                            colStart++;
                            ws.Cells[rowStart, colStart].Value = dt.Rows[j]["ShiftName"].ToString();
                            colStart++;
                            for (int k = 5; k < cols.Count; k++)
                            {
                                if (!string.IsNullOrEmpty(dt.Rows[j][k].ToString()))
                                {
                                    ws.Cells[rowStart, colStart].Value = Convert.ToDouble(dt.Rows[j][k].ToString());
                                }
                                else
                                    ws.Cells[rowStart, colStart].Value = string.Empty;
                                colStart++;
                            }
                            rowStart++;
                        }
                        colStart--;
                        rowStart--;
                        ws.Cells[7, 1, rowStart, colStart].AutoFitColumns();
                        //Assign borders
                        ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                        ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                        ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                        ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                        ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Top.Color.SetColor(Color.Black);
                        ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Right.Color.SetColor(Color.Black);
                        ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Left.Color.SetColor(Color.Black);
                        ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Bottom.Color.SetColor(Color.Black);

                        DownloadMultipleFile(dst, pck.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                    {
                        Generated = "Nodatafound";
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog("CoolingTowerReport :  " + ex.Message);
            }
            return Generated;
        }

