        private static void CumiHeaderSet(ExcelWorksheet ws, int row, int col, string value, bool merge)
        {
            try
            {
                ws.Cells[row, col].Value = value;
                ws.Cells[row, col].Style.Fill.PatternType = ExcelFillStyle.Solid;
                ws.Cells[row, col].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#DDEBF7"));

                if (merge)
                {
                    ws.Cells[row, col, row, col + 1].Merge = true;
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("CUMIHeaderSet: " + ex.Message);
            }
        }
        internal static string GenerateCumiQuarterlyComplianceReport(DataTable dt, int year, string machine)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "QuarterlyComplianceReport.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "QuarterlyComplianceReport" + DateTime.Now.ToString("dd_MM_yyyy HH_mm_ss") + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Quarterly Compliance Report not found - " + src);
                }
                if (true)
                {
                    FileInfo newFile = new FileInfo(src);
                    ExcelPackage pck = new ExcelPackage(newFile, true);
                    var ws = pck.Workbook.Worksheets["Sheet1"];

                    ws.Cells["B3"].Value = year;
                    ws.Cells["E3"].Value = machine.Replace("'", "");

                    int rowStart = 5, colStart = 1;
                    int rowStartCopy = rowStart;

                    if (dt.Rows.Count > 0)
                    {
                        var distMonthVal = dt.AsEnumerable().Select(x => x.Field<string>("MonthName")).Distinct().ToList();
                        var distMach = dt.AsEnumerable().Select(x => x.Field<string>("MachineID")).Distinct().ToList();

                        CumiHeaderSet(ws, rowStart, colStart, "Machine", false);
                        colStart++;
                        CumiHeaderSet(ws, rowStart, colStart, "", false);
                        colStart++;
                        for (int distc = 0; distc < distMonthVal.Count; distc++)
                        {
                            CumiHeaderSet(ws, rowStart, colStart, distMonthVal[distc], true);
                            colStart = colStart + 2;
                        }
                        colStart--;

                        rowStart++;
                        for (int i = 0; i < distMach.Count; i++)
                        {
                            var Machinedt = dt.AsEnumerable().Where(x => x.Field<string>("MachineID").Equals(distMach[i])).Distinct().CopyToDataTable();

                            colStart = 1;
                            ws.Cells[rowStart, colStart].Value = distMach[i];
                            ws.Cells[rowStart, colStart, rowStart + 1, colStart].Merge = true;
                            colStart++;
                            ws.Cells[rowStart, colStart].Value = "Plan";
                            ws.Cells[rowStart + 1, colStart].Value = "Actual";
                            colStart++;

                            for (int k = 0; k < Machinedt.Rows.Count; k++)
                            {
                                ws.Cells[rowStart, colStart].Value = Machinedt.Rows[k]["PlannedDate"];
                                ws.Cells[rowStart + 1, colStart++].Value = Machinedt.Rows[k]["ActualDate"];
                                ws.Cells[rowStart, colStart].Value = Machinedt.Rows[k]["PlannedCheckpoint"];
                                ws.Cells[rowStart + 1, colStart++].Value = Machinedt.Rows[k]["ActualCheckpoint"];
                            }
                            rowStart = rowStart + 2;
                        }

                        rowStart--;
                        colStart--;

                        ws.Cells[rowStartCopy, 2, rowStart, colStart].AutoFitColumns();
                        setThinBorder(ws, rowStartCopy, 1, rowStart, colStart);
                        DownloadMultipleFile(dst, pck.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                    {
                        Generated = "Nodatafound";
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog("QuarterlyComplianceReport :  " + ex.Message);
            }
            return Generated;
        }

        internal static string GenerateFrequencywiseReportCumi(DataTable dt)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "FrequencywiseReport_Cumi.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "FrequencywiseReport_Cumi_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("FrequencywiseReport_Cumi not found - " + src);
                }

                if (dt.Rows.Count > 0)
                {
                    FileInfo newFile = new FileInfo(src);
                    ExcelPackage pck = new ExcelPackage(newFile, true);
                    var ws = pck.Workbook.Worksheets["Sheet1"];

                    int rowStart = 3, colStart = 1, Slno = 1;
                    int rowStartCopy = rowStart;

                    var distMonth = dt.AsEnumerable().Select(k => new { Month = k["MonthName"].ToString(), Year = k["YearNo"].ToString() }).Distinct().ToList();
                    var distlist = dt.AsEnumerable().Select(x => new { MachineID = x["MachineID"].ToString(), ActivityId = x["ActivityID"], Activity = x["Activity"].ToString(), Frequency = x["Frequency"].ToString(), Category = x["Category"].ToString() }).Distinct().ToList();

                    colStart = 6;
                    int lastColumn = 1;
                    foreach (var item in distMonth)
                    {
                        ws.Cells[rowStart, colStart].Value = item.Month;
                        ws.Cells[rowStart, colStart, rowStart, colStart + 2].Merge = true;
                        ws.Cells[rowStart + 1, colStart].Value = "Status";
                        colStart++;
                        ws.Cells[rowStart + 1, colStart].Value = "Action";
                        colStart++;
                        ws.Cells[rowStart + 1, colStart].Value = "Remarks";
                        colStart++;
                    }
                    lastColumn = colStart - 1;
                    rowStart = rowStart + 2;

                    for (int i = 0; i < distlist.Count; i++)
                    {
                        var distC = dt.AsEnumerable().Where(x => x.Field<string>("MachineID").Equals(distlist[i].MachineID) && x.Field<dynamic>("ActivityID").Equals(distlist[i].ActivityId) && x.Field<string>("Activity").Equals(distlist[i].Activity) && x.Field<string>("Frequency").Equals(distlist[i].Frequency) && x.Field<string>("Category").Equals(distlist[i].Category)).Distinct().ToList();

                        colStart = 1;
                        ws.Cells[rowStart, colStart].Value = Slno++;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = distlist[i].MachineID;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = distlist[i].Activity;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = distlist[i].Frequency;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = distlist[i].Category;
                        colStart++;
                        for (int k = 0; k < distC.Count; k++)
                        {
                            ws.Cells[rowStart, colStart].Value = distC[k]["Status"];
                            colStart++;
                            ws.Cells[rowStart, colStart].Value = distC[k]["Action"];
                            colStart++;
                            ws.Cells[rowStart, colStart].Value = distC[k]["Remarks"];
                            colStart++;
                        }
                        rowStart++;
                    }
                    rowStart--;
                    colStart--;
                    ws.Cells[rowStartCopy, 2, rowStart, lastColumn].AutoFitColumns();
                    setThinBorder(ws, rowStartCopy, 1, rowStart, lastColumn);
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Frequencywise report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog("GenerateCumiProductionShiftwiseReport :  " + ex.Message);
            }
            return Generated;
        }

        internal static string GenerateCumiShiftPMActivityReport(DataTable dt, string fromDate, string toDate, string machineID)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "ShiftPMActivityReport_Cumi.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "ShiftPMActivityReport_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("ShiftPMActivityReport not found - " + src);
                }

                if (dt.Rows.Count > 0)
                {
                    FileInfo newFile = new FileInfo(src);
                    ExcelPackage pck = new ExcelPackage(newFile, true);
                    var ws = pck.Workbook.Worksheets["Sheet1"];
                    ws.Cells["B3"].Value = machineID;
                    ws.Cells["D3"].Value = fromDate;
                    ws.Cells["F3"].Value = toDate;
                    int rowStart = 5, colStart = 3, Actualheader = 1;
                    int rowStartCopy = rowStart;
                    string mainHeader = string.Empty;

                    List<string> cols = dt.Columns.Cast<DataColumn>().Select(x => x.ColumnName).ToList();

                    for (int i = 11; i < cols.Count; i++)
                    {
                        string[] headers = cols[i].Split(' ');
                        if (!mainHeader.Equals(headers[1]))
                        {
                            ws.Cells[rowStart, colStart].Value = headers[1];
                            Actualheader = colStart;
                        }
                        else
                        {
                            ws.Cells[rowStart, Actualheader, rowStart, colStart].Merge = true;
                        }
                        ws.Cells[rowStart + 1, colStart].Value = Convert.ToInt32(headers[0]);
                        mainHeader = headers[1];
                        colStart++;
                    }
                    rowStart = rowStart + 2;

                    string tempActivity = "";
                    for (int k = 0; k < dt.Rows.Count; k++)
                    {
                        colStart = 1;
                        int mergeCount = 0;

                        if (tempActivity != dt.Rows[k]["Activity"].ToString())
                        {
                            mergeCount = dt.AsEnumerable().Where(r => r["Activity"].ToString().Equals(dt.Rows[k]["Activity"])).ToList().Count();
                            ws.Cells[rowStart, colStart].Value = dt.Rows[k]["Activity"];
                            if (mergeCount > 1)
                            {
                                ws.Cells[rowStart, colStart, rowStart + mergeCount - 1, colStart].Merge = true;
                            }
                            else
                            {
                                mergeCount = 0;
                            }
                        }
                        tempActivity = dt.Rows[k]["Activity"].ToString();
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = dt.Rows[k]["Criteria"];
                        if (mergeCount > 0)
                        {
                            ws.Cells[rowStart, colStart, rowStart + mergeCount - 1, colStart].Merge = true;
                        }
                        colStart++;
                        for (int i = 11; i < cols.Count; i++)
                        {
                            ws.Cells[rowStart, colStart].Value = dt.Rows[k][i];
                            colStart++;
                        }
                        rowStart++;
                    }
                    rowStart--;
                    colStart--;

                    //ws.Cells[rowStartCopy, 1, rowStart, 2].AutoFitColumns();
                    setThinBorder(ws, rowStartCopy, 1, rowStart, colStart);
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Frequencywise report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog("GenerateCumiProductionShiftwiseReport :  " + ex.Message);
            }
            return Generated;
        }
