            Source = Util.GetReportPath(Filename);
            Template = "ProductionAnalysisReport_" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
            if (!File.Exists(Source))
            {
                Logger.WriteDebugLog("Production Analysis Report- \n " + Source);
            }
            try
            {
                FileInfo newFile = new FileInfo(Source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var wsDt = Excel.Workbook.Worksheets["ProductionAnalysisReport"];
                List<ProductionData> details = new List<ProductionData>();
                List<string> programnumber = new List<string>();
                List<string> partsCount = new List<string>();
