                details = TMPTrakDataBase.GetProductionAnalysisReportRTPL(fromDate, toDate, shiftID, plantID, machineID, "Shift", out summaryData, out programnumber, out partsCount, out OEE);

                if (details.Count > 0)
                {
                    string workSheetName = wsDt.Name;
