                    int rowStart = 3, colStart = 1;

                    if (IsFilterRequired)
                    {
                        ws.Cells[rowStart, colStart].Value = "From Date: ";
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = fromDate;
                        colStart = colStart + 2;
                        ws.Cells[rowStart, colStart].Value = "To Date: ";
                        ws.Cells[rowStart, colStart].Value = toDate;
                        rowStart = rowStart + 2;
                    }

                    int rowStartCopy = rowStart;
                    colStart = 1;
                    CUMIHeaderSet(ws, rowStart, colStart, "Item Code");
                    colStart++;
                    CUMIHeaderSet(ws, rowStart, colStart, "Item Description");
                    colStart++;
                    CUMIHeaderSet(ws, rowStart, colStart, "Updated By");
                    colStart++;
                    CUMIHeaderSet(ws, rowStart, colStart, "Updated TS");
                    colStart++;
                    CUMIHeaderSet(ws, rowStart, colStart, "Std. Cycle Time");
                    colStart++;
                    CUMIHeaderSet(ws, rowStart, colStart, "Std. Machining Time");
                    colStart++;
                    CUMIHeaderSet(ws, rowStart, colStart, "Std. Load Unload Time");
                    colStart++;
                    CUMIHeaderSet(ws, rowStart, colStart, "Machine Id");

                    rowStart++;

                    for (int i = 0; i < list.Count; i++)
                    {
                        colStart = 1;
                        ws.Cells[rowStart, colStart].Value = list[i].ItemCode;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = list[i].ItemDescription;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = list[i].UpdatedBy;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = Convert.ToDateTime(list[i].UpdatedTS).ToString("dd-MM-yyyy HH:mm:ss");
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = list[i].StdCycleTime;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = list[i].StdMachiningTime;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = list[i].StdLoadUnloadTime;
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = list[i].MachineId;
                        rowStart++;
                    }
                    rowStart--;
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].AutoFitColumns();
                    // Assign borders
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Top.Color.SetColor(Color.Black);
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Right.Color.SetColor(Color.Black);
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Left.Color.SetColor(Color.Black);
                    ws.Cells[rowStartCopy, 1, rowStart, colStart].Style.Border.Bottom.Color.SetColor(Color.Black);

                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog("GenerateItemStdCycleTimeDetails :  " + ex.Message);
            }
            return Generated;
        }

