        #region ---- Spindle Idle Time Analysis Report LnTOdisha ----
        internal static string GenerateSpindleIdleTimeAnalysisReportLnTOdisha(DateTime date, string machine, string shift)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "SpindleIdleTimeAnalysisReport_LnTOdisha.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "SpindleIdleTimeAnalysisReport_LnTOdisha_" + DateTime.Now.ToString("dd_MM_yyyy HH_mm_ss") + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("SpindleIdleTimeAnalysisReport_LnTOdisha not found - " + src);
                }
                DataTable dtTotalTime = new DataTable();
                DataTable dt = TMPTrakDataBase.GetSpindleIdleTimeAnalysisReportLnTOdisha(date, machine, shift, out dtTotalTime);
                if (dt.Rows.Count > 0)
                {
                    FileInfo newFile = new FileInfo(src);
                    ExcelPackage pck = new ExcelPackage(newFile, true);
                    var ws = pck.Workbook.Worksheets["Sheet1"];


                    ws.Cells["B3"].Value = date;
                    ws.Cells["D3"].Value = machine;
                    ws.Cells["F3"].Value = shift;

                    int rowStart = 11, colStart = 1;
                    int rowStartCopy = rowStart;
                    foreach (DataRow row in dt.Rows)
                    {
                        colStart = 1;
                        ws.Cells[rowStart, colStart].Value = row["MachineID"].ToString();
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = row["OperatorID"].ToString();
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = row["ComponentID"].ToString();
                        colStart++;
                        if (!string.IsNullOrEmpty(row["IdleStartTime"].ToString()))
                        {
                            ws.Cells[rowStart, colStart].Value = Convert.ToDateTime(row["IdleStartTime"].ToString());
                        }
                        colStart++;
                        if (!string.IsNullOrEmpty(row["IdleEndTime"].ToString()))
                        {
                            ws.Cells[rowStart, colStart].Value = Convert.ToDateTime(row["IdleEndTime"].ToString());
                        }
                        colStart++;
                        setTimeSpanFormat("hh:mm", ws, rowStart, colStart, row["IdleTime"].ToString());
                        rowStart++;
                    }

                    if (dtTotalTime.Rows.Count > 0)
                    {
                        var firstRow = dtTotalTime.Rows[0];
                        setTimeSpanFormat("hh:mm:ss", ws, 5, 2, firstRow["TotalTime"].ToString());
                        setTimeSpanFormat("hh:mm:ss", ws, 6, 2, firstRow["SpindleRunTime"].ToString());
                        setTimeSpanFormat("hh:mm:ss", ws, 7, 2, firstRow["McIdleTime"].ToString());

                        ws.Row(rowStart).Style.Font.Bold = true;
                        ws.Cells[rowStart, 1].Value = "Total";
                        ws.Cells[rowStart, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                        ws.Cells[rowStart, 1, rowStart, colStart].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        ws.Cells[rowStart, 1, rowStart, colStart].Style.Fill.BackgroundColor.SetColor(Color.Yellow);
                        ws.Cells[rowStart, 1, rowStart, 5].Merge = true;
                        setTimeSpanFormat("hh:mm", ws, rowStart, 6, firstRow["McIdleTime"].ToString());
                    }

                    //ws.Cells[rowStartCopy, 1, rowStart, colStart].AutoFitColumns();
                    setThinBorder(ws, rowStartCopy, 1, rowStart, colStart);
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex);
            }
            return Generated;
        }

