        #region ---- Spindle Runtime Report LnTOdisha ----
        internal static string GenerateSpindleRuntimeReportLnTOdisha(DateTime fromDate, DateTime toDate, string shift, string plant, string cell, string machine)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "SpindleRunTimeReport_LnTOdisha.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "SpindleRunTimeReport_LnTOdisha_" + DateTime.Now.ToString("dd_MM_yyyy HH_mm_ss") + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("SpindleRunTimeReport_LnTOdisha not found - " + src);
                }
                DataTable dtTotalTime = new DataTable();
                DataTable dt = TMPTrakDataBase.GetSpindleRunTimeReportLnTOdisha(fromDate, toDate, shift, plant, cell, machine, out dtTotalTime);
                if (dt.Rows.Count > 0)
                {
                    FileInfo newFile = new FileInfo(src);
                    ExcelPackage pck = new ExcelPackage(newFile, true);
                    var ws = pck.Workbook.Worksheets["Sheet1"];


                    ws.Cells["B3"].Value = fromDate;
                    ws.Cells["E3"].Value = toDate;
                    ws.Cells["H3"].Value = plant;


                    int rowStart = 6, colStart = 1;
                    int rowStartCopy = rowStart;
                    DateTime tempDate = new DateTime();
                    string tempShift = "", tempMachine = "", tempComponent = "";
                    foreach (DataRow row in dt.Rows)
                    {
                        int mergeRowCount = 0;
                        int mergeRowCount2 = 0;
                        if (tempDate != Convert.ToDateTime(row["pDate"].ToString()) || tempShift != row["Shift"].ToString() || tempMachine != row["MachineID"].ToString())
                        {
                            mergeRowCount = dt.AsEnumerable().Where(k => k.Field<DateTime>("pDate") == Convert.ToDateTime(row["pDate"].ToString()) && k["Shift"].ToString() == row["Shift"].ToString() && k["MachineID"].ToString() == row["MachineID"].ToString()).ToList().Count();
                        }
                        if (tempDate != Convert.ToDateTime(row["pDate"].ToString()) || tempShift != row["Shift"].ToString() || tempMachine != row["MachineID"].ToString() || tempComponent != row["ComponentID"].ToString())
                        {
                            mergeRowCount2 = dt.AsEnumerable().Where(k => k.Field<DateTime>("pDate") == Convert.ToDateTime(row["pDate"].ToString()) && k["Shift"].ToString() == row["Shift"].ToString() && k["MachineID"].ToString() == row["MachineID"].ToString() && k["ComponentID"].ToString() == row["ComponentID"].ToString()).ToList().Count();
                        }
                        tempDate = Convert.ToDateTime(row["pDate"].ToString());
                        tempShift = row["Shift"].ToString();
                        tempMachine = row["MachineID"].ToString();
                        tempComponent = row["ComponentID"].ToString();
                        colStart = 1;
                        ws.Cells[rowStart, colStart].Value = row["GroupID"].ToString();
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = row["Shift"].ToString();
                        colStart++;
                        if (!string.IsNullOrEmpty(row["pDate"].ToString()))
                        {
                            ws.Cells[rowStart, colStart].Value = Convert.ToDateTime(row["pDate"].ToString());
                        }
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = row["OperatorID"].ToString();
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = row["MachineID"].ToString();
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = row["MachineDescription"].ToString();
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = row["ComponentID"].ToString();
                        colStart++;
                        ws.Cells[rowStart, colStart].Value = row["ComponentDescription"].ToString();
                        colStart++;

                        //mergeRowCount==0 means same record don't add again
                        if (mergeRowCount >= 1)
                        {
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, colStart, row["TotalTime"].ToString());
                        }
                        if (mergeRowCount > 1)
                        {
                            ws.Cells[rowStart, colStart, rowStart + mergeRowCount - 1, colStart].Merge = true;
                        }
                        colStart++;
                        if (mergeRowCount2 >= 1)
                        {
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, colStart, row["UtilisedTime"].ToString());
                        }
                        if (mergeRowCount2 > 1)
                        {
                            ws.Cells[rowStart, colStart, rowStart + mergeRowCount2 - 1, colStart].Merge = true;
                        }
                        colStart++;
                        if (mergeRowCount2 >= 1)
                        {
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, colStart, row["SpindleRunTime"].ToString());
                        }
                        if (mergeRowCount2 > 1)
                        {
                            ws.Cells[rowStart, colStart, rowStart + mergeRowCount2 - 1, colStart].Merge = true;
                        }
                        colStart++;
                        if (mergeRowCount >= 1)
                        {
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, colStart, row["McIdleTime"].ToString());
                        }
                        if (mergeRowCount > 1)
                        {
                            ws.Cells[rowStart, colStart, rowStart + mergeRowCount - 1, colStart].Merge = true;
                        }
                        colStart++;
                        if (mergeRowCount >= 1)
                        {
                            ws.Cells[rowStart, colStart].Value = row["SpindleRunTimePercent"];
                        }
                        if (mergeRowCount > 1)
                        {
                            ws.Cells[rowStart, colStart, rowStart + mergeRowCount - 1, colStart].Merge = true;
                        }
                        colStart++;
                        if (mergeRowCount >= 1)
                        {
                            ws.Cells[rowStart, colStart].Value = row["EnergyConsumption"];
                        }
                        if (mergeRowCount > 1)
                        {
                            ws.Cells[rowStart, colStart, rowStart + mergeRowCount - 1, colStart].Merge = true;
                        }
                        rowStart++;
                    }
                    ws.Cells[rowStartCopy - 1, 1, rowStart, colStart].AutoFitColumns();
                    if (dtTotalTime.Rows.Count > 0)
                    {
                        DataRow firstRow = dtTotalTime.Rows[0];
                        setTimeSpanFormat("hh:mm:ss", ws, rowStart, 9, firstRow["TotalTime"].ToString());
                        setTimeSpanFormat("hh:mm:ss", ws, rowStart, 10, firstRow["UtilisedTime"].ToString());
                        setTimeSpanFormat("hh:mm:ss", ws, rowStart, 11, firstRow["SpindleRunTime"].ToString());
                        setTimeSpanFormat("hh:mm:ss", ws, rowStart, 12, firstRow["McIdleTime"].ToString());
                        ws.Cells[rowStart, 13].Value = firstRow["SpindleRunTimePercent"];
                        ws.Cells[rowStart, 14].Value = firstRow["EnergyConsumption"];
                        ws.Row(rowStart).Style.Font.Bold = true;
                        ws.Cells[rowStart, 1].Value = "Total/Average";
                        ws.Cells[rowStart, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                        ws.Cells[rowStart, 1, rowStart, colStart].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        ws.Cells[rowStart, 1, rowStart, colStart].Style.Fill.BackgroundColor.SetColor(Color.Yellow);
                        ws.Cells[rowStart, 1, rowStart, 8].Merge = true;
                    }

                    setThinBorder(ws, rowStartCopy, 1, rowStart, colStart);
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex);
            }
            return Generated;
        }

