        #region  --Production and Down Report ACE---
        internal static string GenerateProductionandDownReportAce(DateTime fromDate, DateTime toDate, string machineID)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "MachineUtilizationReport_ACE.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "MachineUtilizationReportACE_" + DateTime.Now.ToString("dd_MM_yyyy HH_mm_ss") + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("MachineUtilizationReport not found - " + src);
                }

                DataTable dtSummary = TMPTrakDataBase.GetProductionandDownSummaryDataACE(fromDate, toDate, machineID, out DataTable dtDownReasons);
                DataTable dtCyclewise = TMPTrakDataBase.GetProductionandDownCyclewiseDataACE(fromDate, toDate, machineID);
                DataTable dtScrap = TMPTrakDataBase.GetProductionandDownScrapDataACE(fromDate, toDate, machineID);

                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                int rowStart = 3, colStart = 2, srowStart = 0;
                int rowStartCopy = rowStart;

                if (dtSummary.Rows.Count > 0 || dtCyclewise.Rows.Count > 0 || dtScrap.Rows.Count > 0)
                {
                    #region ---Overview----
                    if (dtSummary.Rows.Count > 0)
                    {
                        var ws = pck.Workbook.Worksheets["Overview"];
                        ws.Cells["B1"].Value = fromDate.ToString("dd-MM-yyyy HH:mm:ss");
                        ws.Cells["D1"].Value = toDate.ToString("dd-MM-yyyy HH:mm:ss");
                        ws.Cells["D2"].Value = fromDate.ToString("MMM-yy");
                        ws.Cells["A2"].Value = machineID + " Utilization";

                        rowStart = 4; colStart = 2;
                        rowStartCopy = rowStart;
                        foreach (DataRow item in dtSummary.Rows)
                        {
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, 2, item["AvailableHours"].ToString());
                            rowStart++;
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, 2, item["PlannedTimeInHrs"].ToString());
                            ws.Cells[rowStart, 3].Value = getdouble(item["PlannedTimePercent"].ToString());
                            rowStart++;
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, 2, item["MachiningTimeInHrs"].ToString());
                            ws.Cells[rowStart, 3].Value = getdouble(item["MachiningTimePercent"].ToString());
                            rowStart++;
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, 2, item["NonMachiningTimeInHrs"].ToString());
                            ws.Cells[rowStart, 3].Value = getdouble(item["NonMachiningTimePercent"].ToString());
                            rowStart++;
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, 2, item["DevelopmentTimeInHrs"].ToString());
                            ws.Cells[rowStart, 3].Value = getdouble(item["DevelopmentPercent"].ToString());
                            rowStart++;
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, 2, item["FirstPieceSetupInHrs"].ToString());
                            ws.Cells[rowStart, 3].Value = getdouble(item["FirstPieceSetupPercent"].ToString());
                            rowStart++;
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, 2, item["PlannedDownTimeInHrs"].ToString());
                            ws.Cells[rowStart, 3].Value = getdouble(item["PlannedDownTimePercent"].ToString());
                        }
                        srowStart = rowStart = rowStart + 3;
                        foreach (DataRow item in dtDownReasons.Rows)
                        {
                            colStart = 1;
                            ws.Cells[rowStart, colStart].Value = item["DownID"];
                            colStart++;
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, colStart, item["DownTimeInHrs"].ToString());
                            colStart++;
                            ws.Cells[rowStart, colStart].Value = getdouble(item["DownPercent"].ToString());
                            rowStart++;
                        }
                        rowStart--;
                        setThinBorder(ws, 12, 1, rowStart, colStart);
                        ws.Cells[srowStart - 1, 2].Formula = "=SUM(B" + (srowStart) + ":B" + (rowStart) + ")";
                        ws.Cells[srowStart - 1, 2].Style.Numberformat.Format = "[h]:mm:ss";

                        var chart = ws.Drawings["Chart 1"] as ExcelBarChart;
                        ExcelChartSerie ch1 = chart.Series.Add(ExcelRange.GetAddress(rowStartCopy, 2, rowStartCopy + 6, 2), ExcelRange.GetAddress(rowStartCopy, 1, rowStartCopy + 6, 1));
                        ch1.Header = machineID + " Plan Vs Actual";
                        chart.VaryColors = true;
                        chart.YAxis.Title.Text = "Time in Hours";
                        chart.DataLabel.ShowValue = true;
                        //chart.Legend.Position = eLegendPosition.Right;

                        var pieChart = ws.Drawings["Chart 2"] as ExcelPieChart;
                        //pieChart.hea = machineID + " Down Time";
                        var series = pieChart.Series.Add(string.Format("B{0}:B{1}", srowStart, rowStart), string.Format("A{0}: A{1}", srowStart, rowStart));
                        series.Header = machineID + " Down Time";
                        pieChart.ShowDataLabelsOverMaximum = true;
                        pieChart.DisplayBlanksAs = eDisplayBlanksAs.Zero;
                        var pieSeries = (ExcelPieChartSerie)series;
                        pieSeries.DataLabel.ShowCategory = false;
                        pieSeries.DataLabel.ShowValue = false;
                        pieSeries.DataLabel.ShowPercent = true;
                        pieSeries.DataLabel.Position = eLabelPosition.BestFit;
                        //pieChart.Legend.Position = eLegendPosition.Right;

                        rowStart = 4;
                        foreach (DataRow item in dtSummary.Rows)
                        {
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, 21, item["MachiningTimeInHrs"].ToString());
                            ws.Cells[rowStart, 22].Value = getdouble(item["MachiningTimePercent"].ToString());
                            rowStart++;
                            setTimeSpanFormat("hh:mm:ss", ws, rowStart, 21, item["DevelopmentTimeInHrs"].ToString());
                            ws.Cells[rowStart, 22].Value = getdouble(item["DevelopmentPercent"].ToString());
                        }
                        pieChart = ws.Drawings["Chart 3"] as ExcelPieChart;
