                        series.Header = machineID + " Development Time";
                        //pieChart.Title.Text = machineID + " Development Time";
                        pieChart.ShowDataLabelsOverMaximum = true;
                        pieChart.DisplayBlanksAs = eDisplayBlanksAs.Zero;
                        pieSeries = (ExcelPieChartSerie)series;
                        pieSeries.DataLabel.ShowCategory = false;
                        pieSeries.DataLabel.ShowValue = false;
                        pieSeries.DataLabel.ShowPercent = true;
                        pieSeries.DataLabel.Position = eLabelPosition.BestFit;
                        //pieChart.Legend.Position = eLegendPosition.Right;
                    }
                    #endregion

                    #region ---Cyclewise Analysis---
                    var ws1 = pck.Workbook.Worksheets["Cyclewise analysis"];
                    rowStart = 2; rowStartCopy = rowStart;
                    int slno = 1;
                    if (dtCyclewise.Rows.Count > 0)
                    {
                        foreach (DataRow item in dtCyclewise.Rows)
