                            ws1.Cells[rowStart, colStart].Value = item["MaterialID"];
                            colStart++;
                            ws1.Cells[rowStart, colStart].Value = item["MaterialDescription"];
                            colStart++;
                            ws1.Cells[rowStart, colStart].Value = item["OperationNo"];
                            colStart++;
                            ws1.Cells[rowStart, colStart].Value = item["OperationDescription"];
                            colStart++;
                            ws1.Cells[rowStart, colStart].Value = item["PlannedQty"];
                            colStart++;
                            ws1.Cells[rowStart, colStart].Value = item["CompletedQty"];
                            colStart++;
