                            rowStart++;
                        }
                        rowStart--;
                        setThinBorder(ws1, rowStartCopy, 1, rowStart, colStart);
                        ws1.Cells[rowStartCopy, 1, rowStart, colStart].AutoFitColumns();
                    }
                    #endregion

                    #region --Scrap Qty---
