                            ws2.Cells[rowStart, colStart].Value = item["CompletedQty"];
                            colStart++;
                            ws2.Cells[rowStart, colStart].Value = item["ScrapQty"];
                            rowStart++;
                        }
                        rowStart--;
                        setThinBorder(ws2, rowStartCopy, 1, rowStart, colStart);
                        ws2.Cells[rowStartCopy, 1, rowStart, colStart].AutoFitColumns();
                    }

                    #endregion
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex);
            }
            return Generated;
        }

        #endregion

        #region UIN Tracking Dashboard Allied
        public static void UINTrackingReport(List<UINDashboardData> list, out string generated)
        {
            generated = "";
            string source = string.Empty, destination = string.Empty, template = string.Empty;
            string Filename = "UINTrackingReport.xlsx";
            source = Util.GetReportPath(Filename);
            template = "UINTrackingReport" + DateTime.Now + ".xlsx";
            destination = Path.Combine(appPath, "Temp", SafeFileName(template));
            if (!File.Exists(source))
            {
                Logger.WriteDebugLog(@"Report template does not found at :" + source);
                generated = "Not Found";
            }
            else
            {
                FileInfo newFile = new FileInfo(source);
                ExcelPackage Excel = new ExcelPackage(newFile, true);
                var workSheet = Excel.Workbook.Worksheets["Sheet1"];
                int rowStart = 1, colStart = 1, colStartCopy = colStart;

                try
                {
                    foreach (var li in list)
                    {
                        colStart = 1;
                        if (li.HeaderEnable == true)
                        {
                            workSheet.Cells[rowStart, colStart].Value = "UIN Number";
                            workSheet.Cells[rowStart, colStart].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            colStart++;
                            workSheet.Cells[rowStart, colStart].Value = "ComponentID";
                            workSheet.Cells[rowStart, colStart].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            colStart++;
                            foreach (var machine in li.machineData)
                            {
                                int row = rowStart;
                                if (machine.HeaderEnable == true)
                                {
                                    workSheet.Cells[row, colStart].Value = machine.OperationNo;
                                    workSheet.Cells[row, colStart, row, colStart + 3].Merge = true;
                                    workSheet.Cells[row, colStart, row, colStart + 3].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                    row++;
                                    workSheet.Cells[row, colStart].Value = "Machine ID";
                                    colStart++;
                                    workSheet.Cells[row, colStart].Value = "Operator Name";
                                    colStart++;
                                    workSheet.Cells[row, colStart].Value = "Start Time";
                                    colStart++;
                                    workSheet.Cells[row, colStart].Value = "EndTime";
                                    colStart++;
                                }
                            }
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(1, 46, 104, 134));

                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Font.Color.SetColor(Color.White);
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Font.Size = 14;
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;

                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Border.Top.Color.SetColor(Color.White);
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Border.Left.Color.SetColor(Color.White);
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Border.Right.Color.SetColor(Color.White);
                            workSheet.Cells[1, colStartCopy, 2, colStart - 1].Style.Border.Bottom.Color.SetColor(Color.White);

                            rowStart += 2;
                        }
                        if (li.ContentEnable == true)
                        {
                            workSheet.Cells[rowStart, colStart].Value = li.UinNo;
                            colStart++;
                            workSheet.Cells[rowStart, colStart].Value = li.ComponentID;
                            workSheet.Cells[rowStart, 1, rowStart, 2].Style.Font.Bold = true;
                            colStart++;
                            foreach (var machine in li.machineData)
                            {
                                if (machine.ContentEnable == true)
                                {
                                    workSheet.Cells[rowStart, colStart].Value = machine.MachineID;
                                    colStart++;
                                    workSheet.Cells[rowStart, colStart].Value = machine.OperatorName;
                                    colStart++;
                                    workSheet.Cells[rowStart, colStart].Value = machine.StartTime;
                                    colStart++;
                                    workSheet.Cells[rowStart, colStart].Value = machine.EndTime;
                                    colStart++;
                                }
                            }
                            rowStart++;
                        }
                    }
                    workSheet.Cells[3, 1, rowStart - 1, colStart - 1].Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[3, 1, rowStart - 1, colStart - 1].Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[3, 1, rowStart - 1, colStart - 1].Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[3, 1, rowStart - 1, colStart - 1].Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    workSheet.Cells[1, 1, rowStart - 1, colStart - 1].AutoFitColumns();
                    DownloadMultipleFile(destination, Excel.GetAsByteArray());
                    generated = "Success";
                }
                catch (Exception ex)
                {
                    Logger.WriteErrorLog(ex.Message);
                    generated = "Error";
                }

            }

        }
        #endregion

        internal static string PDIReportTafeChennai(string slno)
        {
            string Generarted = "";
            try
            {
                string generated = string.Empty;
                string reportName = "";
                string src, dst = string.Empty;
                reportName = "PDIReportTafeChennai.xlsx";
                src = Util.GetReportPath(reportName);
                string tempfileName = "PDIReport" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("PDIReportTafeChennai - \n " + src);
                }

                FileInfo newFile = new FileInfo(src);
                ExcelPackage excelPackage = new ExcelPackage(newFile, true);
                ExcelWorksheet crownWS = excelPackage.Workbook.Worksheets[1];
                ExcelWorksheet pinionWS = excelPackage.Workbook.Worksheets[2];


                DataTable dtCrownHeader = new DataTable();
                DataTable dtPinionHeader = new DataTable();
                DataTable dtCrownData = new DataTable();
                DataTable dtPinionData = new DataTable();
                DataTable dt = TMPTrakDataBase.GetPDIReportData(slno, out dtCrownHeader, out dtPinionHeader, out dtCrownData, out dtPinionData);


                if (dt.Rows.Count > 0 || dtCrownHeader.Rows.Count > 0 || dtPinionHeader.Rows.Count > 0 || dtCrownData.Rows.Count > 0 || dtPinionData.Rows.Count > 0)
                {
                    string backClashNo = "";

                    if (dt.Rows.Count > 0)
                    {
                        backClashNo = dt.Rows[0]["BackClashNo"].ToString();
                    }

                    if (dtCrownHeader.Rows.Count > 0)
                    {
                        var firstRow = dtCrownHeader.Rows[0];
                        crownWS.Cells["B3"].Value = firstRow["HeatCodeType"].ToString();
                        crownWS.Cells["B4"].Value = firstRow["PartNo"].ToString();
                        crownWS.Cells["B5"].Value = firstRow["PartDescription"].ToString();
                        crownWS.Cells["B6"].Value = firstRow["OperationNo"].ToString();
                        crownWS.Cells["E3"].Value = firstRow["DocNo"].ToString();
                        crownWS.Cells["E4"].Value = firstRow["HeatCodeNo"].ToString();
                        crownWS.Cells["E5"].Value = backClashNo;
                        crownWS.Cells["E6"].Value = firstRow["Version"].ToString();
                    }
                    if (dtPinionHeader.Rows.Count > 0)
                    {
                        var firstRow = dtPinionHeader.Rows[0];
                        pinionWS.Cells["B3"].Value = firstRow["HeatCodeType"].ToString();
                        pinionWS.Cells["B4"].Value = firstRow["PartNo"].ToString();
                        pinionWS.Cells["B5"].Value = firstRow["PartDescription"].ToString();
                        pinionWS.Cells["B6"].Value = firstRow["OperationNo"].ToString();
                        pinionWS.Cells["E3"].Value = firstRow["DocNo"].ToString();
                        pinionWS.Cells["E4"].Value = firstRow["HeatCodeNo"].ToString();
                        pinionWS.Cells["E5"].Value = backClashNo;
                        pinionWS.Cells["E6"].Value = firstRow["Version"].ToString();
                    }
                    int rowCount = 9, colCount = 1;
                    string preparedBy = "", approvedBy = "", date = "";
                    if (dtCrownData.Rows.Count > 1)
                    {
                        crownWS.InsertRow(rowCount + 1, dtCrownData.Rows.Count - 1, rowCount);
                    }
                    for (int i = 0; i < dtCrownData.Rows.Count; i++)
                    {
                        colCount = 1;
                        crownWS.Cells[rowCount, colCount].Value = dtCrownData.Rows[i]["RowID"].ToString();
                        colCount++;
                        crownWS.Cells[rowCount, colCount].Value = dtCrownData.Rows[i]["CharateristicCode"].ToString();
                        colCount++;
                        crownWS.Cells[rowCount, colCount].Value = dtCrownData.Rows[i]["Specification"].ToString();
                        colCount++;
                        crownWS.Cells[rowCount, colCount].Value = dtCrownData.Rows[i]["InstrumentType"].ToString();
                        colCount++;
                        crownWS.Cells[rowCount, colCount].Value = dtCrownData.Rows[i]["Interval"].ToString();
                        colCount++;
                        crownWS.Cells[rowCount, colCount].Value = dtCrownData.Rows[i]["RecordingFrequency"].ToString();
                        crownWS.Cells[rowCount, colCount].Style.Fill.PatternType = OfficeOpenXml.Style.ExcelFillStyle.Solid;
                        if (dtCrownData.Rows[i]["ColorIndication"].ToString().Equals("green", StringComparison.OrdinalIgnoreCase))
                        {
                            crownWS.Cells[rowCount, colCount].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(146, 208, 80));
                        }
                        else if (dtCrownData.Rows[i]["ColorIndication"].ToString().Equals("red", StringComparison.OrdinalIgnoreCase))
                        {
                            crownWS.Cells[rowCount, colCount].Style.Fill.BackgroundColor.SetColor(Color.Red);
                        }

                        rowCount++;
                        if (preparedBy == "" && dtCrownData.Rows[i]["InspectedBy"].ToString() != "")
                        {
                            preparedBy = dtCrownData.Rows[i]["InspectedBy"].ToString();
                        }
                        if (approvedBy == "" && dtCrownData.Rows[i]["ApprovedBy"].ToString() != "")
                        {
                            approvedBy = dtCrownData.Rows[i]["ApprovedBy"].ToString();
                        }
                        if (date == "" && dtCrownData.Rows[i]["UpdatedTS"].ToString() != "")
                        {
                            date = Convert.ToDateTime(dtCrownData.Rows[i]["UpdatedTS"].ToString()).ToString("dd-MM-yyyy");
                        }
                    }
                    crownWS.Cells[rowCount, 2].Value = preparedBy;
                    crownWS.Cells[rowCount, 6].Value = approvedBy;
                    crownWS.Cells["B2"].Value = date;
                    pinionWS.Cells["B2"].Value = date;
                    rowCount = 9;
                    preparedBy = ""; approvedBy = "";
                    if (dtPinionData.Rows.Count > 1)
                    {
                        pinionWS.InsertRow(rowCount + 1, dtPinionData.Rows.Count - 1, rowCount);
                    }
                    for (int i = 0; i < dtPinionData.Rows.Count; i++)
                    {
                        colCount = 1;
                        pinionWS.Cells[rowCount, colCount].Value = dtPinionData.Rows[i]["RowID"].ToString();
                        colCount++;
                        pinionWS.Cells[rowCount, colCount].Value = dtPinionData.Rows[i]["CharateristicCode"].ToString();
                        colCount++;
                        pinionWS.Cells[rowCount, colCount].Value = dtPinionData.Rows[i]["Specification"].ToString();
                        colCount++;
                        pinionWS.Cells[rowCount, colCount].Value = dtPinionData.Rows[i]["InstrumentType"].ToString();
                        colCount++;
                        pinionWS.Cells[rowCount, colCount].Value = dtPinionData.Rows[i]["Interval"].ToString();
                        colCount++;
                        pinionWS.Cells[rowCount, colCount].Value = dtPinionData.Rows[i]["RecordingFrequency"].ToString();
                        pinionWS.Cells[rowCount, colCount].Style.Fill.PatternType = OfficeOpenXml.Style.ExcelFillStyle.Solid;
                        if (dtPinionData.Rows[i]["ColorIndication"].ToString().Equals("green", StringComparison.OrdinalIgnoreCase))
                        {
                            pinionWS.Cells[rowCount, colCount].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(146, 208, 80));
                        }
                        else if (dtPinionData.Rows[i]["ColorIndication"].ToString().Equals("red", StringComparison.OrdinalIgnoreCase))
                        {
                            pinionWS.Cells[rowCount, colCount].Style.Fill.BackgroundColor.SetColor(Color.Red);
                        }
                        rowCount++;
                        if (preparedBy == "" && dtPinionData.Rows[i]["InspectedBy"].ToString() != "")
                        {
                            preparedBy = dtPinionData.Rows[i]["InspectedBy"].ToString();
                        }
                        if (approvedBy == "" && dtPinionData.Rows[i]["ApprovedBy"].ToString() != "")
                        {
                            approvedBy = dtPinionData.Rows[i]["ApprovedBy"].ToString();
                        }
                    }
                    pinionWS.Cells[rowCount, 2].Value = preparedBy;
                    pinionWS.Cells[rowCount, 6].Value = approvedBy;
                    DownloadMultipleFile(dst, excelPackage.GetAsByteArray());
                    Logger.WriteDebugLog("Line Meter Report Generated.");
                    generated = "Generated";
                }
                else
                {
                    Generarted = "NoDataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteDebugLog(ex.ToString());
            }
            return Generarted;
        }
        #region--------TOOL CHANGE FREQUENCY RECORD VULKAN---------------------
        internal static string ToolChangeFrequencyReportVulkan(DateTime FromDate, DateTime ToDate, string MachineID)
        {
            string Generated = "";
            try
            {
                string Filename = "TooChangeFrequencyRecord_Vulkan.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "ToolChangeFrequencyRecord_Vulkan" + DateTime.Now.ToString("yyyy-MM-dd") + ".xlsx";
                string destination = Path.Combine(appPath, "GeneratedReports", SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("Tool Change Frequency Record_Vulkan template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var copyworksheet = Excel.Workbook.Worksheets["sheet1"];

                    DataTable dt = TMPTrakDataBase.GetToolChangeFrequencyData_Vulkan(FromDate, ToDate, MachineID);
                    var distMachines = dt.AsEnumerable().Select(x => x["MachineNo"].ToString()).Distinct().ToList();

                    if (dt.Rows.Count > 0)
                    {
                        for (int machine = 0; machine < distMachines.Count; machine++)
                        {
                            int rowStart = 10;
                            var worksheet = Excel.Workbook.Worksheets.Add(distMachines[machine], copyworksheet);
                            worksheet.PrinterSettings.PaperSize = ePaperSize.A3;
                            worksheet.PrinterSettings.Orientation = eOrientation.Portrait;
                            worksheet.PrinterSettings.HorizontalCentered = true;
                            worksheet.PrinterSettings.FitToWidth = 1;
                            worksheet.PrinterSettings.FitToHeight = 0;
                            worksheet.PrinterSettings.FitToPage = true;
                            worksheet.Cells["J3"].Value = distMachines[machine];
                            DataTable tempDt = dt.AsEnumerable().Where(k => k.Field<string>("MachineNo") == distMachines[machine]).CopyToDataTable();
                            foreach (DataRow dtRow in tempDt.Rows)
                            {
                                worksheet.Cells[rowStart, 1].Value = dtRow["MachineNo"].ToString();
                                worksheet.Cells[rowStart, 2].Value = dtRow["OperatorName"].ToString();
                                worksheet.Cells[rowStart, 3].Value = dtRow["PartNo"].ToString();
                                //worksheet.Cells[rowStart, 4].Value = dtRow["OperationNo"].ToString();
                                worksheet.Cells[rowStart, 4].Value = Convert.ToDateTime(dtRow["Date"].ToString()).ToString("yyyy-MM-dd");
                                worksheet.Cells[rowStart, 5].Value = dtRow["Shift"].ToString();
                                worksheet.Cells[rowStart, 6].Value = dtRow["Time"].ToString();
                                worksheet.Cells[rowStart, 7].Value = dtRow["ToolDescription"].ToString();
                                worksheet.Cells[rowStart, 8].Value = dtRow["ToolChangeReason"].ToString();
                                worksheet.Cells[rowStart, 9].Value = Convert.ToInt32(dtRow["ToolLifeInNos"].ToString());
                                worksheet.Cells[rowStart, 10].Value = Convert.ToInt32(dtRow["Production"].ToString());
                                worksheet.Cells[rowStart, 11].Value = dtRow["ToolSerialNo"].ToString();
                                rowStart++;
                            }
                            setThinBorder(worksheet, 10, 1, rowStart - 1, 11);
                        }
                        Excel.Workbook.Worksheets.Delete(1);
                        DownloadMultipleFile(destination, Excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex);
            }
            return Generated;
        }
