        #region --- Vulkan Machine Shop Reports ---
        internal static string GenerateInspectionReport(string StartDate, string ShiftID, string MachineID, string MachineIDForOEE)
        {
            string Generated = "";
            try
            {
                string Filename = "InspectionReportVulkan.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "InspectionReportVulkan" + DateTime.Now + ".xlsx";
                string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
                bool ProductionFlag = false, InspectionFlag = false;
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("Inspection Report template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    DataTable dt_Operator = new DataTable();
                    DataTable dt_InspectionData = new DataTable();
                    DataTable dt_ApprovedData = new DataTable();
                    DataTable dt_Sign = new DataTable();
                    DataTable dt_ProductionData = new DataTable();
                    DataTable dt_HeatCodes = new DataTable();
                    DataTable dt_OEE = new DataTable();

                    dt_InspectionData = VulkanMSDBAccess.GetInspectionReportData(StartDate, ShiftID, MachineID, out dt_Operator, out dt_ApprovedData, out dt_HeatCodes);
                    dt_ProductionData = VulkanMSDBAccess.GetProductionReportDataHourWise(StartDate, ShiftID, MachineID, out dt_Sign);
                    dt_OEE = VulkanMSDBAccess.GetHourWiseProductionReportOEE(StartDate, ShiftID, MachineIDForOEE);
                    var MachineList = MachineID.Split(new[] { ',', '\'' }, StringSplitOptions.RemoveEmptyEntries).ToList();

                    if (dt_ProductionData.Rows.Count > 0)
                    {
                        if (dt_ProductionData.Columns.IndexOf("SaveFlag") == -1)
                            ProductionFlag = true;
                    }
                    if (dt_InspectionData.Rows.Count > 0)
                    {
                        if (dt_InspectionData.Columns.IndexOf("SaveFlag") == -1)
                            InspectionFlag = true;
                    }
                    if ((dt_ProductionData.Rows.Count > 0 && ProductionFlag) || (dt_InspectionData.Rows.Count > 0 && InspectionFlag))
                    {
                        foreach (var Machine in MachineList)
                        {
                            var sheet = Excel.Workbook.Worksheets.Copy("Sheet1", $"Production_{Machine}_{Util.GetDateTime(StartDate).ToString("ddMMyyyy")}_{ShiftID}");
                            int rowStart = 10, colStart = 1, j = 0, Count = 0, tempRowStart = 4, tempRowStartCopy = tempRowStart, rowStartCopy = rowStart;

                            sheet.PrinterSettings.PaperSize = ePaperSize.A4;
                            sheet.PrinterSettings.Orientation = eOrientation.Portrait;
                            sheet.PrinterSettings.HorizontalCentered = true;
                            sheet.PrinterSettings.FitToWidth = 1;
                            sheet.PrinterSettings.FitToHeight = 1;
                            sheet.PrinterSettings.FitToPage = true;
                            sheet.PrinterSettings.TopMargin = 0.5M;
                            sheet.PrinterSettings.BottomMargin = 0.5M;
                            sheet.PrinterSettings.LeftMargin = 0.5M;
                            sheet.PrinterSettings.RightMargin = 0.5M;
                            if (ProductionFlag)
                            {
                                var ProductionData = dt_ProductionData.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Count() > 0 ? dt_ProductionData.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).CopyToDataTable() : new DataTable();
                                if (ProductionData != null && ProductionData.Rows.Count > 0)
                                {

                                    sheet.Cells[tempRowStart, 3].Value = Machine;
                                    tempRowStart++;
                                    sheet.Cells[tempRowStart, 3].Value = dt_Sign.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Select(x => x["Operator"].ToString()).FirstOrDefault();
                                    tempRowStart++;
                                    sheet.Cells[tempRowStart, 3].Value = dt_Sign.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Select(x => x["PartNo"].ToString()).FirstOrDefault();
                                    tempRowStart++;
                                    sheet.Cells[tempRowStart, 3].Value = dt_Sign.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Select(x => x["PartName"].ToString()).FirstOrDefault();
                                    tempRowStart++;
                                    sheet.Cells[tempRowStart, 3].Value = Util.GetDateTime(StartDate).ToString("dd-MM-yyyy");
                                    sheet.Cells[tempRowStart, 4].Value = $"SHIFT: {ShiftID}";

                                    sheet.Cells[tempRowStartCopy, 3, tempRowStart, 3].Style.Font.Bold = true;
                                    sheet.Cells[tempRowStartCopy, 3, tempRowStart, 3].Style.HorizontalAlignment = ExcelHorizontalAlignment.Left;

                                    foreach (DataRow row in ProductionData.Rows)
                                    {
                                        colStart = 1;
                                        sheet.Cells[rowStart, colStart].Value = row["shifthours"].ToString();
                                        colStart++;
                                        sheet.Cells[rowStart, colStart].Value = HelperClassGeneric.getDoubleValueFromString(row["Target"].ToString());
                                        colStart++;
                                        sheet.Cells[rowStart, colStart].Value = HelperClassGeneric.getDoubleValueFromString(row["Actual"].ToString());
                                        colStart++;
                                        sheet.Cells[rowStart, colStart].Value = row["Downtime"].ToString();

                                        rowStart++;
                                    }
                                    sheet.Column(4).Style.WrapText = true;
                                    sheet.Cells[27, 2].Value = dt_Sign.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Select(x => HelperClassGeneric.getDoubleValueFromString(x["TotalTarget"].ToString())).FirstOrDefault();
                                    sheet.Cells[27, 3].Value = dt_Sign.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Select(x => HelperClassGeneric.getDoubleValueFromString(x["TotalActual"].ToString())).FirstOrDefault();

                                    if (dt_OEE.Rows.Count > 0)
                                    {
                                        sheet.Cells[27, 4].Value = "Total Down Time: " + dt_OEE.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Select(x => x["NetDownTime"].ToString()).FirstOrDefault();
                                        sheet.Cells[28, 3].Value = dt_OEE.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Select(x => x["OverAllEfficiency"].ToString()).FirstOrDefault();
                                    }
                                }
                            }


                            sheet = Excel.Workbook.Worksheets.Copy("Sheet2", $"Inspection{Machine}_{Util.GetDateTime(StartDate).ToString("ddMMyyyy")}_{ShiftID}");
                            rowStart = 10; colStart = 1; j = 0; tempRowStart = 4; tempRowStartCopy = tempRowStart;
                            int tempColEnd = colStart;
                            sheet.PrinterSettings.PaperSize = ePaperSize.A4;
                            sheet.PrinterSettings.Orientation = eOrientation.Landscape;
                            sheet.PrinterSettings.HorizontalCentered = true;
                            sheet.PrinterSettings.FitToWidth = 1;
                            sheet.PrinterSettings.FitToHeight = 0;
                            sheet.PrinterSettings.FitToPage = true;
                            sheet.PrinterSettings.Scale = 1;
                            sheet.PrinterSettings.TopMargin = 0.5M;
                            sheet.PrinterSettings.BottomMargin = 0.5M;
                            sheet.PrinterSettings.LeftMargin = 0.5M;
                            sheet.PrinterSettings.RightMargin = 0.5M;
                            sheet.PrinterSettings.ShowGridLines = true;
                            if (InspectionFlag)
                            {
                                var xx = dt_InspectionData.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Count();
                                var InspectionData = dt_InspectionData.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Count() > 0 ? dt_InspectionData.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).CopyToDataTable() : new DataTable();
                                rowStart = 5;
                                colStart = 1;
                                tempRowStart = 4;
                                string PrevCompOpn = "", CurCompOpn = "";
                                if (InspectionData != null && InspectionData.Rows.Count > 0)
                                {
                                    var distComponents = InspectionData.AsEnumerable().Select(x => x["ComponentID"].ToString()).Distinct().ToList();
                                    sheet.Cells[tempRowStart, 2].Value = Machine;
                                    sheet.Cells[tempRowStart, 7].Value = Util.GetDateTime(StartDate).ToString("dd-MM-yyyy");
                                    sheet.Cells[tempRowStart, 11].Value = ShiftID;
                                    sheet.Cells[tempRowStart, 1, tempRowStart, 7].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                    sheet.Cells[tempRowStart, 1, tempRowStart, 7].Style.Font.Bold = true;

                                    while (j < distComponents.Count)
                                    {
                                        Count = 0;
                                        var HeatCodeList = dt_HeatCodes.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase) && x["ComponentID"].ToString().Equals(distComponents[j], StringComparison.OrdinalIgnoreCase)).Select(x => x["HeatCode"].ToString()).Distinct().ToList();
                                        sheet.Cells[rowStart, 1].Value = "Operator Sign";
                                        sheet.Cells[rowStart, 1, rowStart, colStart].Style.Font.Bold = true;
                                        var OperatorRow = dt_Operator.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).CopyToDataTable();
                                        if (OperatorRow.Rows.Count > 0)
                                        {
                                            DataRow row = OperatorRow.Rows[0];
                                            colStart = 4;
                                            foreach (var HeatCode in HeatCodeList)
                                            {
                                                sheet.Cells[rowStart, colStart].Value = row[$"{HeatCode}"].ToString();
                                                sheet.Cells[rowStart, colStart].Style.WrapText = true;
                                                colStart++;
                                            }
                                        }

                                        rowStart++;
                                        colStart = 1;
                                        sheet.Cells[rowStart, colStart].Value = "Component ID";
                                        colStart++;
                                        sheet.Cells[rowStart, colStart].Value = "Operation No";
                                        colStart++;
                                        sheet.Cells[rowStart, colStart].Value = "Characteristic ID";
                                        sheet.Cells[rowStart, colStart].AutoFitColumns();

                                        foreach (var HeatCode in HeatCodeList)
                                        {
                                            colStart++;
                                            sheet.Cells[rowStart, colStart].Value = HeatCode;
                                            sheet.Column(colStart).Width = 15;
                                        }
                                        sheet.Cells[rowStart, 1, rowStart, colStart].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                        rowStartCopy = ++rowStart;

                                        var ComponentWiseList = InspectionData.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase) && x["ComponentID"].ToString().Equals(distComponents[j], StringComparison.OrdinalIgnoreCase)).CopyToDataTable();
                                        PrevCompOpn = $"{ComponentWiseList.Rows[0]["ComponentID"].ToString()}_{ComponentWiseList.Rows[0]["OperationNo"].ToString()}";
                                        foreach (DataRow Component in ComponentWiseList.Rows)
                                        {
                                            CurCompOpn = $"{Component["ComponentID"].ToString()}_{Component["OperationNo"].ToString()}";
                                            colStart = 1;
                                            sheet.Cells[rowStart, colStart].Value = Component["ComponentID"].ToString();
                                            colStart++;
                                            sheet.Cells[rowStart, colStart].Value = Component["OperationNo"].ToString();
                                            if (PrevCompOpn == CurCompOpn)
                                            {
                                                sheet.Cells[rowStart - Count, colStart, rowStart, colStart].Merge = true;
                                                sheet.Cells[rowStart - Count, colStart].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                                Count++;
                                            }
                                            else
                                            {
                                                PrevCompOpn = CurCompOpn;
                                                Count = 1;
                                            }
                                            colStart++;
                                            sheet.Cells[rowStart, colStart].Value = Component["CharacteristicID"].ToString();


                                            foreach (var HeatCode in HeatCodeList)
                                            {
                                                colStart++;
                                                sheet.Cells[rowStart, colStart].Value = Component[$"{HeatCode}"].ToString();
                                                sheet.Cells[rowStart, colStart].Style.WrapText = true;
                                            }
                                            rowStart++;
                                        }
                                        sheet.Cells[rowStartCopy, 1, rowStart - 1, 1].Merge = true;
                                        sheet.Cells[rowStartCopy, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;

                                        sheet.Cells[rowStart, 1, rowStart, 3].Merge = true;
                                        sheet.Cells[rowStart, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;

                                        j++;
                                        if (tempColEnd < colStart)
                                            tempColEnd = colStart;
                                        setThinBorder(sheet, tempRowStart, 1, rowStart, tempColEnd);
                                        rowStart += 2;
                                        tempRowStart = rowStart;
                                    }

                                    setThinBorder(sheet, rowStart - 1, 1, rowStart, tempColEnd);
                                    //if (dt_ApprovedData.Rows.Count > 0)
                                    //{
                                    //    string ApproverSign = dt_ApprovedData.AsEnumerable().Where(x => (x["MachineID"].ToString() == Machine && x["Date"].ToString() == Date && x["Shift"].ToString() == shift)).Select(x => x["ApprovedBy"].ToString()).FirstOrDefault();
                                    //    string ApproverTS = dt_ApprovedData.AsEnumerable().Where(x => (x["MachineID"].ToString() == Machine && x["Date"].ToString() == Date && x["Shift"].ToString() == shift)).Select(x => x["ApprovedTS"].ToString()).FirstOrDefault();
                                    //    sheet.Cells[rowStart + 2, colStart - 2].Value = ApproverSign + "_" + ApproverTS;
                                    //}
                                }

                            }
                        }
                        Excel.Workbook.Worksheets.Delete("Sheet1");
                        Excel.Workbook.Worksheets.Delete("Sheet2");
                        DownloadMultipleFile(destination, Excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                        Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog($"GenerateInspectionReport: {ex.Message}");
            }
            return Generated;
        }

        internal static string GeneratePMReport(string MachineID, string Year, string Month)
        {
            string Generated = "";
            DataTable dt_TransactionData = new DataTable(),
           dt_Sign = new DataTable(),
           dt_Dailyapproval = new DataTable(),
           dt_MonthlyApproval = new DataTable(),
           dt_WeeklyApproval = new DataTable(),
           dt_HeaderTable = new DataTable(),
           dt_HolidayList = new DataTable();
            try
            {
                string Filename = "PMChecksheetReport.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "PMChecksheetReport" + DateTime.Now + ".xlsx";
                string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("PMChecksheetReport template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    dt_TransactionData = VulkanMSDBAccess.GetPMReportData(MachineID, Year, Month, out dt_Sign, out dt_Dailyapproval, out dt_WeeklyApproval, out dt_MonthlyApproval, out dt_HeaderTable, out dt_HolidayList);
                    if (dt_TransactionData.Rows.Count > 0)
                    {
                        //Excel.Workbook.Worksheets.Delete(1);

                        var MachinesList = dt_TransactionData.AsEnumerable().Select(x => x["MachineID"].ToString()).Distinct().ToList();
                        foreach (var Machine in MachinesList)
                        {
                            //Excel.Workbook.Worksheets.Add(Machine);
                            var workSheet = Excel.Workbook.Worksheets.Copy("Sheet1", Machine);

                            int rowStart = 5, colStart = 1, tempCol = 6, HeaderFlag = 0;

                            var Holiday_List = dt_HolidayList.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).Select(x => Util.GetDateTime(x["Holiday"].ToString()).Day).ToList();

                            DataTable tempDt = dt_TransactionData.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).CopyToDataTable();
                            foreach (DataRow row in tempDt.Rows)
                            {

                                #region --- Column Headings ---
                                if (HeaderFlag == 0)
                                {
                                    workSheet.Cells[1, 3].Value = $"Preventive Maintenance CheckList for {Machine}";
                                    workSheet.Cells[1, 3].Style.WrapText = true;
                                    workSheet.Cells[1, 3].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                    workSheet.Cells[2, 6].Value = $"Rev No: {row["RevID"].ToString()}";
                                    workSheet.Cells[1, 8, 1, 6 + dt_Dailyapproval.Columns.Count - 2].Merge = true;
                                    workSheet.Cells[2, 8, 2, 6 + dt_Dailyapproval.Columns.Count - 2].Merge = true;
                                    workSheet.Cells[3, 7, 3, 6 + dt_Dailyapproval.Columns.Count - 2].Merge = true;
                                    workSheet.Cells[3, 7].Value = "DATE";
                                    workSheet.Cells[1, 1, 2, 2].Merge = true;
                                    workSheet.Cells[1, 7].Value = "Year:- ";
                                    workSheet.Cells[1, 8].Value = Year;
                                    workSheet.Cells[2, 7].Value = "Month:- ";
                                    workSheet.Cells[2, 8].Value = Month;
                                    workSheet.Row(1).Height = 70;
                                    workSheet.Row(2).Height = 70;
                                    workSheet.Row(3).Height = 70;

                                    workSheet.Column(6).Width = 28;
                                }

                                #endregion

                                colStart = 1;
                                workSheet.Cells[rowStart, colStart].Value = row["CheckpointID"].ToString();
                                colStart++;
                                workSheet.Cells[rowStart, colStart].Value = row["Particular"].ToString();
                                colStart++;
                                workSheet.Cells[rowStart, colStart].Value = row["CheckpointItem"].ToString();
                                colStart++;
                                workSheet.Cells[rowStart, colStart].Value = row["Frequency"].ToString();
                                colStart++;
                                workSheet.Cells[rowStart, colStart].Value = row["ControlMethod"].ToString();
                                colStart++;
                                workSheet.Cells[rowStart, colStart].Value = row["Responsibility"].ToString();
                                colStart++;


                                foreach (DataColumn column in dt_TransactionData.Columns)
                                {
                                    int res = 0;
                                    int.TryParse(column.ColumnName.ToString(), out res);
                                    if (res > 0)
                                    {
                                        if (HeaderFlag == 0)
                                        {
                                            tempCol++;
                                            workSheet.Cells[4, tempCol].Value = res;

                                            if (Holiday_List.Contains(res))
                                            {
                                                workSheet.Cells[4, tempCol].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                                workSheet.Cells[4, tempCol].Style.Fill.BackgroundColor.SetColor(Color.Red);
                                            }
                                            workSheet.Cells[4, tempCol].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                        }


                                        if (Holiday_List.Contains(res))
                                        {
                                            workSheet.Cells[4, tempCol].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                            workSheet.Cells[4, tempCol].Style.Fill.BackgroundColor.SetColor(Color.Red);
                                        }
                                        if (row[column.ColumnName].ToString().Equals("Done", StringComparison.OrdinalIgnoreCase))
                                        {
                                            workSheet.Cells[rowStart, colStart].Style.Font.Name = "Wingdings";
                                            workSheet.Cells[rowStart, colStart].Style.Font.Size = 28;
                                            workSheet.Cells[rowStart, colStart].Style.Font.Bold = true;
                                            workSheet.Cells[rowStart, colStart].Style.Font.Color.SetColor(Color.FromArgb(44, 140, 41));
                                            workSheet.Cells[rowStart, colStart].Value = "ü";
                                        }
                                        else if (row[column.ColumnName].ToString().Equals("DO", StringComparison.OrdinalIgnoreCase))
                                        {
                                            workSheet.Cells[rowStart, colStart].Style.Font.Name = "Wingdings";
                                            workSheet.Cells[rowStart, colStart].Style.Font.Size = 28;
                                            workSheet.Cells[rowStart, colStart].Style.Font.Bold = true;
                                            workSheet.Cells[rowStart, colStart].Style.Font.Color.SetColor(Color.FromArgb(255, 0, 0));
                                            workSheet.Cells[rowStart, colStart].Value = "û";
                                        }
                                        colStart++;
                                    }
                                }
                                HeaderFlag = 1;
                                rowStart++;

                            }

                            #region -- Sign --
                            workSheet.Row(rowStart).Height = 50;
                            workSheet.Row(rowStart + 1).Height = 50;
                            workSheet.Cells[rowStart, 1, rowStart, 5].Merge = true;
                            workSheet.Cells[rowStart, 6].Value = "Operator Sign";
                            workSheet.Cells[rowStart + 1, 1, rowStart + 1, 5].Merge = true;
                            workSheet.Cells[rowStart + 1, 6].Value = "Maintenance Engineer";
                            var tempDt2 = dt_Sign.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).CopyToDataTable();
                            if (tempDt2.Rows.Count > 0)
                            {
                                tempDt2.AsEnumerable().OrderByDescending(x => x["Type"].ToString());
                                tempCol = 7;
                                foreach (DataColumn column in tempDt2.Columns)
                                {
                                    int res = 0, tempRow = rowStart;
                                    int.TryParse(column.ColumnName, out res);
                                    if (res > 0)
                                    {
                                        workSheet.Cells[tempRow, tempCol].Value = tempDt2.Rows[0][column.ColumnName].ToString();
                                        workSheet.Cells[tempRow, tempCol].Style.WrapText = true;
                                        tempRow++;
                                        workSheet.Cells[tempRow, tempCol].Value = tempDt2.Rows[1][column.ColumnName].ToString();
                                        workSheet.Cells[tempRow - 1, tempCol, tempRow, tempCol].Style.WrapText = true;
                                        tempCol++;
                                    }
                                }

                            }
                            #endregion

                            rowStart += 2; tempCol = 7;
                            workSheet.Row(rowStart).Height = 50;
                            workSheet.Cells[rowStart, 6].Value = "PM - Daily Approval By";
                            if (dt_Dailyapproval.Rows.Count > 0)
                            {
                                var row_OP = dt_Dailyapproval.AsEnumerable().Where(x => x["MachineId"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).ToList<DataRow>();
                                foreach (DataColumn column in dt_Dailyapproval.Columns)
                                {
                                    int res = 0;
                                    int.TryParse(column.ColumnName, out res);
                                    if (res > 0)
                                    {
                                        if (!string.IsNullOrEmpty(row_OP[0][column.ColumnName].ToString()))

                                            workSheet.Cells[rowStart, tempCol].Value = $"{row_OP[0][column.ColumnName].ToString().Split('$')[0]}  {Util.GetDateTime(row_OP[0][column.ColumnName].ToString().Split('$')[1]).ToString("dd-MM-yyyy HH:mm:ss")}";
                                        workSheet.Cells[rowStart, tempCol].Style.WrapText = true;
                                        tempCol++;
                                    }
                                }
                            }

                            rowStart++; tempCol = 6;
                            int PrevDate = 1;
                            workSheet.Row(rowStart).Height = 50;
                            workSheet.Cells[rowStart, 6].Value = "PM - Weekly Approval By";
                            if (dt_WeeklyApproval.Rows.Count > 0)
                            {
                                var rows_ME = dt_WeeklyApproval.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).ToList<DataRow>();
                                if (rows_ME.Count > 0)
                                {
                                    for (int i = 2; i < dt_WeeklyApproval.Columns.Count; i++)
                                    {
                                        var weekdata = dt_WeeklyApproval.Columns[i].ColumnName.Split(new[] { '[', ']' }, StringSplitOptions.RemoveEmptyEntries).ToList();
                                        if (weekdata.Count == 2)
                                        {
                                            var datelist = weekdata[1].Split(' ').ToList();
                                            int EndDate = 1;
                                            int.TryParse(Util.GetDateTime(datelist[2]).ToString("dd"), out EndDate);
                                            if (PrevDate > EndDate)
                                                EndDate = DateTime.DaysInMonth(string.IsNullOrEmpty(Year) ? DateTime.Now.Year : Convert.ToInt32(Year), string.IsNullOrEmpty(Month) ? DateTime.Now.Month : Convert.ToInt32(Month));
                                            workSheet.Cells[rowStart, PrevDate + tempCol, rowStart, tempCol + EndDate].Merge = true;
                                            if (!string.IsNullOrEmpty(rows_ME[0][i].ToString()))
                                                workSheet.Cells[rowStart, PrevDate + tempCol].Value = $"{rows_ME[0][i].ToString().Split('$')[0]} {Util.GetDateTime(rows_ME[0][i].ToString().Split('$')[1]).ToString("dd-MM-yyyy HH:mm:ss")}";
                                            PrevDate = EndDate + 1;
                                        }
                                    }
                                }
                            }

                            rowStart++;
                            tempCol = 6 + DateTime.DaysInMonth(string.IsNullOrEmpty(Year) ? DateTime.Now.Year : Convert.ToInt32(Year), string.IsNullOrEmpty(Month) ? DateTime.Now.Month : Convert.ToInt32(Month));
                            workSheet.Row(rowStart).Height = 50;
                            workSheet.Cells[rowStart, 6].Value = "PM - Monthly Approval By";
                            workSheet.Cells[rowStart, 7, rowStart, tempCol].Merge = true;
                            if (dt_MonthlyApproval.Rows.Count > 0)
                            {
                                var rowMonth = dt_MonthlyApproval.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).ToList<DataRow>();
                                if (rowMonth.Count > 0)
                                {
                                    if (!string.IsNullOrEmpty(rowMonth[0][2].ToString()))
                                        workSheet.Cells[rowStart, 7].Value = $"{rowMonth[0][2].ToString().Split('$')[0]} {Util.GetDateTime(rowMonth[0][2].ToString().Split('$')[1]).ToString("dd-MM-yyyy HH:mm:ss")}";
                                }
                            }
                            workSheet.Cells[rowStart, 1, rowStart, 2].Merge = true;
                            workSheet.Cells[rowStart, 1].Value = "Prepared By";
                            workSheet.Cells[rowStart, 3].Value = "Approved By";
                            workSheet.Cells[rowStart, 4, rowStart, 5].Merge = true;
                            workSheet.Cells[rowStart, 4].Value = "Verified By";
                            workSheet.Cells[rowStart, 1, rowStart, 6].Style.Font.Bold = true;
                            if (dt_HeaderTable.Rows.Count > 0)
                            {
                                var dt = dt_HeaderTable.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).CopyToDataTable();
                                if (dt.Rows.Count > 0)
                                {
                                    workSheet.Cells[rowStart - 1, 1, rowStart - 1, 2].Merge = true;
                                    workSheet.Cells[rowStart - 1, 1].Value = dt.AsEnumerable().Select(x => x["PreparedBy"].ToString()).FirstOrDefault();
                                    workSheet.Cells[rowStart, 1].Style.WrapText = true;
                                    workSheet.Cells[rowStart - 1, 3].Value = dt.AsEnumerable().Select(x => x["ApprovedBy"].ToString()).FirstOrDefault();
                                    workSheet.Cells[rowStart, 1].Style.WrapText = true;
                                    workSheet.Cells[rowStart - 1, 4, rowStart - 1, 5].Merge = true;
                                    workSheet.Cells[rowStart - 1, 4].Value = dt.AsEnumerable().Select(x => x["VerifiedBy"].ToString()).FirstOrDefault();
                                    workSheet.Cells[rowStart, 1].Style.WrapText = true;

                                }
                            }


                            workSheet.Cells[1, 1, 4, colStart].Style.Font.Color.SetColor(Color.FromArgb(112, 48, 160));
                            workSheet.Cells[1, 1, 4, colStart].Style.Font.Bold = true;
                            workSheet.Cells[1, 1, 4, 7].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;

                            workSheet.Cells[rowStart - 4, 1, rowStart, colStart].Style.Font.Bold = true;
                            workSheet.Cells[rowStart - 4, 1, rowStart, colStart].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                            workSheet.Column(3).AutoFit();
                            setThinBorder(workSheet, 1, 1, rowStart, tempCol);
                        }
                        Excel.Workbook.Worksheets.Delete("Sheet1");
                        DownloadMultipleFile(destination, Excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                        Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
            }
            return Generated;
        }

        internal static string GenerateCycleTimeReportVulkanMS(string FromDate, string ToDate, string MachineID)
        {
            string Generated = string.Empty;
            DataTable tempDT = new DataTable();
            DataTable TempdtSign = new DataTable();
            DataTable dtCycleTimeData = new DataTable();
            DataTable dtSummary = new DataTable();
            string PrevCycleStartTime = "", PrevCycleEndTime = "", CurrCycleStartTime = "", CurrCycleEndTime = "";
            int count = 0;
            try
            {
                string Filename = "CycleTimeReportVulkanMS.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "CycleTimeReportVulkanMS" + DateTime.Now + ".xlsx";
                string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("CycleTimeReportVulkanMS template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    FileInfo fileInfo = new FileInfo(Source);
                    ExcelPackage excel = new ExcelPackage(fileInfo);

                    var sheet = excel.Workbook.Worksheets["Sheet1"];
                    int rowStart = 9, colStart = 1, i = 1, tempColStart = colStart, colStartCopy = colStart, rowStartCopy = rowStart;

                    dtCycleTimeData = VulkanMSDBAccess.GetCycleTimeReportData(FromDate, ToDate, MachineID, out dtSummary);

                    if (dtCycleTimeData.Rows.Count > 0)
                    {
                        var ComponentList = dtCycleTimeData.AsEnumerable().Select(x => x["ComponentID"].ToString()).Distinct().ToList();
                        foreach (var Component in ComponentList)
                        {
                            var OperationList = dtCycleTimeData.AsEnumerable().Where(x => x["ComponentID"].ToString().Equals(Component, StringComparison.OrdinalIgnoreCase)).Select(x => x["OperationNo"].ToString()).Distinct().ToList();
                            foreach (var Opn in OperationList)
                            {
                                tempDT = dtCycleTimeData.AsEnumerable().Where(x => x["ComponentID"].ToString().Equals(Component, StringComparison.OrdinalIgnoreCase) && x["OperationNo"].ToString() == Opn).CopyToDataTable();

                                sheet.Cells[rowStart, colStart].Value = i++;
                                colStart++;
                                sheet.Cells[rowStart, colStart].Value = MachineID;
                                colStart++;
                                sheet.Cells[rowStart, colStart].Value = Component;
                                colStart++;
                                sheet.Cells[rowStart, colStart].Value = tempDT.Rows[0]["DrawingNo"].ToString();
                                colStart++;
                                sheet.Cells[rowStart, colStart].Value = Opn;
                                colStart++;
                                sheet.Cells[rowStart, colStart].Value = tempDT.Rows[0]["OperationDescription"].ToString();
                                colStart++;
                                for (int j = 1; j < colStart; j++)
                                    sheet.Cells[rowStart, j, rowStart + tempDT.Rows.Count - 1, j].Merge = true;
                                sheet.Cells[rowStart, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                sheet.Cells[rowStart, 1].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                                PrevCycleStartTime = tempDT.Rows[0]["CycleStartTime"].ToString();
                                PrevCycleEndTime = tempDT.Rows[0]["CycleEndTime"].ToString();

                                foreach (DataRow row in tempDT.Rows)
                                {
                                    tempColStart = colStart;
                                    CurrCycleStartTime = row["CycleStartTime"].ToString();
                                    CurrCycleEndTime = row["CycleEndTime"].ToString();

                                    sheet.Cells[rowStart, tempColStart].Value = Util.GetDateTime(row["CycleStartTime"].ToString()).ToString("dd-MM-yyyy HH:mm:ss");
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = Util.GetDateTime(row["CycleEndTime"].ToString()).ToString("dd-MM-yyyy HH:mm:ss");

                                    if (PrevCycleStartTime == CurrCycleStartTime && PrevCycleEndTime == CurrCycleEndTime)
                                    {
                                        sheet.Cells[rowStart - count, tempColStart - 1, rowStart, tempColStart - 1].Merge = true;
                                        sheet.Cells[rowStart - count, tempColStart, rowStart, tempColStart].Merge = true;
                                        count++;
                                    }
                                    else
                                    {
                                        PrevCycleStartTime = CurrCycleStartTime;
                                        PrevCycleEndTime = CurrCycleEndTime;
                                        count = 1;
                                    }


                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = dtSummary.AsEnumerable().Where(x => x["CycleStartTime"].ToString() == row["CycleStartTime"].ToString()).Select(x => Convert.ToInt32(x["TotalCuttingTime"].ToString())).FirstOrDefault();
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = dtSummary.AsEnumerable().Where(x => x["CycleStartTime"].ToString() == row["CycleStartTime"].ToString()).Select(x => Convert.ToInt32(x["Loadunloadtime"].ToString())).FirstOrDefault();
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = dtSummary.AsEnumerable().Where(x => x["CycleStartTime"].ToString() == row["CycleStartTime"].ToString()).Select(x => Convert.ToInt32(x["Downtime"].ToString())).FirstOrDefault();
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = dtSummary.AsEnumerable().Where(x => x["CycleStartTime"].ToString() == row["CycleStartTime"].ToString()).Select(x => Convert.ToInt32(x["Cycletime"].ToString())).FirstOrDefault();
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = row["ToolGPL"].ToString();
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = row["ToolNo"].ToString();
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = HelperClassGeneric.getDoubleValueFromString(row["DepthOfCut"].ToString());
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = HelperClassGeneric.getDoubleValueFromString(row["FeedMM_MIN"].ToString());
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = HelperClassGeneric.getDoubleValueFromString(row["FeedTooth"].ToString());
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = HelperClassGeneric.getDoubleValueFromString(row["RPM"].ToString());
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = HelperClassGeneric.getDoubleValueFromString(row["NoOfCuttingEdge"].ToString());
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = HelperClassGeneric.getDoubleValueFromString(row["NoOfCut"].ToString());
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = HelperClassGeneric.getDoubleValueFromString(row["Cuttime"].ToString());
                                    tempColStart++;
                                    sheet.Cells[rowStart, tempColStart].Value = HelperClassGeneric.getDoubleValueFromString(row["ToolLifeInMeter"].ToString());
                                    rowStart++;
                                }
                            }
                        }
                        setThinBorder(sheet, rowStartCopy, colStartCopy, rowStart - 1, tempColStart);
                        DownloadMultipleFile(destination, excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                        Generated = "NoDataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog($"GenerateCycleTimeReportVulkanMS: {ex.Message}");
            }
            return Generated;
        }

        internal static string GenerateToolChangeReportVulkanMS(string FromDate, string ToDate, string MachineID)
        {
            string Generated = "";
            DataTable dtToolData = new DataTable();
            DataTable dt_Header = new DataTable();
            try
            {
                string Filename = "ToolLifeReportVulkanMS.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "ToolLifeReportVulkanMS" + DateTime.Now + ".xlsx";
                string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("ToolLifeReportVulkanMS template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var sheet = Excel.Workbook.Worksheets[1];
                    dtToolData = VulkanMSDBAccess.GetToolLifeReportData(FromDate, ToDate, MachineID, out dt_Header);
                    int rowStart = 7, colStart = 1, colEnd = 8, HedaerColStart = 8;
                    if (dtToolData.Rows.Count > 0)
                    {
                        //sheet.Cells[rowStart, colStart].LoadFromDataTable(dtToolData, false);
                        foreach (DataRow row in dtToolData.Rows)
                        {
                            sheet.Cells[rowStart, 1].Value = row["ToolNo"].ToString();
                            sheet.Cells[rowStart, 2].Value = row["ToolType"].ToString();
                            sheet.Cells[rowStart, 3].Value = row["ToolSpecification"].ToString();
                            sheet.Cells[rowStart, 4].Value = string.IsNullOrEmpty(row["NoOfEdges"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["NoOfEdges"].ToString());
                            sheet.Cells[rowStart, 5].Value = string.IsNullOrEmpty(row["ToolLifeInMeter"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["ToolLifeInMeter"].ToString());
                            sheet.Cells[rowStart, 6].Value = string.IsNullOrEmpty(row["ActualLife"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["ActualLife"].ToString());
                            sheet.Cells[rowStart, 7].Value = string.IsNullOrEmpty(row["ToolchangeTime"].ToString()) ? "" : Util.GetDateTime(row["ToolchangeTime"].ToString()).ToString("dd-MM-yyyy HH:mm:ss");
                            sheet.Cells[rowStart, 8].Value = row["Reason"].ToString();
                            rowStart++;

                        }

                        if (dt_Header.Rows.Count > 0)
                        {
                            sheet.Cells[2, HedaerColStart].Value = dt_Header.Rows[0]["DocNo"].ToString();
                            sheet.Cells[3, HedaerColStart].Value = dt_Header.Rows[0]["RevNo"].ToString();
                            sheet.Cells[4, HedaerColStart].Value = dt_Header.Rows[0]["RevDate"].ToString();
                        }
                        setThinBorder(sheet, 1, 1, rowStart, 8);
                        DownloadMultipleFile(destination, Excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                        Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog($"GenerateToolChangeReportVulkanMS:{ex.ToString()}");
            }
            return Generated;
        }

