                                                {
                                                    var stream = new MemoryStream(imageEntity.imgInByte);
                                                    img = System.Drawing.Image.FromStream(stream);

                                                    img = ResizeImage(img, ImageWidth, ImageHeight);
                                                    var excelImage = sheet.Drawings.AddPicture(imageEntity.imgName + arr[i].ToString() + RowStart.ToString() + ColStart.ToString(), img);
