                                            }
                                        }
                                    }
                                    ColStart++;
                                    string InstrumentData = string.IsNullOrEmpty(row["Instrument"].ToString()) ? "" : row["Instrument"].ToString();
                                    if (!string.IsNullOrEmpty(InstrumentData))
                                    {
                                        var arr = InstrumentData.Split(',').ToList();
