                                        {
                                            sheet.Row(RowStart).Height = arr.Count * (ImageHeight + 10);

                                            for (int i = 0; i < arr.Count; i++)
                                            {
                                                imageEntity = DataBaseAccessVulkan.GetMethodImageData(arr[i]);
