                                        }
                                    }
                                    DayValueEnd = ColStart;
                                    RowStart++;
                                }

                                sheet.Cells[8, DayValueStartCol, 8, DayValueEnd - 1].Merge = true;
                                sheet.Cells[8, DayValueStartCol].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                for (int j = 1; j < 7; j++)
                                {
                                    sheet.Cells[j, 28, j, DayValueEnd - 1].Merge = true;
                                }
                                sheet.Cells[1, 28].Value = "DEPT:- LOKRING DIVISION";
                                sheet.Cells[2, 28].Value = $"DOC NO:-{tempDT.Rows[0]["DocNo"].ToString().Trim()}";
                                sheet.Cells[3, 28].Value = $"Machine Name:-{Machine}";
                                sheet.Cells[4, 28].Value = $"Issue Date:-{Util.GetDateTime(tempDT.Rows[0]["IssueDate"].ToString().Trim()).ToString("dd-MM-yyyy")}";
                                sheet.Cells[5, 28].Value = $"Rev NO:-{tempDT.Rows[0]["RevID"].ToString().Trim()}";
                                sheet.Cells[6, 28].Value = $"Rev Date:-{Util.GetDateTime(tempDT.Rows[0]["RevDate"].ToString().Trim()).ToString("dd-MM-yyyy")}";

                                sheet.Cells[1, 4].Value = $"Daily Check list for {Machine}";
                                sheet.Cells[7, 1].Value = $"MACHINE ID:- {Machine}";
                                sheet.Cells[7, 5].Value = $"FREQUENCY:- DAILY";
                                setThinBorder(sheet, 1, 28, 7, DayValueEnd - 1);
                                sheet.Cells[1, 28, 7, 28].Style.Font.Bold = true;
                                sheet.Cells[1, 28, 7, 28].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;

                                sheet.Cells[RowStart, 1, RowStart, 6].Merge = true;
                                sheet.Cells[RowStart, 1].Value = "Checked BY Sign:-";
                                sheet.Cells[RowStart + 1, 1, RowStart + 1, 6].Merge = true;
                                sheet.Cells[RowStart + 1, 1].Value = "Verified BY Sign:-";
                                DayValueEnd = DayValueStartCol;
                                if (dtSign.Rows.Count > 0)
                                {
                                    TempdtSign = dtSign.AsEnumerable().Where(x => x["MachineID"].ToString().Equals(Machine, StringComparison.OrdinalIgnoreCase)).CopyToDataTable();
                                    foreach (DataColumn column in tempDT.Columns)
                                    {
                                        int res = 0;
                                        int.TryParse(column.ColumnName.ToString(), out res);
                                        if (res > 0)
                                        {
                                            var OperatorSign = TempdtSign.AsEnumerable().Where(x => Util.GetDateTime(x["Date"].ToString()).Day == res).Select(x => $"{x["OperatorID"].ToString()}[{(string.IsNullOrEmpty(x["OperatorTS"].ToString()) ? "" : Util.GetDateTime(x["OperatorTS"].ToString()).ToString("dd-MM-yyyy HH:mm:ss"))}]").FirstOrDefault();
                                            var SupervisorSign = TempdtSign.AsEnumerable().Where(x => Util.GetDateTime(x["Date"].ToString()).Day == res).Select(x => $"{x["SupervisorID"].ToString()}[{(string.IsNullOrEmpty(x["SupervisorTS"].ToString()) ? "" : Util.GetDateTime(x["SupervisorTS"].ToString()).ToString("dd-MM-yyyy HH:mm:ss"))}]").FirstOrDefault();

                                            sheet.Cells[RowStart, DayValueEnd].Value = OperatorSign == null ? "" : OperatorSign.ToString();

                                            sheet.Cells[RowStart + 1, DayValueEnd].Value = SupervisorSign == null ? "" : SupervisorSign.ToString();
                                            DayValueEnd++;
                                        }
                                    }
                                    for (int i = DayValueStartCol; i < DayValueEnd; i++)
                                        sheet.Column(i).Width = 22;
                                    sheet.Cells[RowStart, DayValueStartCol, RowStart + 1, DayValueEnd].Style.WrapText = true;
                                }
                                setThinBorder(sheet, 8, 1, RowStart + 1, ColStart - 1);
                            }

                            excel.Workbook.Worksheets.Delete(1);
                            DownloadMultipleFile(destination, excel.GetAsByteArray());
                        }
                        Generated = "Generated";
                    }
                }
                else
                    Generated = "NoDataFound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog($"GenerateAMReport: {ex.ToString()}");
            }
            return Generated;
        }



        public static string DownloadPDF(string Path, string Name)
        {
            string success = "";
            try
            {
                using (FileStream fs = new FileStream(Path, FileMode.Open, FileAccess.Read))
                {
                    byte[] bytes = new byte[(int)fs.Length];
                    fs.Read(bytes, 0, (int)fs.Length);
                    HttpContext.Current.Response.Clear();
                    HttpContext.Current.Response.Buffer = true;
                    HttpContext.Current.Response.ContentType = "application/pdf";
                    HttpContext.Current.Response.AddHeader("content-disposition", $"attachment; filename={Name}.pdf");
                    HttpContext.Current.Response.BinaryWrite(bytes);
                    HttpContext.Current.Response.Flush();
                    HttpContext.Current.Response.Headers.Clear();
                    success = "Downloaded";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex);
            }
            return success;
        }
        static System.Drawing.Image ResizeImage(System.Drawing.Image image, int width, int height)
        {
            var newSize = new Size(width, height);
            var newImage = new Bitmap(newSize.Width, newSize.Height);
            try
            {
                using (var graphics = Graphics.FromImage(newImage))
                    graphics.DrawImage(image, new System.Drawing.Rectangle(Point.Empty, newSize));
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog($"ResizeImage: {ex}");
            }
            return newImage;
        }
