        internal static string GenerateDowntimeCodesReport()
        {
            string generated = "", previousValue = "", currentValue = "";
            int MergeRowsCount = 0, columnToMerge = 1;
            try
            {
                string Filename = "DowntimeCodesReport.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "DowntimeCodesReport" + DateTime.Now + ".xlsx";
                string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    generated = "Template not found";
                }
                else
                {
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);

                    List<DownCodesModel> list = DataBaseAccess.GetDowntimeCodesReportDetails();

                    if (list.Count > 0)
                    {
                        var worksheet = Excel.Workbook.Worksheets["Sheet1"];

                        int rowStart = 4, colStart = 1, rowStartCopy = rowStart;
                        previousValue = list[0].Catagory;
                        for (int i = 0; i < list.Count; i++)
                        {
                            colStart = 1;
                            currentValue = list[i].Catagory;
                            worksheet.Cells[rowStart, colStart].Value = list[i].Catagory;
                            colStart++;
                            worksheet.Cells[rowStart, colStart].Value = list[i].downid;
                            colStart++;
                            worksheet.Cells[rowStart, colStart].Value = list[i].interfaceid;
                            colStart++;
                            worksheet.Cells[rowStart, colStart].Value = list[i].downdescription;
                            colStart++;
                            worksheet.Cells[rowStart, colStart].Value = list[i].chkAvaileffy;
                            colStart++;
                            worksheet.Cells[rowStart, colStart].Value = list[i].Threshold;
                            colStart++;
                            worksheet.Cells[rowStart, colStart].Value = list[i].Owner;


                            if (currentValue == previousValue)
                            {
                                worksheet.Cells[rowStart - MergeRowsCount, columnToMerge, rowStart, columnToMerge].Merge = true;
                                MergeRowsCount++;
                            }
                            else
                            {
                                MergeRowsCount = 1;
                                previousValue = currentValue;
                            }

                            rowStart++;

                        }


                        // worksheet.Column(1).AutoFit();
                        setThinBorder(worksheet, rowStartCopy, 1, rowStart - 1, colStart);

                        var cell = worksheet.Cells[4, 1, rowStart, 1];
                        cell.Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                        worksheet.Cells[3, 1, rowStart, 6].AutoFitColumns();

                        DownloadMultipleFile(destination, Excel.GetAsByteArray());
                        generated = "Generated";
                    }
                    else
                    {
                        generated = "Data not found";
                    }
                }
            }
            catch (Exception ex)
            {
                generated = "Error";
                Logger.WriteErrorLog(ex.Message);
            }
            return generated;
        }

