        #region -- PITTI REPORTS --
        internal static string GenerateWorkOrderReportPitti(List<WorkorderTrackingEntity> data, string FromDate, string ToDate)
        {
            string Generated = "";
            List<WorkorderTrackingEntity> list = data;
            try
            {
                string Filename = "WorkOrderTrackingReport_Pitti.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "WorkOrderTrackingReport_Pitti" + DateTime.Now + ".xlsx";
                string destination = Path.Combine(appPath, "Temp", TMPTrakGenerateReport.SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("Work Order Tracking Report Pitti Template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    if (list.Count > 0)
                    {
                        var fileInfo = new FileInfo(Source);
                        ExcelPackage excel = new ExcelPackage(fileInfo);
                        var sheet = excel.Workbook.Worksheets[1];
                        int rowstart = 6, colStart = 1, rowstartCopy = rowstart, colStartCopy = colStart, HeaderRow = 6, HeaderCol = 4, i = 0;
                        WorkorderTrackingEntity entity = list[0];
                        for (int j = 0; j < list.Count; j++)
                        {
                            if (j != 1)
                            {
                                WorkorderTrackingEntity li = list[j];
                                colStart = 1;
                                HeaderCol = i == 1 ? 4 : HeaderCol;
                                if (i != 0)
                                {
                                    sheet.Cells[rowstart, colStart++].Value = li.WorkOrder;
                                    sheet.Cells[rowstart, colStart++].Value = li.ComponentID;
                                    sheet.Cells[rowstart, colStart++].Value = li.SerialNumber;
                                }
                                foreach (var en in li.OperationList)
                                {
                                    if (i == 0)
                                    {
                                        sheet.Cells[HeaderRow - 1, HeaderCol, HeaderRow - 1, HeaderCol + 4].Merge = true;
                                        sheet.Cells[HeaderRow - 1, HeaderCol].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                        sheet.Cells[HeaderRow - 1, HeaderCol].Value = en.OperationNo;
                                        HeaderCol += 5;
                                    }

                                    if (en.OperationType.Equals("Manual", StringComparison.Ordinal))
                                    {
                                        if (i == 1)
                                        {
                                            sheet.Cells[HeaderRow, HeaderCol, HeaderRow, HeaderCol + 4].Merge = true;
                                            HeaderCol += 5;
                                        }
                                        sheet.Cells[rowstart, colStart, rowstart, colStart + 4].Merge = true;
                                        sheet.Cells[rowstart, colStart].Value = "Manual Cycle";
                                        colStart += 5;
                                    }
                                    else if (en.OperationType.Equals("Auto", StringComparison.OrdinalIgnoreCase))
                                    {
                                        if (i == 1)
                                        {
                                            sheet.Cells[HeaderRow, HeaderCol++].Value = "MC";
                                            sheet.Cells[HeaderRow, HeaderCol++].Value = "Opr";
                                            sheet.Cells[HeaderRow, HeaderCol++].Value = "Str Time";
                                            sheet.Cells[HeaderRow, HeaderCol++].Value = "End Time";
                                            sheet.Cells[HeaderRow, HeaderCol++].Value = "Cycle Time";

                                            sheet.Cells[HeaderRow, HeaderCol].Style.Font.Bold = true;
                                        }
                                        sheet.Cells[rowstart, colStart++].Value = en.MachineID;
                                        sheet.Column(colStart).Style.WrapText = true;
                                        sheet.Column(colStart).Width = 10;
                                        sheet.Cells[rowstart, colStart++].Value = en.UpdatedBy;
                                        sheet.Column(colStart).Style.WrapText = true;
                                        sheet.Column(colStart).Width = 10;
                                        sheet.Cells[rowstart, colStart++].Value = en.StartTime;
                                        sheet.Column(colStart).Style.WrapText = true;
                                        sheet.Column(colStart).Width = 10;
                                        sheet.Cells[rowstart, colStart++].Value = en.EndTime;
                                        sheet.Column(colStart).Style.WrapText = true;
                                        sheet.Column(colStart).Width = 10;
                                        sheet.Cells[rowstart, colStart++].Value = en.CycleTime;
                                        sheet.Column(colStart).Style.WrapText = true;
                                        sheet.Column(colStart).Width = 10;
                                    }

                                }

                                i++;
                                rowstart++;
                            }
                        }
                        sheet.Column(2).AutoFit();
                        sheet.Cells[3, 3].Value = FromDate;
                        sheet.Cells[3, 7].Value = ToDate;

                        sheet.Cells[1, 1, 1, colStart - 1].Merge = true;
                        sheet.Cells[1, 1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        sheet.Cells[1, 1].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(70, 153, 192));
                        sheet.Cells[1, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;


                        sheet.Cells[HeaderRow - 1, 4, HeaderRow, HeaderCol - 1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        sheet.Cells[HeaderRow - 1, 4, HeaderRow, HeaderCol - 1].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(46, 104, 134));
                        sheet.Cells[HeaderRow - 1, 4, HeaderRow, HeaderCol - 1].Style.Font.Color.SetColor(Color.White);
                        sheet.Cells[HeaderRow - 1, 4, HeaderRow, HeaderCol - 1].Style.Font.Bold = true;

                        setThinBorder(sheet, 1, 1, rowstart - 1, colStart - 1);
                        DownloadMultipleFile(destination, excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                        Generated = "NoDataFound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
            }
            return Generated;
        }
        #endregion

