        internal static string GenerateProductionreportSKS(string MachineID, string Date)
        {
            string Generated = "";
            DataTable dt_ProdData = new DataTable();
            DataTable dt_HeaderData = new DataTable();
            DataTable dt = new DataTable();
            try
            {
                string Filename = "ERPPerformanceReportSKS.xlsx";
