                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("ERPPerformanceReportSKS Report SKS Template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    FileInfo fileInfo = new FileInfo(Source);
                    ExcelPackage excel = new ExcelPackage(fileInfo);
                    var workSheet = excel.Workbook.Worksheets[1];
                    dt = SKSDatabaseAccess.GetForgingMachinePerformanceReport(MachineID, Date, out dt_HeaderData); //, out dt_DownCode

                    int drow = 2, dCol = 2, dColEnd = 12, i = 1;
                  
                    workSheet.Cells[1, 11].Value = Date;

                    workSheet.PrinterSettings.Orientation = eOrientation.Landscape;
                    workSheet.PrinterSettings.PaperSize = ePaperSize.A4;
                    workSheet.PrinterSettings.FitToWidth = 1;
                    #region --- Downcode header ---
                    //if (dt_DownCode.Rows.Count > 0)
                    //{
                    //    foreach (DataRow row in dt_DownCode.Rows)
                    //    {
                    //        workSheet.Cells[drow, dCol++].Value = $"{(i++).ToString()}. {row["downid"].ToString()}";
                    //        if (dCol > dColEnd)
                    //        {
                    //            drow++;
                    //            dCol = 2;
                    //        }
                    //    }
                    //    workSheet.Cells[2, 2, drow - 1, 12].Style.WrapText = true;
                    //    workSheet.Cells[2, 1, drow - 1, 1].Merge = true;
                    //    workSheet.Cells[2, 1].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                    //    workSheet.Cells[2, 1].Style.VerticalAlignment = ExcelVerticalAlignment.Center;
                    //}
                    #endregion

                    int rowStart = 7, colStart = 1, tempRowStart = rowStart;
                    if (dt.Rows.Count > 0)
                    {
                        i = 0;
                        workSheet.Cells[1, 8].Value = dt.Rows[0]["MachineDescription"].ToString();
                        var shiftList = dt.AsEnumerable().Select(x => x["Shift"].ToString()).Distinct().ToList();
                        foreach (var shift in shiftList)
                        {
                            int Count = 0;
                            DataTable ShiftWiseDB = dt.AsEnumerable().Where(x => x["Shift"].ToString().Trim().Equals(shift, StringComparison.OrdinalIgnoreCase)).CopyToDataTable();
                            if (ShiftWiseDB.Rows.Count > 0)
                            {
                                var firstRow = ShiftWiseDB.Rows[0];
                                workSheet.Cells[rowStart, 1].Value = shift;
                                workSheet.Cells[rowStart, 2, rowStart, 5].Merge = true;
                                workSheet.Cells[rowStart, 2].Value = $"Operator Name: {dt_HeaderData.AsEnumerable().Where(x => x["shift"].ToString().Equals(shift, StringComparison.OrdinalIgnoreCase)).Select(x => x["OperatorName"].ToString()).FirstOrDefault().ToString()}";
                                workSheet.Cells[rowStart, 6, rowStart, 7].Merge = true;
                                workSheet.Cells[rowStart, 6].Value = $"Setter Name: {dt_HeaderData.AsEnumerable().Where(x => x["shift"].ToString().Equals(shift, StringComparison.OrdinalIgnoreCase)).Select(x => x["SetterName"].ToString()).FirstOrDefault().ToString()}";
                                workSheet.Cells[rowStart, 8, rowStart, 12].Merge = true;
                                workSheet.Cells[rowStart, 8].Value = $"Supervisor Name: {dt_HeaderData.AsEnumerable().Where(x => x["shift"].ToString().Equals(shift, StringComparison.OrdinalIgnoreCase)).Select(x => x["SupervisorName"].ToString()).FirstOrDefault().ToString()}";

                                workSheet.Cells[rowStart, 1, rowStart, 8].Style.Font.Bold = true;
                                rowStart++;

                                if (i == 0)
                                {
                                    colStart = 1;
                                    workSheet.Cells[rowStart, colStart++].Value = "Time From";
                                    workSheet.Cells[rowStart, colStart++].Value = "Time To";
                                    workSheet.Cells[rowStart, colStart++].Value = "Total Time";
                                    workSheet.Cells[rowStart, colStart++].Value = "Delay ID";
                                    workSheet.Cells[rowStart, colStart++].Value = "Delay Details";
                                    workSheet.Cells[rowStart, colStart++].Value = "Product Description";
                                    workSheet.Cells[rowStart, colStart++].Value = "Lot No.";
                                    workSheet.Cells[rowStart, colStart++].Value = "Prod. Qty.";
                                    workSheet.Cells[rowStart, colStart++].Value = "Setup Rej. Qty.";
                                    workSheet.Cells[rowStart, colStart++].Value = "InProcess Rej. Qty.";
                                    workSheet.Cells[rowStart, colStart++].Value = "Re-setting Rej.";
                                    workSheet.Cells[rowStart, colStart].Value = "M/C Speed";
                                    workSheet.Cells[rowStart, 1, rowStart, colStart].Style.WrapText = true;
                                    workSheet.Cells[rowStart, 1, rowStart, colStart].Style.Font.Bold = true;
                                    rowStart++;
                                }
                                i++;
                                var PrevLotNumber = ShiftWiseDB.Rows[0]["LotNumber"].ToString() + ShiftWiseDB.Rows[0]["CatalogCode_Description"].ToString();
                                var curLotNumber = ShiftWiseDB.Rows[0]["LotNumber"].ToString() + ShiftWiseDB.Rows[0]["CatalogCode_Description"].ToString();
                                foreach (DataRow row in ShiftWiseDB.Rows)
                                {
                                    curLotNumber = row["LotNumber"].ToString() + row["CatalogCode_Description"].ToString();
                                    colStart = 1;
                                    workSheet.Cells[rowStart, colStart++].Value = string.IsNullOrEmpty(row["DownstartTime"].ToString()) ? "" : Util.GetDateTime(row["DownstartTime"].ToString()).ToString("dd-MM-yyyy HH:mm:ss");
                                    workSheet.Cells[rowStart, colStart++].Value = string.IsNullOrEmpty(row["DownendTime"].ToString()) ? "" : Util.GetDateTime(row["DownendTime"].ToString()).ToString("dd-MM-yyyy HH:mm:ss");
                                    workSheet.Cells[rowStart, colStart++].Value = row["Downtime"].ToString();
                                    workSheet.Cells[rowStart, colStart++].Value = row["DelayCode"].ToString();
                                    workSheet.Cells[rowStart, colStart++].Value = row["DelayCodeDescription"].ToString();
                                    workSheet.Cells[rowStart, colStart++].Value = row["CatalogCode_Description"].ToString();
                                    workSheet.Cells[rowStart, colStart++].Value = row["LotNumber"].ToString();
                                    workSheet.Cells[rowStart, colStart++].Value = string.IsNullOrEmpty(row["ActualQty"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["ActualQty"].ToString());
                                    workSheet.Cells[rowStart, colStart++].Value = string.IsNullOrEmpty(row["SetUpRejection"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["SetUpRejection"].ToString());
                                    workSheet.Cells[rowStart, colStart++].Value = string.IsNullOrEmpty(row["InProcessRejection"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["InProcessRejection"].ToString());
                                    workSheet.Cells[rowStart, colStart++].Value = string.IsNullOrEmpty(row["ReSettingRejection"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["ReSettingRejection"].ToString());
                                    workSheet.Cells[rowStart, colStart].Value = string.IsNullOrEmpty(row["Speed"].ToString()) ? 0 : Math.Round(HelperClassGeneric.getDoubleValueFromString(row["Speed"].ToString()), 2);

                                    if (PrevLotNumber == curLotNumber)
                                    {
                                        workSheet.Cells[rowStart - Count, 6, rowStart, 6].Merge = true;
                                        workSheet.Cells[rowStart - Count, 7, rowStart, 7].Merge = true;
                                        workSheet.Cells[rowStart - Count, 8, rowStart, 8].Merge = true;
                                        workSheet.Cells[rowStart - Count, 9, rowStart, 9].Merge = true;
                                        workSheet.Cells[rowStart - Count, 10, rowStart, 10].Merge = true;
                                        workSheet.Cells[rowStart - Count, 11, rowStart, 11].Merge = true;
                                        workSheet.Cells[rowStart - Count, 12, rowStart, 12].Merge = true;
                                        Count++;
                                    }
                                    else
                                    {
                                        PrevLotNumber = curLotNumber;
                                        Count = 1;
                                    }
                                    rowStart++;
                                }
                                //workSheet.Cells[rowStart - ShiftWiseDB.Rows.Count - 1, 6, rowStart - 1, 6].Merge = true;
                                rowStart += 2;
                            }
                        }
                        Generated = "Generated";
                        workSheet.Column(6).Style.WrapText = true;
                        workSheet.Cells[rowStart - 2, 1, rowStart - 2, 12].Merge = true;
                        workSheet.Cells[rowStart - 2, 1].Style.Font.Bold = true;
                        workSheet.Cells[rowStart - 2, 1].Value = "Form No: PPC / 03 /08 - Date - 11.10.2022";
                        //workSheet.Cells[4, 1, rowStart - 1, 8].AutoFitColumns();
                        setThinBorder(workSheet, 2, 1, rowStart - 2, 12);
                        DownloadMultipleFile(destination, excel.GetAsByteArray());
                    }
                    else
                        Generated = "NoDataFound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
            }
            return Generated;
        }
