        #region-----Inspection Report - Rexnord-----------------
        internal static string GetInspectionReport(string SerialNo, string OperationNo)
        {
            string Generated = "";
            try
            {
                string Filename = "InspectionReport_Rexnord.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "InspectionReport_Rexnord" + DateTime.Now.ToString("yyyy-MM-dd") + ".xlsx";
                string destination = Path.Combine(appPath, "GeneratedReports", SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("Inspection Report - Rexnord template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var workSheet = Excel.Workbook.Worksheets[1];

                    DataTable dt = DataBaseAccess.GetInspectionReportData_Rexnord(SerialNo, OperationNo);
                    if (dt.Rows.Count > 0)
                    {
                        var distOperations = dt.AsEnumerable().Select(x => x["OperationNo"].ToString()).Distinct().ToList();
                        workSheet.Cells["B3"].Value = dt.Rows[0]["componentid"].ToString();
                        workSheet.Cells["B4"].Value = SerialNo;
                        workSheet.Cells["H3"].Value = dt.Rows[0]["description"].ToString();
                        var workorderno = dt.AsEnumerable().Select(x => x["WorkOrderNo"].ToString()).Distinct().ToList();
                        var minWorkorder = workorderno.Min();
                        var maxWorkOrder = workorderno.Max();
                        foreach (var workorder in workorderno)
                        {
                            if (workSheet.Cells["H4"].Value == null)
                            {
                                workSheet.Cells["H4"].Value = workorder;
                            }
                            else
                            {
                                workSheet.Cells["H4"].Value = workSheet.Cells["H4"].Value + "," + workorder;
                            }
                        }
                        int rowStart = 7, row = 7;
                        foreach (var Operation in distOperations)
                        {
                            workSheet.Cells[rowStart, 1, rowStart, 8].Merge = true;
                            workSheet.Cells[rowStart, 1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            workSheet.Cells[rowStart, 1].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(248, 203, 173));
                            workSheet.Cells[rowStart, 1].Value = "OPN" + " " + Operation + " " + "Inprocess Inspection Report";
                            workSheet.Cells[rowStart, 1].Style.Font.Bold = true;
                            rowStart++;
                            workSheet.Cells[rowStart, 1, rowStart, 8].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            workSheet.Cells[rowStart, 1, rowStart, 8].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(248, 203, 173));
                            workSheet.Cells[rowStart, 1].Value = "SlNo";
                            workSheet.Cells[rowStart, 2].Value = "Opr";
                            workSheet.Cells[rowStart, 3].Value = "Inspection Characterstics";
                            workSheet.Cells[rowStart, 4].Value = "Mean";
                            workSheet.Cells[rowStart, 5].Value = "LSL";
                            workSheet.Cells[rowStart, 6].Value = "USL";
                            workSheet.Cells[rowStart, 7].Value = "Value Entered";
                            workSheet.Cells[rowStart, 8].Value = "Updated TS";
                            workSheet.Cells[rowStart, 1, rowStart, 8].Style.Font.Bold = true;
                            rowStart++;
                            DataTable dtOperation = dt.AsEnumerable().Where(x => x.Field<int>("OperationNo") == Convert.ToInt32(Operation)).CopyToDataTable();
                            foreach (DataRow dtRow in dtOperation.Rows)
                            {
                                workSheet.Cells[rowStart, 1].Value = dtRow["SerialNumber"].ToString();
                                workSheet.Cells[rowStart, 2].Value = dtRow["Opr"].ToString();
                                workSheet.Cells[rowStart, 3].Value = dtRow["CharacteristicCode"].ToString();
                                workSheet.Cells[rowStart, 4].Value = dtRow["SpecificationMean"].ToString();
                                workSheet.Cells[rowStart, 5].Value = dtRow["LSL"].ToString();
                                workSheet.Cells[rowStart, 6].Value = dtRow["USL"].ToString();
                                workSheet.Cells[rowStart, 7].Value = dtRow["Value"].ToString();
                                workSheet.Cells[rowStart, 8].Value = Convert.ToDateTime(dtRow["Timestamp"].ToString()).ToString("dd-MM-yyyy HH:mm:ss");
                                rowStart++;
                            }
                            setThinBorder(workSheet, row, 1, rowStart - 1, 8);
                            rowStart++;
                            row = rowStart;
                        }

                        DownloadMultipleFile(destination, Excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    Generated = "NodataFound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex);
            }
            return Generated;
        }
        internal static string GenerateWorkOrderReportRexnord(List<WorkOrderTrackingData_Rexnord> data, string FromDate, string ToDate)
        {
            string Generated = "";
            List<WorkOrderTrackingData_Rexnord> list = data;
            try
            {
                string Filename = "WorkOrderReport_Rexnord.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "WorkOrderReport_Rexnord" + DateTime.Now + ".xlsx";
                string destination = Path.Combine(appPath, "Temp", TMPTrakGenerateReport.SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("Work Order Report Rexnord Template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    if (list.Count > 0)
                    {
                        var fileInfo = new FileInfo(Source);
                        ExcelPackage excel = new ExcelPackage(fileInfo);
                        var sheet = excel.Workbook.Worksheets[1];
                        sheet.Cells["B3"].Value = FromDate;
                        sheet.Cells["E3"].Value = ToDate;
                        int rowstart = 6;
                        for (int i = 0; i < list.Count; i++)
                        {
                            sheet.Cells[rowstart, 1, rowstart, 12].Style.Fill.PatternType = ExcelFillStyle.Solid;
                            sheet.Cells[rowstart, 1, rowstart, 12].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml(list[i].trBackColor));
                            sheet.Cells[rowstart, 1].Value = list[i].WorkOrder;
                            sheet.Cells[rowstart, 2].Value = list[i].ComponentID;
                            sheet.Cells[rowstart, 3].Value = list[i].SerialNo;
                            sheet.Cells[rowstart, 4].Value = list[i].OperationNo;
                            if (list[i].OperationType.Equals("Manual", StringComparison.OrdinalIgnoreCase))
                            {
                                sheet.Cells[rowstart, 5, rowstart, 9].Merge = true;
                                sheet.Cells[rowstart, 5].Value = "Manual Cycle";
                                //sheet.Cells[rowstart, 5].Value = "Manual Cycle" + "\u25EF";
                                //var circleFont = sheet.Cells[rowstart, 5].Style.Font;
                                //circleFont.Size = 12;
                                //circleFont.Color.SetColor(Color.Green);
                                //var checkmarkFont = sheet.Cells[rowstart, 5].RichText.Add("\u2713");
                                //checkmarkFont.Bold = true;
                                //checkmarkFont.Color.ToArgb();
                            }
                            else
                            {
                                sheet.Cells[rowstart, 5].Value = list[i].Machine;
                                sheet.Cells[rowstart, 6].Value = list[i].Operator;
                                sheet.Cells[rowstart, 7].Value = list[i].StartTime;
                                sheet.Cells[rowstart, 8].Value = list[i].EndTime;
                                sheet.Cells[rowstart, 9].Value = list[i].ActualTime;
                            }
                            sheet.Cells[rowstart, 10].Value = list[i].Rejection;
                            sheet.Cells[rowstart, 11].Value = list[i].RejectionRemarks;
                            sheet.Cells[rowstart, 12].Value = list[i].RejectionBy;
                            rowstart++;
                        }

                        setThinBorder(sheet, 6, 1, rowstart - 1, 12);
                        DownloadMultipleFile(destination, excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                        Generated = "NoDataFound";
                }

            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex.Message);
            }
            return Generated;
        }
