        #region-------Daily Report WebApplication -KunAero-----------------
        internal static string GetDailyProductionReport_KunAero(DateTime Date, string MachineID, string ComponentID)
        {
            string Generated = "";
            try
            {
                string FileName = "DailyProductionReport_KunAero.xlsx";
                string Source = Util.GetReportPath(FileName);
                string Template = "DailyProductionReport_KunAero" + DateTime.Now.ToString("yyyy-MM-dd") + ".xlsx";
                string destination = Path.Combine(appPath, "GeneratedReports", SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("DailyProductionReport_KunAero template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    FileInfo newFile = new FileInfo(Source);
                    ExcelPackage Excel = new ExcelPackage(newFile, true);
                    var workSheet = Excel.Workbook.Worksheets[1];
                    DataTable dt1 = new DataTable();
                    DataTable dt = TMPTrakDataBase.GetDailyProductionReportData_KunAero(out dt1, Date, MachineID, ComponentID);
                    int rowStart = 7, colStart = 1;
                    if (dt.Rows.Count > 0)
                    {
                        var distShifts = dt1.AsEnumerable().Select(x => x.Field<string>("ShiftName")).Distinct().ToList();
                        workSheet.Cells["B3"].Value = Convert.ToDateTime(Date).ToString("dd-MM-yyyy");
                        for (int i = 0; i < dt.Columns.Count; i++)
                        {
                            if (dt.Columns[i].ColumnName == "StdLoadUnloadTime")
                            {
                                workSheet.Cells[5, colStart, 6, colStart].Merge = true;
                                workSheet.Cells[5, colStart].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                workSheet.Cells[5, colStart].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(0, 176, 240));
                                workSheet.Cells[5, colStart].Value = dt.Columns[i].ColumnName;
                                colStart++;
                                foreach (var shift in distShifts)
                                {
                                    workSheet.Cells[4, colStart, 4, colStart + 11].Merge = true;
                                    workSheet.Cells[4, colStart, 4, colStart + 11].Value = shift;
                                    workSheet.Cells[4, colStart, 4, colStart + 11].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                    workSheet.Cells[4, colStart, 4, colStart + 11].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(230, 184, 183));
                                    setThinBorder(workSheet, 4, 13, 4, 13 + (distShifts.Count * (dt1.Columns.Count - 7)) - 1);
                                    for (int j = 7; j < dt1.Columns.Count; j++)
                                    {
                                        if (dt1.Columns[j].ColumnName == "AcceptedPercentage")
                                        {
                                            workSheet.Cells[5, colStart, 5, colStart + 1].Merge = true;
                                            workSheet.Cells[5, colStart].Value = "Percentage";
                                        }
                                        if (dt1.Columns[j].ColumnName != "RejectedPercentage" && dt1.Columns[j].ColumnName != "AcceptedPercentage")
                                        {
                                            workSheet.Cells[5, colStart, 6, colStart].Merge = true;
                                            workSheet.Cells[5, colStart].Value = dt1.Columns[j].ColumnName;
                                        }
                                        else
                                        {
                                            workSheet.Cells[6, colStart].Value = dt1.Columns[j].ColumnName;
                                        }
                                        workSheet.Cells[5, colStart, 6, colStart].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                        workSheet.Cells[5, colStart, 6, colStart].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(0, 176, 80));
                                        colStart++;
                                    }
                                }
                            }
                            else
                            {
                                if (dt.Columns[i].ColumnName == "TotalAcceptedPercentage")
                                {
                                    workSheet.Cells[5, colStart, 5, colStart + 1].Merge = true;
                                    workSheet.Cells[5, colStart].Value = "Total Cumulative Quantity";
                                }
                                else if (dt.Columns[i].ColumnName == "AEffy")
                                {
                                    workSheet.Cells[5, colStart, 5, colStart + 2].Merge = true;
                                    workSheet.Cells[5, colStart].Value = "Overall (%)";
                                }
                                if (dt.Columns[i].ColumnName != "TotalAcceptedPercentage" && dt.Columns[i].ColumnName != "TotalRejectedPercentage" && dt.Columns[i].ColumnName != "AEffy" && dt.Columns[i].ColumnName != "PEffy" && dt.Columns[i].ColumnName != "OEffy" && dt.Columns[i].ColumnName != "QEffy")
                                {
                                    workSheet.Cells[5, colStart, 6, colStart].Merge = true;
                                    workSheet.Cells[5, colStart].Value = dt.Columns[i].ColumnName;
                                }
                                else
                                {
                                    workSheet.Cells[6, colStart].Value = dt.Columns[i].ColumnName;
                                }
                                workSheet.Cells[5, colStart, 6, colStart].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                workSheet.Cells[5, colStart, 6, colStart].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(0, 176, 240));
                                colStart++;
                            }
                        }
                        workSheet.Cells[1, 1, 1, colStart].Merge = true;
                        workSheet.Cells[1, 1].Value = "Daily Production Report";
                        workSheet.Cells[1, 1, 1, colStart].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        workSheet.Cells[1, 1, 1, colStart].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(230, 184, 183));
                        foreach (DataRow dtRow in dt.Rows)
                        {
                            colStart = 1;
                            for (int i = 0; i < dt.Columns.Count; i++)
                            {
                                if (dt.Columns[i].ColumnName == "StdLoadUnloadTime")
                                {
                                    workSheet.Cells[rowStart, colStart].Value = dtRow[dt.Columns[i].ColumnName].ToString();
                                    colStart++;
                                    foreach (var shift in distShifts)
                                    {
                                        DataRow firstRow = dt1.AsEnumerable().Where(k => k["MachineName"].ToString().Equals(dtRow["MachineName"].ToString(), StringComparison.OrdinalIgnoreCase) && k["ShiftName"].ToString().Equals(shift, StringComparison.OrdinalIgnoreCase) && k["ComponentID"].ToString().Equals(dtRow["ComponentID"].ToString(), StringComparison.OrdinalIgnoreCase) && k["OperationNo"].ToString().Equals(dtRow["OperationNo"].ToString(), StringComparison.OrdinalIgnoreCase) && k["CustomerName"].ToString().Equals(dtRow["CustomerName"].ToString(), StringComparison.OrdinalIgnoreCase) && k["WorkOrderNo"].ToString().Equals(dtRow["WorkOrderNo"].ToString(), StringComparison.OrdinalIgnoreCase)).FirstOrDefault();
                                        if (firstRow != null)
                                        {
                                            for (int j = 7; j < dt1.Columns.Count; j++)
                                            {
                                                workSheet.Cells[rowStart, colStart].Value = firstRow[dt1.Columns[j].ColumnName].ToString();
                                                colStart++;
                                            }
                                        }
                                        else
                                        {
                                            colStart = colStart + 12;
                                        }
                                    }
                                }
                                else
                                {
                                    if (dt.Columns[i].ColumnName == "WorkOrderDate")
                                    {
                                        workSheet.Cells[rowStart, colStart].Value = Convert.ToDateTime(dtRow[dt.Columns[i].ColumnName].ToString()).ToString("dd-MM-yyyy");
                                    }
                                    else
                                    {
                                        workSheet.Cells[rowStart, colStart].Value = dtRow[dt.Columns[i].ColumnName].ToString();
                                    }
                                    colStart++;
                                }
                            }
                            rowStart++;
                        }
                        setThinBorder(workSheet, 5, 1, rowStart - 1, colStart - 1);
                        workSheet.Cells[7, 1, rowStart - 1, colStart - 1].AutoFitColumns();
                        DownloadMultipleFile(destination, Excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                    {
                        Generated = "NodataFound";
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog(ex);
            }
            return Generated;
        }
        #endregion

        #region -- Production Componentwise Report - Aggregated ----

        internal static string ComponentwiseReport_Agg(DateTime StartDate, string ComponentID, string OperationNo, DateTime EndDate)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "PR_ComponentwiseReportAgg.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "PR_ComponentwiseReportAgg" + "_" + Guid.NewGuid() + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (OperationNo.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    OperationNo = "";
                if (ComponentID.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    ComponentID = "";
                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Production - Componentwise Report Agg EXCEL - \n " + src);
                }
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];

                wsDts.Cells["B2"].Value = StartDate.ToString("dd-MMM-yyyy");
                wsDts.Cells["B4"].Value = EndDate.ToString("dd-MMM-yyyy");
                wsDts.Cells["H2"].Value = ComponentID == "" ? "All" : ComponentID;
                wsDts.Cells["H4"].Value = OperationNo == "" ? "All" : OperationNo;
                int row = 9;
                DataTable dt = TMPTrakDataBase.ComponentwiseReportAgg(StartDate, ComponentID, OperationNo, EndDate);
                if (dt != null && dt.Rows.Count > 0)
                {
                    string timeFormat = DataBaseAccess.getTimeFormatFromCockpit();

                    foreach (DataRow item in dt.Rows)
                    {
                        wsDts.Cells[row, 1].Value = item["ComponentID"];
                        wsDts.Cells[row, 2].Value = Convert.ToInt32(item["OperationNo"].ToString());
                        wsDts.Cells[row, 3].Value = item["MachineID"];
                        wsDts.Cells[row, 4].Value = item["Machinedescription"];
                        setTimeSpanFormat(timeFormat, wsDts, row, 5, item["StdCycleTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 6, item["AvgCycleTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 7, item["MaxMachiningTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 8, item["MinMachiningTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 9, item["StdLoadUnloadTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 10, item["AvgLoadUnloadTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 11, item["MaxLoadUnloadTime"].ToString());
                        setTimeSpanFormat(timeFormat, wsDts, row, 12, item["MinLoadUnloadTime"].ToString());
                        wsDts.Cells[row, 13].Value = Math.Round(Convert.ToDouble(item["SpeedRatio"]), 2);
                        wsDts.Cells[row, 14].Value = Math.Round(Convert.ToDouble(item["LoadRatio"]), 2);
                        wsDts.Cells[row, 15].Value = item["Count"];
                        if (!(item["AE"] is DBNull))
                            wsDts.Cells[row, 16].Value = Math.Round(Convert.ToDouble(item["AE"]), 2);
                        if (!(item["PE"] is DBNull))
                            wsDts.Cells[row, 17].Value = Math.Round(Convert.ToDouble(item["PE"]), 2);
                        if (!(item["QE"] is DBNull))
                            wsDts.Cells[row, 18].Value = Math.Round(Convert.ToDouble(item["QE"]), 2);
                        if (!(item["OEE"] is DBNull))
                            wsDts.Cells[row, 19].Value = Math.Round(Convert.ToDouble(item["OEE"]), 2);
                        row++;
                    }

                    string modelRange = "A9:S" + (row - 1).ToString();
                    var modelTable = wsDts.Cells[modelRange];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    wsDts.Cells[modelRange].AutoFitColumns();
                    if (DataBaseAccess.isQERequired() == false)
                    {
                        wsDts.Column(18).Hidden = true;
                    }
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Production report-Componentwise Agg Report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("ComponentwiseReportAgg=" + ex.Message);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }

