                string tempfileName = "OperatorEfficiency_PrecisionEngg" + "_" + DateTime.Now + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (Operator.Equals("ALL", StringComparison.OrdinalIgnoreCase))
