                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("OperatorEfficiency Report PrecisionEngg EXCEL - \n " + src);
                }
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];

                wsDts.Cells["B2"].Value = StartDate.ToString("dd-MMM-yyyy");
                wsDts.Cells["B4"].Value = EndDate.ToString("dd-MMM-yyyy");
                wsDts.Cells["E2"].Value = Operator == "" ? "All" : Operator;
                int row = 7, col = 1;
                DataTable dt = TMPTrakDataBase.GetPrecisionEnggReport(StartDate, EndDate, "", "", "", Operator, "OperatorWise");
                if (dt != null && dt.Rows.Count > 0)
                {
                    foreach (DataRow item in dt.Rows)
                    {
                        col = 1;
                        wsDts.Cells[row, col++].Value = item["OperatorName"];
                        wsDts.Cells[row, col++].Value = item["MachineID"];
                        wsDts.Cells[row, col++].Value = item["ComponentID"];
                        wsDts.Cells[row, col++].Value = item["OperationNo"];
                        wsDts.Cells[row, col].Value = item["ProdCount"];
                        row++;
                    }
                    row--;
                    var modelTable = wsDts.Cells[6, 1, row, col];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    //wsDts.Cells[6, 1, row, col].AutoFitColumns();
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Operator Efficiency Precision Engg Report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("OperatorEfficiency_PrecisionEngg=" + ex.Message);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }

        internal static string GetDailyCleaningAndMaintenance_PrecisionEnggReport(DateTime fromDate, string groupID, string machineId)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "DailyCleaningAndMaintenance_PrecisionEngg.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "DailyCleaningAndMaintenance_PrecisionEngg" + "_" + DateTime.Now + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (groupID.Equals("ALL", StringComparison.OrdinalIgnoreCase))
                    groupID = "";

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Daily Cleaning and Maintenance Report PrecisionEngg EXCEL - \n " + src);
                }
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];

                int colStart = 2, rowStart = 2, maxColCount = 0;
                wsDts.Cells["A1"].Value = fromDate.ToString("dd-MMM-yyyy");

                DataTable dt = TMPTrakDataBase.GetDailyCleaningAndMaintenance_PrecisionEnggReport(fromDate, groupID, machineId, "View_DailyCheckSheet");
                if (dt != null && dt.Rows.Count > 0)
                {
                    List<string> GroupIDLst = dt.AsEnumerable().Select(x => x.Field<string>("GroupID")).Distinct().ToList();
                    foreach (var GroupId in GroupIDLst)
                    {
                        colStart = 2;
                        wsDts.Cells[rowStart, 1].Value = GroupId;
                        wsDts.Cells[rowStart, 1, rowStart + 1, 1].Merge = true;
                        wsDts.Cells[rowStart, 1, rowStart + 1, 1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        wsDts.Cells[rowStart, 1, rowStart + 1, 1].Style.Fill.BackgroundColor.SetColor(ColorTranslator.FromHtml("#B2A1C7"));
                        wsDts.Cells[rowStart, 1].Style.Font.Bold = true;
                        wsDts.Cells[rowStart, 1].Style.Font.Size = 14;
                        DataTable distdt = dt.AsEnumerable().Where(x => x.Field<string>("GroupID").Equals(GroupId)).Distinct().CopyToDataTable();
                        var distColLst = distdt.AsEnumerable().Select(k => new { CheckPoint = k.Field<string>("CheckpointDesc"), CheckPointInHindi = k.Field<string>("CheckpointDescInHindi") }).Distinct().ToList();
                        foreach (var item in distColLst)
                        {
                            wsDts.Cells[rowStart, colStart].Value = item.CheckPointInHindi;
                            wsDts.Cells[rowStart, colStart].Style.Font.Bold = true;
                            colStart++;
                        }
                        rowStart++;
                        colStart = 2;
                        foreach (var item in distColLst)
                        {
                            wsDts.Cells[rowStart, colStart].Value = item.CheckPoint;
                            wsDts.Cells[rowStart, colStart].Style.Font.Bold = true;
                            colStart++;
                        }
                        rowStart++;
                        List<string> machineLst = distdt.AsEnumerable().Select(x => x.Field<string>("MachineID")).Distinct().ToList();
                        foreach (var mach in machineLst)
                        {
                            colStart = 1;
                            var distval = distdt.AsEnumerable().Where(x => x.Field<string>("MachineID").Equals(mach)).Select(k => new { CheckPointID = k.Field<string>("CheckpointID"), CheckPoint = k.Field<string>("CheckpointDesc"), Value = k.Field<string>("Value"), Remarks = k.Field<string>("Remarks") }).Distinct().ToList();
                            wsDts.Cells[rowStart, colStart].Value = mach;
                            wsDts.Cells[rowStart, colStart++].Style.Font.Bold = true;
                            foreach (var val in distval)
                            {
                                if (string.IsNullOrEmpty(val.Remarks))
                                    wsDts.Cells[rowStart, colStart++].Value = val.Value;
                                else
                                    wsDts.Cells[rowStart, colStart++].Value = val.Value + "(" + val.Remarks + ")";
                            }
                            rowStart++;
                        }
                        rowStart++;
                        if (maxColCount < colStart)
                            maxColCount = colStart;
                    }
                    rowStart = rowStart - 2;
                    colStart--;
                    wsDts.Cells[1, 3, 1, colStart].Merge = true;
                    wsDts.Cells[1, 3, 1, colStart].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                    var modelTable = wsDts.Cells[2, 1, rowStart, maxColCount - 1];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    modelTable.AutoFitColumns();
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("DailyCleaningAndMaintenance Precision Engg Report generated sucessfully.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("DailyCleaningAndMaintenance_PrecisionEngg=" + ex.Message);
                ErrorSignal.FromCurrentContext().Raise(ex);
            }
            return Generated;
        }
        internal static string GetMaintenanceParticularReport_PrecisionEngg(DateTime Date, DateTime ToDate, string MachineID, string Type)
        {
            string Generated = "";
            try
            {
                string src, dst = string.Empty;
                string reportName = "MaintenanceParticularReport_precisionEngg.xlsx";
                src = Util.GetReportPath(reportName);

                string tempfileName = "MaintenanceParticularReport_precisionEngg" + "_" + DateTime.Now + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(tempfileName));

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Maintenance Particular Report precisionEngg EXCEL - \n " + src);
                }
                FileInfo newFile = new FileInfo(src);
                ExcelPackage pck = new ExcelPackage(newFile, true);
                var wsDts = pck.Workbook.Worksheets["Sheet1"];

                int row = 4, col = 1;
                DataTable dt = new DataTable();
                if (Type == "Machinewise")
                {
                    dt = TMPTrakDataBase.GetMaintenanceParticularReport_precisionEnggData(Date, ToDate, MachineID, Type);
                }
                else if (Type == "Operatorwise")
                {
                    dt = TMPTrakDataBase.GetMaintenanceParticularReport_precisionEnggData(Date, ToDate, MachineID, Type);
                }
                else if (Type == "Particularwise")
                {
                    dt = TMPTrakDataBase.GetMaintenanceParticularReport_precisionEnggData(Date, ToDate, MachineID, Type);
                }
                wsDts.Cells["A1"].Value = Type == "Machinewise" ? "MAINTENANCE PARTICULAR - MACHINE WISE" : Type == "Operatorwise" ? "MAINTENANCE PARTICULAR - OPERATOR WISE" : Type == "Particularwise" ? "MAINTENANCE PARTICULAR - PARTICULAR WISE" : "MAINTENANCE PARTICULAR";
                if (dt != null && dt.Rows.Count > 0)
                {
                    foreach (DataRow item in dt.Rows)
                    {
                        col = 1;
                        if (Type == "Machinewise")
                        {
                            wsDts.Cells[row, col++].Value = item["MachineID"];
                            wsDts.Cells[row, col++].Value = Convert.ToDateTime(item["UpdatedTS"]).ToString("dd-MM-yyyy HH:mm:ss");
                            wsDts.Cells[row, col++].Value = item["Shift"];
                            wsDts.Cells[row, col++].Value = item["Frequency"];
                            wsDts.Cells[row, col++].Value = item["CheckpointDesc"];
                            wsDts.Cells[row, col++].Value = item["UpdatedBy"];
                        }
                        else if (Type == "Operatorwise")
                        {
                            if (row == 4)
                            {
                                wsDts.Cells[3, col++].Value = "EMPLOYEE";
                                wsDts.Cells[3, col++].Value = "MAINTENANCE PARTICULAR";
                                wsDts.Cells[3, col++].Value = "FREQUENCY";
                                wsDts.Cells[3, col++].Value = "MACHINE";
                                wsDts.Cells[3, col++].Value = "DATE";
                                wsDts.Cells[3, col++].Value = "SHIFT";
                            }
                            col = 1;
                            wsDts.Cells[row, col++].Value = item["UpdatedBy"];
                            wsDts.Cells[row, col++].Value = item["CheckpointDesc"];
                            wsDts.Cells[row, col++].Value = item["Frequency"];
                            wsDts.Cells[row, col++].Value = item["MachineID"];
                            wsDts.Cells[row, col++].Value = Convert.ToDateTime(item["UpdatedTS"]).ToString("dd-MM-yyyy HH:mm:ss");
                            wsDts.Cells[row, col++].Value = item["Shift"];
                        }
                        else if (Type == "Particularwise")
                        {
                            if (row == 4)
                            {
                                wsDts.Cells[3, col++].Value = "MAINTENANCE PARTICULAR";
                                wsDts.Cells[3, col++].Value = "MACHINE";
                                wsDts.Cells[3, col++].Value = "DATE";
                                wsDts.Cells[3, col++].Value = "SHIFT";
                                wsDts.Cells[3, col++].Value = "FREQUENCY";
                                wsDts.Cells[3, col++].Value = "EMPLOYEE";
                            }
                            col = 1;
                            wsDts.Cells[row, col++].Value = item["CheckpointDesc"];
                            wsDts.Cells[row, col++].Value = item["MachineID"];
                            wsDts.Cells[row, col++].Value = Convert.ToDateTime(item["UpdatedTS"]).ToString("dd-MM-yyyy HH:mm:ss");
                            wsDts.Cells[row, col++].Value = item["Shift"];
                            wsDts.Cells[row, col++].Value = item["Frequency"];
                            wsDts.Cells[row, col++].Value = item["UpdatedBy"];
                        }
                        row++;
                    }
                    row--;
                    var modelTable = wsDts.Cells[4, 1, row, col - 1];
                    // Assign borders
                    modelTable.Style.Border.Top.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Left.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Right.Style = ExcelBorderStyle.Thin;
                    modelTable.Style.Border.Bottom.Style = ExcelBorderStyle.Thin;
                    DownloadMultipleFile(dst, pck.GetAsByteArray());
                    Logger.WriteDebugLog("Maintenance Particular Report precisionEngg generated sucessfully.");
                    Generated = "Generated";
                }
                else
                {
                    Generated = "Nodatafound";
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("MaintenanceParticularReport_precisionEngg=" + ex.Message);
            }
            return Generated;
        }
