        #region -- Custom Production Report(Aggregated) - Dynamic Flow
        internal static string ProductionReportDynamicFlow_Agg(string CellID, string MachineID, string shift, DateTime FromDate, DateTime ToDate)
        {
            string Generated = string.Empty;
            DataTable dt_DownID = new DataTable();
            DataTable dt_ProductionData = new DataTable();
            DataTable dt_SummaryData = new DataTable();
            int DownColStart = 15, rowStart = 2, tempRowstart = rowStart, tempColStart = DownColStart, colStart = 1, TargetCol = 1, ProdHoursCol = 1;
            double StdCycleTime = 0, STMinusBT = 0, ProdQty = 0;
            try
            {
                string Filename = "CustomProductionReport_Agg_DynamicFlow.xlsx";
                string Source = Util.GetReportPath(Filename);
                string Template = "CustomProductionReport_Agg_DynamicFlow" + DateTime.Now + ".xlsx";
                string destination = Path.Combine(appPath, "Temp", SafeFileName(Template));
                if (!File.Exists(Source))
                {
                    Logger.WriteDebugLog("CustomProductionReport_Agg_DynamicFlow template does not exists at - " + Source);
                    Generated = "TemplateNotFound";
                }
                else
                {
                    dt_ProductionData = DataBaseAccess.GetCustomProductionReport_DF(CellID, MachineID, shift, FromDate, ToDate, out dt_SummaryData, out dt_DownID);
                    if (dt_ProductionData.Rows.Count > 0 && dt_ProductionData.Columns.IndexOf("SaveFlag") == -1)
                    {
                        FileInfo fInfo = new FileInfo(Source);
                        ExcelPackage excel = new ExcelPackage(fInfo);
                        var wb = excel.Workbook.Worksheets[1];
                        if (wb != null)
                        {
                            var DistinctDate = dt_ProductionData.AsEnumerable().Select(x => new { pDate = x["Date"].ToString(), MachineID = x["MachineId"].ToString() }).Distinct().ToList();
                            foreach (var ele in DistinctDate)
                            {
                                DataTable dt_ProdData_Temp = dt_ProductionData.AsEnumerable().Where(x => x["Date"].ToString() == ele.pDate && x["MachineId"].ToString().Equals(ele.MachineID, StringComparison.OrdinalIgnoreCase)).CopyToDataTable();
                                tempRowstart = rowStart;
                                foreach (DataRow row in dt_ProdData_Temp.Rows)
                                {
                                    colStart = 1;
                                    wb.Cells[rowStart, colStart++].Value = Util.GetDateTime(row["Date"].ToString()).ToString("dd-MM-yyyy");
                                    wb.Cells[rowStart, colStart++].Value = row["MachineId"].ToString();
                                    wb.Cells[rowStart, colStart++].Value = row["ItemDescription"].ToString();
                                    wb.Cells[rowStart, colStart++].Value = row["JobCodeNo"].ToString();
                                    wb.Cells[rowStart, colStart++].Value = row["JobCardNo"].ToString();
                                    wb.Cells[rowStart, colStart++].Value = row["Operation"].ToString();
                                    wb.Cells[rowStart, colStart++].Value = row["Department"].ToString();
                                    wb.Cells[rowStart, colStart++].Value = row["Shift"].ToString();
                                    wb.Cells[rowStart, colStart++].Value = row["Operators"].ToString();


                                    StdCycleTime = string.IsNullOrEmpty(row["CycletimeStd"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["CycletimeStd"].ToString());
                                    wb.Cells[rowStart, colStart++].Value = (double)(string.IsNullOrEmpty(row["CycletimeStd"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["CycletimeStd"].ToString()));

                                    ProdQty = string.IsNullOrEmpty(row["Prd_Qty"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["Prd_Qty"].ToString());
                                    wb.Cells[rowStart, colStart++].Value = (string.IsNullOrEmpty(row["Prd_Qty"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["Prd_Qty"].ToString()));

                                    wb.Cells[rowStart, colStart++].Value = string.IsNullOrEmpty(row["Rejection_Qty"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["Rejection_Qty"].ToString());
                                    TargetCol = colStart++;
                                    wb.Cells[rowStart, colStart++].Value = row["Remarks"].ToString();

                                    foreach (DataRow down in dt_DownID.Rows)
                                    {
                                        if (rowStart == 2)
                                        {
                                            wb.Cells[1, colStart].Value = down["Downid"].ToString();
                                        }
                                        wb.Cells[rowStart, colStart++].Value = string.IsNullOrEmpty(row[down["Downid"].ToString()].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row[down["Downid"].ToString()].ToString());
                                    }

                                    if (rowStart == 2)
                                    {

                                        wb.Cells[1, colStart++].Value = "";
                                        wb.Cells[1, colStart++].Value = "";
                                        wb.Cells[1, DownColStart, 1, colStart - 1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                        wb.Cells[1, DownColStart, 1, colStart - 1].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(0, 197, 217, 241));

                                        ProdHoursCol = colStart;
                                        wb.Cells[1, colStart].Value = "PRD. HRS";
                                        wb.Cells[1, colStart + 1].Value = "SHIFT TIME - BREAK TIME";
                                        wb.Cells[1, colStart, 1, colStart + 1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                        wb.Cells[1, colStart, 1, colStart + 1].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(0, 255, 192, 0));

                                        wb.Cells[1, DownColStart, 1, colStart + 1].Style.Font.Color.SetColor(Color.FromArgb(0, 226, 107, 10));


                                        wb.Cells[1, colStart + 2].Value = "Availability";
                                        wb.Cells[1, colStart + 3].Value = "Performance";
                                        wb.Cells[1, colStart + 4].Value = "Quality";
                                        wb.Cells[1, colStart + 5].Value = "OEE";
                                        wb.Cells[1, DownColStart, 1, colStart + 5].Style.WrapText = true;
                                        wb.Cells[1, colStart + 2, 1, colStart + 5].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                        wb.Cells[1, colStart + 2, 1, colStart + 5].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(0, 196, 215, 155));

                                        wb.Cells[1, 1, 1, colStart + 5].Style.Font.Bold = true;
                                        wb.Cells[1, 1, 1, colStart + 5].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                                        wb.Cells[1, 1, 1, colStart + 5].AutoFilter = true;

                                    }
                                    else
                                        colStart += 2;

                                    wb.Cells[rowStart, colStart++].Value = string.IsNullOrEmpty(row["ProductionHours"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["ProductionHours"].ToString());
                                    STMinusBT = (string.IsNullOrEmpty(row["STMinusBT"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["STMinusBT"].ToString()));
                                    wb.Cells[rowStart, colStart++].Value = (string.IsNullOrEmpty(row["STMinusBT"].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(row["STMinusBT"].ToString()));

                                    if (StdCycleTime > 0)
                                        wb.Cells[rowStart, TargetCol].Formula = $"{new ExcelAddress(rowStart, ProdHoursCol, rowStart, ProdHoursCol)}/{new ExcelAddress(rowStart, 10, rowStart, 10)}"; // Target Value: (Prod. Hours/Std. Cycle Time)
                                    else
                                        wb.Cells[rowStart, TargetCol].Value = 0;

                                    if (STMinusBT > 0)
                                        wb.Cells[rowStart, colStart].Formula = $"({new ExcelAddress(rowStart, ProdHoursCol, rowStart, ProdHoursCol)}/{new ExcelAddress(rowStart, ProdHoursCol + 1, rowStart, ProdHoursCol + 1)})*100"; //AE: (Prod. Hours / ST-BT)*100
                                    else
                                        wb.Cells[rowStart, colStart].Value = 0;

                                    colStart++;

                                    if (StdCycleTime > 0)
                                        wb.Cells[rowStart, colStart++].Formula = $"({new ExcelAddress(rowStart, 11, rowStart, 11)}/{new ExcelAddress(rowStart, 13, rowStart, 13)})*100"; //PE: (Prd. Qty/Trg.QTY*100)
                                    else
                                        wb.Cells[rowStart, colStart++].Value = 0;

                                    if (ProdQty > 0)
                                        wb.Cells[rowStart, colStart++].Formula = $"({new ExcelAddress(rowStart, 11, rowStart, 11)}-{new ExcelAddress(rowStart, 12, rowStart, 12)})/{new ExcelAddress(rowStart, 11, rowStart, 11)}*100"; //QE: (PRD. QTY - REJ. QTY)/PRD. QTY * 100
                                    else
                                        wb.Cells[rowStart, colStart++].Value = 0;
                                    wb.Cells[rowStart, colStart].Formula = $"({new ExcelAddress(rowStart, colStart - 3, rowStart, colStart - 3)}*{new ExcelAddress(rowStart, colStart - 2, rowStart, colStart - 2)}*{new ExcelAddress(rowStart, colStart - 1, rowStart, colStart - 1)})/10000";  //OEE: "AE10*AF10*AG10/10000";
                                    wb.Cells[rowStart, colStart - 3, rowStart, colStart].Style.Numberformat.Format = "0.00";

                                    rowStart++;
                                }
                                wb.Cells[tempRowstart, 1, rowStart - 1, 1].Merge = true;
                                wb.Cells[tempRowstart, 2, rowStart - 1, 2].Merge = true;

                                //wb.Cells[rowStart, 1].Value = "Summary Data";
                                wb.Cells[rowStart, 1, rowStart, colStart].Style.Fill.PatternType = ExcelFillStyle.Solid;
                                wb.Cells[rowStart, 1, rowStart, colStart].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(0, 196, 215, 155));

                                //var Summary_Row = dt_SummaryData.AsEnumerable().Where(x => x["Date"].ToString() == ele.pDate && x["MachineId"].ToString().Equals(ele.MachineID, StringComparison.OrdinalIgnoreCase)).FirstOrDefault();
                                //if (Summary_Row != null)
                                //{
                                //    wb.Cells[rowStart, 11].Value = HelperClassGeneric.getDoubleValueFromString(Summary_Row["Prd_Qty"].ToString());
                                //    wb.Cells[rowStart, 12].Value = HelperClassGeneric.getDoubleValueFromString(Summary_Row["Rejection_Qty"].ToString());
                                //    wb.Cells[rowStart, 13].Formula = $"SUM({new ExcelAddress(tempRowstart, 13, rowStart - 1, 13)})";//Target Value: Formula based Calculation
                                //    int DownStart = DownColStart;
                                //    foreach (DataRow down in dt_DownID.Rows)
                                //    {
                                //        wb.Cells[rowStart, DownStart++].Value = string.IsNullOrEmpty(Summary_Row[down["Downid"].ToString()].ToString()) ? 0 : HelperClassGeneric.getDoubleValueFromString(Summary_Row[down["Downid"].ToString()].ToString());
                                //    }

                                //    //AE,PE<QE,OEE Summary
                                //    wb.Cells[rowStart, colStart - 3].Formula = $"SUM({new ExcelAddress(tempRowstart, colStart - 3, rowStart - 1, colStart - 3)})/{rowStart - tempRowstart}"; // Summary: AVG of AE

                                //    wb.Cells[rowStart, colStart - 2].Formula = $"SUM({new ExcelAddress(tempRowstart, colStart - 2, rowStart - 1, colStart - 2)})/{rowStart - tempRowstart}"; // Summary: AVG of PE

                                //    wb.Cells[rowStart, colStart - 1].Formula = $"SUM({new ExcelAddress(tempRowstart, colStart - 1, rowStart - 1, colStart - 1)})/{rowStart - tempRowstart}"; // Summary: AVG of QE

                                //    wb.Cells[rowStart, colStart].Formula = $"SUM({new ExcelAddress(tempRowstart, colStart, rowStart - 1, colStart)})/{rowStart - tempRowstart}"; // Summary: AVG of OEE
                                //}
                                rowStart++;

                            }
                        }
                        wb.Column(TargetCol).Style.Numberformat.Format = "0.00";
                        wb.Column(colStart - 3).Style.Numberformat.Format = "0.00";
                        wb.Column(colStart - 2).Style.Numberformat.Format = "0.00";
                        wb.Column(colStart - 1).Style.Numberformat.Format = "0.00";
                        wb.Column(colStart).Style.Numberformat.Format = "0.00";
                        setThinBorder(wb, 1, 1, rowStart - 1, colStart);
                        DownloadMultipleFile(destination, excel.GetAsByteArray());
                        Generated = "Generated";
                    }
                    else
                    {
                        Generated = "NodataFound";
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("ProductionReportDynamicFlow_Agg: " + ex.Message);
            }
            return Generated;
        }

