        internal static string MonthlyProductionReport_RNGupta( string yearNo, string monthNo)
        {
            string Generated = string.Empty;
            try
            {
                string src = string.Empty, dst = string.Empty;
                string ReportName = "MonthlyProductionReport_RNGupta.xlsx";
                src = Util.GetReportPath(ReportName);

                string TempFileName = "MonthlyProductionReport_RNGupta_" + DateTime.Now + ".xlsx";
                dst = Path.Combine(appPath, "Temp", SafeFileName(TempFileName));
                

                if (!File.Exists(src))
                {
                    Logger.WriteDebugLog("Monthly Production Report - RNGupta template does not exists at - " + src);
                    Generated = "TemplateNotFound";
                    return string.Empty;
                }
                FileInfo newFile = new FileInfo(src);
                ExcelPackage excel = new ExcelPackage(newFile, true);
                var ws = excel.Workbook.Worksheets[1];
                int col = 1, row = 3;
                DataTable dt = DataBaseAccess.GetMonthlyProductionReport_RNGupta(yearNo, monthNo);
                if (dt != null && dt.Rows.Count > 0)
                {
                    ws.Cells["A2"].Style.Font.Bold = true;
                    ws.Cells["A2"].Value = "YearNo";
                    setThinBorder(ws, 2, 1, 2, 2);
                    ws.Cells["B2"].Value = Convert.ToDecimal(yearNo);
                    ws.Cells["D2"].Style.Font.Bold = true;
                    ws.Cells["D2"].Value = "MonthNo";
                    setThinBorder(ws, 2, 3, 2, 4);
                    ws.Cells["E2"].Value = Convert.ToDecimal(monthNo);



                    int currentColumn = 6;
                    for (int j = 5; j < dt.Columns.Count; j++)
                    {
                        ws.Cells[row, currentColumn].Value =Convert.ToDateTime( dt.Columns[j].ColumnName).ToString("dd-MM-yyyy");
                        ws.Cells[row, currentColumn].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                        ws.Cells[row, currentColumn].Style.Fill.PatternType = ExcelFillStyle.Solid;
                        ws.Cells[row, currentColumn].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(252, 213, 180));
                        currentColumn++;
                    }

                    ws.Cells[1, 1, 1, 5].Merge = true; 
                    ws.Cells[1, 1,1,5].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;
                    ws.Row(row).Style.Font.Bold = true;
                    ws.Cells[1, 1, 1, 5].Style.Font.Size = 15;
                    ws.Cells[1, 1, 1,  5].Value = "Monthly Production Report";

                    setThinBorder(ws, 1, 1, 1, 5);


                    ws.Cells[1, 6, 1, currentColumn - 1].Merge = true;
                    ws.Cells[1, 1, 1, currentColumn-1].Style.Fill.PatternType = ExcelFillStyle.Solid;
                    ws.Cells[1, 1, 1, currentColumn-1].Style.Fill.BackgroundColor.SetColor(Color.FromArgb(250, 191, 143));
                     
                    row = 4;
                    foreach (DataRow item in dt.Rows)
                    {
                        col = 1;
                        ws.Cells[row, col].Value = item["ComponentId"].ToString();
                        col++;
                        ws.Cells[row, col].Value = item["ComponentDescription"].ToString();
                        col++;
                        ws.Cells[row, col].Value = Convert.ToDecimal( item["OpnNo"].ToString());
                        col++;
                        ws.Cells[row, col].Value = item["OpnDescription"].ToString();
                        col++;
                        ws.Cells[row, col].Value = Convert.ToDecimal(item["TotalProd"].ToString());
                        col = 6;
                        for (int j = 5; j < dt.Columns.Count; j++)
                        {
                            ws.Cells[row, col].Value =Convert.ToDecimal(item[j].ToString());
                            ws.Cells[row, col].Style.HorizontalAlignment = ExcelHorizontalAlignment.Center;

                            col++;
                        }
                        row++;
                    }
                    for (int cRow = 4; cRow < 5; cRow++)
                    {
                        for (int cCol = 1; cCol < 7; cCol++)
                        {
                            ws.View.FreezePanes(cRow, cCol);
                        }
                    }

                    

                    setThinBorder(ws, 3, 1, row - 1, col-1);
                    ws.Cells[1, 1, row-1, col - 1].Style.Border.BorderAround(ExcelBorderStyle.Thick, Color.Black);
                    DownloadMultipleFile(dst, excel.GetAsByteArray());
                    Generated = "Generated";
                }
                else
                    Generated = "NodataFound";
            }
            catch (Exception ex)
            {
                Logger.WriteErrorLog("MonthlyProductionReport_RNGupta: " + ex.ToString());
            }
            return Generated;
        }


